window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["ibnu-majah_2"] = {"1001":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بِأَصْحَابِهِ فَلَمَّا قَضَى الصَّلَاةَ أَقْبَلَ عَلَى الْقَوْمِ بِوَجْهِهِ فَقَالَ مَا بَالُ أَقْوَامٍ يَرْفَعُونَ أَبْصَارَهُمْ إِلَى السَّمَاءِ حَتَّى اشْتَدَّ قَوْلُهُ فِي ذَلِكَ لَيَنْتَهُنَّ عَنْ ذَلِكَ أَوْ لَيَخْطَفَنَّ اللَّهُ أَبْصَارَهُمْ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abdul A'la] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Pernah suatu hari Rasulullah shallallahu 'alaihi wasallam shalat bersama sahabatnya, selesai shalat beliau menghadap ke arah orang-orang dan bersabda: \"Kenapa orang-orang suka mengangkat mata mereka ke langit -hingga suara beliau meninggi- mereka segera mengakhiri perbuatannya itu atau Allah akan menyambar mata mereka. \""},"1002":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَنْتَهِيَنَّ أَقْوَامٌ يَرْفَعُونَ أَبْصَارَهُمْ إِلَى السَّمَاءِ أَوْ لَا تَرْجِعُ أَبْصَارُهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Tamim bin Tharafah] dari [Jabir bin Samurah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Orang-orang itu segera mengakhiri perbuatannya mengangkat mata ke langit atau mata mereka tidak akan kembali lagi. \""},"1003":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالَا حَدَّثَنَا نُوحُ بْنُ قَيْسٍ حَدَّثَنَا عَمْرُو بْنُ مَالِكٍ عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ امْرَأَةٌ تُصَلِّي خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَسْنَاءُ مِنْ أَحْسَنِ النَّاسِ فَكَانَ بَعْضُ الْقَوْمِ يَسْتَقْدِمُ فِي الصَّفِّ الْأَوَّلِ لِئَلَّا يَرَاهَا وَيَسْتَأْخِرُ بَعْضُهُمْ حَتَّى يَكُونَ فِي الصَّفِّ الْمُؤَخَّرِ فَإِذَا رَكَعَ قَالَ هَكَذَا يَنْظُرُ مِنْ تَحْتِ إِبْطِهِ فَأَنْزَلَ اللَّهُ{ وَلَقَدْ عَلِمْنَا الْمُسْتَقْدِمِينَ مِنْكُمْ وَلَقَدْ عَلِمْنَا الْمُسْتَأْخِرِينَ }فِي شَأْنِهَا","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] dan [Abu Bakr bin Khallad] keduanya berkata; telah menceritakan kepada kami [Nuh bin Qais] berkata, telah menceritakan kepada kami [Amru bin Malik] dari [Abul Jauza`] dari [Ibnu Abbas] ia berkata, \"Seorang wanita pernah shalat di belakang Nabi shallallahu 'alaihi wasallam -ia adalah wanita tercantik-. Sebagian sahabat maju ke barisan depan agar tidak dapat melihatnya, sementara sebagian sahabat yang lain sengaja mundur ke barisan belakang. Maka ketika rukuk (orang yang di barisan belakang), Ibnu Abbas berkata, \"Seperti ini -yakni melihat dari bawah ketiaknya-. Maka Allah pun menurunkan ayat: \" (Dan sungguh Kami telah mengetahui orang-orang yang terdepan di antara kalian dan sungguh Kami telah mengetahui orang-orang yang di belakang), \" dalam perkara wanita tersebut. \" "},"1004":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَحَدُنَا يُصَلِّي فِي الثَّوْبِ الْوَاحِدِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَ كُلُّكُمْ يَجِدُ ثَوْبَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Salah seorang dari kami shalat dengan hanya mengenakan satu kain?\" beliau bersabda: \"Apakah kalian semua mempunyai dua kain?\""},"1005":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ حَدَّثَنِي أَبُو سَعِيدٍ الْخُدْرِيُّأَنَّهُ دَخَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ مُتَوَشِّحًا بِهِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Umar bin Ubaid] dari [A'masy] dari [Abu Sufyan] dari [Jabir] berkata, telah menceritakan kepadaku [Abu Sa'id Al Khudlri] bahwasanya ia pernah mengunjungi Rasulullah shallallahu 'alaihi wasallam, ketika itu beliau shalat dengan mengenakan satu kain yang diselempangkan. \" "},"1006":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ مُتَوَشِّحًا بِهِ وَاضِعًا طَرَفَيْهِ عَلَى عَاتِقَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Umar bin Abu Salamah] ia berkata, \"Aku pernah Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan satu kain, beliau menyelempangkan dan meletakkan ujungnya pada kedua pundak. \""},"1007":{"ar":"حَدَّثَنَا أَبُو إِسْحَقَ الشَّافِعِيُّ إِبْرَاهِيمُ بْنُ مُحَمَّدِ بْنِ الْعَبَّاسِ حَدَّثَنَا مُحَمَّدُ بْنُ حَنْظَلَةَ بْنِ مُحَمَّدِ بْنِ عَبَّادٍ الْمَخْزُومِيُّ عَنْ مَعْرُوفِ بْنِ مُشْكَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَيْسَانَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالْبِئْرِ الْعُلْيَا فِي ثَوْبٍ","id":"Telah menceritakan kepada kami [Abu Ishaq Asy Syafi'I Ibrahim bin Muhammad bin Al Abbas] berkata, telah menceritakan kepada kami [Muhammad bin Hanzhalah bin Abbad Al Makhzumi] dari [Ma'ruf bin Musykan] dari ['Abdurrahman bin Kaisan] dari [Bapaknya] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan satu kain di Bi`rul 'Ulya. \""},"1008":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا عَمْرُو بْنُ كَثِيرٍ حَدَّثَنَا ابْنُ كَيْسَانَ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ وَالْعَصْرَ فِي ثَوْبٍ وَاحِدٍ مُتَلَبِّبًا بِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Amru bin Katsir] dari [Ibnu Kaisan] dari [Bapaknya] ia berkata, \"Aku pernah melihat Nabi shallallahu 'alaihi wasallam shalat zhuhur dan ashar dengan mengenakan satu kain mutalabbiban (mengumpulkan ujungnya di depan dada). \""},"1009":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَرَأَ ابْنُ آدَمَ السَّجْدَةَ فَسَجَدَ اعْتَزَلَ الشَّيْطَانُ يَبْكِي يَقُولُ يَا وَيْلَهُ أُمِرَ ابْنُ آدَمَ بِالسُّجُودِ فَسَجَدَ فَلَهُ الْجَنَّةُ وَأُمِرْتُ بِالسُّجُودِ فَأَبَيْتُ فَلِي النَّارُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika anak Adam membaca ayat sajadah kemudian sujud, maka setan menjauh sambil menangis, ia berkata, \"Duhai malangnya, anak Adam diperintahkan sujud lalu ia sujud, maka ia pun masuk surga. sementara aku diperintah sujud namun aku menolak, maka aku pun masuk neraka. \""},"1010":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ بْنِ خُنَيْسٍ عَنْ الْحَسَنِ بْنِ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ قَالَ قَالَ لِي ابْنُ جُرَيْجٍ يَا حَسَنُ أَخْبَرَنِي جَدُّكَ عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ عَنْ ابْنِ عَبَّاسٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ رَجُلٌ فَقَالَ إِنِّي رَأَيْتُ الْبَارِحَةَ فِيمَا يَرَى النَّائِمُ كَأَنِّي أُصَلِّي إِلَى أَصْلِ شَجَرَةٍ فَقَرَأْتُ السَّجْدَةَ فَسَجَدْتُ فَسَجَدَتْ الشَّجَرَةُ لِسُجُودِي فَسَمِعْتُهَا تَقُولُ اللَّهُمَّ احْطُطْ عَنِّي بِهَا وِزْرًا وَاكْتُبْ لِي بِهَا أَجْرًا وَاجْعَلْهَا لِي عِنْدَكَ ذُخْرًا قَالَ ابْنُ عَبَّاسٍ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ السَّجْدَةَ فَسَجَدَ فَسَمِعْتُهُ يَقُولُ فِي سُجُودِهِ مِثْلَ الَّذِي أَخْبَرَهُ الرَّجُلُ عَنْ قَوْلِ الشَّجَرَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Muhammad bin Yazid bin Khunais] dari [Al Hasan bin Muhammad bin Ubaidullah bin Abu Yazid] ia berkata; [Ibnu Juraij] berkata kepadaku, \"Wahai Hasan, [kakekmu] telah mengabarkan kepadaku dari [Ibnu Abbas], bahwa ia pernah berkata, \"Aku bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba datang seorang laki-laki kepada beliau dan berkata, \"Semalam aku bermimpi seakan-akan aku shalat di bawah pohon, aku membaca ayat sajadah lalu bersujud. Tiba-tiba pohon itu ikut sujud karena sujudku. Dan aku mendengar pohon itu mengatakan, \"Ya Allah, dengan sujud ini hapuskanlah dosaku, tulislah pahala untukku, serta jadikanlah itu di sisi-Mu sebagai simpanan. \" Ibnu Abbas berkata: \"Lalu aku melihat Rasulullah shallallahu 'alaihi wasallam membaca ayat sajadah lalu sujud, dan aku mendengar beliau berdo`a dalam sujudnya seperti do`a yang diucapkan oleh pohon, sebagaimana yang dikabarkan oleh laki-laki itu. \" "},"1011":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَمْرٍو الْأَنْصَارِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ عَنْ ابْنِ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَجَدَ قَالَ اللَّهُمَّ لَكَ سَجَدْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ أَنْتَ رَبِّي سَجَدَ وَجْهِي لِلَّذِي شَقَّ سَمْعَهُ وَبَصَرَهُ تَبَارَكَ اللَّهُ أَحْسَنُ الْخَالِقِينَ","id":"Telah menceritakan kepada kami [Ali bin Amru Al Anshari] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Umawi] dari [Ibnu Juraij] dari [Musa bin Uqbah] dari [Abdullah Ibnul Fadll] dari [Al A'raj] dari [Ubaidullah bin Abu Rafi'] dari [Ali] berkata, \"Nabi shallallahu 'alaihi wasallam jika sujud membaca: ALLAHUMMA AAMANTU WA LAKA ASLAMTU ANTA RABBI SAJADA WAJHII LILLADZII SYAQQA SA'AHUU WA BASHARAHUU TABAARAKA ALLAHU AHSANUL KHAALIGIIN. \""},"1012":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ عُمَرَ الدِّمَشْقِيِّ عَنْ أُمِّ الدَّرْدَاءِ قَالَتْ حَدَّثَنِي أَبُو الدَّرْدَاءِأَنَّهُ سَجَدَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً مِنْهُنَّ النَّجْمُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Amru Ibnul Harits] dari [Ibnu Abu Hilal] dari [Umar Ad Dimasyqi] dari [Ummu Darda] ia berkata, \" [Abu Darda] menceritakan kepadaku bahwa ia pernah sujud bersama Nabi shallallahu 'alaihi wasallam sebanyak sebelas kali, salah satunya adalah dalam surat An Najm. \""},"1013":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ حَدَّثَنَا عُثْمَانُ بْنُ فَائِدٍ حَدَّثَنَا عَاصِمُ بْنُ رَجَاءِ بْنِ حَيْوَةَ عَنْ الْمَهْدِيِّ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عُبَيْدَةَ بْنِ خَاطِرٍ قَالَ حَدَّثَتْنِي عَمَّتِي أُمُّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَسَجَدْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى عَشْرَةَ سَجْدَةً لَيْسَ فِيهَا مِنْ الْمُفَصَّلِ شَيْءٌ الْأَعْرَافُ وَالرَّعْدُ وَالنَّحْلُ وَبَنِي إِسْرَائِيلَ وَمَرْيَمُ وَالْحَجُّ وَسَجْدَةُ الْفُرْقَانِ وَسُلَيْمَانُ سُورَةِ النَّمْلِ وَالسَّجْدَةُ وَفِي ص وَسَجْدَةُ الْحَوَامِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Sulaiman bin 'Abdurrahman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Utsman bin Fa`id] berkata, telah menceritakan kepada kami [Ashim bin Raja` bin Haiwah] dari [Al Mahdi bin 'Abdurrahman bin Abidah bin Khathir] berkata; berkata, telah menceritakan kepadaku bibiku [Ummu Darda] dari [Abu Darda] ia berkata, \"Aku pernah sujud sajadah bersama Nabi shallallahu 'alaihi wasallam sebanyak sebelas kali, seluruhnya tidak terdapat dalam surat Al Mufashshal; Al A'raf, Ar Ra'd, An Nahl, Bani Isra'il, Maryam, Al Hajj, Al Furqan, Sulaiman dalam surat An Naml, sajadah dalam surat Shaad, dan sajdah surat Al Hawamim. \""},"1014":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ عَنْ نَافِعِ بْنِ يَزِيدَ حَدَّثَنَا الْحَارِثُ بْنُ سَعِيدٍ الْعُتَقِيُّ عَنْ عَبْدِ اللَّهِ بْنِ مُنَيْنٍ مِنْ بَنِي عَبْدِ كِلَالٍ عَنْ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَهُ خَمْسَ عَشْرَةَ سَجْدَةً فِي الْقُرْآنِ مِنْهَا ثَلَاثٌ فِي الْمُفَصَّلِ وَفِي الْحَجِّ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ibnu Abu Maryam] dari [Nafi' bin Yazid] berkata, telah menceritakan kepada kami [Al Harits bin Sa'id Al 'Utaqi] dari [Abdullah bin Munain] -seorang dari Bani Abdu Kilal- dari [Amru bin Al 'Ash] bahwasanya Rasulullah shallallahu 'alaihi wasallam membacakan kepadanya lima belas ayat sajadah dalam Al Qur'an; di antaranya tiga dalam Al Mufashshal dan dua dalam di Surat Al Hajj. \" "},"1015":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَطَاءِ بْنِ مِينَاءَ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِذَا السَّمَاءُ انْشَقَّتْ وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ayyub bin Musa] dari ['Atho` bin Mina] dari [Abu Hurairah] ia berkata, \"Kami sujud sajdah bersama Rasulullah shallallahu 'alaihi wasallam pada ayat IDZAS SAMAA`UN SYAQQAT (Apabila langit terbelah) dan IQRA` BISMIRABBIKA (Bacalah dengan (menyebut) nama Tuhanmu). \""},"1016":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي إِذَا السَّمَاءُ انْشَقَّتْقَالَ أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ هَذَا الْحَدِيثُ مِنْ حَدِيثِ يَحْيَى بْنِ سَعِيدٍ مَا سَمِعْتُ أَحَدًا يَذْكُرُهُ غَيْرَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Umar bin Abdul Aziz] dari [Abu Bakr bin 'Abdurrahman bin Ibnul Harits bin Hisyam] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam sujud pada ayat; IDZAS SAMAA`UN SYAQQAT (Apabila langit terbelah). \" Abu Bakr bin Abu Syaibah berkata, \"Ini adalah hadits yang berasal dari Yahya bin Sa'id, dan aku tidak mendengar seorang pun yang menyebutkannya selain dia. \""},"1017":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ فَصَلَّى وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاحِيَةٍ مِنْ الْمَسْجِدِ فَجَاءَ فَسَلَّمَ فَقَالَ وَعَلَيْكَ فَارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَعَلَيْكَ فَارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ بَعْدُ قَالَ فِي الثَّالِثَةِ فَعَلِّمْنِي يَا رَسُولَ اللَّهِ قَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَأَسْبِغْ الْوُضُوءَ ثُمَّ اسْتَقْبِلْ الْقِبْلَةَ فَكَبِّرْ ثُمَّ اقْرَأْ مَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ رَأْسَكَ حَتَّى تَسْتَوِيَ قَاعِدًا ثُمَّ افْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah bin Umar] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] berkata, \"Seorang laki-laki masuk ke dalam masjid dan shalat, sementara Rasulullah shallallahu 'alaihi wasallam berada di sudut masjid. laki-laki itu kemudian datang seraya mengucapkan salam, tetapi Nabi bersabda: \"Kembali dan shalatlah, sebab engkau belum shalat. \" Laki-laki itu pun kembali shalat, lalu kembali menemui beliau dan mengucapkan shalat kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kembali dan shalatlah, sebab engkau belum shalat. \" Dan pada kali ketiganya ia berkata, \"Wahai Rasulullah, ajarkanlah kepadaku. \" Beliau bersabda: \"Jika engkau shalat maka sempurnakanlah wudlu dan menghadaplah ke arah kiblat. Kemudian takbir dan bacalah ayat al Qur'an yang mudah menurut kamu, kemudian rukuklah hingga engkau tenang, kemudian berdirilah hingga engkau tegak berdiri, kemudian sujudlah hingga engkau tenang, kemudian angkatlah kepalamu hingga engkau tegak duduk. Dan lakukanlah hal seperti dalam semua shalatmu. \""},"1018":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ قَالَسَمِعْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ فِي عَشْرَةٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِمْ أَبُو قَتَادَةَ فَقَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا لِمَ فَوَاللَّهِ مَا كُنْتَ بِأَكْثَرِنَا لَهُ تَبَعَةً وَلَا أَقْدَمَنَا لَهُ صُحْبَةً قَالَ بَلَى قَالُوا فَاعْرِضْ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ كَبَّرَ ثُمَّ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ وَيَقِرَّ كُلُّ عُضْوٍ مِنْهُ فِي مَوْضِعِهِ ثُمَّ يَقْرَأُ ثُمَّ يُكَبِّرُ وَيَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ يَرْكَعُ وَيَضَعُ رَاحَتَيْهِ عَلَى رُكْبَتَيْهِ مُعْتَمِدًا لَا يَصُبُّ رَأْسَهُ وَلَا يُقْنِعُ مُعْتَدِلًا ثُمَّ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَيَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ حَتَّى يَقِرَّ كُلُّ عَظْمٍ إِلَى مَوْضِعِهِ ثُمَّ يَهْوِي إِلَى الْأَرْضِ وَيُجَافِي بَيْنَ يَدَيْهِ عَنْ جَنْبَيْهِ ثُمَّ يَرْفَعُ رَأْسَهُ وَيَثْنِي رِجْلَهُ الْيُسْرَى فَيَقْعُدُ عَلَيْهَا وَيَفْتَخُ أَصَابِعَ رِجْلَيْهِ إِذَا سَجَدَ ثُمَّ يَسْجُدُ ثُمَّ يُكَبِّرُ وَيَجْلِسُ عَلَى رِجْلِهِ الْيُسْرَى حَتَّى يَرْجِعَ كُلُّ عَظْمٍ مِنْهُ إِلَى مَوْضِعِهِ ثُمَّ يَقُومُ فَيَصْنَعُ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ ثُمَّ إِذَا قَامَ مِنْ الرَّكْعَتَيْنِ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا صَنَعَ عِنْدَ افْتِتَاحِ الصَّلَاةِ ثُمَّ يُصَلِّي بَقِيَّةَ صَلَاتِهِ هَكَذَا حَتَّى إِذَا كَانَتْ السَّجْدَةُ الَّتِي يَنْقَضِي فِيهَا التَّسْلِيمُ أَخَّرَ إِحْدَى رِجْلَيْهِ وَجَلَسَ عَلَى شِقِّهِ الْأَيْسَرِ مُتَوَرِّكًا قَالُوا صَدَقْتَ هَكَذَا كَانَ يُصَلِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Ashim] berkata, telah menceritakan kepada kami [Abdul Hamid bin Ja'far] berkata, telah menceritakan kepada kami [Muhammad bin Amru bin 'Atho`] berkata; aku mendengar [Abu Humaid As Sa'idi] -ia adalah seorang dari sepuluh orang sahabat Rasulullah shallallahu 'alaihi wasallam yang sedang berkumpul- di antara mereka juga ada [Abu Qatadah], ia berkata, \"Aku adalah orang yang paling tahu tentang shalat Rasulullah shallallahu 'alaihi wasallam daripada kalian semua, \" mereka bertanya, \"Bagaimana bisa! Demi Allah, tidaklah engkau lebih banyak mengikuti Rasulullah ketimbang kami, dan tidak lebih dahulu bertemu dengan beliau daripada kami?\" Abu Qatadah menjawab, \"Benar. \" Mereka berkata, \"Maka jelaskanlah (kepada kami), \" Abu Qatadah berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam berdiri shalat, beliau takbir dan mengangkat kedua tangannya hingga sejajar dengan kedua pundak dan setiap organ tubuh kembali ke tempatnya. Kemudian beliau meletakkan dua telapak tangannya dan bertumpu pada lutut, seimbang tidak mengangkat atau pun menurunkan kepalanya. Kemudian beliau mengucapkan; SAMI'A ALLAHU LIMAN HAMIDAHU seraya mengangkat kedua tangannya hingga sejajar dengan kedua pundak dan setiap tulang kembali ke tempatnya. Setelah itu beliau turun ke bumi (sujud) dan menjauhkan kedua tangannya dari lambung, kemudian beliau mengangkat kepala dan membentangkan kaki kiri dan duduk di atasnya -beliau juga melenturkan jari-jari kakinya dan mengarahkan menghadap kiblat ketika sujud-, kemudian beliau sujud, kemudian takbir dan duduk di atas kaki kiri hingga setai tulang kembali ke asalnya. Setelah itu beliau bangun dan melakukan seperti itu pada raka'at yang lain. kemudian jika berdiri dari raka'at kedua, beliau mengangkat kedua tangannya sejajar dengan kedua pundak sebagaimana ketika beliau memulai shalat (Takbiratul Ikram). Kemudian beliau melakukan sisa shalatnya seperti itu, hingga ketika sampai pada sujud terakhir sebelum salam beliau mengakhirkan salah satu kakinya dan duduk tawarruk pada sisi kiri. \" Mereka berkata, \"Engkau benar, begitulah Rasulullah shallallahu 'alaihi wasallam shalat. \""},"1019":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ حَارِثَةَ بْنِ أَبِي الرِّجَالِ عَنْ عَمْرَةَ قَالَتْسَأَلْتُ عَائِشَةَ كَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ فَوَضَعَ يَدَيْهِ فِي الْإِنَاءِ سَمَّى اللَّهَ وَيُسْبِغُ الْوُضُوءَ ثُمَّ يَقُومُ مُسْتَقْبِلَ الْقِبْلَةِ فَيُكَبِّرُ وَيَرْفَعُ يَدَيْهِ حِذَاءَ مَنْكِبَيْهِ ثُمَّ يَرْكَعُ فَيَضَعُ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَيُجَافِي بِعَضُدَيْهِ ثُمَّ يَرْفَعُ رَأْسَهُ فَيُقِيمُ صُلْبَهُ وَيَقُومُ قِيَامًا هُوَ أَطْوَلُ مِنْ قِيَامِكُمْ قَلِيلًا ثُمَّ يَسْجُدُ فَيَضَعُ يَدَيْهِ تُجَاهَ الْقِبْلَةِ وَيُجَافِي بِعَضُدَيْهِ مَا اسْتَطَاعَ فِيمَا رَأَيْتُ ثُمَّ يَرْفَعُ رَأْسَهُ فَيَجْلِسُ عَلَى قَدَمِهِ الْيُسْرَى وَيَنْصِبُ الْيُمْنَى وَيَكْرَهُ أَنْ يَسْقُطَ عَلَى شِقِّهِ الْأَيْسَرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Haritsah bin Abu Rijal] dari [Amrah] ia berkata, \"Aku bertanya kepada ['Aisyah], \"Bagaimana shalat Rasulullah shallallahu 'alaihi wasallam?\" 'Aisyah menjawab, \"Nabi shallallahu 'alaihi wasallam apabila berwudlu, beliau meletakkan kedua tangannya dalam bejana, membaca basmallah, dan menyempurnakan wudlunya. Lalu beliau berdiri menghadap kiblat, bertakbir dan mengangkat kedua tangannya sejajar dengan kedua bahunya. Beliau rukuk dan meletakkan kedua tangannya di atas kedua lututnya. Kemudian menjauhkan kedua tangannya dari lambung, beliau mengangkat kepalanya hingga punggungnya lurus, dan beliau berdiri lebih lama dari berdirinya kalian. Setelah itu beliau sujud dan meletakkan kedua tangannya menghadap kiblat seraya menjauhkan keduanya dari lambung semampunya sebagaimana yang aku lihat. Setelah itu beliau mengangkat kepalanya dan duduk di atas kaki kiri dan menegakkan kaki kanan, dan beliau tidak suka condong ke sebelah kiri. \" "},"1020":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عُمَرَ قَالَصَلَاةُ السَّفَرِ رَكْعَتَانِ وَالْجُمُعَةُ رَكْعَتَانِ وَالْعِيدُ رَكْعَتَانِ تَمَامٌ غَيْرُ قَصْرٍ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dari [Zubaid] dari ['Abdurrahman bin Abu Laila] dari [Umar] ia berkata, \"Shalat safar itu dua raka'at, jum'at dua raka'at, dan ied dua raka'at, sempurna tanpa meringkas sebagaimana sabda Muhammad shallallahu 'alaihi wasallam. \""},"1021":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ أَنْبَأَنَا يَزِيدُ بْنُ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ عُمَرَ قَالَصَلَاةُ السَّفَرِ رَكْعَتَانِ وَصَلَاةُ الْجُمُعَةِ رَكْعَتَانِ وَالْفِطْرُ وَالْأَضْحَى رَكْعَتَانِ تَمَامٌ غَيْرُ قَصْرٍ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah memberitakan kepada kami [Yazid bin Ziyad bin Abu Al Ju'd] dari [Zubaid] dari ['Abdurrahman bin Abu Laila] dari [Ka'b bin Ujrah] dari [Umar] ia berkata, \"Shalat safar itu dua raka'at, jum'at dua raka'at, iedul Fithri dan iedul Adlha dua raka'at, sempurna tanpa meringkas sebagaimana sabda Muhammad shallallahu 'alaihi wasallam. \""},"1022":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَسَأَلْتُ عُمَرَ بْنَ الْخَطَّابِ قُلْتُ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا وَقَدْ أَمِنَ النَّاسُ فَقَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu Juraij] dari [Ibnu Abu Ammar] dari [Abdullah bin Babaih] dari [Ya'la bin Umayyah] ia berkata, \"Aku bertanya kepada Umar bin Al Khaththab, aku katakan, \" (maka tidaklah mengapa kamu men-qashar sembahyang (mu), jika kamu takut diserang orang-orang kafir), sekarang bagaimana padahal manusia sudah merasa aman?\" Umar lalu menjawab, \"Aku pernah merasa heran sebagaimana yang engkau alami, kemudian aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu, beliau menjawab: \"Itu adalah sedekah yang Allah sedekahkan kepada kalian, maka terimalah sedekah tersebut. \""},"1023":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمَيَّةَ بْنِ عَبْدِ اللَّهِ بْنِ خَالِدٍأَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ عُمَرَ إِنَّا نَجِدُ صَلَاةَ الْحَضَرِ وَصَلَاةَ الْخَوْفِ فِي الْقُرْآنِ وَلَا نَجِدُ صَلَاةَ السَّفَرِ فَقَالَ لَهُ عَبْدُ اللَّهِ إِنَّ اللَّهَ بَعَثَ إِلَيْنَا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا نَعْلَمُ شَيْئًا فَإِنَّمَا نَفْعَلُ كَمَا رَأَيْنَا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari [Abdullah bin Abu Bakr bin 'Abdurrahman] dari [Umayyah bin Abdullah bin Khalid] ia berkata kepada [Abdullah bin Umar], \"Dalam Al Quran kami mendapati ada shalat hadlr dan shalat khauf, tetapi kami tidak mendapatkan shalat safar?\" lalu Abdullah menjawab, \"Allah mengutus Muhammad shallallahu 'alaihi wasallam kepada kami sedang kami tidak mengetahui apa-apa, maka kami melakukan sebagaimana kami melihat Rasulullah shallallahu 'alaihi wasallam melakukannya. \" "},"1024":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ بِشْرِ بْنِ حَرْبٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ مِنْ هَذِهِ الْمَدِينَةِ لَمْ يَزِدْ عَلَى رَكْعَتَيْنِ حَتَّى يَرْجِعَ إِلَيْهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Bisyr bin Harb] dari [Ibnu Umar] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam keluar dari kota Madinah, beliau tidak pernah shalat lebih dari dua raka'at hingga beliau kembali. \""},"1025":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ وَجُبَارَةُ بْنُ الْمُغَلِّسِ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَافْتَرَضَ اللَّهُ الصَّلَاةَ عَلَى لِسَانِ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَضَرِ أَرْبَعًا وَفِي السَّفَرِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhamad bin Abdul Malik bin Abu Asy Syawarib] dan [Jubarah bin Al Mughallas] keduanya berkata; telah menceritakan kepada kami [Abu Awanah] dari [Bukair bin Al Akhnas] dari [Mujahid] dari [Ibnu Abbas] ia berkata, \"Allah telah menetapkan bahwa shalat di saat tidak bepergian sebanyak empat raka'at dan dua raka'at saat perjalanan, melalui lisan Nabi kalian shallallahu 'alaihi wasallam. \""},"1026":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَعِيلَ عَنْ عَبْدِ الْكَرِيمِ عَنْ مُجَاهِدٍ وَسَعِيدِ بْنِ جُبَيْرٍ وَعَطَاءِ بْنِ أَبِي رَبَاحٍ وَطَاوُسٍ أَخْبَرُوهُ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ فِي السَّفَرِ مِنْ غَيْرِ أَنْ يُعْجِلَهُ شَيْءٌ وَلَا يَطْلُبَهُ عَدُوُّ وَلَا يَخَافَ شَيْئًا","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al Adani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ibrahim bin Isma'il] dari [Abdul Karim] dari [Mujahid] dan [Sa'id bin Jubair] dan ['Atho` bin Abu Rabah] dan [Thawus] mereka mengabarkan kepadanya dari [Ibnu Abbas] bahwasanya mereka mengabarkan, bahwa Rasulullah shallallahu 'alaihi wasallam menjamak shalat maghrib dan isya, bukan karena sakit, atau diburu musuh atau karena takut sesuatu. \""},"1027":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ أَبِي الطُّفَيْلِ عَنْ مُعَاذِ بْنِ جَبَلٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ فِي غَزْوَةِ تَبُوكَ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Az Zubair] dari [Abu Ath Thufail] dari [Mu'adz bin Jabal] berkata, \"Nabi shallallahu 'alaihi wasallam menjamak antara zhuhur dan asar, maghrib dan isya dalam perjalanan perang Tabuk. \""},"1028":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا أَبُو عَامِرٍ عَنْ عِيسَى بْنِ حَفْصِ بْنِ عَاصِمِ بْنِ عُمَرَ بْنِ الْخَطَّابِ حَدَّثَنِي أَبِي قَالَكُنَّا مَعَ ابْنِ عُمَرَ فِي سَفَرٍ فَصَلَّى بِنَا ثُمَّ انْصَرَفْنَا مَعَهُ وَانْصَرَفَ قَالَ فَالْتَفَتَ فَرَأَى أُنَاسًا يُصَلُّونَ فَقَالَ مَا يَصْنَعُ هَؤُلَاءِ قُلْتُ يُسَبِّحُونَ قَالَ لَوْ كُنْتُ مُسَبِّحًا لَأَتْمَمْتُ صَلَاتِي يَا ابْنَ أَخِي إِنِّي صَحِبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ فِي السَّفَرِ حَتَّى قَبَضَهُ اللَّهُ ثُمَّ صَحِبْتُ أَبَا بَكْرٍ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ ثُمَّ صَحِبْتُ عُمَرَ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ ثُمَّ صَحِبْتُ عُثْمَانَ فَلَمْ يَزِدْ عَلَى رَكْعَتَيْنِ حَتَّى قَبَضَهُمْ اللَّهُ وَاللَّهُ يَقُولُ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Abu Bakar bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Abu Amir] dari [Isa bin Hafsh bin Ashim bin Umar Ibnul Khaththab] berkata, telah menceritakan kepadaku [Bapakku] ia berkata, \"Kami bersama [Ibnu Umar] dalam sebuah perjalanan, lalu ia shalat bersama kami, kemudian kami beranjak pergi bersamanya. \" Ia berkata lagi, \"Ibnu Umar menoleh dan melihat beberapa orang melaksanakan shalat, lalu Ibnu Umar bertanya, \"Apa yang dilakukan oleh orang-orang itu?\" aku menjawab, \"Mereka melaksanakan shalat sunnah. \" Ibnu Umar berkata, \"Wahai putera saudaraku, jika aku melaksanakan shalat sunnah maka akan aku sempurnakan. Aku pernah menemani Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak pernah melebihkan dari dua raka'at ketika safar hingga Allah mewafatkannya. Kemudian aku menemani Abu Bakar, dan ia juga tidak melebihkan dari dua raka'at. Kemudian aku menemani Umar, dan ia juga tidak melebihkan dari dua raka'at. Kemudian aku menemani Utsman, dan ia juga tidak melebihkan dari dua raka'at hingga Allah mewafatkannya. Demi Allah, ia mengatakan, \"Sungguh pada diri Rasulullah shallallahu 'alaihi wasallam ada teladan yang baik. \""},"1029":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ قَالَ سَأَلْتُ طَاوُسًا عَنْ السُّبْحَةِ فِي السَّفَرِ وَالْحَسَنُ بْنُ مُسْلِمِ بْنِ يَنَّاقٍ جَالِسٌ عِنْدَهُ فَقَالَ حَدَّثَنِي طَاوُسٌ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُفَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْحَضَرِ وَصَلَاةَ السَّفَرِ فَكُنَّا نُصَلِّي فِي الْحَضَرِ قَبْلَهَا وَبَعْدَهَا وَكُنَّا نُصَلِّي فِي السَّفَرِ قَبْلَهَا وَبَعْدَهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Khallad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Usamah bin Zaid] berkata; aku bertanya kepada Thawus tentang shalat sunah dalam safar -waktu itu [Hasan bin Muslim bin Yannaq] sedang duduk di sisinya-, ia berkata, \"Aku mendengar [Thawus] mengatakan, bahwa ia mendengar [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam mewajibkan kami untuk melaksanakan shalat hadlr (shalat dalam kondisi mukim dan tidak dalam perjalanan) dan shalat safar, maka selalu melaksanakan shalat sunah sebelum dan sesudahnya (shalat wajib) baik dalam kondisi mukim atau pun safar. \""},"1030":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدٍ الزُّهْرِيِّ قَالَسَأَلْتُ السَّائِبَ بْنَ يَزِيدَ مَاذَا سَمِعْتَ فِي سُكْنَى مَكَّةَ قَالَ سَمِعْتُ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا لِلْمُهَاجِرِ بَعْدَ الصَّدَرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari ['Abdurrahman bin Humaid Az Zuhri] ia berkata, \"Aku bertanya kepada [Sa`ib bin Yazid]; apa yang engkau dengar sewaktu tinggal di Makkah?\" ia menjawab, \"Aku mendengar [Al 'Ala Ibnul Hadlrami] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Bagi orang yang hijrah adalah tiga hari semenjak selesainya prosesi ibadah haji (atau umrah). \" "},"1031":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو عَاصِمٍ وَقَرَأْتُهُ عَلَيْهِ أَنْبَأَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ فِي أُنَاسٍ مَعِي قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ صُبْحَ رَابِعَةٍ مَضَتْ مِنْ شَهْرِ ذِي الْحِجَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu 'Ashim] -saya membacakan kepadanya- Telah memberitakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku ['Atho`] berkata, telah mengabarkan kepadaku [Jabir Bin Abdullah] -di antara orang-orang yang bersamaku- ia berkata, \"Nabi shallallahu 'alaihi wasallam tiba di Makkah di waktu subuh hari keempat dari berlalunya bulan Dzul Hijjah. \""},"1032":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعَةَ عَشَرَ يَوْمًا يُصَلِّي رَكْعَتَيْنِ رَكْعَتَيْنِ فَنَحْنُ إِذَا أَقَمْنَا تِسْعَةَ عَشَرَ يَوْمًا نُصَلِّي رَكْعَتَيْنِ رَكْعَتَيْنِ فَإِذَا أَقَمْنَا أَكْثَرَ مِنْ ذَلِكَ صَلَّيْنَا أَرْبَعًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tinggal selama sembilan belas hari, beliau shalat dua raka'at-dua raka'at. Maka jika kami tinggal selama sembilan belas hari, kami shalat sebanyak dua raka'at-dua raka'at, namun jika tinggal lebih dari itu kami shalat empat raka'at. \""},"1033":{"ar":"حَدَّثَنَا أَبُو يُوسُفَ الصَّيْدَلَانِيُّ مُحَمَّدُ بْنُ أَحْمَدَ الرَّقِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَ بِمَكَّةَ عَامَ الْفَتْحِ خَمْسَ عَشْرَةَ لَيْلَةً يَقْصُرُ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Abu Yusuf Ash Shaidalani Muhammad bin Ahmad Ar Raqqi] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] berkata, \"Pada tahun pembukaan Makkah Rasulullah shallallahu 'alaihi wasallam menetap di sana selama lima belas hari, dan beliau selalu menqashar shalat. \""},"1034":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ وَعَبْدُ الْأَعْلَى قَالَا حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ عَنْ أَنَسٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَصَلَّى رَكْعَتَيْنِ رَكْعَتَيْنِ حَتَّى رَجَعْنَا قُلْتُ كَمْ أَقَامَ بِمَكَّةَ قَالَ عَشْرًا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dan [Abdul A'la] berdua berkata; telah menceritakan kepada kami [Yahya bin Abu Ishaq] dari [Anas] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam berangkat dari Madinah menuju Makkah, lalu beliau shalat dua raka'at-dua raka'at hingga kami kembali. \" Aku bertanya, \"Berapa hari beliau tinggal di Makkah?\" ia menjawab, \"Sepuluh hari. \""},"1035":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْعَبْدِ وَبَيْنَ الْكُفْرِ تَرْكُ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" (Pembatas) antara seorang hamba dan kekafiran adalah meninggalkan shalat. \""},"1036":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ الْبَالِسِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ حَدَّثَنَا حُسَيْنُ بْنُ وَاقِدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَهْدُ الَّذِي بَيْنَنَا وَبَيْنَهُمْ الصَّلَاةُ فَمَنْ تَرَكَهَا فَقَدْ كَفَرَ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim Al Balisi] berkata, telah menceritakan kepada kami [Ali bin Al Hasan bin Syaqiq] berkata, telah menceritakan kepada kami [Husain bin Waqid] berkata, telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perjanjian antara kita dengan mereka adalah shalat, maka barangsiapa meninggalkannya ia telah kafir. \""},"1037":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَمْرِو بْنِ سَعْدٍ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ بَيْنَ الْعَبْدِ وَالشِّرْكِ إِلَّا تَرْكُ الصَّلَاةِ فَإِذَا تَرَكَهَا فَقَدْ أَشْرَكَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Amru bin Sa'd] dari [Yazid Ar Raqasyi] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada pembatas antara seorang hamba dengan kesyirikan selain meninggalkan shalat, jika ia meninggalkan shalat maka ia telah kafir. \" "},"1038":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا الْوَلِيدُ بْنُ بُكَيْرٍ أَبُو جَنَّابٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْعَدَوِيُّ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَيُّهَا النَّاسُ تُوبُوا إِلَى اللَّهِ قَبْلَ أَنْ تَمُوتُوا وَبَادِرُوا بِالْأَعْمَالِ الصَّالِحَةِ قَبْلَ أَنْ تُشْغَلُوا وَصِلُوا الَّذِي بَيْنَكُمْ وَبَيْنَ رَبِّكُمْ بِكَثْرَةِ ذِكْرِكُمْ لَهُ وَكَثْرَةِ الصَّدَقَةِ فِي السِّرِّ وَالْعَلَانِيَةِ تُرْزَقُوا وَتُنْصَرُوا وَتُجْبَرُوا وَاعْلَمُوا أَنَّ اللَّهَ قَدْ افْتَرَضَ عَلَيْكُمْ الْجُمُعَةَ فِي مَقَامِي هَذَا فِي يَوْمِي هَذَا فِي شَهْرِي هَذَا مِنْ عَامِي هَذَا إِلَى يَوْمِ الْقِيَامَةِ فَمَنْ تَرَكَهَا فِي حَيَاتِي أَوْ بَعْدِي وَلَهُ إِمَامٌ عَادِلٌ أَوْ جَائِرٌ اسْتِخْفَافًا بِهَا أَوْ جُحُودًا لَهَا فَلَا جَمَعَ اللَّهُ لَهُ شَمْلَهُ وَلَا بَارَكَ لَهُ فِي أَمْرِهِ أَلَا وَلَا صَلَاةَ لَهُ وَلَا زَكَاةَ لَهُ وَلَا حَجَّ لَهُ وَلَا صَوْمَ لَهُ وَلَا بِرَّ لَهُ حَتَّى يَتُوبَ فَمَنْ تَابَ تَابَ اللَّهُ عَلَيْهِ أَلَا لَا تَؤُمَّنَّ امْرَأَةٌ رَجُلًا وَلَا يَؤُمَّ أَعْرَابِيٌّ مُهَاجِرًا وَلَا يَؤُمَّ فَاجِرٌ مُؤْمِنًا إِلَّا أَنْ يَقْهَرَهُ بِسُلْطَانٍ يَخَافُ سَيْفَهُ وَسَوْطَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Al Walid bin Bukair Abu Jannab] berkata, telah menceritakan kepadaku [Abdullah bin Muhammad Al 'Adawi] dari [Ali bin Zaid] dari [Sa'id Ibnul Musayyab] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan kami, beliau mengatakan: \"Wahai manusia, bertaubatlah kepada Allah sebelum kalian mati, bersegeralah beramal shalih sebelum kalian sibuk, dan sambunglah antara kalian dengan Rabb kalian dengan memperbanyak dzikir kepada-Nya, banyak sedekah dengan sembunyi-sembunyi maupun terang-terangan. Niscaya kalian akan diberi rizki, ditolong dan dicukupi. Ketahuilah, sesungguhnya Allah telah mewajibkan kepada kalian shalat jum'at di tempat berdiriku ini, di hariku ini, di bulanku ini dan di tahunku ini hingga hari kiamat. Barangsiapa meninggalkannya di waktu hidupku atau setelahku, dan dia memiliki imam adil atau bejat, kemudian meremehkan atau menolaknya, maka Allah tidak akan menyatukannya dan urusannya tidak akan diberkahi. Ketahuilah, tidak ada shalat, tidak ada zakat, tidak ada haji, tidak ada puasa, dan tidak ada kebaikan baginya hingga ia bertaubat. Maka barangsiapa bertaubat, Allah akan menerima taubatnya. Ketahuilah, tidak boleh seorang perempuan mengimami laki-laki, orang badui mengimami seorang muhajir dan tidak boleh orang fajir mengimami seorang mukmin, kecuali jika ia memaksanya dengan kekuasaan yang ditakuti pedang dan cambuknya. \""},"1039":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ أَبُو سَلَمَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِيهِ أَبِي أُمَامَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ قَالَكُنْتُ قَائِدَ أَبِي حِينَ ذَهَبَ بَصَرُهُ فَكُنْتُ إِذَا خَرَجْتُ بِهِ إِلَى الْجُمُعَةِ فَسَمِعَ الْأَذَانَ اسْتَغْفَرَ لِأَبِي أُمَامَةَ أَسْعَدَ بْنِ زُرَارَةَ وَدَعَا لَهُ فَمَكَثْتُ حِينًا أَسْمَعُ ذَلِكَ مِنْهُ ثُمَّ قُلْتُ فِي نَفْسِي وَاللَّهِ إِنَّ ذَا لَعَجْزٌ إِنِّي أَسْمَعُهُ كُلَّمَا سَمِعَ أَذَانَ الْجُمُعَةِ يَسْتَغْفِرُ لِأَبِي أُمَامَةَ وَيُصَلِّي عَلَيْهِ وَلَا أَسْأَ��ُهُ عَنْ ذَلِكَ لِمَ هُوَ فَخَرَجْتُ بِهِ كَمَا كُنْتُ أَخْرُجُ بِهِ إِلَى الْجُمُعَةِ فَلَمَّا سَمِعَ الْأَذَانَ اسْتَغْفَرَ كَمَا كَانَ يَفْعَلُ فَقُلْتُ لَهُ يَا أَبَتَاهُ أَرَأَيْتَكَ صَلَاتَكَ عَلَى أَسْعَدَ بْنِ زُرَارَةَ كُلَّمَا سَمِعْتَ النِّدَاءَ بِالْجُمُعَةِ لِمَ هُوَ قَالَ أَيْ بُنَيَّ كَانَ أَوَّلَ مَنْ صَلَّى بِنَا صَلَاةَ الْجُمُعَةِ قَبْلَ مَقْدَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ فِي نَقِيعِ الْخَضَمَاتِ فِي هَزْمٍ مِنْ حَرَّةِ بَنِي بَيَاضَةَ قُلْتُ كَمْ كُنْتُمْ يَوْمَئِذٍ قَالَ أَرْبَعِينَ رَجُلًا","id":"Telah menceritakan kepada kami [Yahya bin Khalaf Abu Salamah] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Muhammad bin Ishaq] dari [Muhamad bin Abu Umamah bin Sahl bin Hunaif] dari bapaknya [Abu Umamah] dari ['Abdurrahman bin Ka'b bin Malik] ia berkata, \"Aku adalah pemandu [bapakku] tatkala penglihatannya telah hilang. Jika aku keluar dengannya untuk shalat Jum'at dan ia mendengar adzan, maka ia memintakan ampun dan berdo`a untuk Abu Umamah As'ad bin Zurarah. Sejenak aku terdiam untuk mendengarkannya, kemudian aku berguman di dalam hatiku, \"Demi Allah, ia (bapakku) adalah orang yang lemah, setiap ia mendengar adzan jum'at dan meminta ampun bagi Abu Umamah aku mendengarnya, namun aku tidak pernah bertanya kenapa ia melakukan hal itu. \" Lalu aku berangkat bersama untuk shalat jum'at sebagaimana biasa, ketika mendengar adzan ia juga meminta ampun sebagaimana yang biasa dilakukannya. Maka aku pun bertanya kepadanya, \"Wahai bapakku, kenapa engkau selalu mendo`akan As'ad bin Zurarah setiap kali engkau mendengar adzan pada hari jum'at?\" ia menjawab, \"Wahai putraku, dia adalah orang yang pertama kali mengimami kami shalat jum'at sebelum kedatangan Rasulullah shallallahu 'alaihi wasallam dari Makkah di Naqi' Al Khadlamat daerah gurun dataran rendah bani Bayadlah. \" Aku bertanya kembali, \"Berapakah jumlah kalian saat itu?\" ia menjawab, \"Empat puluh orang. \" "},"1040":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْمُنْذِرِ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا أَبُو مَالِكٍ الْأَشْجَعِيُّ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ وَعَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَضَلَّ اللَّهُ عَنْ الْجُمُعَةِ مَنْ كَانَ قَبْلَنَا كَانَ لِلْيَهُودِ يَوْمُ السَّبْتِ وَالْأَحَدُ لِلنَّصَارَى فَهُمْ لَنَا تَبَعٌ إِلَى يَوْمِ الْقِيَامَةِ نَحْنُ الْآخِرُونَ مِنْ أَهْلِ الدُّنْيَا وَالْأَوَّلُونَ الْمَقْضِيُّ لَهُمْ قَبْلَ الْخَلَائِقِ","id":"Telah menceritakan kepada kami [Ali Ibnul Mundzir] berkata, telah menceritakan kepada kami [Ibnu Fudlail] berkata, telah menceritakan kepada kami [Abu Malik Al Asyja'i] dari [Rib'I bin Hirasy] dari [Hudzaifah] dan dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah telah menyesatkan orang-orang sebelum kita di hari jum'at, hari sabtu untuk orang yahudi dan hari ahad untuk orang nashara. Dan mereka akan mengikuti kita hingga hari kiamat, kita terakhir dari penduduk dunia namun pertama dalam penghisaban di akhirat, sebelum mereka. \""},"1041":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى ابْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ الْأَنْصَارِيِّ عَنْ أَبِي لُبَابَةَ بْنِ عَبْدِ الْمُنْذِرِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ يَوْمَ الْجُمُعَةِ سَيِّدُ الْأَيَّامِ وَأَعْظَمُهَا عِنْدَ اللَّهِ وَهُوَ أَعْظَمُ عِنْدَ اللَّهِ مِنْ يَوْمِ الْأَضْحَى وَيَوْمِ الْفِطْرِ فِيهِ خَمْسُ خِلَالٍ خَلَقَ اللَّهُ فِيهِ آدَمَ وَأَهْبَطَ اللَّهُ فِيهِ آدَمَ إِلَى الْأَرْضِ وَفِيهِ تَوَفَّى اللَّهُ آدَمَ وَفِيهِ سَاعَةٌ لَا يَسْأَلُ اللَّهَ فِيهَا الْعَبْدُ شَيْئًا إِلَّا أَعْطَاهُ مَا لَمْ يَسْأَلْ حَرَامًا وَفِيهِ تَقُومُ السَّاعَةُ مَا مِنْ مَلَكٍ مُقَرَّبٍ وَلَا سَمَاءٍ وَلَا أَرْضٍ وَلَا رِيَاحٍ وَلَا جِبَالٍ وَلَا بَحْرٍ إِلَّا وَهُنَّ يُشْفِقْنَ مِنْ يَوْمِ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin Aqil] dari ['Abdurrahman bin Yazid Al Anshari] dari [Abu Lubabah bin Abdul Mundzir] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Hari jum'at adalah sebaik-baik dan seagung-agung hari. Di sisi Allah ia lebih utama dari iedul adlha dan iedul fithri. Pada hari itu ada lima perkara (besar); pada hari itu Adam dicipta, hari itu ia diturunkan ke bumi, pada hari itu ia diwafatkan, pada hari itu kiamat tiba. Dan pada hari itu tidaklah malaikat, langit, bumi, angin, gunung dan laut kecuali takut karena keagungan hari jum'at. \""},"1042":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَفْضَلِ أَيَّامِكُمْ يَوْمَ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ النَّفْخَةُ وَفِيهِ الصَّعْقَةُ فَأَكْثِرُوا عَلَيَّ مِنْ الصَّلَاةِ فِيهِ فَإِنَّ صَلَاتَكُمْ مَعْرُوضَةٌ عَلَيَّ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ كَيْفَ تُعْرَضُ صَلَاتُنَا عَلَيْكَ وَقَدْ أَرَمْتَ يَعْنِي بَلِيتَ فَقَالَ إِنَّ اللَّهَ حَرَّمَ عَلَى الْأَرْضِ أَنْ تَأْكُلَ أَجْسَادَ الْأَنْبِيَاءِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Al Husain bin Ali] dari ['Abdurrahman bin Jabir] dari [Abu Al Asy'ats Ash Shan'ani] dari [Aus bin Aus] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hari yang paling utama dari hari-hari kalian adalah hari jum'at, pada hari itu Adam diciptakan, sangkakala ditiup dan di hari itu datang hari kiamat. Maka perbanyaklah shalawat kepadaku pada hari itu, sesungguhnya shalawat kalian akan sampai kepadaku. \" Seorang laki-laki bertanya, \"Wahai Rasulullah, bagaimana shalawat kami bisa sampai kepadamu, sementara engkau telah tiada dan jasadmu telah hancur?\" Beliau menjawab: \"Allah telah mengharamkan bagi bumi untuk makan jasad para Nabi. \""},"1043":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْجُمُعَةُ إِلَى الْجُمُعَةِ كَفَّارَةُ مَا بَيْنَهُمَا مَا لَمْ تُغْشَ الْكَبَائِرُ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al 'Adani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Al 'Ala] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jum'at hingga jum'at berikutnya adalah penghapus dosa antara keduanya selama dosa besar dijauhi. \""},"1044":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ الْأَوْزَاعِيِّ حَدَّثَنَا حَسَّانُ بْنُ عَطِيَّةَ حَدَّثَنِي أَبُو الْأَشْعَثِ حَدَّثَنِي أَوْسُ بْنُ أَوْسٍ الثَّقَفِيُّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ غَسَّلَ يَوْمَ الْجُمُعَةِ وَاغْتَسَلَ وَبَكَّرَ وَابْتَكَرَ وَمَشَى وَلَمْ يَرْكَبْ وَدَنَا مِنْ الْإِمَامِ فَاسْتَمَعَ وَلَمْ يَلْغُ كَانَ لَهُ بِكُلِّ خَطْوَةٍ عَمَلُ سَنَةٍ أَجْرُ صِيَامِهَا وَقِيَامِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Al Auza'i] berkata, telah menceritakan kepada kami [Hassan bin Athiah] berkata, telah menceritakan kepada kami [Abul Asy'ats] berkata, telah menceritakan kepada kami [Aus bin Ats Tsaqafi] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membasuh kepala dan seluruh badannya, berangkat di awal waktu dan mendapat awal khutbah, berjalan dan tidak berkendaraan, mendekati imam dan mendengarkan khutbah serta tidak berbuat sia-sia maka setiap langkah akan dihitung sebagai ibadah selama satu tahun dengan pahala puasa dan tahajud. \""},"1045":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ أَبِي إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ مَنْ أَتَى الْجُمُعَةَ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Umar bin Ubaid] dari [Abu Ishaq] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Barangsiapa menghadiri jum'at hendaklah mandi besar. \""},"1046":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غُسْلُ يَوْمِ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Shofwan bin Sulaiman] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandi di hari jum'at hukumnya wajib bagi orang yang telah mimpi basah. \""},"1047":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْجُمُعَةَ فَدَنَا وَأَنْصَتَ وَاسْتَمَعَ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى وَزِيَادَةُ ثَلَاثَةِ أَيَّامٍ وَمَنْ مَسَّ الْحَصَى فَقَدْ لَغَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu dan membaguskan wudlunya, kemudian menghadiri shalat jum'at, mendekati imam, diam dan mendengarkan khutbah, maka dosanya antara jum'at tersebut hingga jum'at berikutnya akan diampuni, dengan ditambah tiga hari. Dan barangsiapa menyentuh kerikil maka ia telah sia-sia. \""},"1048":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ الْمَكِّيُّ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ يَوْمَ الْجُمُعَةِ فَبِهَا وَنِعْمَتْ تُجْزِئُ عَنْهُ الْفَرِيضَةُ وَمَنْ اغْتَسَلَ فَالْغُسْلُ أَفْضَلُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Isma'il bin Muslim Al Makki] dari [Yazid Ar Raqqasyi] dari [Anas bin Malik] Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu pada hari jum'at, maka itu adalah kebaikan yang dengannya shalat wajib bisa dilaksanakan. Dan barangsiapa mandi, maka mandi itu lebih utama. \""},"1049":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ كَانَ عَلَى كُلِّ بَابٍ مِنْ أَبْوَابِ الْمَسْجِدِ مَلَائِكَةٌ يَكْتُبُونَ النَّاسَ عَلَى قَدْرِ مَنَازِلِهِمْ الْأَوَّلَ فَالْأَوَّلَ فَإِذَا خَرَجَ الْإِمَامُ طَوَوْا الصُّحُفَ وَاسْتَمَعُوا الْخُطْبَةَ فَالْمُهَجِّرُ إِلَى الصَّلَاةِ كَالْمُهْدِي بَدَنَةً ثُمَّ الَّذِي يَلِيهِ كَمُهْدِي بَقَرَةٍ ثُمَّ الَّذِي يَلِيهِ كَمُهْدِي كَبْشٍ حَتَّى ذَكَرَ الدَّجَاجَةَ وَالْبَيْضَةَ زَادَ سَهْلٌ فِي حَدِيثِهِ فَمَنْ جَاءَ بَعْدَ ذَلِكَ فَإِنَّمَا يَجِيءُ بِحَقٍّ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyaniah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari jum'at di setiap pintu masjid ada malaikat yang menulis manusia sesuai kedatangan mereka ke masjid, yang pertama dan seterusnya. Jika imam telah tiba mereka menutup buku catatannya dan mendengarkan khutbah. Orang yang pertama datang ke masjid seperti orang yang bersedekah unta, setelahnya seperti orang yang bersedekah sapi, setelahnya seperti orang yang bersedekah domba, \" hingga beliau menyebutkan ayam dan telur. \" Sahl menambahkan dalam haditsnya, \"Barangsiapa datang setelah itu maka ia datang layaknya orang yang datang untuk shalat. \""},"1050":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سَعِيدِ بْنِ بَشِيرٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَرَبَ مَثَلَ الْجُمُعَةِ ثُمَّ التَّبْكِيرِ كَنَاحِرِ الْبَدَنَةِ كَنَاحِرِ الْبَقَرَةِ كَنَاحِرِ الشَّاةِ حَتَّى ذَكَرَ الدَّجَاجَةَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Waki'] dari [Sa'id bin Basyir] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] berkata, \"Rasulullah shallallahu 'alaihi wasallam membuat perumpamaan hari jum'at, maka barangsiapa bersegera menuju jum'at seperti seorang yang berkurban unta, seperti seorang yang berkurban sapi, seperti orang yang berkurban kambing, hingga beliau menyebutkan seperti orang yang menyembelih ayam. \""},"1051":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا عَبْدُ الْمَجِيدِ بْنُ عَبْدِ الْعَزِيزِ عَنْ مَعْمَرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَخَرَجْتُ مَعَ عَبْدِ اللَّهِ إِلَى الْجُمُعَةِ فَوَجَدَ ثَلَاثَةً وَقَدْ سَبَقُوهُ فَقَالَ رَابِعُ أَرْبَعَةٍ وَمَا رَابِعُ أَرْبَعَةٍ بِبَعِيدٍ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ يَجْلِسُونَ مِنْ اللَّهِ يَوْمَ الْقِيَامَةِ عَلَى قَدْرِ رَوَاحِهِمْ إِلَى الْجُمُعَاتِ الْأَوَّلَ وَالثَّانِيَ وَالثَّالِثَ ثُمَّ قَالَ رَابِعُ أَرْبَعَةٍ وَمَا رَابِعُ أَرْبَعَةٍ بِبَعِيدٍ","id":"Telah menceritakan kepada kami [Katsir bin Ubaid Al Himshi] berkata, telah menceritakan kepada kami [Abdul Majid bin Abdul Aziz] dari [Ma'mar] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] ia berkata, \"Aku bersama [Abdullah] berangkat menuju shalat jum'at, kemudian ia menjumpai tiga orang yang telah mendahuluinya, maka ia pun berkata, \"Yang ke empat dari empat, dan tidaklah yang ke empat dari yang empat itu jauh. Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauh-dekatnya kedudukan manusia di sisi Allah pada hari kiamat sesuai dengan perginya mereka menuju shalat jum'at; yang pertama, kedua dan ketiga. \" Kemudian beliau bersabda lagi: \"Yang ke empat dari empat, dan tidaklah yang keempat dari empat itu jauh. \""},"1052":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُوسَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ فِي يَوْمِ الْجُمُعَةِ مَا عَلَى أَحَدِكُمْ لَوْ اشْتَرَى ثَوْبَيْنِ لِيَوْمِ الْجُمُعَةِ سِوَى ثَوْبِ مِهْنَتِهِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَيْخٌ لَنَا عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ أَبِيهِ قَالَ خَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Amru bin Al Harits] dari [Yazid bin Abu Habib] dari [Musa bin Sa'id] dari [Muhammad bin Yahya bin Habban Abu Habib] dari [Abdullah bin Salam] Bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar pada hari jum'at: \"Apa susahnya jika seseorang dari kalian membeli dua baju untuk hari jum'at selain baju kerjanya. \" Telah menceritakan kepada kami [Abu Bakar Ibnu Abu Syaibah] berkata, telah menceritakan kepada kami [salah seorang syaikh kami], dari [Abdul Hamid bin Ja'far] dari [Muhamma bin Yahya bin Habban] dari [Yusuf bin Abdullah bin Salam] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam berkhutbah di hadapan kami, lalu beliau menyebutkan hal tersebut. \" "},"1053":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ عَنْ زُهَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ يَوْمَ الْجُمُعَةِ فَرَأَى عَلَيْهِمْ ثِيَابَ النِّمَارِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عَلَى أَحَدِكُمْ إِنْ وَجَدَ سَعَةً أَنْ يَتَّخِذَ ثَوْبَيْنِ لِجُمُعَتِهِ سِوَى ثَوْبَيْ مِهْنَتِهِ","id":"Telah menceritakan kepada kami [Muhamad bin Yahya] berkata, telah menceritakan kepada kami [Amru bin Abu Salamah] dari [Zuhair] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Pada hari jum'at Nabi shallallahu 'alaihi wasallam berkhutbah di hadapan para sahabat, beliau melihat mereka mengenakan baju wool, maka beliau bersabda: \"Apa susahnya jika salah seorang kalian mendapatkan kemudahan mengambil (membeli) dua baju untuk jum'atnya selain baju kerja. \""},"1054":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ وَحَوْثَرَةُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ وَدِيعَةَ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ فَأَحْسَنَ غُسْلَهُ وَتَطَهَّرَ فَأَحْسَنَ طُهُورَهُ وَلَبِسَ مِنْ أَحْسَنِ ثِيَابِهِ وَمَسَّ مَا كَتَبَ اللَّهُ لَهُ مِنْ طِيبِ أَهْلِهِ ثُمَّ أَتَى الْجُمُعَةَ وَلَمْ يَلْغُ وَلَمْ يُفَرِّقْ بَيْنَ اثْنَيْنِ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] dan [Hautsarah bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Ibnu Ajlan] dari [Sa'id Al Maqburi] dari [Bapaknya] dari [Abdullah bin Wadi'ah] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mandi di hari jum'at dan membaguskan mandinya, lalu bersuci dan membaguskan cara bersucinya, lalu memakai pakaian terbaiknya dan memakai wewangian, setelah itu menghadiri shalat jum'at, tidak melakukan perbuatan sia-sia atau memisahkan antara dua orang, maka akan diampuni semua dosanya antara jum'at tersebut hingga jum'at berikutnya. \""},"1055":{"ar":"حَدَّثَنَا عَمَّارُ بْنُ خَالِدٍ الْوَاسِطِيُّ حَدَّثَنَا عَلِيُّ بْنُ غُرَابٍ عَنْ صَالِحِ بْنِ أَبِي الْأَخْضَرِ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا يَوْمُ عِيدٍ جَعَلَهُ اللَّهُ لِلْمُسْلِمِينَ فَمَنْ جَاءَ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ وَإِنْ كَانَ طِيبٌ فَلْيَمَسَّ مِنْهُ وَعَلَيْكُمْ بِالسِّوَاكِ","id":"Telah menceritakan kepada kami [Ammar bin Khalid Al Wasithi] berkata, telah menceritakan kepada kami [Ali bin Ghurab] dari [Shalih bin Abu Al Akhdlar] dari [Az Zuhri] dari [Ubaid bin As Sabbaq] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ini adalah hari raya yang telah Allah jadikan bagi kaum muslimin. Barangsiapa menghadiri shalat jum'at hendaklah mandi, jika mempunyai minyak wangi hendaklah mengoleskannya, dan hendaklah kalian bersiwak. \""},"1056":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ حَدَّثَنِي أَبِي عَنْ سَهْلِ بْنِ سَعْدٍ قَالَمَا كُنَّا نَقِيلُ وَلَا نَتَغَدَّى إِلَّا بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] berkata, telah menceritakan kepadaku [Bapakku] dari [Sahl bin Sa'd] ia berkata, \"Kami tidak tidur dan makan ghada (makan di awal siang) kecuali setelah jum'at. \" "},"1057":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا يَعْلَى بْنُ الْحَارِثِ قَالَ سَمِعْتُ إِيَاسَ بْنَ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَرْجِعُ فَلَا نَرَى لِلْحِيطَانِ فَيْئًا نَسْتَظِلُّ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Ya'la Ibnul Harits] berkata; Aku mendengar [Iyas bin Salamah Ibnul Akwa'] dari [Bapaknya] ia berkata, \"Kami pernah shalat jum'at bersama Nabi shallallahu 'alaihi wasallam, kemudian kami pulang dan kami belum mendapati bayangan tembok yang bisa kami jadikan sebagai perlindungan dari terik matahari. \""},"1058":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ مُؤَذِّنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ كَانَ يُؤَذِّنُ يَوْمَ الْجُمُعَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الْفَيْءُ مِثْلَ الشِّرَاكِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin 'Ammar bin Sa'd] -mu`adzin Nabi shallallahu 'alaihi wasallam- berkata, telah menceritakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] bahwa pada masa Rasulullah shallallahu 'alaihi wasallam ia mengumandangkan adzan di hari jum'at ketika bayangan sudah seperti tali sandal. \" "},"1059":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَكُنَّا نُجَمِّعُ ثُمَّ نَرْجِعُ فَنَقِيلُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] berkata, telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata, \"Kami pergi shalat jum'at kemudian kembali dan tidur siang. \" "},"1060":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ ح و حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ أَبُو سَلَمَةَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ خُطْبَتَيْنِ يَجْلِسُ بَيْنَهُمَا جَلْسَةً زَادَ بِشْرٌ وَهُوَ قَائِمٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Khalaf Abu Salamah] berkata, telah menceritakan kepada kami [Bisyr bin Mufadldlal] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam khutbah dua kali dan beliau duduk di antara dua khutbah sejenak. \" Bisyr menambahkan, \"beliau dalam kondisi akan berdiri. \""},"1061":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُسَاوِرٍ الْوَرَّاقِ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Musawir Al Warraq] dari [Ja'far bin Amru bin Huraits] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam berkhutbah di atas mimbar sedang beliau memakai imamah (semacam surban yang diikatkan pada kepala) warna hitam. \""},"1062":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا غَيْرَ أَنَّهُ كَانَ يَقْعُدُ قَعْدَةً ثُمَّ يَقُومُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad Ibnul Walid] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] ia berkata, \"Aku mendengar [Jabir bin Samurah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah dengan berdiri, hanya saja beliau duduk sebentar kemudian berdiri lagi. \""},"1063":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ فَيَقْرَأُ آيَاتٍ وَيَذْكُرُ اللَّهَ وَكَانَتْ خُطْبَتُهُ قَصْدًا وَصَلَاتُهُ قَصْدًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Simak] dari [Jabir bin Abdullah] ia berkata, \"Nabi shallallahu 'alaihi wasallam berkhutbah dengan berdiri kemudian duduk, setelah itu beliau berdiri lagi membaca beberapa ayat dan berdzikir kepada Allah. Khutbah dan shalat beliau sedang. \" "},"1064":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَطَبَ فِي الْحَرْبِ خَطَبَ عَلَى قَوْسٍ وَإِذَا خَطَبَ فِي الْجُمُعَةِ خَطَبَ عَلَى عَصًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin Ammar bin Sa'd] berkata, telah menceritakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam jika berkhutbah dalam peperangan, beliau berpegangan tombak dan jika khutbah di hari jum'at beliau berpegangan tongkat. \" "},"1065":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّهُ سُئِلَ أَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا أَوْ قَاعِدًا قَالَ أَوَمَا تَقْرَأُ{ وَتَرَكُوكَ قَائِمًا }قَالَ أَبُو عَبْد اللَّهِ غَرِيبٌ لَا يُحَدِّثُ بِهِ إِلَّا ابْنُ أَبِي شَيْبَةَ وَحْدَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Abu Ghaniyyah] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] bahwasanya ia pernah ditanya; apakah Nabi shallallahu 'alaihi wasallam berkhutbah sambil berdiri atau duduk? Ia menjawab: \"Apakah kamu tidak membaca ayat: \" (dan mereka meninggalkanmu dalam keadaan berdiri)?\" Abu Abdullah berkata: \"Ini adalah hadits gharib, dan tidak ada yang meriwatkannya kecuali hanya Abu Syaibah. \" "},"1066":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ مُهَاجِرٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَعِدَ الْمِنْبَرَ سَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Amru bin Khalid] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Muhammad bin Zaid bin Muhajir] dari [Muhammad bin Munkadir] dari [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam apabila naik mimbar selalu mengucapkan salam. \" "},"1067":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah bin Sawwar] dari [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika engkau mengatakan kepada kawanmu 'diamlah' sementara imam sedang berkhutbah di hari jum'at maka engkau telah sia-sia. \""},"1068":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ يَوْمَ الْجُمُعَةِ تَبَارَكَ وَهُوَ قَائِمٌ فَذَكَّرَنَا بِأَيَّامِ اللَّهِ وَأَبُو الدَّرْدَاءِ أَوْ أَبُو ذَرٍّ يَغْمِزُنِي فَقَالَ مَتَى أُنْزِلَتْ هَذِهِ السُّورَةُ إِنِّي لَمْ أَسْمَعْهَا إِلَّا الْآنَ فَأَشَارَ إِلَيْهِ أَنْ اسْكُتْ فَلَمَّا انْصَرَفُوا قَالَ سَأَلْتُكَ مَتَى أُنْزِلَتْ هَذِهِ السُّورَةُ فَلَمْ تُخْبِرْنِي فَقَالَ أُبَيٌّ لَيْسَ لَكَ مِنْ صَلَاتِكَ الْيَوْمَ إِلَّا مَا لَغَوْتَ فَذَهَبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ وَأَخْبَرَهُ بِالَّذِي قَالَ أُبَيٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ أُبَيٌّ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al Adani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Syarik bin Abdullah bin Abu Namir] dari ['Atho` bin Yasar] dari [Ubai bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam pada hari jum'at membaca TABAARAKA sementara beliau berdiri. Beliau juga mengingatkan kami dengan hari-hari Allah. Lalu Abu Darda atau Abu Dzar mencubitku seraya berkata, \"Kapan ayat ini diturunkan, aku belum pernah mendengarnya kecuali sekarang ini? Namun Ubai memberi isyarat agar ia diam. Ketika orang-orang bubar, Abu Darda berkata, \"Aku bertanya kepadamu kapan surat ini diturunkan, namun engkau tidak memberitahukan kepadaku! \" Ubai bin Ka'b berkata, \"Hari ini engkau tidak mendapatkan pahala shalatmu kecuali sesuatu yang telah engkau sia-siakan itu. \" Abu Darda akhirnya menemui Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepada beliau dengan apa yang dikatakan oleh Ubai, lalu Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ubai benar. \""},"1069":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ جَابِرًا وَأَبُو الزُّبَيْرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَدَخَلَ سُلَيْكٌ الْغَطَفَانِيُّ الْمَسْجِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ أَصَلَّيْتَ قَالَ لَا قَالَ فَصَلِّ رَكْعَتَيْنِ وَأَمَّا عَمْرٌو فَلَمْ يَذْكُرْ سُلَيْكًا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Jabir] dan [Abu Az Zubair] ia mendengar [Jabir bin Abdullah] ia berkata, \"Sulaik Al Ghathafani masuk ke dalam masjid sementara Nabi shallallahu 'alaihi wasallam berkhutbah, beliau bersabda: \"Apakah engkau sudah melaksanakan shalat sunnah?\" ia menjawab, \"Belum, \" beliau bersabda: \"Shalatlah dua rakaat. \" Sedangkan Amru tidak menyebutkan nama Sulaik. "},"1070":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ عَجْلَانَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ قَالَجَاءَ رَجُلٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ أَصَلَّيْتَ قَالَ لَا قَالَ فَصَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Ibnu 'Ajlan] dari ['Iyadl bin Abdullah] dari [Abu Sa'id] ia berkata, \"Seorang laki-laki datang sementara Nabi shallallahu 'alaihi wasallam berkhutbah, kemudian beliau bertanya: \"Apakah kamu sudah shalat? Ia menjawab: \"Belum, \" beliau bersabda: \"Shalatlah dua raka'at. \""},"1071":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ وَعَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَاجَاءَ سُلَيْكٌ الْغَطَفَانِيُّ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَّيْتَ رَكْعَتَيْنِ قَبْلَ أَنْ تَجِيءَ قَالَ لَا قَالَ فَصَلِّ رَكْعَتَيْنِ وَتَجَوَّزْ فِيهِمَا","id":"Telah menceritakan kepada kami [Dawud bin Rusyaid] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dan [Abu Sufyan] dari [Jabir] keduanya berkata, \"Sulaik Al Ghathafani masuk ke dalam masjid sementara Rasulullah shallallahu 'alaihi wasallam berkhutbah, lalu Nabi shallallahu 'alaihi wasallam bersabda bertanya kepadanya: \"Apakah engkau telah melaksanakan shalat sebelum engkau tiba?\" ia berkata, \"Belum, \" beliau bersabda: \"Shalatlah dua raka'at dan ringankanlah. \""},"1072":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ الْحَسَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ يَوْمَ الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَجَعَلَ يَتَخَطَّى النَّاسَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسْ فَقَدْ آذَيْتَ وَآنَيْتَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami ['Abdurrahman Al Muharibi] dari [Isma'il bin Muslim] dari [Al Hasan] dari [Jabir bin Abdullah] berkata, \"Seorang laki-laki masuk masjid pada hari jum'at sementara Rasulullah shallallahu 'alaihi wasallam berkhutbah. Laki-laki itu melangkahi orang-orang hingga Rasulullah shallallahu 'alaihi wasallam bersabda: \"Duduk! Sungguh engkau telah terlambat dan menyakiti (orang lain). \" "},"1073":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ زَبَّانَ بْنِ فَائِدٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَخَطَّى رِقَابَ النَّاسِ يَوْمَ الْجُمُعَةِ اتُّخِذَ جِسْرًا إِلَى جَهَنَّمَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Risydin bin Sa'd] dari [Zabban bin Fa`id] dari [Sahl bin Mu'adz bin Anas] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di hari jum'at melangkahi pundak orang lain, maka akan dibuatkan baginya jembatan ke jahannam. \""},"1074":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُكَلَّمُ فِي الْحَاجَةِ إِذَا نَزَلَ عَنْ الْمِنْبَرِ يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Jarir bin Hazim] dari [Tsabit] dari [Anas bin Malik] berkata, \"Jika Nabi shallallahu 'alaihi wasallam turun dari mimbar di hari jum'at, beliau diadui tentang hajat kebutuhan. \""},"1075":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ الْمَدَنِيُّ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ قَالَاسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ عَلَى الْمَدِينَةِ فَخَرَجَ إِلَى مَكَّةَ فَصَلَّى بِنَا أَبُو هُرَيْرَةَ يَوْمَ الْجُمُعَةِ فَقَرَأَ بِسُورَةِ الْجُمُعَةِ فِي السَّجْدَةِ الْأُولَى وَفِي الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ عُبَيْدُ اللَّهِ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ حِينَ انْصَرَفَ فَقُلْتُ لَهُ إِنَّكَ قَرَأْتَ بِسُورَتَيْنِ كَانَ عَلِيٌّ يَقْرَأُ بِهِمَا بِالْكُوفَةِ فَقَالَ أَبُو هُرَيْرَةَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il Al Madani] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ubaidullah bin Abu Rafi'] ia berkata, \"Marwan mewakilkan kota Madinah kepada Abu Hurairah, pada suatu hari ia keluar menuju Makkah, kemudian di hari jum'at Abu Hurairah shalat bersama kami. Ia membaca surat Al Jumu'ah di raka'at pertama dan membaca IDZAA JAA`AKAL MUNAAFIQUUN di raka'at terakhir. \" Ubaidullah berkata, \"Ketika Abu Hurairah berlalu pergi aku menjumpainya dan bertanya, \"Engkau membaca dua surat yang pernah Ali baca di Kufah?\" [Abu Hurairah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam membaca keduanya. \" "},"1076":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ أَنْبَأَنَا ضَمْرَةُ بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَكَتَبَ الضَّحَّاكُ بْنُ قَيْسٍ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ أَخْبِرْنَا بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ مَعَ سُورَةِ الْجُمُعَةِ قَالَ كَانَ يَقْرَأُ فِيهَا هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] berkata, telah memberitakan kepada kami [Dlamrah bin Sa'id] dari [Ubaidullah bin Abdullah] berkata; Adl Dlahhak bin Qais menulis surat kepada [An Nu'man bin Basyir]; kabarkanlah kepada kami surat apa yang di baca Rasulullah shallallahu 'alaihi wasallam pada hari jum'at, selain surat Al Jumu'ah?\" ia menjawab, \"Di hari jum'at beliau membaca HAL ATAAKA HADIITSUL GHAASYIAH (Sudah datangkah kepadamu berita (tentang) hari pembalasan?) \""},"1077":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ سِنَانٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ أَبِي عِنَبَةَ الْخَوْلَانِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Sa'id bin Sinan] dari [Abu Az Zahiriyah] dari [Abu 'Inabah Al Khaulani] berkata, \"Nabi shallallahu 'alaihi wasallam pada hari jum'at membaca SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) dan HAL ATAAKA HADIITSUL GHAASYIAH (Sudah datangkah kepadamu berita (tentang) hari pembalasan?) \""},"1078":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عُمَرُ بْنُ حَبِيبٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الْجُمُعَةِ رَكْعَةً فَلْيَصِلْ إِلَيْهَا أُخْرَى","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Umar bin Habib] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Abu Salamah] dan [Sa'id bin Musayyab] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan shalat jum'at satu raka'at, maka hendaklah ia genapkan. \" "},"1079":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ مِنْ الصَّلَاةِ رَكْعَةً فَقَدْ أَدْرَكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu raka'at maka ia telah mendapatkannya. \""},"1080":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ الْأَيْلِيُّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ رَكْعَةً مِنْ صَلَاةِ الْجُمُعَةِ أَوْ غَيْرِهَا فَقَدْ أَدْرَكَ الصَّلَاةَ","id":"Telah menceritakan kepada kami [Amru bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah bin Walid] berkata, telah menceritakan kepada kami [Yunus bin Yazid Al Aili] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapatkan satu raka'at dari shalat jum'at atau selainnya, maka dia telah mendapatkan shalat. \""},"1081":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَإِنَّ أَهْلَ قُبَاءَ كَانُوا يُجَمِّعُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Sa'id bin Abi Maryam] dari [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Penduduk Quba melaksanakan shalat jum'at bersama Rasulullah shallallahu 'alaihi wasallam pada hari jum'at. \""},"1082":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَيَزِيدُ بْنُ هَارُونَ وَمُحَمَّدُ بْنُ بِشْرٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنِي عُبَيْدَةُ بْنُ سُفْيَانَ الْحَضْرَمِيُّ عَنْ أَبِي الْجَعْدِ الضَّمْرِيِّ وَكَانَ لَهُ صُحْبَةٌ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْجُمُعَةَ ثَلَاثَ مَرَّاتٍ تَهَاوُنًا بِهَا طُبِعَ عَلَى قَلْبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dan [Yazid bin Harun] dan [Muhammad bin Bisyr] mereka berkata; telah menceritakan kepada kami [Muhammad bin Amru] berkata; telah menceritakan kepadaku [Ubaidah bin Sufyan Al Hadlrami] dari [Abul Ja'd Ad Dlamri] -ia pernah bertemu Nabi shallallahu 'alaihi wasallam- Ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan jum'at sebanyak tiga kali karena meremehkannya, maka hatinya akan ditutup. \""},"1083":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَسِيدِ بْنِ أَبِي أَسِيدٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ أَسِيدِ بْنِ أَبِي أَسِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْجُمُعَةَ ثَلَاثًا مِنْ غَيْرِ ضَرُورَةٍ طَبَعَ اللَّهُ عَلَى قَلْبِهِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Zuhair] dari [Usaid bin Abu Asid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Isa Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] dari [Ibnu Abu Dzi'b] dari [Asid bin Abu Asid] dari [Abdullah bin Abu Qatadah] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan jum'at sebanyak tiga kali tanpa udzur, maka hatinya akan ditutup. \""},"1084":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مَعْدِيُّ بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا هَلْ عَسَى أَحَدُكُمْ أَنْ يَتَّخِذَ الصُّبَّةَ مِنْ الْغَنَمِ عَلَى رَأْسِ مِيلٍ أَوْ مِيلَيْنِ فَيَتَعَذَّرَ عَلَيْهِ الْكَلَأُ فَيَرْتَفِعَ ثُمَّ تَجِيءُ الْجُمُعَةُ فَلَا يَجِيءُ وَلَا يَشْهَدُهَا وَتَجِيءُ الْجُمُعَةُ فَلَا يَشْهَدُهَا وَتَجِيءُ الْجُمُعَةُ فَلَا يَشْهَدُهَا حَتَّى يُطْبَعَ عَلَى قَلْبِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ma'di bin Sulaiman] berkata, telah menceritakan kepada kami [Ibnu 'Ajlan] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, bisa jadi salah seorang dari kalian membawa sekawanan kambing di ujung (jarak) satu mil atau dua mil, kemudian rerumputan tidak ada sementara matahari semakin tinggi dan tibalah waktu jum'at. Namun ia tidak datang dan tidak menghadirinya, kemudian datang lagi jum'at berikutnya namun ia tidak menghadirinya, kemudian datang lagi jum'at berikutnya namun ia tidak menghadirinya, hingga hatinya ditutup. \""},"1085":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ أَخِيهِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ الْجُمُعَةَ مُتَعَمِّدًا فَلْيَتَصَدَّقْ بِدِينَارٍ فَإِنْ لَمْ يَجِدْ فَبِنِصْفِ دِينَارٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Nuh bin Qais] dari [Saudaranya] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa meninggalkan shalat jum'at dengan sengaja hendaklah bersedekah dengan satu dinar, jika tidak mendapatkannya hendaklah dengan setengahnya. \""},"1086":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ عَنْ مُبَشِّرِ بْنِ عُبَيْدٍ عَنْ حَجَّاجِ بْنِ أَرْطَاةَ عَنْ عَطِيَّةَ الْعُوفِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكَعُ قَبْلَ الْجُمُعَةِ أَرْبَعًا لَا يَفْصِلُ فِي شَيْءٍ مِنْهُنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Abdu Rabbih] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Mubassyir bin Ubaid] dari [Hajjaj bin Arthah] dari [Atiyah Al 'Ufi] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat empat raka'at sebelum jum'at secara bersambung. \" "},"1087":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ كَانَ إِذَا صَلَّى الْجُمُعَةَ انْصَرَفَ فَصَلَّى سَجْدَتَيْنِ فِي بَيْتِهِ ثُمَّ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Abdullah bin Umar] Bahwasanya jika telah selesai shalat jum'at ia shalat dua raka'at di rumah, kemudian ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan hal itu. \""},"1088":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] dari [Amru] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] berkata, \"Nabi shallallahu 'alaihi wasallam shalat dua raka'at setelah shalat jum'at. \" "},"1089":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّيْتُمْ بَعْدَ الْجُمُعَةِ فَصَلُّوا أَرْبَعًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu As Sa`ib Salm bin Junadah] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Idris] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian telah selesai dari shalat jum'at, maka shalatlah empat raka'at. \""},"1090":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا ابْنُ لَهِيعَةَ جَمِيعًا عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُحَلَّقَ فِي الْمَسْجِدِ يَوْمَ الْجُمُعَةِ قَبْلَ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Hatim bin Isma'il]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Ibnu Lahi'ah] semuanya dari [Ibnu 'Ajlan] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata, \"Pada hari jum'at Rasulullah shallallahu 'alaihi wasallam melarang membuat halaqah dalam masjid sebelum shalat jum'at selesai. \" "},"1091":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ عَبْدِ اللَّهِ بْنِ وَاقِدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الِاحْتِبَاءِ يَوْمَ الْجُمُعَةِ يَعْنِي وَالْإِمَامُ يَخْطُبُ","id":"Telah menceritakan kepada kami [Muhammad bin Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Abdullah bin Waqid] dari [Muhammad bin 'Ajlan] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam duduk ihtiba` di hari jum'at, yaitu ketika imam sedang berkhutbah. \""},"1092":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى الْقَطَّانُ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ جَمِيعًا عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَمَا كَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مُؤَذِّنٌ وَاحِدٌ إِذَا خَرَجَ أَذَّنَ وَإِذَا نَزَلَ أَقَامَ وَأَبُو بَكْرٍ وَعُمَرُ كَذَلِكَفَلَمَّا كَانَ عُثْمَانُ وَكَثُرَ النَّاسُ زَادَ النِّدَاءَ الثَّالِثَ عَلَى دَارٍ فِي السُّوقِ يُقَالُ لَهَا الزَّوْرَاءُ فَإِذَا خَرَجَ أَذَّنَ وَإِذَا نَزَلَ أَقَامَ","id":"Telah menceritakan kepada kami [Yusuf Al Qaththan] berkata, telah menceritakan kepada kami [Jarir]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] semuanya dari [Muhammad bin Ishaq] dari [Az Zuhri] dari [As Sa`ib bin Yazid] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam hanya ada satu adzan, jika beliau keluar adzan dikumandangkan, dan jika beliau turun (dari mimbar) iqamah dikumandangkan. Demikian juga pada masa Abu Bakar dan Umar. Ketika masa Utsman orang-orang semakin banyak, lalu ia menambahkan adzan yang ketiga di suatu rumah di pasar yang disebut Zaura`. Jika ia keluar, adzan dikumandangkan dan jika ia turun (dari mimbar) iqamah dikumandangkan. \""},"1093":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ أَبَانَ بْنِ تَغْلِبَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ عَلَى الْمِنْبَرِ اسْتَقْبَلَهُ أَصْحَابُهُ بِوُجُوهِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Haitsam bin Jamil] berkata, telah menceritakan kepada kami [Ibnu Mubarak] dari [Aban bin Taghlib] dari ['Adiy bin Tsabit] dari [Bapaknya] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam bangun dari mimbar, maka para sahabat menyambutnya dengan wajah-wajah mereka. \""},"1094":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجُمُعَةِ سَاعَةً لَا يُوَافِقُهَا رَجُلٌ مُسْلِمٌ قَائِمٌ يُصَلِّي يَسْأَلُ اللَّهَ فِيهَا خَيْرًا إِلَّا أَعْطَاهُ وَقَلَّلَهَا بِيَدِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada hari jum'at ada satu waktu, tidaklah seorang muslim berdiri shalat dan meminta kebaikan kepada Allah pada waktu itu, kecuali Ia akan mengabulkannya, \" dan beliau mensedikitkan waktu itu dengan isyarat tangan. \""},"1095":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ الْمُزَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي يَوْمِ الْجُمُعَةِ سَاعَةٌ مِنْ النَّهَارِ لَا يَسْأَلُ اللَّهَ فِيهَا الْعَبْدُ شَيْئًا إِلَّا أُعْطِيَ سُؤْلَهُ قِيلَ أَيُّ سَاعَةٍ قَالَ حِينَ تُقَامُ الصَّلَاةُ إِلَى الِانْصِرَافِ مِنْهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami [Katsir bin Abdullah bin Amru bin Auf Al Muzani] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam mengatakan tentang hari jum'at: \"Satu waktu pada siang hari di hari jum'at, tidaklah seorang hamba berdiri memohon sesuatu kepada Allah di dalamnya melainkan Ia akan mengabulkan permintaannya. \" Ditanyakan kepada beliau, \"Kapan itu?\" beliau menjawab: \"Ketika shalat didirikan hingga selesai. \" "},"1096":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَقُلْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ إِنَّا لَنَجِدُ فِي كِتَابِ اللَّهِ فِي يَوْمِ الْجُمُعَةِ سَاعَةً لَا يُوَافِقُهَا عَبْدٌ مُؤْمِنٌ يُصَلِّي يَسْأَلُ اللَّهَ فِيهَا شَيْئًا إِلَّا قَضَى لَهُ حَاجَتَهُ قَالَ عَبْدُ اللَّهِ فَأَشَارَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ بَعْضُ سَاعَةٍ فَقُلْتُ صَدَقْتَ أَوْ بَعْضُ سَاعَةٍ قُلْتُ أَيُّ سَاعَةٍ هِيَ قَالَ هِيَ آخِرُ سَاعَاتِ النَّهَارِ قُلْتُ إِنَّهَا لَيْسَتْ سَاعَةَ صَلَاةٍ قَالَ بَلَى إِنَّ الْعَبْدَ الْمُؤْمِنَ إِذَا صَلَّى ثُمَّ جَلَسَ لَا يَحْبِسُهُ إِلَّا الصَّلَاةُ فَهُوَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adl Dlahhak bin Utsman] dari [Abu An Nadlrah] dari [Abu Salamah] dari [Abdullah bin Salam] berkata; Aku bertanya sementara Rasulullah shallallahu 'alaihi wasallam sedang duduk, \"Dalam Kitabullah kami mendapati satu waktu di hari jum'at, tidaklah seorang mukmin pada waktu itu berdiri shalat dan meminta sesuatu kepada Allah, kecuali Ia akan memenuhinya. \" Abdullah berkata, \"Rasulullah shallallahu 'alaihi wasallam berisyarat kepadaku; \"atau sebagian waktu, \" lalu aku berkata, \"Engkau benar, atau sebagian waktu. Aku tanyakan, \"Kapan waktu itu?\" ia menjawab, \"Di akhir waktu siang hari. \" Aku bertanya, \"Bukankah itu waktu shalat?\" ia menjawab, \"Benar, sesungguhnya seorang hamba yang beriman apabila shalat kemudian duduk, dan tidak ada yang menahannya untuk duduk kecuali karena menunggu shalat, maka ia adalah hitungan shalat. \""},"1097":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ أَبُو يَحْيَى الرَّازِيُّ عَنْ مُغِيرَةَ بْنِ زِيَادٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ثَابَرَ عَلَى ثِنْتَيْ عَشْرَةَ رَكْعَةً مِنْ السُّنَّةِ بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ أَرْبَعٍ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ وَرَكْعَتَيْنِ قَبْلَ الْفَجْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ishaq bin Sulaiman Abu Yahya Ar Razi] dari [Mughirah bin Ziyad] dari ['Atho`] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjaga dua belas raka'at shalat sunnah maka akan dibangunkan baginya rumah di surga; empat raka'at sebelum zhuhur, dua raka'at setelah zhuhur, dua raka'at setelah maghrib, dua raka'at setelah isya dan dua raka'at sebelum fajar. \""},"1098":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى فِي يَوْمٍ وَلَيْلَةٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Isma'il bin Abu Kholid] dari [Al Musayyab bin Rafi'] dari [Anbasah bin Abu Sufyan] dari [Ummu Habibah binti Abu Sufyan] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa shalat dua belas raka'at (shalat sunnah) dalam sehari semalam maka akan dibangunkan baginya rumah di surga. \""},"1099":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ بْنِ الْأَصْبَهَانِيِّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ رَكْعَتَيْنِ قَبْلَ الْفَجْرِ وَرَكْعَتَيْنِ قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ بَعْدَ الظُّهْرِ وَرَكْعَتَيْنِ أَظُنُّهُ قَالَ قَبْلَ الْعَصْرِ وَرَكْعَتَيْنِ بَعْدَ الْمَغْرِبِ أَظُنُّهُ قَالَ وَرَكْعَتَيْنِ بَعْدَ الْعِشَاءِ الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Sulaiman bin Al Ashbahani] dari [Suhail] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam \"Barangsiapa shalat dalam sehari sebanyak dua belas raka'at, maka akan dibangunkan baginya rumah di surga; dua raka'at sebelum fajar, dua raka'at setelah zhuhur, dua raka'at setelah zhuhur, dua raka'at, aku menduga bahwa beliau mengatakan: \"sebelum ashar, dua raka'at setelah maghrib, dan aku menduga beliau mengatakan: \"dan dua raka'at setelah isya yang akhir. \""},"1100":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَضَاءَ لَهُ الْفَجْرُ صَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Ibnu Umar] berkata, \"Jika fajar telah meneranginya, Nabi shallallahu 'alaihi wasallam shalat dua raka'at. \" "},"1101":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الرَّكْعَتَيْنِ قَبْلَ الْغَدَاةِ كَأَنَّ الْأَذَانَ بِأُذُنَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Anas bin Sirin] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat dua raka'at sebelum subuh, seakan-akan adzan di kedua telinganya (tidak terlalu lama). \""},"1102":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ بِنْتِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا نُودِيَ لِصَلَاةِ الصُّبْحِ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ يَقُومَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] dari [Hafsh binti Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam jika diseru untuk melaksanakan shalat subuh, beliau shalat dua raka'at dengan ringan sebelum pergi shalat. \""},"1103":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأَ صَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] ia berkata, \"Jika berwudlu Nabi shallallahu 'alaihi wasallam shalat dua raka'at, kemudian berangkat shalat. \""},"1104":{"ar":"حَدَّثَنَا الْخَلِيلُ بْنُ عَمْرٍو أَبُو عَمْرٍو حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الرَّكْعَتَيْنِ عِنْدَ الْإِقَامَةِ","id":"Telah menceritakan kepada kami [Al Khalil bin Amru Abu Amru] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata \"Nabi shallallahu 'alaihi wasallam shalat dua raka'at menjelang iqamah. \" "},"1105":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam membaca QUL YAA AYYUHAL KAAFIRUUN dan QUL HUWA ALLAHU AHAD pada dua raka'at sebelum fajar. \""},"1106":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ وَمُحَمَّدُ بْنُ عُبَادَةَ الْوَاسِطِيَّانِ قَالَا حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَرَمَقْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا فَكَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] dan [Muhammad bin Ubadah Al Wasithiyani] keduanya berkata; telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Mujahid] dari [Ibnu Umar] ia berkata, \"Aku selalu memperhatikan Nabi shallallahu 'alaihi wasallam selama satu bulan, beliau membaca QUL YAA AYYUHAL KAAFIRUUN dan QUL HUWA ALLAHU AHAD pada dua raka'at sebelum fajar. \""},"1107":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَكْعَتَيْنِ قَبْلَ الْفَجْرِ وَكَانَ يَقُولُ نِعْمَ السُّورَتَانِ هُمَا يُقْرَأُ بِهِمَا فِي رَكْعَتَيْ الْفَجْرِ قُلْ هُوَ اللَّهُ أَحَدٌ وَقُلْ يَا أَيُّهَا الْكَافِرُونَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Al Jurairi] dari [Abdullah bin Syaqiq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat dua raka'at sebelum fajar. Beliau mengatakan: \"Itu adalah dua surat yang paling baik, ia dibaca pada dua raka'at sebelum subuh; QUL HUWA ALLAHU AHAD dan QUL YAA AYYUHAL KAAFIRUUN. \""},"1108":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَزْهَرُ بْنُ الْقَاسِمِ ح و حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَا حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُحَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Azhar Ibnul Qasim]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] keduanya berkata; telah menceritakan kepada kami [Zakaria bin Ishaq] dari [Amru bin Dinar] dari ['Atho` bin Yasar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika iqamah telah dikumandangkan maka tidak ada shalat kecuali shalat wajib. \" Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Amru bin Dinar] dari ['Atho` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1109":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُصَلِّي الرَّكْعَتَيْنِ قَبْلَ صَلَاةِ الْغَدَاةِ وَهُوَ فِي الصَّلَاةِ فَلَمَّا صَلَّى قَالَ لَهُ بِأَيِّ صَلَاتَيْكَ اعْتَدَدْتَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari ['Ashim] dari [Abdullah bin Sarjis] berkata, \"Ketika sedang melaksanakan shalat Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki shalat dua raka'at sebelum subuh. Ketika selesai shalat, beliau bertanya kepadanya: \"Shalat mana yang sudah kamu persiapkan?\""},"1110":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَ��ْ عَبْدِ اللَّهِ بْنِ مَالِكِ بْنِ بُحَيْنَةَ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ وَقَدْ أُقِيمَتْ صَلَاةُ الصُّبْحِ وَهُوَ يُصَلِّي فَكَلَّمَهُ بِشَيْءٍ لَا أَدْرِي مَا هُوَ فَلَمَّا انْصَرَفَ أَحَطْنَا بِهِ نَقُولُ لَهُ مَاذَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ لِي يُوشِكُ أَحَدُكُمْ أَنْ يُصَلِّيَ الْفَجْرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Abu Marwan bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Bapaknya] dari [Hafsh bin Ashim] dari [Abdullah bin Malik bin Buhainah] berkata, \"Nabi shallallahu 'alaihi wasallam melewati seorang laki-laki yang sedang mengerjakan shalat padahal iqamah telah dikumandangkan, maka beliau pun berbicara dengannya, namun aku tidak tahu apa yang beliau perbincangkan. Ketika shalat telah selesai, kami mengerumuni seraya bertanya kepadanya, \"Apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kepadamu?\" ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Hampir-hampir salah seorang dari kalian shalat subuh empat raka'at. \""},"1111":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ عَنْ قَيْسِ بْنِ عَمْرٍو قَالَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي بَعْدَ صَلَاةِ الصُّبْحِ رَكْعَتَيْنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَاةَ الصُّبْحِ مَرَّتَيْنِ فَقَالَ لَهُ الرَّجُلُ إِنِّي لَمْ أَكُنْ صَلَّيْتُ الرَّكْعَتَيْنِ اللَّتَيْنِ قَبْلَهُمَا فَصَلَّيْتُهُمَا قَالَ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Sa'd bin Sa'id] berkata, telah menceritakan kepadaku [Muhammad bin Ibrahim] dari [Qais bin Amru] ia berkata, \"Nabi shallallahu 'alaihi wasallam melihat seorang laki-laki shalat dua raka'at setelah subuh, maka Nabi shallallahu 'alaihi wasallam pun bertanya kepadanya: \"Apakah ada shalat subuh dikerjakan dua kali! \" laki-laki itu menjawab, \"Aku belum mengerjakan dua raka'at sebelum subuh, maka aku mengerjakannya, \" Nabi shallallahu 'alaihi wasallam pun diam. \""},"1112":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَامَ عَنْ رَكْعَتَيْ الْفَجْرِ فَقَضَاهُمَا بَعْدَ مَا طَلَعَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam tertidur hingga tidak mengerjakan dua raka'at sebelum subuh, lalu beliau mengqadla keduanya setelah matahari terbit. \""},"1113":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ قَابُوسَ عَنْ أَبِيهِ قَالَأَرْسَلَ أَبِي إِلَى عَائِشَةَ أَيُّ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَحَبَّ إِلَيْهِ أَنْ يُوَاظِبَ عَلَيْهَا قَالَتْ كَانَ يُصَلِّي أَرْبَعًا قَبْلَ الظُّهْرِ يُطِيلُ فِيهِنَّ الْقِيَامَ وَيُحْسِنُ فِيهِنَّ الرُّكُوعَ وَالسُّجُودَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Qabus] dari [Bapaknya] berkata; Bapakku mengutus seseorang untuk bertanya kepada ['Aisyah]; shalat apa yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam untuk dijadikan sebagai kebiasaan?\" 'Aisyah menjawab, \"Beliau suka mengerjakan empat raka'at sebelum zhuhur, dengan memanjangkan berdiri dan membaguskan rukuk dan sujudnya. \""},"1114":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ عُبَيْدَةَ بْنِ مُعَتِّبٍ الضَّبِّيِّ عَنْ إِبْرَاهِيمَ عَنْ سَهْمِ بْنِ مِنْجَابٍ عَنْ قَزَعَةَ عَنْ قَرْثَعٍ عَنْ أَبِي أَيُّوبَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الظُّهْرِ أَرْبَعًا إِذَا زَالَتْ الشَّمْسُ لَا يَفْصِلُ بَيْنَهُنَّ بِتَسْلِيمٍ وَقَالَ إِنَّ أَبْوَابَ السَّمَاءِ تُفْتَحُ إِذَا زَالَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ubaidah bin Mu'attib Adl Dlabbi] dari [Ibrahim] dari [Sahm bin Minjab] dari [Qaza'ah] dari [Qartsa'] dari [Abu Ayyub] berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat sebelum zhuhur empat raka'at apabila matahari telah bergeser, dengan tidak memisahkan antara raka'at dengan salam. Beliau bersabda: \"Sesungguhnya pintu-pintu langit dibuka apabila matahari sudah tergelincir. \""},"1115":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَزَيْدُ بْنُ أَخْزَمَ وَمُحَمَّدُ بْنُ مَعْمَرٍ قَالُوا حَدَّثَنَا مُوسَى بْنُ دَاوُدَ الْكُوفِيُّ حَدَّثَنَا قَيْسُ بْنُ الرَّبِيعِ عَنْ شُعْبَةَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَاتَتْهُ الْأَرْبَعُ قَبْلَ الظُّهْرِ صَلَّاهَا بَعْدَ الرَّكْعَتَيْنِ بَعْدَ الظُّهْرِقَالَ أَبُو عَبْد اللَّهِ لَمْ يُحَدِّثْ بِهِ إِلَّا قَيْسٌ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Zaid bin Akhzam] dan [Muhammad bin Ma'mar] keduanya berkata; telah menceritakan kepada kami [Musa bin Dawud Al Kufi] berkata, telah menceritakan kepada kami [Qais bin Ar Rabi'] dari [Syu'bah] dari [Khalid Al Hadda] dari [Abdullah bin Syaqiq] dari ['Aisyah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam tidak sempat mengerjakan empat raka'at sebelum zhuhur, beliau menggantinya dengan dua raka'at setelah mengerjakan dua raka'at ba'diah zhuhur. \" Abu Abdullah berkata, \"Tidak ada yang meriwayatkannya kecuali Qais, dari Syu'bah. \""},"1116":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَأَرْسَلَ مُعَاوِيَةُ إِلَى أُمِّ سَلَمَةَ فَانْطَلَقْتُ مَعَ الرَّسُولِ فَسَأَلَ أُمَّ سَلَمَةَ فَقَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ يَتَوَضَّأُ فِي بَيْتِي لِلظُّهْرِ وَكَانَ قَدْ بَعَثَ سَاعِيًا وَكَثُرَ عِنْدَهُ الْمُهَاجِرُونَ وَقَدْ أَهَمَّهُ شَأْنُهُمْ إِذْ ضُرِبَ الْبَابُ فَخَرَجَ إِلَيْهِ فَصَلَّى الظُّهْرَ ثُمَّ جَلَسَ يَقْسِمُ مَا جَاءَ بِهِ قَالَتْ فَلَمْ يَزَلْ كَذَلِكَ حَتَّى الْعَصْرِ ثُمَّ دَخَلَ مَنْزِلِي فَصَلَّى رَكْعَتَيْنِ ثُمَّ قَالَ شَغَلَنِي أَمْرُ السَّاعِي أَنْ أُصَلِّيَهُمَا بَعْدَ الظُّهْرِ فَصَلَّيْتُهُمَا بَعْدَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Yazid bin Abu Ziyad] dari [Abdullah Ibnul Harits] ia berkata, \"Mu'awiyah mengutus seorang utusan menemui Ummu Salamah, maka aku ikut pergi bersama utusan tersebut. Utusan itu bertanya kepada Ummu Salamah, lalu [Ummu Salamah] pun menjawab, \"Ketika Rasulullah shallallahu 'alaihi wasallam berwudlu di rumahku untuk shalat zhuhur, beliau telah mengirim para pengambil zakat, di sisi beliau juga banyak sahabat Muhajirin hingga persoalan mereka menjadikan beliau sibuk. Ketika pintu diketuk beliau keluar dan shalat zhuhur, kemudian beliau duduk dan membagikan harta zakat yang datang kepada beliau. \" Ummu Salamah berkata, \"Beliau masih tersibukkan dengan hal itu hingga datang waktu ashar, setelah itu beliau masuk ke dalam rumahku dan shalat dua raka'at. Beliau kemudian bersabda: \"Persoalan petugas zakat itu telah menyibukkan aku dari mengerjakan dua raka'at setelah zhuhur, maka aku mengerjakannya setelah ashar. \""},"1117":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الشُّعَيْثِيُّ عَنْ أَبِيهِ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى قَبْلَ الظُّهْرِ أَرْبَعًا وَبَعْدَهَا أَرْبَعًا حَرَّمَهُ اللَّهُ عَلَى النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Asy Syu'aitsi] dari [Bapaknya] dari [Anbasah bin Abu Sufyan] dari [Ummu Habibah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa shalat sebelum zhuhur empat raka'at dan setelahnya empat raka'at, maka Allah mengharamkannya masuk neraka. \""},"1118":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ وَأَبِي وَإِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ السَّلُولِيِّ قَالَسَأَلْنَا عَلِيًّا عَنْ تَطَوُّعِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّهَارِ فَقَالَ إِنَّكُمْ لَا تُطِيقُونَهُ فَقُلْنَا أَخْبِرْنَا بِهِ نَأْخُذْ مِنْهُ مَا اسْتَطَعْنَا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الْفَجْرَ يُمْهِلُ حَتَّى إِذَا كَانَتْ الشَّمْسُ مِنْ هَا هُنَا يَعْنِي مِنْ قِبَلِ الْمَشْرِقِ بِمِقْدَارِهَا مِنْ صَلَاةِ الْعَصْرِ مِنْ هَا هُنَا يَعْنِي مِنْ قِبَلِ الْمَغْرِبِ قَامَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ يُمْهِلُ حَتَّى إِذَا كَانَتْ الشَّمْسُ مِنْ هَا هُنَا يَعْنِي مِنْ قِبَلِ الْمَشْرِقِ مِقْدَارَهَا مِنْ صَلَاةِ الظُّهْرِ مِنْ هَا هُنَا قَامَ فَصَلَّى أَرْبَعًا وَأَرْبَعًا قَبْلَ الظُّهْرِ إِذَا زَالَتْ الشَّمْسُ وَرَكْعَتَيْنِ بَعْدَهَا وَأَرْبَعًا قَبْلَ الْعَصْرِ يَفْصِلُ بَيْنَ كُلِّ رَكْعَتَيْنِ بِالتَّسْلِيمِ عَلَى الْمَلَائِكَةِ الْمُقَرَّبِينَ وَالنَّبِيِّينَ وَمَنْ تَبِعَهُمْ مِنْ الْمُسْلِمِينَ وَالْمُؤْمِنِينَ قَالَ عَلِيٌّ فَتِلْكَ سِتَّ عَشْرَةَ رَكْعَةً تَطَوُّعُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّهَارِ وَقَلَّ مَنْ يُدَاوِمُ عَلَيْهَاقَالَ وَكِيعٌ زَادَ فِيهِ أَبِي فَقَالَ حَبِيبُ بْنُ أَبِي ثَابِتٍ يَا أَبَا إِسْحَقَ مَا أُحِبُّ أَنَّ لِي بِحَدِيثِكَ هَذَا مِلْءَ مَسْجِدِكَ هَذَا ذَهَبًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dan [Bapakku] dan [Isra'il] dari [Abu Ishaq] dari [Ashim bin Dlamrah As Saluli] ia berkata, \"Kami bertanya kepada [Ali] tentang shalat sunnah Rasulullah shallallahu 'alaihi wasallam di waktu siang hari, \" Ali pun menjawab, \"Kalian tidak akan sanggup, \" kami berkata, \"Kabarkanlah, kami akan melakukan semampunya, \" Ali berkata, \"Kebiasaan Nabi shallallahu 'alaihi wasallam apabila hendak melaksanakan Shalat fajar (shubuh), beliau menundanya sehingga apabila matahari terbit dari arah sini yaitu dari arah timur, ukurannya seperti Shalat Ashar ketika matahari dari arah sini yaitu dari arah barat, maka beliau melaksanakan Shalat dua rakaat. Kemudian beliau menunda sehingga apabila matahari terbit dari arah sini yaitu dari arah timur, ukurannya jika dari Shalat Dzuhur dari arah sini yaitu dari arah barat, kemudian beliau melaksanakan Shalat sunnah empat rakaat, dan empat rakaat sebelum dzuhur apabila matahari telah tergelincir, dan shalat dua rakaat setelah Shalat dzuhur, kemudian beliau melaksanakan Shalat sunnah sebelum Shalat Ashar empat rakaat pada setiap dua rakaat dipisah dengan salam kepada para Malaikat, para Nabi serta orang-orang yang mengikuti mereka dari kaum muslimin dan mukminin.\" Ashim berkata; Ali berkata; \"Itulah enam belas raka'at Shalat sunnahnya Nabi shallallahu 'alaihi wasallam di siang hari dan sangat sedikit orang mampu menekuninya.\" Waki' berkata; dalam hadits ini bapakku menambahkan; Habib Bin Abu Tsabit berkata; wahai Abu Ishaq \"Wahai Abu Ishaq aku tidak menyukai kalau saja masjidmu di penuhi dengan emas kalau dibandingkan dengan haditsmu ini.\""},"1119":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَوَكِيعٌ عَنْ كَهْمَسٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ قَالَهَا ثَلَاثًا قَالَ فِي الثَّالِثَةِ لِمَنْ شَاءَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dan [Waki'] dari [Kahmas] berkata, telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara dua adzan ada shalat, beliau ucapkan itu hingga tiga kali, dan pada kali ketiganya beliau mengatakan: \"Bagi yang mau. \""},"1120":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَلِيَّ بْنَ زَيْدِ بْنِ جُدْعَانَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُإِنْ كَانَ الْمُؤَذِّنُ لَيُؤَذِّنُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَرَى أَنَّهَا الْإِقَامَةُ مِنْ كَثْرَةِ مَنْ يَقُومُ فَيُصَلِّي الرَّكْعَتَيْنِ قَبْلَ الْمَغْرِبِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] berkata; Aku mendengar [Ali bin Zaid bin Jud'an] berkata; Aku mendengar [Anas bin Malik] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, ketika seorang mu`adzin mengumandangkan adzan maka kami mengira kalau itu adalah iqamah karena banyaknya orang yang melakukannya (shalat sunnah). Lalu ia shalat dua raka'at sebelum maghrib. \""},"1121":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا هُشَيْمٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَغْرِبَ ثُمَّ يَرْجِعُ إِلَى بَيْتِي فَيُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] berkata, telah menceritakan kepada kami [Husyaim] dari [Khalid Al Hadda] dari [Abdullah bin Syaqiq] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat maghrib kemudian kembali ke rumahku dan mengerjakan shalat dua raka'at. \""},"1122":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَنِي عَبْدِ الْأَشْهَلِ فَصَلَّى بِنَا الْمَغْرِبَ فِي مَسْجِدِنَا ثُمَّ قَالَ ارْكَعُوا هَاتَيْنِ الرَّكْعَتَيْنِ فِي بُيُوتِكُمْ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Adl Dlahhak] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Muhammad bin Ishaq] dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi kami di Bani Abdul Asyhal, beliau shalat maghrib bersama kami di masjid kami, kemudian beliau bersabda: \"Laksanakanlah dua raka'at ini di rumah-rumah kalian. \""},"1123":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ وَاقِدٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُؤَمَّلِ بْنِ الصَّبَّاحِ حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ قَالَا حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الْوَلِيدِ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ زِرٍّ وَأَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ بَعْدَ صَلَاةِ الْمَغْرِبِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Ahmad bin Al Azhar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Waqid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Mu`ammal bin Ash Shabbah] berkata, telah menceritakan kepada kami [Badal bin Muhabbar] keduanya berkata; telah menceritakan kepada kami [Abdul Malik bin Al Walid] berkata, telah menceritakan kepada kami ['Ashim bin Bahdalah] dari [Zir] dan [Abu Wa`il] dari [Abdullah bin Mas'ud] berkata, \"Nabi shallallahu 'alaihi wasallam selalu membaca di dua rakaat setelah maghrib QUL YAA AYYUHAL KAAFIRUUN (Katakanlah: \"Hai orang-orang kafir) dan QUL HUWA ALLAHU AHAD (Katakanlah: \"Dia-lah Allah, Yang Maha Esa). \""},"1124":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو الْحُسَيْنِ الْعُكْلِيُّ أَخْبَرَنِي عُمَرُ بْنُ أَبِي خَثْعَمٍ الْيَمَامِيُّ أَنْبَأَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى بَعْدَ الْمَغْرِبِ سِتَّ رَكَعَاتٍ لَمْ يَتَكَلَّمْ بَيْنَهُنَّ بِسُوءٍ عُدِلْنَ لَهُ بِعِبَادَةِ ثِنْتَيْ عَشْرَةَ سَنَةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abul Husain Al 'Ukli] berkata, telah mengabarkan kepadaku [Umar bin Abu Khats'am Al Yamami] berkata, telah memberitakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdurrahman bin 'Auf] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat setelah maghrib enam raka'at, ia tidak berbicara di sela-sela raka'at itu dengan perkataan jelek, maka ia seperti mengerjakan shalat dua belas raka'at selama setahun. \" "},"1125":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ رَاشِدٍ الزَّوْفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُرَّةَ الزَّوْفِيِّ عَنْ خَارِجَةَ بْنِ حُذَافَةَ الْعَدَوِيِّ قَالَخَرَجَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ قَدْ أَمَدَّكُمْ بِصَلَاةٍ لَهِيَ خَيْرٌ لَكُمْ مِنْ حُمُرِ النَّعَمِ الْوِتْرُ جَعَلَهُ اللَّهُ لَكُمْ فِيمَا بَيْنَ صَلَاةِ الْعِشَاءِ إِلَى أَنْ يَطْلُعَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Muhmmad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abdullah bin Rasyid Az Zaufi] dari [Abdullah bin Abu Murrah Az Zaufi] dari [Kharijah bin Hudzafah Al 'Adawi] ia berkata \"Nabi shallallahu 'alaihi wasallam mengunjungi kami, lalu beliau bersabda: \"Sesungguhnya Allah telah menetapkan bagi kalian shalat yang lebih baik kalian dari pada unta merah, yakni shalat witir. Shalat tersebut Allah jadikan bagi kalian antara shalat isya hingga terbit fajar. \""},"1126":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ السَّلُولِيِّ قَالَ قَالَ عَلِيُّ بْنُ أَبِي طَالِبٍإِنَّ الْوِتْرَ لَيْسَ بِحَتْمٍ وَلَا كَصَلَاتِكُمْ الْمَكْتُوبَةِ وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْتَرَ ثُمَّ قَالَ يَا أَهْلَ الْقُرْآنِ أَوْتِرُوا فَإِنَّ اللَّهَ وِتْرٌ يُحِبُّ الْوِتْرَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abu Ishaq] dari [Ashim bin Dlamrah As Saluli] ia berkata, \" [Ali bin Abu Thalib] berkata, \"Shalat witir tidak wajib dan tidak pula seperti shalat maktubah kalian, hanya saja Rasulullah shallallahu 'alaihi wasallam selalu mengerjakannya, beliau mengatakan: \"Wahai ahli Qur`an, hendaklah kalian shalat witir, sesungguhnya Allah menyukai shalat witir. \""},"1127":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو حَفْصٍ الْأَبَّارُ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ وِتْرٌ يُحِبُّ الْوِتْرَ أَوْتِرُوا يَا أَهْلَ الْقُرْآنِ فَقَالَ أَعْرَابِيٌّ مَا يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ لَكَ وَلَا لِأَصْحَابِكَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Hafs Al Abbar] dari [A'masy] dari [Amru bin Murrah] dari [Abu Ubaidah] dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah itu ganjil, menyukai yang ganjil, maka laksanakanlah witir wahai ahli Qur'an. \" Kemudian seorang badui berkata, \"Apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam?\" Beliau bersabda: \"Bukan bagimu dan bukan pula bagi teman-temanmu. \""},"1128":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو حَفْصٍ الْأَبَّارُ حَدَّثَنَا الْأَعْمَشُ عَنْ طَلْحَةَ وَزُبَيْدٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Hafs Al Abbar] dari [A'masy] dari [Thalhah] dan [Zaid] dari [Dzarr] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] dari [Ubai bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat witir dengan membaca; \"SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) dan QUL YAA AYYUHAL KAAFIRUUN (Katakanlah: \"Hai orang-orang kafir) serta QUL HUWAALLAHU AHAD (Katakanlah: \"Dia-lah Allah yang Maha Esa) "},"1129":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌحَدَّثَنَا أَحْمَدُ بْنُ مَنْصُورٍ أَبُو بَكْرٍ قَالَ حَدَّثَنَا شَبَابَةُ قَالَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Bapaknya] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat witir dengan membaca; SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) dan QUL YAA AYYUHAL KAAFIRUUN (Katakanlah: \"Hai orang-orang kafir) serta QUL HUWAALLAHU AHAD (Katakanlah: \" Dia-lah Allah yang Maha Esa). \" Telah menceritakan kepada kami [Ahmad bin Manshur Abu Bakr] berkata; telah menceritakan kepada kami [Syababah] berkata; telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Bapaknya] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1130":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ وَأَبُو يُوسُفَ الرَّقِّيُّ مُحَمَّدُ بْنُ أَحْمَدَ الصَّيْدَلَانِيُّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ خُصَيْفٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ قَالَ سَأَلْنَا عَائِشَةَبِأَيِّ شَيْءٍ كَانَ يُوتِرُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الثَّانِيَةِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ قُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] dan [Abu Yusuf Ar Raqqi Muhammad bin Ahmad Ash Shaidalani] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Khushaif] dari [Abdul Aziz bin Juraij] ia berkata, \"Kami bertanya kepada ['Aisyah]; surat apa yang biasa Rasulullah shallallahu 'alaihi wasallam ketika melaksanakan shalat witir?\" ia menjawab, \"Di raka'at pertama Rasulullah shallallahu 'alaihi wasallam membaca 'SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi), raka'at kedua membaca QUL YAA AYYUHAL KAAFIRUUN (Katakanlah: \"Hai orang-orang kafir) dan raka'at ketiga membaca QUL HUWAALLAHU AHAD (Katakanlah: \"Hai orang-orang kafir) dan AL MU'AWIDZATAIN (Al Falaq dan An Nas). \" "},"1131":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ مَثْنَى مَثْنَى وَيُوتِرُ بِرَكْعَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Anas bin Sirin] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat malam dua raka'at dua raka'at, dan witir dengan satu raka'at. \""},"1132":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى وَالْوِتْرُ رَكْعَةٌ قُلْتُ أَرَأَيْتَ إِنْ غَلَبَتْنِي عَيْنِي أَرَأَيْتَ إِنْ نِمْتُ قَالَ اجْعَلْ أَرَأَيْتَ عِنْدَ ذَلِكَ النَّجْمِ فَرَفَعْتُ رَأْسِي فَإِذَا السِّمَاكُ ثُمَّ أَعَادَ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى وَالْوِتْرُ رَكْعَةٌ قَبْلَ الصُّبْحِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] berkata, telah menceritakan kepada kami [Ashim] dari [Abu Mijlaz] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua raka'at dua raka'at, sedangkan witir satu raka'at. \" Aku bertanya, \"Bagaimana pendapatmu seandainya aku terkalahkan oleh mataku hingga aku tidur?\" ia menjawab, \"Jadikanlah perandaianmu itu pada bintang (maksudnya; tidur), \" aku pun mengangkat kepalaku dan ternyata bintang itu telah nampak. Ibnu Umar mengulangi ucapannya lagi, kemudian ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua raka'at dua raka'at, sedangkan witir adalah satu raka'at sebelum subuh. \""},"1133":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الْمُطَّلِبُ بْنُ عَبْدِ اللَّهِ قَالَسَأَلَ ابْنَ عُمَرَ رَجُلٌ فَقَالَ كَيْفَ أُوتِرُ قَالَ أَوْتِرْ بِوَاحِدَةٍ قَالَ إِنِّي أَخْشَى أَنْ يَقُولَ النَّاسُ الْبُتَيْرَاءُ فَقَالَ سُنَّةُ اللَّهِ وَرَسُولِهِ يُرِيدُ هَذِهِ سُنَّةُ اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Al Muthallib bin Abdullah] ia berkata, \"Seorang laki-laki bertanya kepada [Ibnu Umar], \"Berapa rakaat aku harus shalat witir?\" ia menjawab, \"Witirlah satu raka'at, \" laki-laki itu berkata, \"Aku khawatir orang-orang akan mengatakan kepadaku Butaira`, \" Ibnu Umar berkata, \"Sunnah Allah dan Rasul-Nya, \" maksudnya; ini adalah sunnah Allah dan Rasul-Nya shallallahu 'alaihi wasallam. \""},"1134":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلِّمُ فِي كُلِّ ثِنْتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengucapkan salam pada setiap dua raka'at dan witir dengan satu raka'at. \""},"1135":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ عَنْ الْحَسَنِ بْنِ عَلِيٍّ قَالَعَلَّمَنِي جَدِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي قُنُوتِ الْوِتْرِ اللَّهُمَّ عَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَاهْدِنِي فِيمَنْ هَدَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ إِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ إِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ سُبْحَانَكَ رَبَّنَا تَبَارَكْتَ وَتَعَالَيْتَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Abu Al Haura`] dari [Al Hasan bin Ali] ia berkata, \"Kakekku, Rasulullah shallallahu 'alaihi wasallam mengajariku beberapa kalimat yang aku baca ketika qunut dalam shalat witir; ALLAHUMMA 'AAFANI FIIMAN 'AAFAITA WA TAWALLANII FIIMAN TAWALLAITA WAH DINII FIIMAN HADAITA WAQINII MAA QADLAITA WA BAARIKLII FIIMAA A'THAITA INNAKA TAQDLII WA LAA YUQDLAA 'ALAIKA INNAHU LAA YADZILLU MAN WAA LAITA SUBHAANAKA RABBANAA TABAARAKTA WA TA'AALAIKA. "},"1136":{"ar":"حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ عَمْرٍو حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنِي هِشَامُ بْنُ عَمْرٍو الْفَزَارِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ الْمَخْزُومِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي آخِرِ الْوِتْرِ اللَّهُمَّ إِنِّي أَعُوذُ بِرِضَاكَ مِنْ سُخْطِكَ وَأَعُوذُ بِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah menceritakan kepada kami [Abu Umar Hafsh bin Amru] berkata, telah menceritakan kepada kami [Bahz bin Asad] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah menceritakan kepadaku [Hisyam bin Amru Al Fazari] dari ['Abdurrahman bin Harits bin Hisyam Al Makhzumi] dari [Ali bin Abu Thalib] berkata, \"Nabi shallallahu 'alaihi wasallam di akhir shalat witir membaca do'a, \"ALLHUMMA INNI A'UUDZU BI RIDLAAKA MIN SUKHTIKA WA A'UUDZU BI MU'AAFAATIKA MIN 'UQUUBATIKA WA A'UUDZU BIKA MINKA LAA UHSHI TSNAA`AN 'ALAIKA ANTA KAMAA ATSNAITA 'ALAA NAFSIKA (Ya Allah sesungguhnya aku berlindung dengan keridlaan-Mu dari kemurkaan-Mu, dan aku berlindung dengan maaf-Mu dari siksaan-Mu, dan aku berlindung kepada-Mu dari-Mu, aku tidak bisa menghitung pujian kepada-Mu, Engkau sebagaimana Engkau memuji pada diri-Mu. \""},"1137":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ دُعَائِهِ إِلَّا عِنْدَ الِاسْتِسْقَاءِ فَإِنَّهُ كَانَ يَرْفَعُ يَدَيْهِ حَتَّى يُرَى بَيَاضُ إِبْطَيْهِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Anas bin Malik] berkata, \"Nabi Allah shallallahu 'alaihi wasallam tidak pernah mengangkat kedua tangannya ketika berdo`a kecuali pada shalat istisqa`. Beliau mengangkat kedua tangannya hingga terlihat putihnya kedua ketiak beliau. \" "},"1138":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا عَائِذُ بْنُ حَبِيبٍ عَنْ صَالِحِ بْنِ حَسَّانَ الْأَنْصَارِيِّ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَوْتَ اللَّهَ فَادْعُ بِبَاطِنِ كَفَّيْكَ وَلَا تَدْعُ بِظُهُورِهِمَا فَإِذَا فَرَغْتَ فَامْسَحْ بِهِمَا وَجْهَكَ","id":"Telah menceritakan kepada kami [Abu Kuraib] dan [Muhammad bin Ash Shabbah] keduanya berkata; telah menceritakan kepada kami ['A`id bin Habib] dari [Shalih bin Hassan Al Anshari] dari [Muhammad bin Ka'ab Al Qurazhi] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu berdo'a kepada Allah gunakanlah bagian dalam telapak tanganmu dan jangan dengan bagian luarnya, jika selesai do`a maka usaplah wajahmu dengan keduanya. \""},"1139":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مَيْمُونٍ الرَّقِّيُّ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ سُفْيَانَ عَنْ زُبَيْدٍ الْيَامِيِّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ فَيَقْنُتُ قَبْلَ الرُّكُوعِ","id":"Telah menceritakan kepada kami [Ali bin Maimun Ar-Raqqi] berkata, telah menceritakan kepada kami [Makhlad bin Yazid] dari [Sufyan] dari [Zubaid Al Yami] dari [Sa'id bin 'Abdurrahman bin Abza] dari [Bapaknya] dari [Ubai bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat witir dan qunut sebelum rukuk. \""},"1140":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا سَهْلُ بْنُ يُوسُفَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسُئِلَ عَنْ الْقُنُوتِ فِي صَلَاةِ الصُّبْحِ فَقَالَ كُنَّا نَقْنُتُ قَبْلَ الرُّكُوعِ وَبَعْدَهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Sahl bin Yusuf] berkata, telah menceritakan kepada kami [Humaid] dari [Anas bin Malik] ia berkata, \"Ia ditanya tentang qunut dalam shalat subuh?\" maka Anas pun menjawab, \"Kami melakukan qunut sebelum rukuk dan sesudahnya. \""},"1141":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ قَالَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ الْقُنُوتِ فَقَالَ قَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الرُّكُوعِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Ayyub] dari [Muhammad] ia berkata, \"Aku bertanya kepada [Anas bin Malik] tentang qunut, maka ia pun menjawab, \"Rasulullah shallallahu 'alaihi wasallam melakukan qunut setelah rukuk. \""},"1142":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حُصَيْنٍ عَنْ يَحْيَى بْنِ وَثَّابٍ عَنْ مَسْرُوقٍ قَالَسَأَلْتُ عَائِشَةَ عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مِنْ كُلِّ اللَّيْلِ قَدْ أَوْتَرَ مِنْ أَوَّلِهِ وَأَوْسَطِهِ وَانْتَهَى وِتْرُهُ حِينَ مَاتَ فِي السَّحَرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abu Hushain] dari [Yahya bin Watstsab] dari [Masruq] ia berkata, \"Aku pernah bertanya kepada ['Aisyah] tentang witirnya Rasulullah shallallahu 'alaihi wasallam, lalu ia menjawab, \"Beliau pernah witir di awal malam, tengah malam dan waktu witirnya berakhir di akhir malam, di waktu sahur. \" "},"1143":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَمِنْ كُلِّ اللَّيْلِ قَدْ أَوْتَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَوَّلِهِ وَأَوْسَطِهِ وَانْتَهَى وِتْرُهُ إِلَى السَّحَرِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata; telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Ashim bin Dlamrah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada setiap malamnya witir di awal malam, tengah malam dan berakhir di akhir malam menjelang sahur. \""},"1144":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ خَافَ مِنْكُمْ أَنْ لَا يَسْتَيْقِظَ مِنْ آخِرِ اللَّيْلِ فَلْيُوتِرْ مِنْ أَوَّلِ اللَّيْلِ ثُمَّ لِيَرْقُدْ وَمَنْ طَمِعَ مِنْكُمْ أَنْ يَسْتَيْقِظَ مِنْ آخِرِ اللَّيْلِ فَلْيُوتِرْ مِنْ آخِرِ اللَّيْلِ فَإِنَّ قِرَاءَةَ آخِرِ اللَّيْلِ مَحْضُورَةٌ وَذَلِكَ أَفْضَلُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Ibnu Abu Ghaniah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa di antara kalian khawatir tidak bisa bangun di akhir malam hendaklah ia witir di awal malam kemudian tidur, dan barangsiapa mampu bangun di akhir malam hendaklah ia witir di akhir malam, sebab shalat di akhir malam itu disaksikan. Dan itulah yang lebih afdlal. \""},"1145":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ أَحْمَدُ بْنُ أَبِي بَكْرٍ الْمَدِينِيُّ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ الْوِتْرِ أَوْ نَسِيَهُ فَلْيُصَلِّ إِذَا أَصْبَحَ أَوْ ذَكَرَهُ","id":"Telah menceritakan kepada kami [Abu Mush'ab Ahmad bin Abu Bakr Al Madini] dan [Suwaid bin Sa'id] berkata; telah menceritakan kepada kami ['Abdurrahman bin Zaid bin Aslam] dari [Bapaknya] dari ['Atho` bin Yasar] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa kehilangan shalat witir karena tidur atau lupa, hendaklah ia kerjakan ketika bangun (subuh) atau teringat. \""},"1146":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَأَحْمَدُ بْنُ الْأَزْهَرِ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْتِرُوا قَبْلَ أَنْ تُصْبِحُواقَالَ مُحَمَّدُ بْنُ يَحْيَى فِي هَذَا الْحَدِيثِ دَلِيلٌ عَلَى أَنَّ حَدِيثَ عَبْدِ الرَّحْمَنِ وَاهٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Ahmad Ibnul Azhar] keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Witirlah sebelum datang waktu subuh. \" Muhammad bin Yahya berkata, \"Hadits ini menjadi dalil bahwa hadits 'Abdurrahman itu lemah. \""},"1147":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْفِرْيَابِيُّ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوِتْرُ حَقٌّ فَمَنْ شَاءَ فَلْيُوتِرْ بِخَمْسٍ وَمَنْ شَاءَ فَلْيُوتِرْ بِثَلَاثٍ وَمَنْ شَاءَ فَلْيُوتِرْ بِوَاحِدَةٍ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim bin Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Firyabi] dari [Al Auza'i] dari [Az Zuhri] dari ['Atho` bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Witir adalah haq (disyariatkan), barangsiapa berkehendak ia bisa witir lima raka'at, barangsiapa berkehendak ia bisa witir tiga raka'at dan barangsiapa berkehendak ia bisa witir satu raka'at. \""},"1148":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ قَالَسَأَلْتُ عَائِشَةَ قُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَفْتِينِي عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُنَّا نُعِدُّ لَهُ سِوَاكَهُ وَطَهُورَهُ فَيَبْعَثُهُ اللَّهُ فِيمَا شَاءَ أَنْ يَبْعَثَهُ مِنْ اللَّيْلِ فَيَتَسَوَّكُ وَيَتَوَضَّأُ ثُمَّ يُصَلِّي تِسْعَ رَكَعَاتٍ لَا يَجْلِسُ فِيهَا إِلَّا عِنْدَ الثَّامِنَةِ فَيَدْعُو رَبَّهُ فَيَذْكُرُ اللَّهَ وَيَحْمَدُهُ وَيَدْعُوهُ ثُمَّ يَنْهَضُ وَلَا يُسَلِّمُ ثُمَّ يَقُومُ فَيُصَلِّي التَّاسِعَةَ ثُمَّ يَقْعُدُ فَيَذْكُرُ اللَّهَ وَيَحْمَدُهُ وَيَدْعُو رَبَّهُ وَيُصَلِّي عَلَى نَبِيِّهِ ثُمَّ يُسَلِّمُ تَسْلِيمًا يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ بَعْدَ مَا يُسَلِّمُ وَهُوَ قَاعِدٌ فَتِلْكَ إِحْدَى عَشْرَةَ رَكْعَةً فَلَمَّا أَسَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخَذَ اللَّحْمَ أَوْتَرَ بِسَبْعٍ وَصَلَّى رَكْعَتَيْنِ بَعْدَ مَا سَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Zurarah bin Abu Aufa] dari [Sa'd bin Hisyam] ia berkata, \"Aku bertanya kepada ['Aisyah], \"Aku katakan, \"Wahai Ummul mukminin, berilah fatwa kami tentang witirnya Rasulullah shallallahu 'alaihi wasallam! \" ia menjawab, \"Kami menyiapkan siwak dan air wudlu beliau, lalu Allah membangunkannya atas kehendak-Nya kapan beliau harus bangun. Beliau bersiwak dan wudlu, kemudian shalat sembilan raka'at tanpa duduk kecuali pada raka'at ke delapan. Beliau berdo`a, dzikir kepada Allah, memuji dan memohon kepada-Nya. Kemudian beliau berdiri tanpa salam terlebih dahulu, lalu diam berdiri. Setelah itu beliau shalat pada raka'at kesembilan, lalu duduk dan dzikir kepada Allah, memuji, memohon kepada Rabbnya, dan bershalawat atas Nabi-Nya. Kemudian beliau mengucapkan salam dengan suara keras hingga kami mendengarnya, setelah salam itu beliau shalat lagi dua raka'at dalam keadaan duduk. Maka itulah sebelas raka'at. Setelah Rasulullah shallallahu 'alaihi wasallam berusia senja, beliau witir tujuh raka'at dan shalat dua raka'at setelah salam. \""},"1149":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ زُهَيْرٍ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبْعٍ أَوْ بِخَمْسٍ لَا يَفْصِلُ بَيْنَهُنَّ بِتَسْلِيمٍ وَلَا كَلَامٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Humaid bin 'Abdurrahman] dari [Zuhair] dari [Mansur] dari [Al Hakam] dari [Miqsam] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat witir dengan tujuh atau lima raka'at, dan beliau tidak memisahkannya dengan salam atau perkataan. \" "},"1150":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا شُعْبَةُ عَنْ جَابِرٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي السَّفَرِ رَكْعَتَيْنِ لَا يَزِيدُ عَلَيْهِمَا وَكَانَ يَتَهَجَّدُ مِنْ اللَّيْلِ قُلْتُ وَكَانَ يُوتِرُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] dan [Ishaq bin Manshur] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Syu'bah] dari [Jabir] dari [Salim] dari [bapaknya] ia berkata, \"Dalam safar Rasulullah shallallahu 'alaihi wasallam shalat dua raka'at tidak lebih, dan beliau selalu shalat malam. \" Aku berkata, \"Beliau juga shalat witir?! Ia menjawab, \"Benar. \""},"1151":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى حَدَّثَنَا شَرِيكٌ عَنْ جَابِرٍ عَنْ عَامِرٍ عَنْ ابْنِ عَبَّاسٍ وَابْنِ عُمَرَ قَالَاسَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ السَّفَرِ رَكْعَتَيْنِ وَهُمَا تَمَامٌ غَيْرُ قَصْرٍ وَالْوِتْرُ فِي السَّفَرِ سُنَّةٌ","id":"Telah menceritakan kepada kami [Isma'il bin Musa] berkata, telah menceritakan kepada kami [Syarik] dari [Jabir] dari [Amir] dari [Ibnu Abbas] dan [Ibnu Umar] keduanya berkata; Rasulullah shallallahu 'alaihi wasallam memberi contoh shalat safar dengan dua raka'at, sempurna dan tidak diringkas. Dan shalat witir dalam perjalanan adalah sunnah. \""},"1152":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ حَدَّثَنَا مَيْمُونُ بْنُ مُوسَى الْمَرَئِيُّ عَنْ الْحَسَنِ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْوِتْرِ رَكْعَتَيْنِ خَفِيفَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Hammad bin Mas'adah] berkata, telah menceritakan kepada kami [Maimun bin Musa Al Mara`i] dari [Al Hasan] dari [Ibunya] dari [Ummu Salamah] berkata, \"Setelah witir beliau melaksanakan shalat dua raka'at yang ringan sambil duduk. \" "},"1153":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ حَدَّثَتْنِي عَائِشَةُ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِوَاحِدَةٍ ثُمَّ يَرْكَعُ رَكْعَتَيْنِ يَقْرَأُ فِيهِمَا وَهُوَ جَالِسٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَرَكَعَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Umar bin Abdul Wahid] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] berkata; telah menceritakan kepadaku ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat witir satu raka'at, kemudian beliau mengerjakan shalat dua raka'at sambil membaca sedang beliau duduk, jika akan rukuk beliau bangun kemudian baru rukuk. \" "},"1154":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ وَسُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْمَا كُنْتُ أُلْفِي أَوْ أَلْقَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ آخِرِ اللَّيْلِ إِلَّا وَهُوَ نَائِمٌ عِنْدِيقَالَ وَكِيعٌ تَعْنِي بَعْدَ الْوِتْرِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Mis'ar] dan [Sufyan] dari [Sa'd bin Ibrahim] dari [Abu Salamah bin 'Abdurrahman] dari ['Aisyah] ia berkata, \"Aku tidak pernah mendapati Nabi shallallahu 'alaihi wasallam di akhir malam kecuali dalam keadaan tidur. \" Waki' berkata, \"Yakni setelah shalat witir. \""},"1155":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari ['Abdurrahman bin Ishaq] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam jika selesai melaksanakan shalat dua raka'at sebelum fajar, beliau berbaring pada sisi sebelah kanan. \""},"1156":{"ar":"حَدَّثَنَا عُمَرُ بْنُ هِشَامٍ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَنْبَأَنَا شُعْبَةُ حَدَّثَنِي سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ اضْطَجَعَ","id":"Telah menceritakan kepada kami [Umar bin Hisyam] berkata, telah menceritakan kepada kami [An Nadlr bin Syumail] berkata, telah memberitakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam selesai dari dua raka'at fajar, beliau berbaring. \""},"1157":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي بَكْرِ بْنِ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ سَعِيدِ بْنِ يَسَارٍ قَالَكُنْتُ مَعَ ابْنِ عُمَرَ فَتَخَلَّفْتُ فَأَوْ��َرْتُ فَقَالَ مَا خَلَفَكَ قُلْتُ أَوْتَرْتُ فَقَالَ أَمَا لَكَ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسْوَةٌ حَسَنَةٌ قُلْتُ بَلَى قَالَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى بَعِيرِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Malik bin Anas] dari [Abu Bakar bin Umar bin 'Abdurrahman bin Abdullah bin Umar Ibnul Khaththab] dari [Sa'id bin Yasar] ia berkata, \"Aku pernah bersama [Ibnu Umar], lalu aku mengakhirkan diri untuk shalat witir. Hingga Ibnu Umar pun bertanya, \"Kenapa kamu terakhir?\" Aku menjawab, \"Aku shalat witir. \" Ibnu Umar berkata, \"Tidakkah pada diri Rasulullah shallallahu 'alaihi wasallam terdapat teladan baik bagimu?\" Aku menjawab, \"Tentu, \" ia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah shalat witir di atas kendaraannya. \""},"1158":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْأَسْفَاطِيُّ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى رَاحِلَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yazid Al Asfathi] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami ['Abbad bin Manshur] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam pernah melaksanakan shalat witir di atas kendaraannya. \""},"1159":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ تَوْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا زَائِدَةُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي بَكْرٍ أَيَّ حِينٍ تُوتِرُ قَالَ أَوَّلَ اللَّيْلِ بَعْدَ الْعَتَمَةِ قَالَ فَأَنَتَ يَا عُمَرُ فَقَالَ آخِرَ اللَّيْلِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنْتَ يَا أَبَا بَكْرٍ فَأَخَذْتَ بِالْوُثْقَى وَأَمَّا أَنْتَ يَا عُمَرُ فَأَخَذْتَ بِالْقُوَّةِحَدَّثَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ تَوْبَةَ أَنْبَأَنَا مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا يَحْيَى بْنُ سَلِيمٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Dawud Sulaiman bin Taubah] berkata, telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata, telah menceritakan kepada kami [Za`idah] dari [Abdullah bin Muhammad bin Aqil] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abu Bakar: \"Jam berapa kamu witir?\" Abu Bakar menjawab, \"Di awal malam, selepas isya. \" Beliau bersabda: \"Kalau kamu, jam berapa Umar?\" Umar menjawab, \"Di akhir malam. \" Lalu Nabi shallallahu 'alaihi wasallam pun bersabda: \"Adapun kamu wahai Abu Bakar, engkau melakukannya dengan penuh kehati-hatian. Dan engkau wahai Umar, engkau melakukannya dengan penuh kekuatan (yakin). \" Telah menceritakan kepada kami [Abu Dawud Sulaiman bin Taubah] berkata, telah memberitakan kepada kami [Muhammad bin Abbad] berkata, telah menceritakan kepada kami [Yahya bin Salim] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda kepada Abu Bakar, lalu ia menyebutkan sebagaimana dalam hadits. \""},"1160":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزَادَ أَوْ نَقَصَ قَالَ إِبْرَاهِيمُ وَالْوَهْمُ مِنِّي فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ أَزِيدَ فِي الصَّلَاةِ شَيْءٌ قَالَ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ فَإِذَا نَسِيَ أَحَدُكُمْ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ ثُمَّ تَحَوَّلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat, lalu beliau kelebihan atau kurang dalam raka'at. Ibrahim berkata, \"Keraguan itu sumbernya dariku, \" lalu dikatakan kepada beliau, \"Wahai Rasulullah, apakah engkau menambahkan sesuatu dalam shalat?\" beliau menjawab: \"Aku hanyalah manusia seperti kalian yang terkadang lupa sebagaimana kalian lupa. Jika salah seorang dari kalian lupa, hendaklah ia sujud (sahwi) dengan dua kali sujud dalam keadaan duduk. \" Setelah Nabi shallallahu 'alaihi wasallam bergeser dan sujud dengan dua kali sujud. \""},"1161":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ هِشَامٍ حَدَّثَنِي يَحْيَى حَدَّثَنِي عِيَاضٌ أَنَّهُسَأَلَ أَبَا سَعِيدٍ الْخُدْرِيَّ فَقَالَ أَحَدُنَا يُصَلِّي فَلَا يَدْرِي كَمْ صَلَّى فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ فَلَمْ يَدْرِ كَمْ صَلَّى فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Hisyam] berkata, telah menceritakan kepadaku [Yahya] dari [Iyadl] Bahwasanya ia pernah bertanya kepada [Abu Sa'id Al Khudri], ia mengatakan, \"Salah seorang dari kami shalat tetapi tidak tahu berapa raka'at yang telah ia kerjakan?\" Abu Sa'di Al Khudri menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat dan tidak tahu berapa raka'at yang telah ia kerjakan, maka hendaklah ia sujud dua kali sedang ia dalam keadaan duduk. \""},"1162":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ خَمْسًا فَقِيلَ لَهُ أَزِيدَ فِي الصَّلَاةِ قَالَ وَمَا ذَاكَ فَقِيلَ لَهُ فَثَنَى رِجْلَهُ فَسَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Abu Bakr bin Khallad] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata, telah menceritakan kepadaku [Al Hakam] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat zhuhur lima raka'at, lalu katakan kepada beliau, \"Apa shalatnya ditambah?\" beliau bertanya: \"Apakah itu benar?\" lalu dikatakan kepada beliau, kemudian beliau menekuk kakinya dan sujud dua kali. \""},"1163":{"ar":"حَدَّثَنَا عُثْمَانُ وَأَبُو بَكْرٍ ابْنَا أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالُوا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ الْأَعْرَجِ عَنْ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةً أَظُنُّ أَنَّهَا الظُّهْرُ فَلَمَّا كَانَ فِي الثَّانِيَةِ قَامَ قَبْلَ أَنْ يَجْلِسَ فَلَمَّا كَانَ قَبْلَ أَنْ يُسَلِّمَ سَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Utsman] dan [Abu Bakr] -keduanya anak Abu Syaibah- dan [Hisyam bin Ammar] mereka berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Al A'raj] dari [Ibnu Buhainah] berkata, \"Nabi shallallahu 'alaihi wasallam mengerjakan suatu shalat, aku mengira bahwa itu adalah shalat zhuhur, maka ketika sampai raka'at kedua beliau langsung berdiri tanpa duduk tasyahud. Kemudian sebelum salam beliau sujud (sahwi) dengan dua kali sujud. \""},"1164":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ وَابْنُ فُضَيْلٍ وَيَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ وَيَزِيدُ بْنُ هَارُونَ وَأَبُو مُعَاوِيَةَ كُلُّهُمْ لَهُمْ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ أَنَّ ابْنَ بُحَيْنَةَ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي ثِنْتَيْنِ مِنْ الظُّهْرِ نَسِيَ الْجُلُوسَ حَتَّى إِذَا فَرَغَ مِنْ صَلَاتِهِ إِلَّا أَنْ يُسَلِّمَ سَجَدَ سَجْدَتَيْ السَّهْوِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ibnu Numair] dan [Ibnu Fudlail] dan [Yazid bin Harun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dan [Yazid bin Harun] dan [Abu Mu'awiyah] semuanya dari [Yahya bin Sa'id] dari ['Abdurrahman Al A'raj] bahwa [Ibnu Buhainah] mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam ketika shalat zhuhur beliau berdiri pada raka'at kedua karena lupa duduk, selesai shalat dan akan salam beliau sujud sahwi dua kali, kemudian salam. \""},"1165":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ جَابِرٍ عَنْ الْمُغِيرَةِ بْنِ شُبَيْلٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ مِنْ الرَّكْعَتَيْنِ فَلَمْ يَسْتَتِمَّ قَائِمًا فَلْيَجْلِسْ فَإِذَا اسْتَتَمَّ قَائِمًا فَلَا يَجْلِسْ وَيَسْجُدْ سَجْدَتَيْ السَّهْوِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Sufyan] dari [Jabir] dari [Al Mughirah bin Syumail] dari [Qais bin Abu Hazim] dari [Al Mughirah bin Syu'bah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berdiri pada raka'at kedua namun belum sempurna dalam berdirinya, hendaklah ia duduk. Namun jika telah tegak berdiri janganlah duduk, hendaklah ia sujud sahwi dengan dua kali sujud. \""},"1166":{"ar":"حَدَّثَنَا أَبُو يُوسُفَ الرَّقِّيُّ مُحَمَّدُ بْنُ أَحْمَدَ الصَّيْدَلَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مَكْحُولٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا شَكَّ أَحَدُكُمْ فِي الثِّنْتَيْنِ وَالْوَاحِدَةِ فَلْيَجْعَلْهَا وَاحِدَةً وَإِذَا شَكَّ فِي الثِّنْتَيْنِ وَالثَّلَاثِ فَلْيَجْعَلْهَا ثِنْتَيْنِ وَإِذَا شَكَّ فِي الثَّلَاثِ وَالْأَرْبَعِ فَلْيَجْعَلْهَا ثَلَاثًا ثُمَّ لِيُتِمَّ مَا بَقِيَ مِنْ صَلَاتِهِ حَتَّى يَكُونَ الْوَهْمُ فِي الزِّيَادَةِ ثُمَّ يَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ","id":"Telah menceritakan kepada kami [Abu Yusuf Ar Raqqi Muhammad bin Ahmad Ash Shaidalani] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Makhul] dari [Kuraib] dari [Ibnu Abbas] dari ['Abdurrahman bin Auf] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ragu antara dua raka'at atau satu, hendaklah ia jadikan satu raka'at. Jika ragu antara dua raka'at atau tiga, hendaklah ia jadikan dua. Jika ragu antara tiga atau empat, hendaklah ia jadikan tiga. Setelah itu hendaklah ia menyempurnakan kekurangannya, hingga keraguan itu bertumpu pada sesuatu yang lebih. Kemudian sujud sahwi dua kali dalam keadaan duduk sebelum salam. \""},"1167":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيُلْغِ الشَّكَّ وَلْيَبْنِ عَلَى الْيَقِينِ فَإِذَا اسْتَيْقَنَ التَّمَامَ سَجَدَ سَجْدَتَيْنِ فَإِنْ كَانَتْ صَلَاتُهُ تَامَّةً كَانَتْ الرَّكْعَةُ نَافِلَةً وَإِنْ كَانَتْ نَاقِصَةً كَانَتْ الرَّكْعَةُ لِتَمَامِ صَلَاتِهِ وَكَانَتْ السَّجْدَتَانِ رَغْمَ أَنْفِ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian merasa ragu dalam shalat hendaklah ia hilangkan keraguannya dan kembali pada keyakinan. Jika ia yakin telah sempurna hendaklah sujud sahwi dua kali, jika shalatnya ternyata telah sempurna maka tambahan raka'at itu sebagai nafilah. Namun, jika raka'at shalatnya kurang, maka tambahan itu sebagai penyempurnanya. Dan dua sujud (sahwi) itu akan membuat setan benci. \""},"1168":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ شُعْبَةُ كَتَبَ إِلَيَّ وَقَرَأْتُهُ عَلَيْهِ قَالَ أَخْبَرَنِي إِبْرَاهِيمُ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً لَا نَدْرِي أَزَادَ أَوْ نَقَصَ فَسَأَلَ فَحَدَّثْنَاهُ فَثَنَى رِجْلَهُ وَاسْتَقْبَلَ الْقِبْلَةَ وَسَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ لَوْ حَدَثَ فِي الصَّلَاةِ شَيْءٌ لَأَنْبَأْتُكُمُوهُ وَإِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ فَإِذَا نَسِيتُ فَذَكِّرُونِي وَأَيُّكُمْ مَا شَكَّ فِي الصَّلَاةِ فَلْيَتَحَرَّ أَقْرَبَ ذَلِكَ مِنْ الصَّوَابِ فَيُتِمَّ عَلَيْهِ وَيُسَلِّمَ وَيَسْجُدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Manshur] -Syu'bah berkata; ia menuliskan untukku, lalu aku membacakan di hadapannya- telah mengabarkan kepadaku [Ibrahim] dari [Alqamah] dari [Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat, namun beliau tidak mengetahui apakah jumlah raka'atnya lebih atau tidak, hingga beliau bertanya kami dan kami pun memberitahukannya kepada beliau. Beliau kemudian menekuk kakinya dan menghadap kiblat, lalu sujud dua kali dan salam. Setelah itu beliau menghadap ke arah kami dengan wajahnya dan bersabda: \"Jika terjadi sesuatu dalam shalat pasti aku beritahukan pada kalian, aku hanyalah manusia biasa yang kadang lupa sebagaimana kalian lupa. Maka, jika aku lupa hendaklah kalian ingatkan. Siapa saja dari kalian merasa ragu dalam shalat hendaklah memilih yang paling dekat dengan kebenaran, lalu menyempurnakan, kemudian salam dan sujud dua kali. \" "},"1169":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَكَّ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَتَحَرَّ الصَّوَابَ ثُمَّ يَسْجُدْ سَجْدَتَيْنِقَالَ الطَّنَافِسِيُّ هَذَا الْأَصْلُ وَلَا يَقْدِرُ أَحَدٌ يَرُدُّهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian merasa ragu dalam shalat, hendaklah memilih yang paling benar kemudian sujud dua kali. \" Ath Thanafisi berkata, \"Ini adalah dasar dan tidak ada seorang pun yang menolaknya. \""},"1170":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو كُرَيْبٍ وَأَحْمَدُ بْنُ سِنَانٍ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهَا فَسَلَّمَ فِي الرَّكْعَتَيْنِ فَقَالَ لَهُ رَجُلٌ يُقَالُ لَهُ ذُو الْيَدَيْنِ يَا رَسُولَ اللَّهِ أَقَصُرَتْ أَمْ نَسِيتَ قَالَ مَا قَصُرَتْ وَمَا نَسِيتُ قَالَ إِذًا فَصَلَّيْتَ رَكْعَتَيْنِ قَالَ أَكَمَا يَقُولُ ذُو الْيَدَيْنِ قَالُوا نَعَمْ فَتَقَدَّمَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Kuraib] dan [Ahmad bin Sinan] mereka berkata; telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam lupa hingga beliau salam pada raka'at kedua. Lalu seorang laki-laki yang bernama Dzul Yadain berkata kepada beliau, \"Wahai Rasulullah, apakah shalatnya diringkas atau memang engkau lupa?\" Beliau menjawab: \"Shalatnya tidak diringkas dan aku juga tidak lupa. \" Ia berkata kembali, \"Tetapi kenapa engkau shalat dua raka'at? beliau bersabda: \"Benarkah yang dikatakan Dzul Yadain?\" Para sahabat menjawab, \"Ya. \" Beliau kemudian maju dan shalat dua raka'at dan salam, setelah itu sujud sahwi. \" "},"1171":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ ابْنِ عَوْنٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى صَلَاتَيْ الْعَشِيِّ رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ قَامَ إِلَى خَشَبَةٍ كَانَتْ فِي الْمَسْجِدِ يَسْتَنِدُ إِلَيْهَا فَخَرَجَ سَرَعَانُ النَّاسِ يَقُولُونَ قَصُرَتْ الصَّلَاةُ وَفِي الْقَوْمِ أَبُو بَكْرٍ وَعُمَرُ فَهَابَاهُ أَنْ يَقُولَا لَهُ شَيْئًا وَفِي الْقَوْمِ رَجُلٌ طَوِيلُ الْيَدَيْنِ يُسَمَّى ذَا الْيَدَيْنِ فَقَالَ يَا رَسُولَ اللَّهِ أَقَصُرَتْ الصَّلَاةُ أَمْ نَسِيتَ فَقَالَ لَمْ تَقْصُرْ وَلَمْ أَنْسَ قَالَ فَإِنَّمَا صَلَّيْتَ رَكْعَتَيْنِ فَقَالَ أَكَمَا يَقُولُ ذُو الْيَدَيْنِ فَقَالُوا نَعَمْ فَقَامَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Ibnu Aun] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata, \"Pernah bersama kami Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat salah satu shalat yang dilakukan di malam hari (antara maghrib dan isya) dua raka'at lalu salam. Kemudian beliau berdiri menghampiri sebuah kayu yang ada di masjid dan bersandar kepadanya. Orang-orang bergegas keluar seraya berkata, \"Shalatnya telah diringkas! \" sementara di antara orang-orang itu ada Abu Bakar dan Umar. Dan keduanya tidak mungkin menyampaikan hal itu kepada beliau (karena keduanya sangat menghormati beliau). Di antara orang-orang itu juga ada seorang laki-laki yang keduanya tangannya panjang, hingga ia disebut Dzul Yadaini (orang yang kedua tangannya panjang), ia berkata, \"Wahai Rasulullah, apakah shalatnya diringkas atau memang engkau lupa?\" Beliau menjawab: \"Shalatnya tidak diringkas dan aku juga tidak lupa. \" Dzul Yadaini berkata, \"Tetapi engkau shalat dua raka'at! \" beliau bertanya: \"Apakah benar yang dikatakan oleh Dzul Yadaini?\" para sahabat menjawab, \"Ya, \" maka beliau pun berdiri dan shalat dua raka'at, kemudian salam dan sujud dua kali, setelah itu beliau kembali salam. \""},"1172":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَأَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثِ رَكَعَاتٍ مِنْ الْعَصْرِ ثُمَّ قَامَ فَدَخَلَ الْحُجْرَةَ فَقَامَ الْخِرْبَاقُ رَجُلٌ بَسِيطُ الْيَدَيْنِ فَنَادَى يَا رَسُولَ اللَّهِ أَقَصُرَتْ الصَّلَاةُ فَخَرَجَ مُغْضَبًا يَجُرُّ إِزَارَهُ فَسَأَلَ فَأُخْبِرَ فَصَلَّى تِلْكَ الرَّكْعَةَ الَّتِي كَانَ تَرَكَ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] dan [Ahmad bin Tsabit Al Jahdari] berkata, telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Muhallab] dari [Imran Ibnul Hushain] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah salam pada raka'at ketiga dalam shalat ashar, lalu beliau berdiri dan masuk kamar. Maka berdirilah Al Khirbaq, seorang laki-laki yang tangannya pendek, ia berkata, \"Wahai Rasulullah, apakah shalatnya diringkas?\" beliau pun keluar dan marah sambil menjinjing kain sarungnya, beliau bertanya tentang hal itu hingga beliau diberitahu tentang hal itu. Kemudian beliau melaksanakan raka'at yang tertinggal lalu salam, kemudian beliau sujud dua kali dan salam kembali. \""},"1173":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا يُونُسُ بْنُ بَكِيرٍ حَدَّثَنَا ابْنُ إِسْحَقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الشَّيْطَانَ يَأْتِي أَحَدَكُمْ فِي صَلَاتِهِ فَيَدْخُلُ بَيْنَهُ وَبَيْنَ نَفْسِهِ حَتَّى لَا يَدْرِيَ زَادَ أَوْ نَقَصَ فَإِذَا كَانَ ذَلِكَ فَلْيَسْجُدْ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَ ثُمَّ يُسَلِّمْ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Yunus bin Bukair] berkata, telah menceritakan kepada kami [Ibnu Ishaq] berkata, telah menceritakan kepadaku [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setan datang pada salah seorang kalian di saat shalat, lalu setan masuk dan mengganggu shalatnya hingga ia tidak tahu apakah raka'atnya lebih atau kurang. Jika sudah begitu hendaklah ia sujud dua kali sebelum salam, kemudian salam. \""},"1174":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا يُونُسُ بْنُ بَكِيرٍ حَدَّثَنَا ابْنُ إِسْحَقَ أَخْبَرَنِي سَلَمَةُ بْنُ صَفْوَانَ بْنِ سَلَمَةَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الشَّيْطَانَ يَدْخُلُ بَيْنَ ابْنِ آدَمَ وَبَيْنَ نَفْسِهِ فَلَا يَدْرِي كَمْ صَلَّى فَإِذَا وَجَدَ ذَلِكَ فَلْيَسْجُدْ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Yunus bin Bukair] berkata, telah menceritakan kepada kami [Ibnu Ishaq] berkata, telah mengabarkan kepadaku [Salamah bin Shofwan bin Salamah] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setan masuk antara anak Adam dan hatinya, hingga tidak tahu berapa raka'at yang telah ia kerjakan. Maka jika ia mendapatkan hal seperti itu hendaklah sujud dua kali sebelum salam. \""},"1175":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَأَنَّ ابْنَ مَسْعُودٍ سَجَدَ سَجْدَتَيْ السَّهْوِ بَعْدَ السَّلَامِ وَذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Manshur] dari [Ibrahim] dari [Alqamah] berkata, \" [Ibnu Mas'ud] pernah sujud sahwi dengan dua kali sujud setelah salam, lalu ia menyebutkan bahwa Nabi shallallahu 'alaihi wasallam melakukan seperti itu. \""},"1176":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ زُهَيْرِ بْنِ سَالِمٍ الْعَنْسِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ ثَوْبَانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي كُلِّ سَهْوٍ سَجْدَتَانِ بَعْدَ مَا يُسَلِّمُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Utsman bin Abu Syaibah] keduanya berkata; telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Ubaidullah bin Ubaid] dari [Zuhair bin Salim Al 'Ansi] dari ['Abdurrahman bin Jubair bin Nufair] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sujud sahwi itu sujud dua kali setelah salam. \""},"1177":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُوسَى التَّيْمِيُّ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ مَوْلَى الْأَسْوَدِ بْنِ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ وَكَبَّرَ ثُمَّ أَشَارَ إِلَيْهِمْ فَمَكَثُوا ثُمَّ انْطَلَقَ فَاغْتَسَلَ وَكَانَ رَأْسُهُ يَقْطُرُ مَاءً فَصَلَّى بِهِمْ فَلَمَّا انْصَرَفَ قَالَ إِنِّي خَرَجْتُ إِلَيْكُمْ جُنُبًا وَإِنِّي نَسِيتُ حَتَّى قُمْتُ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdullah bin Musa At Taimi] dari [Usamah bin Zaid] dari [Abdullah bin Yazid] mantan budak Al Aswad bin Sufyan, dari [Muhammad bin 'Abdurrahman bin Tsauban] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam keluar shalat dan takbir, namun beliau memberi isyarat kepada para sahabat agar mereka diam di tempat. Kemudian beliau pergi dan mandi, beliau shalat bersama mereka sementara rambutnya masih basah dengan air. Setelah selesai shalat beliau bersabda: \"Aku keluar kepada kalian dalam keadaan junub, namun aku lupa hingga shalat didirikan. \""},"1178":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْهَيْثَمُ بْنُ خَارِجَةَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَصَابَهُ قَيْءٌ أَوْ رُعَافٌ أَوْ قَلَسٌ أَوْ مَذْيٌ فَلْيَنْصَرِفْ فَلْيَتَوَضَّأْ ثُمَّ لِيَبْنِ عَلَى صَلَاتِهِ وَهُوَ فِي ذَلِكَ لَا يَتَكَلَّمُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Haitsam bin Kharijah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa terkena muntah, atau mimisan, atau muntahan atau madzi, hendaknya ia pergi berwudlu. Kemudian tetap melaksanakan shalat dalam kondisi seperti itu, dan tidak berbicara. \" "},"1179":{"ar":"حَدَّثَنَا عُمَرُ بْنُ شَبَّةَ بْنِ عَبِيدَةَ بْنِ زَيْدٍ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ الْمُقَدَّمِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَأَحْدَثَ فَلْيُمْسِكْ عَلَى أَنْفِهِ ثُمَّ لِيَنْصَرِفْحَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا عُمَرُ بْنُ قَيْسٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Umar bin Syabbah bin 'Abidah bin Zaid] berkata, telah menceritakan kepada kami [Umar bin 'Ali Al Muqaddami] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian shalat kemudian berhadats, maka hendaklah ia pegang hidungnya dan pergi. \" Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah menceritakan kepada kami [Umar bin Qais] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \" "},"1180":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ ابْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَكَانَ بِيَ النَّاصُورُ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ فَقَالَ صَلِّ قَائِمًا فَإِنْ لَمْ تَسْتَطِعْ فَقَاعِدًا فَإِنْ لَمْ تَسْتَطِعْ فَعَلَى جَنْبٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibrahim bin Thahman] dari [Husain Al Mu'allim] dari [Ibnu Buraidah] dari [Imran bin Hushain] berkata, \"Aku mengalami sakit wasir, maka aku bertanya kepada Nabi shallallahu 'alaihi wasallam tentang pelaksanaan shalat, beliau bersabda: \"Shalatlah dengan berdiri, jika tidak mampu hendaklah dengan duduk, jika tidak mampu hendaklah dengan berbaring. \""},"1181":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ بَيَانٍ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ عَنْ سُفْيَانَ عَنْ جَابِرٍ عَنْ أَبِي حَرِيزٍ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى جَالِسًا عَلَى يَمِينِهِ وَهُوَ وَجِعٌ","id":"Telah menceritakan kepada kami [Abdul Hamid bin Bayan Al Wasithi] berkata, telah menceritakan kepada kami [Ishaq Al Azraq] dari [Sufyan] dari [Jabir] dari [Abu Hariz] dari [Wa`il bin Hujr] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam shalat sambil duduk pada bagian sebelah kanan ketika sakit. \" "},"1182":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْوَالَّذِي ذَهَبَ بِنَفْسِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَاتَ حَتَّى كَانَ أَكْثَرُ صَلَاتِهِ وَهُوَ جَالِسٌ وَكَانَ أَحَبُّ الْأَعْمَالِ إِلَيْهِ الْعَمَلَ الصَّالِحَ الَّذِي يَدُومُ عَلَيْهِ الْعَبْدُ وَإِنْ كَانَ يَسِيرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Abu Salamah] dari [Ummu Salamah] ia berkata, \"Demi Dzat yang mencabut jiwa shallallahu 'alaihi wasallam, beliau tidak meninggal hingga kebanyakan shalat yang beliau lakukan adalah dengan duduk, dan amalan yang paling beliau sukai adalah amal shalih yang dikerjakan secara rutin oleh seorang hamba meskipun sepele. \""},"1183":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ الْوَلِيدِ بْنِ أَبِي هِشَامٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَهُوَ قَاعِدٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ قَدْرَ مَا يَقْرَأُ إِنْسَانٌ أَرْبَعِينَ آيَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Al Walid bin Abu Hisyam] dari [Abu Bakr bin Muhammad] dari [Amrah] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam membaca dalam kondisi duduk, maka ketika akan rukuk beliau berdiri sekadar orang membaca empat puluh ayat. \""},"1184":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي شَيْءٍ مِنْ صَلَاةِ اللَّيْلِ إِلَّا قَائِمًا حَتَّى دَخَلَ فِي السِّنِّ فَجَعَلَ يُصَلِّي جَالِسًا حَتَّى إِذَا بَقِيَ عَلَيْهِ مِنْ قِرَاءَتِهِ أَرْبَعُونَ آيَةً أَوْ ثَلَاثُونَ آيَةً قَامَ فَقَرَأَهَا وَسَجَدَ","id":"Telah menceritakan kepada kami [Abu Marwan Al Utsmani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat di malam hari kecuali dengan berdiri, hingga ketika telah tua beliau shalat dengan duduk. Maka ketika bacaan beliau masih tersisa antara empat puluh atau tiga puluh ayat, beliau berdiri dan membacanya dengan berdiri lalu sujud. \""},"1185":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ حُمَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ الْعُقَيْلِيِّ قَالَسَأَلْتُ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَقَالَتْ كَانَ يُصَلِّي لَيْلًا طَوِيلًا قَائِمًا وَلَيْلًا طَوِيلًا قَاعِدًا فَإِذَا قَرَأَ قَائِمًا رَكَعَ قَائِمًا وَإِذَا قَرَأَ قَاعِدًا رَكَعَ قَاعِدًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Humaid] dari [Abdullah bin Syaqiq Al Uqaili] berkata; Aku bertanya kepada ['Aisyah] tentang shalatnya Rasulullah shallallahu 'alaihi wasallam di waktu malam, maka ia pun menjawab, \"Beliau kadang shalat malam yang panjang dengan berdiri, dan kadang shalat malam yang panjang dengan duduk. Jika beliau membaca dengan berdiri maka beliau rukuk dengan berdiri, dan jika beliau membaca dengan duduk maka beliau rukuk dengan duduk. \""},"1186":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا قُطْبَةُ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَاهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يُصَلِّي جَالِسًا فَقَالَ صَلَاةُ الْجَالِسِ عَلَى النِّصْفِ مِنْ صَلَاةِ الْقَائِمِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Adam] berkata, telah menceritakan kepada kami [Quthbah] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Abdullah bin Babah] dari [Abdullah bin Amru] bahwa Nabi shallallahu 'alaihi wasallam pernah melewatinya, sedangkan waktu itu ia shalat dengan duduk. Maka beliau bersabda: \"Shalat dengan duduk pahalanya separuh dari orang yang shalat dengan berdiri. \""},"1187":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ حَدَّثَنِي إِسْمَعِيلُ بْنُ مُحَمَّدِ بْنِ سَعْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَرَأَى أُنَاسًا يُصَلُّونَ قُعُودًا فَقَالَ صَلَاةُ الْقَاعِدِ عَلَى النِّصْفِ مِنْ صَلَاةِ الْقَائِمِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Bisyr bin Umar] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far] berkata, telah menceritakan kepadaku [Isma'il bin Muhammad bin Sa'd] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar dan melihat manusia shalat dengan duduk, maka beliau pun bersabda: \"Shalat dengan duduk pahalanya separuh dari orang yang shalat dengan berdiri. \""},"1188":{"ar":"حَدَّثَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّهُسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُصَلِّي قَاعِدًا قَالَ مَنْ صَلَّى قَائِمًا فَهُوَ أَفْضَلُ وَمَنْ صَلَّى قَاعِدًا فَلَهُ نِصْفُ أَجْرِ الْقَائِمِ وَمَنْ صَلَّى نَائِمًا فَلَهُ نِصْفُ أَجْرِ الْقَاعِدِ","id":"Telah menceritakan kepada kami [Bisyr bin Hilal Ash Shawwaf] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] dari [Husain Al Mu'allim] dari [Abdullah bin Buraid] dari [Imran bin Hushain] Bahwasanya ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang seorang laki-laki yang shalat dengan duduk, beliau bersabda: \"Barangsiapa shalat dengan berdiri maka itu lebih utama, dan barangsiapa shalat dengan duduk maka ia akan mendapatkan setengah dari pahala orang yang shalat dengan berdiri. Dan barangsiapa shalat dengan berbaring maka ia akan mendapatkan setengah dari pahala orang yang shalat dengan duduk. \""},"1189":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَمَّا مَرِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَضَهُ الَّذِي مَاتَ فِيهِ وَقَالَ أَبُو مُعَاوِيَةَ لَمَّا ثَقُلَ جَاءَ بِلَالٌ يُؤْذِنُهُ بِالصَّلَاةِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّ أَبَا بَكْرٍ رَجُلٌ أَسِيفٌ تَعْنِي رَقِيقٌ وَمَتَى مَا يَقُومُ مَقَامَكَ يَبْكِي فَلَا يَسْتَطِيعُ فَلَوْ أَمَرْتَ عُمَرَ فَصَلَّى بِالنَّاسِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَإِنَّكُنَّ صَوَاحِبَاتُ يُوسُفَ قَالَتْ فَأَرْسَلْنَا إِلَى أَبِي بَكْرٍ فَصَلَّى بِالنَّاسِ فَوَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَفْسِهِ خِفَّةً فَخَرَجَ إِلَى الصَّلَاةِ يُهَادَى بَيْنَ رَجُلَيْنِ وَرِجْلَاهُ تَخُطَّانِ فِي الْأَرْضِ فَلَمَّا أَحَسَّ بِهِ أَبُ�� بَكْرٍ ذَهَبَ لِيَتَأَخَّرَ فَأَوْمَى إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَكَانَكَ قَالَ فَجَاءَ حَتَّى أَجْلَسَاهُ إِلَى جَنْبِ أَبِي بَكْرٍ فَكَانَ أَبُو بَكْرٍ يَأْتَمُّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يَأْتَمُّونَ بِأَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy]. (dalam jalur lain disebutkan); Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sakit yang membawanya kepada kematian, Abu Mu'awiyah berkata, \"Ketika sakit beliau semakin parah, Bilal datang kepada beliau memberitahukan datangnya waktu shalat, maka beliau bersabda: \"Suruhlah Abu Bakar, dan perintahkan kepadanya agar shalat bersama orang-orang. \" Kami berkata, \"Wahai Rasulullah, Abu Bakar itu seorang laki-laki yang hatinya sangat lembut, jika ia menggantikanmu maka ia pasti menangis, bagaimana jika Umar saja yang engkau perintahkan untuk shalat bersama orang-orang?\" beliau bersabda: \"Suruhlah Abu Bakar, dan perintahkan kepadanya agar shalat bersama orang-orang. Sesungguhnya kalian (isteri-isteri nabi) seperti sahabat Yusuf, \" 'Aisyah berkata, \"Lalu kami mengutus seseorang kepada Abu Bakar hingga ia pun shalat bersama manusia. Rasulullah shallallahu 'alaihi wasallam kemudian mendapatkan sedikit kesegaran pada tubuhnya, beliau keluar untuk shalat dengan dipapah oleh dua orang, sementara kedua kaki beliau berjalan di atas tanah. Ketika Abu bakar merasakan kehadiran beliau, maka ia berniat mundur ke belakang. Namun Nabi shallallahu 'alaihi wasallam memberi isyarat agar ia tetap shalat pada tempatnya. \" Abu Mu'awiyah berkata, \"Beliau pun datang, dan beliau didudukkan di sisi Abu Bakar. Abu Bakar bermakmum kepada Nabi shallallahu 'alaihi wasallam, sementara orang-orang bermakmum kepada Abu Bakar. \""},"1190":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ فِي مَرَضِهِ فَكَانَ يُصَلِّي بِهِمْ فَوَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِفَّةً فَخَرَجَ وَإِذَا أَبُو بَكْرٍ يَؤُمُّ النَّاسَ فَلَمَّا رَآهُ أَبُو بَكْرٍ اسْتَأْخَرَ فَأَشَارَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ كَمَا أَنْتَ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِذَاءَ أَبِي بَكْرٍ إِلَى جَنْبِهِ فَكَانَ أَبُو بَكْرٍ يُصَلِّي بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Di saat sakitnya, Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Bakar untuk shalat bersama manusia. Abu Bakar pun shalat bersama mereka, ketika Rasulullah shallallahu 'alaihi wasallam mendapatkan kekuatan pada tubuhnya beliau keluar untuk shalat, sementara Abu Bakar sedang mengimami manusia. Maka tatkala Abu Bakar melihat kehadiran beliau, ia berniat mundur ke belakang, namun Rasulullah shallallahu 'alaihi wasallam memberi isyarat agar ia tetap di tempatnya. Rasulullah shallallahu 'alaihi wasallam kemudian duduk di sisi Abu Bakar, Abu Bakar mengikuti shalat Rasulullah shallallahu 'alaihi wasallam sementara orang-orang mengikuti shalat Abu Bakar. \""},"1191":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ مِنْ كِتَابِهِ فِي بَيْتِهِ قَالَ سَلَمَةُ بْنُ نُبَيْطٍ أَنْبَأَنَا عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ عَنْ نُبَيْطِ بْنِ شَرِيطٍ عَنْ سَالِمِ بْنِ عُبَيْدٍ قَالَأُغْمِيَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ ثُمَّ أَفَاقَ فَقَالَ أَحَضَرَتْ الصَّلَاةُ قَالُوا نَعَمْ قَالَ مُرُوا بِلَالًا فَلْيُؤَذِّنْ وَمُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ ثُمَّ أُغْمِيَ عَلَيْهِ فَأَفَاقَ فَقَالَ أَحَضَرَتْ الصَّلَاةُ قَالُوا نَعَمْ قَالَ مُرُوا بِلَالًا فَلْيُؤَذِّنْ وَمُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ ثُمَّ أُغْمِيَ عَلَيْهِ فَأَفَاقَ فَقَالَ أَحَضَرَتْ الصَّلَاةُ قَالُوا نَعَمْ قَالَ مُرُوا بِلَالًا فَلْيُؤَذِّنْ وَمُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَقَالَتْ عَائِشَةُ إِنَّ أَبِي رَجُلٌ أَسِيفٌ إِذَا قَامَ ذَلِكَ الْمَقَامَ يَبْكِي لَا يَسْتَطِيعُ فَلَوْ أَمَرْتَ غَيْرَهُ ثُمَّ أُغْمِيَ عَلَيْهِ فَأَفَاقَ فَقَالَ مُرُوا بِلَالًا فَلْيُؤَذِّنْ وَمُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَإِنَّكُنَّ صَوَاحِبُ يُوسُفَ أَوْ صَوَاحِبَاتُ يُوسُفَ قَالَ فَأُمِرَ بِلَالٌ فَأَذَّنَ وَأُمِرَ أَبُو بَكْرٍ فَصَلَّى بِالنَّاسِ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ خِفَّةً فَقَالَ انْظُرُوا لِي مَنْ أَتَّكِئُ عَلَيْهِ فَجَاءَتْ بَرِيرَةُ وَرَجُلٌ آخَرُ فَاتَّكَأَ عَلَيْهِمَا فَلَمَّا رَآهُ أَبُو بَكْرٍ ذَهَبَ لِيَنْكِصَ فَأَوْمَأَ إِلَيْهِ أَنْ اثْبُتْ مَكَانَكَ ثُمَّ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جَلَسَ إِلَى جَنْبِ أَبِي بَكْرٍ حَتَّى قَضَى أَبُو بَكْرٍ صَلَاتَهُ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُبِضَقَالَ أَبُو عَبْد اللَّهِ هَذَا حَدِيثٌ غَرِيبٌ لَمْ يُحَدِّثْ بِهِ غَيْرُ نَصْرِ بْنِ عَلِيٍّ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah memberitakan kepada kami [Abdullah bin Dawud] -dalam kitabnya yang ada di rumahnya- berkata, telah memberitakan kepada kami [Salamah bin Nubaith] dari [Nu'aim bin Abu Hindun] dari [Nubaith bin Syarith] dari [Salim bin Ubaid] ia berkata, \"Di saat sakit Rasulullah shallallahu 'alaihi wasallam pingsan kemudian tersadar, beliau bertanya: \"Apakah waktu shalat sudah masuk?\" Para sahabat menjawab, \"Sudah, \" beliau bersabda: \"Perintahkanlah Bilal mengumandangkan adzan, dan perintahkan Abu Bakar agar mengimami orang-orang. \" Kemudian beliau pingsan dan sadar kembali, beliau lalu bertanya: \"Apakah waktu shalat sudah masuk?\" para sahabat menjawab: \"Sudah, \" beliau bersabda: \"Perintahkanlah Bilal mengumandangkan adzan, dan perintahkan Abu Bakar agar mengimami orang-orang. \" Kemudian beliau pingsan dan sadar kembali, beliau lalu bertanya: \"Apakah waktu shalat sudah masuk?\" para sahabat menjawab: \"Sudah, \" beliau bersabda: \"Perintahkanlah Bilal mengumandangkan adzan, dan perintahkan Abu Bakar agar mengimami orang-orang. \" 'Aisyah lalu berkata, \"Sesungguhnya ayahku adalah seorang lelaki yang lembut hatinya, jika dia menempati kedudukan itu, dia akan menangis dan tidak mampu (membaca), cobalah engkau perintahkan yang lain\". Kemudian beliau pingsan dan tersadar, beliau bersabda: \"Perintahkanlah Bilal mengumandangkan adzan, dan perintahkan Abu Bakar untuk mengimami orang-orang. Sesungguhnya kalian adalah sahabat-sahabat Yusuf atau sahabat-sahabat perempuan Yusuf. \" Salim bin Ubaid berkata, \"Bilal pun diperintahkan hingga ia adzan, dan Abu Bakar juga diperintahkan hingga ia pun mengimami orang-orang. Setelah itu Rasulullah shallallahu 'alaihi wasallam merasa lebih baik, beliau bersabda: \"Lihatlah aku, siapa yang bisa aku jadikan sebagai sandaran?\" Lalu datanglah Barirah dan seorang laki-laki lain, kemudian beliau bersandar kepada keduanya. Tatkala Abu Bakar melihatnya, dia bergeser ke belakang, tetapi beliau memberi isyarat kepadanya; tetaplah di tempatmu. \" Kemudian Rasulullah shallallahu 'alaihi wasallam datang dan duduk di samping Abu Bakar, hingga Abu Bakar menyelesaikan shalatnya. Setelah itu Rasulullah shallallahu 'alaihi wasallam wafat. \" Abu Abdullah berkata: \"Hadits ini gharib, dan tidak ada yang meriwayatkannya selain Nasr bin Ali. \""},"1192":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْأَرْقَمِ بْنِ شُرَحْبِيلَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا مَرِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَضَهُ الَّذِي مَاتَ فِيهِ كَانَ فِي بَيْتِ عَائِشَةَ فَقَالَ ادْعُوا لِي عَلِيًّا قَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ نَدْعُو لَكَ أَبَا بَكْرٍ قَالَ ادْعُوهُ قَالَتْ حَفْصَةُ يَا رَسُولَ اللَّهِ نَدْعُو لَكَ عُمَرَ قَالَ ادْعُوهُ قَالَتْ أُمُّ الْفَضْلِ يَا رَسُولَ اللَّهِ نَدْعُو لَكَ الْعَبَّاسَ قَالَ نَعَمْ فَلَمَّا اجْتَمَعُوا رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ فَنَظَرَ فَسَكَتَ فَقَالَ عُمَرُ قُومُوا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَ بِلَالٌ يُؤْذِنُهُ بِالصَّلَاةِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَقَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا بَكْرٍ رَجُلٌ رَقِيقٌ حَصِرٌ وَمَتَى لَا يَرَاكَ يَبْكِي وَالنَّاسُ يَبْكُونَ فَلَوْ أَمَرْتَ عُمَرَ يُصَلِّي بِالنَّاسِ فَخَرَجَ أَبُو بَكْرٍ فَصَلَّى بِالنَّاسِ فَوَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفْسِهِ خِفَّةً فَخَرَجَ يُهَادَى بَيْنَ رَجُلَيْنِ وَرِجْلَاهُ تَخُطَّانِ فِي الْأَرْضِ فَلَمَّا رَآهُ النَّاسُ سَبَّحُوا بِأَبِي بَكْرٍ فَذَهَبَ لِيَسْتَأْخِرَ فَأَوْمَأَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ مَكَانَكَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ عَنْ يَمِينِهِ وَقَامَ أَبُو بَكْرٍ فَكَانَ أَبُو بَكْرٍ يَأْتَمُّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يَأْتَمُّونَ بِأَبِي بَكْرٍ قَالَ ابْنُ عَبَّاسٍ وَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْقِرَاءَةِ مِنْ حَيْثُ كَانَ بَلَغَ أَبُو بَكْرٍقَالَ وَكِيعٌ وَكَذَا السُّنَّةُ قَالَ فَمَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ ذَلِكَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Abu Ishaq] dari [Al Arqam Abu Isa Syurahbil] dari [Ibnu Abbas] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sakit yang membawanya pada kematian, beliau sedang berada di rumah 'Aisyah. Beliau bersabda, \"Panggillah Ali untuk menghadapku, \" 'Aisyah berkata, \"Wahai Rasulullah, bagaimana jika kami panggilkan Abu Bakar?\" beliau menjawab: \"Panggilkan dia. \" Hafshah berkata, \"Wahai Rasulullah, bagaimana jika kami panggilkan Umar?\" \"Panggilkan dia. \" Ummu Al Fadll berkata, \"Wahai Rasulullah, bagaimana jika kami panggilkan Al Abbas?\" beliau menjawab: \"Ya. \" Maka ketika semuanya telah berkumpul, Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya. Beliau memandangi mereka lalu diam. Umar pun berkata, \"Berdirilah kalian semua untuk Rasulullah shallallahu 'alaihi wasallam. \" Kemudian Bilal datang memberitahukan Rasulullah bahwa waktu shalat telah tiba. Beliau lalu bersabda: \"Perintahkanlah Abu Bakar untuk mengimami orang-orang shalat, \" 'Aisyah berkata, \"Wahai Rasulullah, sesungguhnya Abu Bakar seorang laki-laki yang hatinya lemah dan tidak akan sanggup membaca (ayat Al Qur`an), ia selalu menangis jika melihatmu hingga orang-orang ikut menangis. Bagaimana jika Umar saja yang menjadi Imam shalat bagi orang-orang?\" Lalu Abu Bakar keluar dan shalat bersama manusia, sementara Rasulullah shallallahu 'alaihi wasallam juga mendapatkan kesegaran pada tubuhnya hingga beliau pun keluar shalat dengan dipapah oleh dua orang laki-laki, sedangkan kedua kaki beliau berjalan di atas tanah. Ketika orang-orang melihat kehadiran Rasulullah, mereka mengucapkan tasbih untuk (mengingatkan) Abu Bakar, hingga ia pun mundur ke belakang. Akan tetapi Nabi shallallahu 'alaihi wasallam justru berisyarat agar ia tetap di tempatnya. Rasulullah shallallahu 'alaihi wasallam kemudian datang dan duduk di sisi kanannya, Abu Bakar berdiri. Abu Bakar mengikuti berimam kepada Nabi shallallahu 'alaihi wasallam, dan orang-orang berimam kepada Abu Bakar. \" Ibnu Abbas berkata, \"Nabi shallallahu 'alaihi wasallam membaca ayat terakhir yang dibaca oleh Abu Bakar. \" Waki' berkata, \"Seperti inilah sunnah. \" Ibnu Abbas berkata, \"Lalu Rasulullah shallallahu 'alaihi wasallam wafat di saat sakitnya itu. \""},"1193":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ حَمْزَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِقَالَ تَخَلَّفَ رَسُ��لُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَهَيْنَا إِلَى الْقَوْمِ وَقَدْ صَلَّى بِهِمْ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ رَكْعَةً فَلَمَّا أَحَسَّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ يَتَأَخَّرُ فَأَوْمَأَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُتِمَّ الصَّلَاةَ قَالَ وَقَدْ أَحْسَنْتَ كَذَلِكَ فَافْعَلْ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Humaid] dari [Bukair bin Abdullah] dari [Hamzah Ibnul Mughirah bin Syu'bah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam datang terlambat hingga kami pun terlambat datang pada orang-orang, sementara mereka telah shalat satu raka'at bersama 'Abdurrahman bin Auf. Maka ketika 'Abdurrahman bin Auf merasakan kehadiran Nabi shallallahu 'alaihi wasallam ia mundur ke belakang, namun Nabi shallallahu 'alaihi wasallam berisyarat agar ia menyempurnakan shalatnya. Beliau bersabda: \"Engkau sudah tepat, lakukanlah seperti itu. \""},"1194":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْاشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ عَلَيْهِ نَاسٌ مِنْ أَصْحَابِهِ يَعُودُونَهُ فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا فَصَلَّوْا بِصَلَاتِهِ قِيَامًا فَأَشَارَ إِلَيْهِمْ أَنْ اجْلِسُوا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam merasakan sakit, lalu para sahabat masuk mengunjunginya. Nabi shallallahu 'alaihi wasallam shalat dengan duduk sedangkan para sahabat shalat mengikuti beliau dengan berdiri, hingga beliau pun berisyarat kepada mereka agar shalat dengan duduk. Ketika selesai beliau bersabda: \"Hanyasanya dijadikannya imam agar diikuti, jika ia rukuk maka rukuklah, jika ia mengangkat kepala maka angkatlah dan jika ia shalat dengan duduk maka shalatlah dengan duduk. \""},"1195":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُرِعَ عَنْ فَرَسٍ فَجُحِشَ شِقُّهُ الْأَيْمَنُ فَدَخَلْنَا نَعُودُهُ وَحَضَرَتْ الصَّلَاةُ فَصَلَّى بِنَا قَاعِدًا وَصَلَّيْنَا وَرَاءَهُ قُعُودًا فَلَمَّا قَضَى الصَّلَاةَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا صَلَّى قَاعِدًا فَصَلُّوا قُعُودًا أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam jatuh dari atas kuda hingga tubuh bagian kanannya terluka. Kami mengunjunginya, lalu waktu pun shalat tiba. Beliau shalat bersama kami dengan duduk, dan kami juga shalat di belakangnya dengan duduk. Beliau bersabda: \"Hanyasanya dijadikannya imam agar diikuti, jika ia takbir maka takbirlah, jika ia rukuk maka rukuklah, dan jika ia mengucapkan; SAMI'A ALLAHU LIMAN HAMIDAHU maka ucapkanlah; RABBANA LAKAL HAMDU. Jika ia sujud maka sujudlah, dan jika ia shalat dengan duduk maka shalatlah dengan duduk. \""},"1196":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمُ بْنُ بَشِيرٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِنْ صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِنْ صَلَّى قَاعِدًا فَصَلُّوا قُعُودًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim bin Basyir] dari [Umar bin Abu Salamah] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanyasanya dijadikannya imam agar diikuti, jika ia takbir maka takbirlah, jika ia rukuk maka rukuklah, dan jika ia mengucapkan; SAMI'A ALLAHU LIMAN HAMIDAHU maka ucapkanlah; RABBANA WA LAKAL HAMDU. Jika shalat dengan berdiri maka shalatlah dengan berdiri, dan jika shalat dengan duduk maka shalatlah dengan duduk. \" "},"1197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَاشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّيْنَا وَرَاءَهُ وَهُوَ قَاعِدٌ وَأَبُو بَكْرٍ يُكَبِّرُ يُسْمِعُ النَّاسَ تَكْبِيرَهُ فَالْتَفَتَ إِلَيْنَا فَرَآنَا قِيَامًا فَأَشَارَ إِلَيْنَا فَقَعَدْنَا فَصَلَّيْنَا بِصَلَاتِهِ قُعُودًا فَلَمَّا سَلَّمَ قَالَ إِنْ كِدْتُمْ أَنْ تَفْعَلُوا فِعْلَ فَارِسَ وَالرُّومِ يَقُومُونَ عَلَى مُلُوكِهِمْ وَهُمْ قُعُودٌ فَلَا تَفْعَلُوا ائْتَمُّوا بِأَئِمَّتِكُمْ إِنْ صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِنْ صَلَّى قَاعِدًا فَصَلُّوا قُعُودًا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengeluh sakit, kami pun shalat di belakangnya sementara beliau shalat dengan duduk. Kemudian Abu Bakar bertakbir dengan takbir Rasulullah agar manusia dapat mendengarnya, beliau berpaling ke arah kami hingga beliau melihat kami sedang shalat dengan berdiri, beliau lalu berisyarat (agar kami shalat dengan duduk), maka kami pun shalat dengan duduk mengikuti beliau. Selesai salam beliau bersabda: \"Janganlah kalian mengikuti perbuatan orang-orang Faris dan Rum, mereka berdiri sementara raja-raja mereka duduk. Ikutilah imam-imam kalian, jika ia shalat dengan berdiri maka shalatlah dengan berdiri, dan jika ia shalat dengan duduk maka shalatlah dengan duduk. \""},"1198":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَحَفْصُ بْنُ غِيَاثٍ وَيَزِيدُ بْنُ هَارُونَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ سَعْدِ بْنِ طَارِقٍ قَالَقُلْتُ لِأَبِي يَا أَبَتِ إِنَّكَ قَدْ صَلَّيْتَ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَعَلِيٍّ هَاهُنَا بِالْكُوفَةِ نَحْوًا مِنْ خَمْسِ سِنِينَ فَكَانُوا يَقْنُتُونَ فِي الْفَجْرِ فَقَالَ أَيْ بُنَيَّ مُحْدَثٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dan [Hafsh bin Ghiyats] dan [Yazid bin Harun] dari [Abu Malik Al Asyja'i Sa'd bin Thariq] berkata; Aku berkata kepada [bapakku], \"Wahai bapakku, engkau pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar, Utsman dan Ali di Kufah ini selama lima puluh tahun, apakah mereka melakukan qunut pada waktu shalat subuh?\" ia menjawab, \"Wahai putraku, itu adalah perkara baru. \""},"1199":{"ar":"حَدَّثَنَا حَاتِمُ بْنُ بَكْرٍ الضَّبِّيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يَعْلَى زُنْبُورٌ حَدَّثَنَا عَنْبَسَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَ قَالَتْنُهِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقُنُوتِ فِي الْفَجْرِ","id":"Telah menceritakan kepada kami [Hatim bin Bakr Adl Dlabbi] berkata, telah menceritakan kepada kami [Muhammad bin Ya'la Zunbur] berkata, telah menceritakan kepada kami ['Anbasah bin 'Abdurrahman] dari [Abdullah bin Nafi'] dari [Bapaknya] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam dilarang untuk melakukan qunut dalam shalat subuh. \" "},"1200":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْنُتُ فِي صَلَاةِ الصُّبْحِ يَدْعُو عَلَى حَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ شَهْرًا ثُمَّ تَرَكَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan qunut dalam shalat subuh mendo`akan salah satu suku arab selama sebulan, kemudian meninggalkannya. \""},"1201":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ مِنْ صَلَاةِ الصُّبْحِ قَالَ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ بِمَكَّةَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dalam shalat subuh, beliau mengucapkan: \"Ya Allah, selamatkanlah Al Walid Ibnul Walid, Salamah bin Hisyam, Ayyasy bin Abu Rabi'ah dan orang-orang lemah yang berada di Makkah. Ya Allah, keraskanlah hukuman-Mu kepada Mudlar dan jadikanlah untuk mereka paceklik sebagaimana paceklik yang terjadi di masa Yusuf. \""},"1202":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الصَّبَّاحِ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ ضَمْضَمِ بْنِ جَوْسٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْأَسْوَدَيْنِ فِي الصَّلَاةِ الْعَقْرَبِ وَالْحَيَّةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Ash Shahhab] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari [Dlamdlam bin Jaus] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuh al aswadain dalam shalat; yakni kalajengking dan ular. \""},"1203":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ الْأَوْدِيُّ وَالْعَبَّاسُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا عَلِيُّ بْنُ ثَابِتٍ الدَّهَّانُ حَدَّثَنَا الْحَكَمُ بْنُ عَبْدِ الْمَلِكِ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَائِشَةَ قَالَتْلَدَغَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقْرَبٌ وَهُوَ فِي الصَّلَاةِ فَقَالَ لَعَنَ اللَّهُ الْعَقْرَبَ مَا تَدَعُ الْمُصَلِّيَ وَغَيْرَ الْمُصَلِّي اقْتُلُوهَا فِي الْحِلِّ وَالْحَرَمِ","id":"Telah menceritakan kepada kami [Ahmad bin Utsman bin Hakim Al Audi] dan [Al Abbas bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Ali bin Tsabit Ad Dahhan] berkata, telah menceritakan kepada kami [Al Hakam bin Abdul Malik] dari [Qatadah] dari [Sa'id Ibnul Musayyab] dari ['Aisyah] ia berkata, \"Ketika dalam keadaan shalat seekor kalajengking menyengat Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Semoga Allah melaknat kalajengking, ia selalu menggigit orang yang shalat maupun yang tidak, bunuhlah mereka baik di wilayah hil (di luar wilayah haram) atau pun wilayah haram. \""},"1204":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ حَدَّثَنَا مِنْدَلٌ عَنْ ابْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتَلَ عَقْرَبًا وَهُوَ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Haitsam bin Jamil] berkata, telah menceritakan kepada kami [Mindal] dari [Ibnu Abu Rafi'] dari [Bapaknya] dari [Kakeknya] berkata, \"Nabi shallallahu 'alaihi wasallam membunuh kalajengking, padahal beliau dalam shalat. \" "},"1205":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صَلَاتَيْنِ عَنْ الصَّلَاةِ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Usamah] dari [Ubaidullah bin Umar] dari [Khubaib bin 'Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dua shalat; shalat setelah fajar hingga matahari terbit dan shalat setelah atsar hingga matahari terbenam. \""},"1206":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى التَّيْمِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Ya'la At Taimi] dari [Abdul Malik bin Umair] dari [Qaza'ah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat setelah ashar hingga matahari terbenam, dan tidak dan shalat setelah subuh hingga matahari terbit. \""},"1207":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَشَهِدَ عِنْدِي رِجَالٌ مَرْضِيُّونَ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ وَأَرْضَاهُمْ عِنْدِي عُمَرُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Qatadah] dari [Abul Aliyah] dari [Ibnu Abbas] ia berkata, \"Beberapa orang yang diridhai bersaksi di sisiku, di antara mereka ada [Umar Ibnul Khaththab], dan menurutku orang yang paling diridhai dari mereka semua adalah Umar. Mereka bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat setelah fajar hingga matahari terbit dan shalat setelah ashar hingga matahari terbenam. \""},"1208":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ يَزِيدَ بْنِ طَلْقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ هَلْ مِنْ سَاعَةٍ أَحَبُّ إِلَى اللَّهِ مِنْ أُخْرَى قَالَ نَعَمْ جَوْفُ اللَّيْلِ الْأَوْسَطُ فَصَلِّ مَا بَدَا لَكَ حَتَّى يَطْلُعَ الصُّبْحُ ثُمَّ انْتَهِ حَتَّى تَطْلُعَ الشَّمْسُ وَمَا دَامَتْ كَأَنَّهَا حَجَفَةٌ حَتَّى تُبَشْبِشَ ثُمَّ صَلِّ مَا بَدَا لَكَ حَتَّى يَقُومَ الْعَمُودُ عَلَى ظِلِّهِ ثُمَّ انْتَهِ حَتَّى تَزِيغَ الشَّمْسُ فَإِنَّ جَهَنَّمَ تُسْجَرُ نِصْفَ النَّهَارِ ثُمَّ صَلِّ مَا بَدَا لَكَ حَتَّى تُصَلِّيَ الْعَصْرَ ثُمَّ انْتَهِ حَتَّى تَغْرُبَ الشَّمْسُ فَإِنَّهَا تَغْرُبُ بَيْنَ قَرْنَيْ الشَّيْطَانِ وَتَطْلُعُ بَيْنَ قَرْنَيْ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Ya'la bin Atha] dari [Yazid bin Thalq] dari ['Abdurrahman Ibnul Bailamani] dari [Amru bin Anbasah] ia berkata, \"Aku menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Apakah ada satu waktu yang lebih disukai oleh Allah dari waktu yang lain?\" beliau menjawab: \"Ya, pertengahan malam, maka shalatlah semampumu hingga datang waktu subuh, setelah itu berhentilah (dari mengerjakan shalat) hingga matahari terbit, dan selagi matahari seperti perisai sampai memancar terang (terik menyengat), kemudian shalatlah sekehendak kamu sampai  tongkat berdiri tegak diatas bayangnya, kemudian berhentilah sampai matahari bergeser, karena  sesungguhnya jahannam di kobarkan pada perengahan hari. Kemudian shalatlah sekehendak kamu sampai kamu melaksanakan shalat ashar, kemudian berhentilah sampai matahari terbenam, karena sesungguhnya matahari terbenam diantara dua tanduk setan dan terbit diantara dua tanduk setan."},"1209":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ دَاوُدَ الْمُنْكَدِرِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَسَأَلَ صَفْوَانُ بْنُ الْمُعَطَّلِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي سَائِلُكَ عَنْ أَمْرٍ أَنْتَ بِهِ عَالِمٌ وَأَنَا بِهِ جَاهِلٌ قَالَ وَمَا هُوَ قَالَ هَلْ مِنْ سَاعَاتِ اللَّيْلِ وَالنَّهَارِ سَاعَةٌ تُكْرَهُ فِيهَا الصَّلَاةُ قَالَ نَعَمْ إِذَا صَلَّيْتَ الصُّبْحَ فَدَعْ الصَّلَاةَ حَتَّى تَطْلُعَ الشَّمْسُ فَإِنَّهَا تَطْلُعُ بِقَرْنَيْ الشَّيْطَانِ ثُمَّ صَلِّ فَالصَّلَاةُ مَحْضُورَةٌ مُتَقَبَّلَةٌ حَتَّى تَسْتَوِيَ الشَّمْسُ عَلَى رَأْسِكَ كَالرُّمْحِ فَإِذَا كَانَتْ عَلَى رَأْسِكَ كَالرُّمْحِ فَدَعْ الصَّلَاةَ فَإِنَّ تِلْكَ السَّاعَةَ تُسْجَرُ فِيهَا جَهَنَّمُ وَتُفْتَحُ فِيهَا أَبْوَابُهَا حَتَّى تَزِيغَ الشَّمْسُ عَنْ حَاجِبِكَ الْأَيْمَنِ فَإِذَا زَالَتْ فَالصَّلَاةُ مَحْضُورَةٌ مُتَقَبَّلَةٌ حَتَّى تُصَلِّيَ الْعَصْرَ ثُمَّ دَعْ الصَّلَاةَ حَتَّى تَغِيبَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Al Hasan bin Dawud Al Munkadir] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adl Dlahhaq bin Utsman] dari [Al Maqburi] dari [Abu Hurairah] ia berkata, \"Shafwan Ibnul Mu'aththal bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Wahai Rasulullah, aku ingin bertanya kepadamu sesuatu yang engkau ketahui dan tidak aku ketahui, \" beliau bersabda: \"Apa itu?\" ia berkata, \"Apakah pada waktu siang dan malam ada waktu-waktu yang seseorang tidak boleh shalat di dalamnya?\" beliau bersabda: \"Ya, jika engkau telah selesai dari shalat subuh, maka tinggalkanlah shalat hingga matahari terbit, sebab ia terbit antara dua tanduk setan. Setelah itu shalatlah, sebab shalat pada waktu itu dihadiri dan diterima hingga matahari berdiri tegak di atas kepalamu seperti tombak. Jika matahari telah tegak di atas kepalamu sebagaimana tombak maka tinggalkanlah shalat, sebab pada waktu itu jahannam sedang menyala-nyala dan semua pintunya terbuka hingga matahari bergeser dari alis matamu yang sebelah kanan. Jika matahari telah bergeser maka shalat pada waktu itu disaksikan dan diterima hingga engkau mengerjakan shalat ashar. Setelah itu tinggalkanlah shalat hingga matahari terbenam. \""},"1210":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي عَبْدِ اللَّهِ الصُّنَابِحِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الشَّمْسَ تَطْلُعُ بَيْنَ قَرْنَيْ الشَّيْطَانِ أَوْ قَالَ يَطْلُعُ مَعَهَا قَرْنَا الشَّيْطَانِ فَإِذَا ارْتَفَعَتْ فَارَقَهَا فَإِذَا كَانَتْ فِي وَسَطِ السَّمَاءِ قَارَنَهَا فَإِذَا دَلَكَتْ أَوْ قَالَ زَالَتْ فَارَقَهَا فَإِذَا دَنَتْ لِلْغُرُوبِ قَارَنَهَا فَإِذَا غَرَبَتْ فَارَقَهَا فَلَا تُصَلُّوا هَذِهِ السَّاعَاتِ الثَّلَاثَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah memberitakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari ['Atho` bin Yasar] dari [Abu Abdullah Ash Shunabihi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari terbit antara dua tanduk setan, atau beliau mengatakan: \"terbit bersamaan dengan dua tanduk setan. Jika matahari telah meninggi ia memisahkan diri darinya, dan jika matahari berada di tengah langit ia kembali mendekatinya. Jika bergeser, atau beliau mengatakan: \"condong, ia kembali memisahkan diri darinya, jika matahari hampir tenggelam ia kembali mendekatinya, dan jika matahari terbenam ia memisahkan dirinya. Maka janganlah kalian shalat di tiga waktu ini. \""},"1211":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَنِي عَبْدِ مَنَافٍ لَا تَمْنَعُوا أَحَدًا طَافَ بِهَذَا الْبَيْتِ وَصَلَّى أَيَّةَ سَاعَةٍ شَاءَ مِنْ اللَّيْلِ وَالنَّهَارِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zubair] dari [Abdullah bin Babaih] dari [Jubair bin Muth'im] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Bani Abdu Manaf, janganlah kalian halangi seorang pun thawaf di rumah ini (Ka'bah), \" Dan beliau shalat di siang dan malam hari pada waktu kapan pun yang beliau kehendaki. \""},"1212":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكُمْ سَتُدْرِكُونَ أَقْوَامًا يُصَلُّونَ الصَّلَاةَ لِغَيْرِ وَقْتِهَا فَإِنْ أَدْرَكْتُمُوهُمْ فَصَلُّوا فِي بُيُوتِكُمْ لِلْوَقْتِ الَّذِي تَعْرِفُونَ ثُمَّ صَلُّوا مَعَهُمْ وَاجْعَلُوهَا سُبْحَةً","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Abu Bakr bin Ayyasy] dari [Ashim] dari [Zir] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga kalian nanti mendapati orang-orang yang mengerjakan shalat di luar waktunya, jika kalian mendapati mereka maka shalatlah di rumah-rumah kalian pada waktu yang telah kalian ketahui, setelah itu shalatlah bersama mereka sebagai shalat tathawwu' (tambahan). \""},"1213":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلِّ الصَّلَاةَ لِوَقْتِهَا فَإِنْ أَدْرَكْتَ الْإِمَامَ يُصَلِّي بِهِمْ فَصَلِّ مَعَهُمْ وَقَدْ أَحْرَزْتَ صَلَاتَكَ وَإِلَّا فَهِيَ نَافِلَةٌ لَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Imran Al Jauni] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kerjakanlah shalat pada waktunya, jika engkau mendapatkan imam shalat bersama orang-orang maka bergabunglah bersama mereka, maka kamu telah menjaga shalatmu. Jika tidak (mendapatkan imam shalat bersama orang-orang pada waktunya), maka itu (shalat bersamanya di luar waktu) adalah tambahan bagimu. \""},"1214":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي الْمُثَنَّى عَنْ أَبِي أُبَيٍّ ابْنِ امْرَأَةِ عُبَادَةَ بْنِ الصَّامِتِ يَعْنِي عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَكُونُ أُمَرَاءُ تَشْغَلُهُمْ أَشْيَاءُ يُؤَخِّرُونَ الصَّلَاةَ عَنْ وَقْتِهَا فَاجْعَلُوا صَلَاتَكُمْ مَعَهُمْ تَطَوُّعًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Manshur] dari [Hilal bin Yasaf] dari [Abul Mutsanna] dari [Abu Ubai] -anak dari istri Ubadah bin Shamit- dari [Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan datang para pemimpin yang disibukkan urusan-urusan hingga mereka mengakhirkan shalat dari waktunya, maka jadikanlah shalat kalian bersama mereka sebagai tathawwu'. \""},"1215":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا جَرِيرٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْخَوْفِ أَنْ يَكُونَ الْإِمَامُ يُصَلِّي بِطَائِفَةٍ مَعَهُ فَيَسْجُدُونَ سَجْدَةً وَاحِدَةً وَتَكُونُ طَائِفَةٌ مِنْهُمْ بَيْنَهُمْ وَبَيْنَ الْعَدُوِّ ثُمَّ يَنْصَرِفُ الَّذِينَ سَجَدُوا السَّجْدَةَ مَعَ أَمِيرِهِمْ ثُمَّ يَكُونُونَ مَكَانَ الَّذِينَ لَمْ يُصَلُّوا وَيَتَقَدَّمُ الَّذِينَ لَمْ يُصَلُّوا فَيُصَلُّوا مَعَ أَمِيرِهِمْ سَجْدَةً وَاحِدَةً ثُمَّ يَنْصَرِفُ أَمِيرُهُمْ وَقَدْ صَلَّى صَلَاتَهُ وَيُصَلِّي كُلُّ وَاحِدٍ مِنْ الطَّائِفَتَيْنِ بِصَلَاتِهِ سَجْدَةً لِنَفْسِهِ فَإِنْ كَانَ خَوْفٌ أَشَدَّ مِنْ ذَلِكَ فَرِجَالًا أَوْ رُكْبَانًاقَالَ يَعْنِي بِالسَّجْدَةِ الرَّكْعَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Jarir] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda tentang shalat khauf: \"Hendaklah Imam shalat bersama sekelompok orang lalu sujud sekali, sementara satu kelompok lagi berdiri antara mereka menghadap musuh. Kemudian kelompok yang telah mendapatkan satu sujud bersama pemimpinnya pindah ke tempat kelompok yang belum melaksanakan shalat, kelompok yang belum shalat itu kemudian maju dan shalat bersama pemimpinnya hingga mendapatkan satu sujud. Pemimpin (Imam) itu kemudian berlalu pergi karena telah mengerjakan shalatnya (dengan sempurna), sementara setiap kelompok tersebut menyempurnakan shalat mereka sendiri-sendiri. Jika rasa takut melebihi dari kadar tersebut maka hendaklah melakukannya dengan berjalan atau berkendaraan. \" Ibnu Umar berkata, \"Yakni sujud untuk raka'at. \""},"1216":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّهُ قَالَ فِي صَلَاةِ الْخَوْفِ قَالَ يَقُومُ الْإِمَامُ مُسْتَقْبِلَ الْقِبْلَةِ وَتَقُومُ طَائِفَةٌ مِنْهُمْ مَعَهُ وَطَائِفَةٌ مِنْ قِبَلِ الْعَدُوِّ وَوُجُوهُهُمْ إِلَى الصَّفِّ فَيَرْكَعُ بِهِمْ رَكْعَةً وَيَرْكَعُونَ لِأَنْفُسِهِمْ وَيَسْجُدُونَ لِأَنْفُسِهِمْ سَجْدَتَيْنِ فِي مَكَانِهِمْ ثُمَّ يَذْهَبُونَ إِلَى مُقَامِ أُولَئِكَ وَيَجِيءُ أُولَئِكَ فَيَرْكَعُ بِهِمْ رَكْعَةً وَيَسْجُدُ بِهِمْ سَجْدَتَيْنِ فَهِيَ لَهُ ثِنْتَانِ وَلَهُمْ وَاحِدَةٌ ثُمَّ يَرْكَعُونَ رَكْعَةً وَيَسْجُدُونَ سَجْدَتَيْنِقَالَ مُحَمَّدُ بْنُ بَشَّارٍ فَسَأَلْتُ يَحْيَى بْنَ سَعِيدٍ الْقَطَّانَ عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِي عَنْ شُعْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ يَحْيَى بْنِ سَعِيدٍ قَالَ قَالَ لِي يَحْيَى اكْتُبْهُ إِلَى جَنْبِهِ وَلَسْتُ أَحْفَظُ الْحَدِيثَ وَلَكِنْ مِثْلُ حَدِيثِ يَحْيَى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] berkata, telah menceritakan kepadaku [Yahya bin Sa'id Al Anshari] dari [Al Qasim bin Muhammad] dari [Sholih bin Khawwat] dari [Sahl bin Abu Hatsmah] Bahwasanya ia pernah berkata tentang shalat khauf, ia mengatakan, \"Imam menghadap ke arah kiblat, satu kelompok berdiri bersamanya dan kelompok lain ke arah musuh, sementara wajah mereka menghadap ke arah shaf. Imam rukuk sekali bersama mereka, lalu mereka rukuk dan sujud dua kali di tempat mereka berada secara sendiri-sendiri. Setelah itu mereka pergi menempati tempat kelompok (yang belum shalat), kemudian kelompok yang belum shalat itu datang hingga imam rukuk satu kali, dan sujud dua kali bersama mereka. Dengan demikian maka imam mendapatkan dua kali rukuk sementara mereka satu kali rukuk, lalu mereka rukuk satu kali lagi dan sujud dua kali. \" [Muhammad bin Basysyar] berkata, \"Aku bertanya kepada [Yahya bin Sa'id Al Qaththan] tentang hadits ini, maka ia menceritakan kepadaku dari [Syu'bah] dari ['Abdurrahman Ibnul Qasim] dari [Bapaknya] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah] dari Nabi shallallahu 'alaihi wasallam sebagaimana hadits Yahya bin Sa'id. \" Ia berkata; Yahya berkata kepadaku, \"Tulislah hadits tersebut di sisinya, aku bukan seorang yang hafal hadits, tetapi seperti hadits Yahya. \""},"1217":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِأَصْحَابِهِ صَلَاةَ الْخَوْفِ فَرَكَعَ بِهِمْ جَمِيعًا ثُمَّ سَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّفُّ الَّذِينَ يَلُونَهُ وَالْآخَرُونَ قِيَامٌ حَتَّى إِذَا نَهَضَ سَجَدَ أُولَئِكَ بِأَنْفُسِهِمْ سَجْدَتَيْنِ ثُمَّ تَأَخَّرَ الصَّفُّ الْمُقَدَّمُ حَتَّى قَامُوا مُقَامَ أُولَئِكَ وَتَخَلَّلَ أُولَئِكَ حَتَّى قَامُوا مُقَامَ الصَّفِّ الْمُقَدَّمِ فَرَكَعَ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيعًا ثُمَّ سَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّفُّ الَّذِي يَلُونَهُ فَلَمَّا رَفَعُوا رُءُوسَهُمْ سَجَدَ أُولَئِكَ سَجْدَتَيْنِ وَكُلُّهُمْ قَدْ رَكَعَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَجَدَ طَائِفَةٌ بِأَنْفُسِهِمْ سَجْدَتَيْنِ وَكَانَ الْعَدُوُّ مِمَّا يَلِي الْقِبْلَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Az Zubair] dari [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam shalat khauf bersama para sahabatnya, beliau rukuk bersama mereka semua. Kemudian beliau sujud bersama shaf yang berada di belakangnya (shaf paling depan), sementara yang lain tetap berdiri. Hingga ketika beliau bangkit mereka tetap meneruskan sujud dua kali sendiri-sendiri. Kemudian shaf yang paling depan mundur ke belakang menempati tempat mereka (kelompok yang ada di barisan kedua). Kemudian kelompok (kedua) tersebut maju melalui celah-celah hingga menempati posisi shaf pertama. Nabi shallallahu 'alaihi wasallam kemudian rukuk bersama mereka semua, selanjutnya Rasulullah shallallahu 'alaihi wasallam sujud bersama shaf yang berada di belakangnya. Maka ketika mereka mengangkat kepala, mereka sujud kembali dua kali, hingga semua kelompok telah rukuk bersama Nabi shallallahu 'alaihi wasallam. Dan kelompok tersebut sujud dua kali sendiri-sendiri, sementara musuh ada di arah kiblat. \" "},"1218":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ مِنْ النَّاسِ فَإِذَا رَأَيْتُمُوهُ فَقُومُوا فَصَلُّوا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazm] dari [Abu Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari dan bulan tidaklah terbit karena kematian seorang manusia, jika kalian melihatnya maka berdiri dan shalatlah. \" "},"1219":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَأَحْمَدُ بْنُ ثَابِتٍ وَجَمِيلُ بْنُ الْحَسَنِ قَالُوا حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ فَزِعًا يَجُرُّ ثَوْبَهُ حَتَّى أَتَى الْمُسْجِدَ فَلَمْ يَزَلْ يُصَلِّي حَتَّى انْجَلَتْ ثُمَّ قَالَ إِنَّ أُنَاسًا يَزْعُمُونَ أَنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ إِلَّا لِمَوْتِ عَظِيمٍ مِنْ الْعُظَمَاءِ وَلَيْسَ كَذَلِكَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا تَجَلَّى اللَّهُ لِشَيْءٍ مِنْ خَلْقِهِ خَشَعَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ahmad bin Tsabit] dan [Jamil bin Al Hasan] mereka berkata; telah menceritakan kepada kami [Abdul Wahhab] dari [Khalid Al Hadzdza] dari [Abu Qilabah] dari [An Nu'man bin Basysyar] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam terjadi gerhana, lalu Beliau keluar tergesa-gesa sambil menjinjing kainnya hingga tiba di masjid. Beliau tetap melaksanakan shalat hingga gerhana berakhir, setelah itu beliau bersabda: \"Orang-orang mengklaim bahwa tidak akan terjadi gerhana matahari dan bulan kecuali karena kematian salah seorang pembesar, padahal tidak seperti itu. Matahari dan bulan tidak terjadi gerhana karena kematian atau hidupnya seseorang, Maka jika Allah menampakkan kepada salah satu dari hamba-Nya, maka ia akan tunduk kepada-Nya. \" "},"1220":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْكَسَفَتْ الشَّمْسُ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَقَامَ فَكَبَّرَ فَصَفَّ النَّاسُ وَرَاءَهُ فَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةً طَوِيلَةً ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ قَامَ فَقَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا هُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ فَعَلَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ فَاسْتَكْمَلَ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ قَبْلَ أَنْ يَنْصَرِفَ ثُمَّ قَامَ فَخَطَبَ النَّاسَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَافْزَعُوا إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Urwah bin Az Zubair] dari ['Aisyah] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam terjadi gerhana matahari, maka Rasulullah shallallahu 'alaihi wasallam berangkat menuju masjid. Beliau berdiri dan takbir, sementara orang-orang membuat shaf di belakangnya. Rasulullah shallallahu 'alaihi wasallam membaca bacaan yang panjang, kemudian takbir, lalu rukuk dengan rukuk yang panjang, kemudian mengangkat kepalanya. Beliau mengucapkan: \"RABBANA WA LAKAL HAMDU. Kemudian beliau kembali berdiri dan membaca bacaan yang panjang, namun lebih pendek dari bacaan yang pertama. Kemudian takbir, lalu rukuk dan memperpanjang rukuknya, namun lebih pendek dari rukuk yang pertama. Kemudian mengucapkan: \"SAMI'A ALLAHU LIMAN HAMIDAH RABBANAA WA LAKAL HAMDU. Kemudian beliau mengerjakan raka'at yang lain (kedua) seperti itu. Dengan begitu beliau telah menyempurnakan empat raka'at dan empat sujud, sementara matahari mulai muncul sebelum beliau bergeser. Setelah itu beliau berdiri dan berkhutbah di hadapan orang-orang, beliau memuji Allah sebagaimana mestinya, lalu mengatakan: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda (kekuasaan) Allah, keduanya tidak gerhana karena kematian atau lahirnya seseorang, jika kalian melihatnya (gerhana) maka laksanakanlah shalat. \""},"1221":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ ثَعْلَبَةَ بْنِ عِبَادٍ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكُسُوفِ فَلَا نَسْمَعُ لَهُ صَوْتًا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Al Aswad bin Qais] dari [Tsa'labah bin 'Ibad] dari [Samurah bin Jundab] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah shalat gerhana bersama kami, dan kami tidak mendengar beliau bersuara. \" "},"1222":{"ar":"حَدَّثَنَا مُحْرِزُ بْنُ سَلَمَةَ الْعَدَنِيُّ قَالَ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْكُسُوفِ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ انْصَرَفَ فَقَالَ لَقَدْ دَنَتْ مِنِّي الْجَنَّةُ حَتَّى لَوْ اجْتَرَأْتُ عَلَيْهَا لَجِئْتُكُمْ بِقِطَافٍ مِنْ قِطَافِهَا وَدَنَتْ مِنِّي النَّارُ حَتَّى قُلْتُ أَيْ رَبِّ وَأَنَا فِيهِمْ قَالَ نَافِعٌ حَسِبْتُ أَنَّهُ قَالَ وَرَأَيْتُ امْرَأَةً تَخْدِشُهَا هِرَّةٌ لَهَا فَقُلْتُ مَا شَأْنُ هَذِهِ قَالُوا حَبَسَتْهَا حَتَّى مَاتَتْ جُوعًا لَا هِيَ أَطْعَمَتْهَا وَلَا هِيَ أَرْسَلَتْهَا تَأْكُلُ مِنْ خِشَاشِ الْأَرْضِ","id":"Telah menceritakan kepada kami [Muhriz bin Salamah Al Adani] berkata; telah menceritakan kepada kami [Nafi' bin Umar Al Juhami] dari [Ibnu Abu Mulaikah] dari [Asma binti Abu Bakr] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat gerhana, beliau berdiri dan memperpanjang berdirinya, kemudian rukuk dan memperpanjang rukuknya, kemudian berdiri dan memperpanjang berdirinya, kemudian rukuk dan memperpanjang rukuknya, setelah itu beliau mengangkat (kepala) kemudian sujud dan memperpanjang sujudnya, kemudian mengangkat (kepala) kemudian sujud dan memperpanjang sujudnya, kemudian mengangkat kepala berdiri dan memperpanjang berdirinya, kemudian rukuk dan memperpanjang rukuknya, kemudian mengangkat kepala berdiri dan memperpanjang berdirinya, kemudian rukuk dan memperpanjang rukuknya, kemudian mengangkat kepalanya, kemudian sujud dan memperpanjang sujudnya, kemudian mengangkat kepalanya, kemudian sujud dan memperpanjang sujudnya. Setelah itu beliau bergeser dan bersabda: \"Surga telah dekat denganku, sekiranya aku berani sungguh akan aku ambilkan untuk kalian buah dari buah-buahan surga. Dan neraka telah dekat denganku hingga aku berkata: \"Wahai Rabb, aku masih bersama mereka! \" Nafi' berkata, \"Menurutku beliau mengatakan: \"Aku melihat seorang wanita yang dicakar-cakar oleh kucing miliknya. Aku bertanya: \"Ada apa dengan wanita ini?\" mereka menjawab, \"Wanita itu telah menahannya, kucing itu mati karena lapar. Ia tidak memberi makan dan tidak membiarkannya pergi untuk makan serangga bumi. \""},"1223":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ هِشَامِ بْنِ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ كِنَانَةَ عَنْ أَبِيهِ قَالَأَرْسَلَنِي أَمِيرٌ مِنْ الْأُمَرَاءِ إِلَى ابْنِ عَبَّاسٍ أَسْأَلُهُ عَنْ الصَّلَاةِ فِي الِاسْتِسْقَاءِ فَقَالَ ابْنُ عَبَّاسٍ مَا مَنَعَهُ أَنْ يَسْأَلَنِي قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَاضِعًا مُتَبَذِّلًا مُتَخَشِّعًا مُتَرَسِّلًا مُتَضَرِّعًا فَصَلَّى رَكْعَتَيْنِ كَمَا يُصَلِّي فِي الْعِيدِ وَلَمْ يَخْطُبْ خُطْبَتَكُمْ هَذِهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Hisyam bin Ishaq bin Abdullah bin Kinanah] dari [Bapaknya] ia berkata, \"Salah seorang pemimpin mengirimku menemui [Ibnu Abbas] untuk menanyakan kepadanya tentang shalat istisqa`, Ibnu Abbas pun berkata, \"Apa yang menghalanginya bertanya langsung kepadaku?\" ia berkata lagi: \"Rasulullah shallallahu 'alaihi wasallam keluar dengan penuh tawadlu', memakai baju biasa, khusyu', perlahan-lahan dan menunduk. Lalu Beliau shalat dua raka'at sebagaimana shalat 'ied, namun beliau tidak berkhutbah seperti khutbah kalian ini. \""},"1224":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ قَالَ سَمِعْتُ عَبَّادَ بْنَ تَمِيمٍ يُحَدِّثُ أَبِي عَنْ عَمِّهِأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمُصَلَّى لِيَسْتَسْقِي فَاسْتَقْبَلَ الْقِبْلَةَ وَقَلَبَ رِدَاءَهُ وَصَلَّى رَكْعَتَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ قَالَ سُفْيَانُ عَنْ الْمَسْعُودِيِّ قَالَ سَأَلْتُ أَبَا بَكْرِ بْنَ مُحَمَّدِ بْنِ عَمْرٍو أَجَعَلَ أَعْلَاهُ أَسْفَلَهُ أَوْ الْيَمِينَ عَلَى الشِّمَالِ قَالَ لَا بَلْ الْيَمِينَ عَلَى الشِّمَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Bakr] berkata; aku mendengar [Abbad bin Tamim] -menceritakan kepada bapakku- dari [Pamannya] bahwasanya ia bersaksi, bahwa Nabi shallallahu 'alaihi wasallam pernah keluar untuk shalat istisqa`, beliau menghadap kiblat, lalu membalik selendangnya dan shalat dua raka'at. \" Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Abbad bin Tamim] dari [Pamannya] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. Sufyan menyebutkan dari Al Mas'udi ia berkata, \"Aku bertanya kepada Abu Bakr bin Muhammad bin Amru, \"Apakah beliau menjadikan bagian atas pada bagian bawahnya, atau bagian kanan pada bagian kirinya?\" ia menjawab, \"Tidak, tetapi bagian kanan pada bagian kiri. \" "},"1225":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ وَالْحَسَنُ بْنُ أَبِي الرَّبِيعِ قَالَا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ النُّعْمَانَ يُحَدِّثُ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا يَسْتَسْقِي فَصَلَّى بِنَا رَكْعَتَيْنِ بِلَا أَذَانٍ وَلَا إِقَامَةٍ ثُمَّ خَطَبَنَا وَدَعَا اللَّهَ وَحَوَّلَ وَجْهَهُ نَحْوَ الْقِبْلَةِ رَافِعًا يَدَيْهِ ثُمَّ قَلَبَ رِدَاءَهُ فَجَعَلَ الْأَيْمَنَ عَلَى الْأَيْسَرِ وَالْأَيْسَرَ عَلَى الْأَيْمَنِ","id":"Telah menceritakan kepada kami [Ahmad Ibnul Azhar] dan [Al Hasan bin Abu Rabi'] keduanya berkata; telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] berkata; aku mendengar [An Nu'man] menceritakan dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam keluar shalat istisqa`, beliau shalat dua raka'at bersama kami tanpa adzan dan iqamah, kemudian beliau berkhutbah di hadapan kami dan berdo`a kepada Allah, beliau mengarahkan wajahnya ke arah kiblat seraya mengangkat kedua tangannya. Setelah itu beliau membalik selendangnya, menjadikan bagian kanan pada bagian kiri dan bagian kiri pada bagian kanan. \""},"1226":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِأَنَّهُ قَالَ لِكَعْبٍ يَا كَعْبُ بْنَ مُرَّةَ حَدِّثْنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحْذَرْ قَالَ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ اسْتَسْقِ اللَّهَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ فَقَالَ اللَّهُمَّ اسْقِنَا غَيْثًا مَرِيئًا مَرِيعًا طَبَقًا عَاجِلًا غَيْرَ رَائِثٍ نَافِعًا غَيْرَ ضَارٍّ قَالَ فَمَا جَمَّعُوا حَتَّى أُجِيبُوا قَالَ فَأَتَوْهُ فَشَكَوْا إِلَيْهِ الْمَطَرَ فَقَالُوا يَا رَسُولَ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ فَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا قَالَ فَجَعَلَ السَّحَابُ يَنْقَطِعُ يَمِينًا وَشِمَالًا","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Amru bin Murrah] dari [Salim bin Abul Ju'd] dari [Surahbil bin As Sibth] bahwasanya ia berkata kepada Ka'b, \"Wahai Ka'b bin Murrah, ceritakanlah sebuah hadits Rasulullah shallallahu 'alaihi wasallam kepada kami, dan hati-hatilah engkau (dalam menyampaikan hadits), \" [Ka'b bin Murrah] berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam seraya berkata, \"Wahai Rasulullah, beristisqa`lah engkau kepada Allah! \" Rasulullah shallallahu 'alaihi wasallam lalu mengangkat keduanya dan mengucapkan: \"ALLAHUMMAS QINAA GHAITSAN MARII`AN MARII'AN THABAQAN 'AAJILAN GHAIRA RA`ITSIN NAAFI'AN GHAIRA DLAARRIN (Ya Allah, berilah kepada kami hujan yang tenang dan merata, menyegarkan tubuh dan menyuburkan tanaman, segera dan tidak ditunda-tunda, bermanfaat dan tidak membahayakan). \" Ka'b bin Murrah berkata, \"Belum genap satu minggu mereka pun mendapatkan hujan. \" Ka'b bin Murrah berkata, \"Lalu mereka mendatangi beliau lagi dan mengeluhkan perihal hujan, mereka mengatakan, \"Wahai Rasulullah, banyak rumah yang hancur (karena hujan)! \" maka beliau pun mengucapkan: \"ALLAHUMMA HAWAALAINAA WA LAA 'ALAINAA (Ya Allah, hujanilah sekitar kami dan jangan atas kami). \" Ka'b bin Murrah berkata, \"Maka mendung pun terbelah ke kanan dan ke kiri. \""},"1227":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْقَاسِمِ أَبُو الْأَحْوَصِ حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ حَدَّثَنَا حُصَيْنٌ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ لَقَدْ جِئْتُكَ مِنْ عِنْدِ قَوْمٍ مَا يَتَزَوَّدُ لَهُمْ رَاعٍ وَلَا يَخْطِرُ لَهُمْ فَحْلٌ فَصَعِدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ ثُمَّ قَالَ اللَّهُمَّ اسْقِنَا غَيْثًا مُغِيثًا مَرِيئًا طَبَقًا مَرِيعًا غَدَقًا عَاجِلًا غَيْرَ رَائِثٍ ثُمَّ نَزَلَ فَمَا يَأْتِيهِ أَحَدٌ مِنْ وَجْهٍ مِنْ الْوُجُوهِ إِلَّا قَالُوا قَدْ أُحْيِينَا","id":"Telah menceritakan kepada kami [Muhammad bin Abul Qasim Abul Ahwash] berkata, telah menceritakan kepada kami [Al Hasan Ibnur Rabi'] berkata, telah menceritakan kepada kami [Abdullah bin Idris] berkata, telah menceritakan kepada kami [Hushain] dari [Habib bin Abu Tsabit] dari [Ibnu Abbas] ia berkata, \"Seorang arab dusun datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku datang dari kaumku, para penggembala tidak bisa lagi membekali mereka (dengan susu), dan unta jantan tidak lagi membahayakan mereka (karena lemah)! \" Lalu beliau naik mimbar memuji Allah seraya mengucapkan: \"ALLAHUMMASQINAA GHAITSAN MUGHITSAN MARII`AN MARII'AN THABAQAN GHADAQAN 'AAJILAN GHAIRAA`TSIN (Ya Allah, berilah kami hujan yang tenang dan merata, menyegarkan tubuh dan menyuburkan tanaman, melimpah, segera dan tidak ditunda-tunda). \" Setelah itu beliau turun dari mimbar, dan tidaklah seseorang datang kecuali mengucapkan, \"Kami telah mendapatkan kehidupan. \""},"1228":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ بَرَكَةَ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى حَتَّى رَأَيْتُ أَوْ رُئِيَ بَيَاضُ إِبْطَيْهِقَالَ مُعْتَمِرٌ أُرَاهُ فِي الِاسْتِسْقَاءِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Mu'tamir] dari [Bapaknya] dari [Barakah] dari [Basyir bin Nahik] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam shalat istisqa` meminta hujan hingga aku melihat putihnya ketiak beliau. \" Mu'tamir berkata, \"Menurutku, hal itu terjadi pada waktu shalat istisqa`. \""},"1229":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو عَقِيلٍ عَنْ عُمَرَ بْنِ حَمْزَةَ حَدَّثَنَا سَالِمٌ عَنْ أَبِيهِ قَالَرُبَّمَا ذَكَرْتُ قَوْلَ الشَّاعِرِ وَأَنَا أَنْظُرُ إِلَى وَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَمَا نَزَلَ حَتَّى جَيَّشَ كُلُّ مِيزَابٍ بِالْمَدِينَةِ فَأَذْكُرُ قَوْلَ الشَّاعِرِ وَأَبْيَضَ يُسْتَسْقَى الْغَمَامُ بِوَجْهِهِثِمَالُ الْيَتَامَى عِصْمَةٌ لِلْأَرَامِلِوَهُوَ قَوْلُ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami [Ahmad Ibnul Azhar] berkata, telah menceritakan kepada kami [Abu An Nadlr] berkata, telah menceritakan kepada kami [Abu Aqil] dari [Umar bin Hamzah] berkata, telah menceritakan kepada kami [Salim] dari [Bapaknya] ia berkata, \"Aku ingat perkataan sya'ir ketika memperhatikan wajah Rasulullah shallallahu 'alaihi wasallam di atas mimbar, dan beliau tidak turun dari atas mimbar kecuali semua saluran air di Madinah penuh dengan air. Aku mengingat perkataan sya'ir, \"Orang yang berkulit putih (Rasulullah), dengan wajahnya hujan di minta, penyantun anak yatim dan pelindung kaum janda. \" Itu adalah ucapan Abu Thalib. "},"1230":{"ar":"حَدّ��ثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَيُّوبَ عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُأَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ فَرَأَى أَنَّهُ لَمْ يُسْمِعْ النِّسَاءَ فَأَتَاهُنَّ فَذَكَّرَهُنَّ وَوَعَظَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ وَبِلَالٌ قَائِلٌ بِيَدَيْهِ هَكَذَا فَجَعَلَتْ الْمَرْأَةُ تُلْقِي الْخُرْصَ وَالْخَاتَمَ وَالشَّيْءَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Ayyub] dari ['Atho`] berkata; aku mendengar [Ibnu Abbas] berkata, \"Aku bersaksi atas Rasulullah shallallahu 'alaihi wasallam bahwa beliau shalat sebelum khutbah, setelah itu berkhutbah. Beliau merasa bahwa suaranya tidak dapat didengar oleh kaum wanita, maka beliau pun mendatangi mereka seraya mengingatkan, memberi tausiah dan memerintahkan mereka untuk bersedekah. Bilal berkata dengan isyarat tangannya seperti ini, hingga kaum wanita pun memberikan anting, cincin dan sesuatu yang lain. \""},"1231":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْعِيدِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] dari [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam pada hari ied melaksanakan shalat tanpa adzan dan iqamah. \""},"1232":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ و عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي سَعِيدٍ قَالَأَخْرَجَ مَرْوَانُ الْمِنْبَرَ يَوْمَ الْعِيدِ فَبَدَأَ بِالْخُطْبَةِ قَبْلَ الصَّلَاةِ فَقَامَ رَجُلٌ فَقَالَ يَا مَرْوَانُ خَالَفْتَ السُّنَّةَ أَخْرَجْتَ الْمِنْبَرَ يَوْمَ عِيدٍ وَلَمْ يَكُنْ يُخْرَجُ بِهِ وَبَدَأْتَ بِالْخُطْبَةِ قَبْلَ الصَّلَاةِ وَلَمْ يَكُنْ يُبْدَأُ بِهَا فَقَالَ أَبُو سَعِيدٍ أَمَّا هَذَا فَقَدْ قَضَى مَا عَلَيْهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَأَى مُنْكَرًا فَاسْتَطَاعَ أَنْ يُغَيِّرَهُ بِيَدِهِ فَلْيُغَيِّرْهُ بِيَدِهِ فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ فَإِنْ لَمْ يَسْتَطِعْ بِلِسَانِهِ فَبِقَلْبِهِ وَذَلِكَ أَضْعَفُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Isma'il bin Raja`] dari [Bapaknya] dari [Abu Sa'id]. (dalam jalur lain disebutkan) Dari [Qais bin Muslim] dari [Thariq bin Syihab] dari [Abu Sa'id] berkata; Marwan mengeluarkan mimbar di hari ied dan memulai khutbah sebelum melaksanakan shalat, maka seorang laki-laki berdiri dan berkata, \"Wahai Marwan, engkau telah menyelisihi sunnah! Engkau keluarkan mimbar padahal ia belum pernah dikeluarkan sebelumnya, dan engkau memulai dengan khutbah padahal itu belum pernah dilakukan sebelumnya. \" Lalu Abu Sa'id berkata, \"Adapun orang ini, sungguh ia telah melaksanakan apa yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa melihat kemungkaran dan mampu untuk mengubah dengan tangannya hendaklah ia ubah dengan tangannya. Jika tidak mampu hendaklah dengan lisannya, jika tidak mampu dengan tangan hendaklah dengan hatinya. Dan itu adalah selemah-lemah iman. \""},"1233":{"ar":"حَدَّثَنَا حَوْثَرَةُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَبُو بَكْرٍ ثُمَّ عُمَرُ يُصَلُّونَ الْعِيدَ قَبْلَ الْخُطْبَةِ","id":"Telah menceritakan kepada kami [Hautsarah bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar melaksanakan shalat ied sebelum khutbah. \""},"1234":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ مُؤَذِّنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُكَبِّرُ فِي الْعِيدَيْنِ فِي الْأُولَى سَبْعًا قَبْلَ الْقِرَاءَةِ وَفِي الْآخِرَةِ خَمْسًا قَبْلَ الْقِرَاءَةِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin Ammar bin Sa'd] -mu`adzin Rasulullah shallallahu 'alaihi wasallam- berkata, telah menceritakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] berkata, \"Pada hari raya Rasulullah shallallahu 'alaihi wasallam bertakbir pada raka'at pertama sebanyak tujuh kali sebelum bacaan, dan pada raka'at kedua sebanyak lima kali. \" "},"1235":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ فِي صَلَاةِ الْعِيدَيْنِ سَبْعًا وَخَمْسًا","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al 'Ala] berkata, telah menceritakan kepada kami [Abdullah bin Mubarak] dari [Abdullah bin 'Abdurrahman bin Ya'la] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata, \"Nabi shallallahu 'alaihi wasallam bertakbir sebanyak tujuh dan lima kali dalam shalat iedain (iedul fitri dan iedul adlha). \""},"1236":{"ar":"حَدَّثَنَا أَبُو مَسْعُودٍ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عَقِيلٍ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ عَثْمَةَ حَدَّثَنَا كَثِيرُ بْنُ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ فِي الْعِيدَيْنِ سَبْعًا فِي الْأُولَى وَخَمْسًا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Mas'ud Muhammad bin Abdullah bin 'Ubaid bin Aqil] berkata, telah menceritakan kepada kami [Muhammad bin Khalid bin 'Atsmah] berkata, telah menceritakan kepada kami [Katsir bin Abdullah bin Amru bin 'Auf] dari [Bapaknya] dari [Kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bertakbir di dua shalat ied sebanyak tujuh kali di raka'at pertama dan lima kali di raka'at terakhir. \""},"1237":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنْ خَالِدِ بْنِ يَزِيدَ وَعُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ فِي الْفِطْرِ وَالْأَضْحَى سَبْعًا وَخَمْسًا سِوَى تَكْبِيرَتَيْ الرُّكُوعِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Khalid bin Yazid] dan [Uqail] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bertakbir pada shalat iedul fitri dan adlha sebanyak tujuh dan lima kali, selain dua takbir rukuk. \""},"1238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْعِيدَيْنِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan bin Uyainah] dari [Ibrahim bin Muhammad Ibnul Muntasyir] dari [Bapaknya] dari [Habib bin Salim] dari [An Nu'man bin Basyir] berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) dan HAL ATAAKA HADIITSUL GHAASYIYAH (Sudah datangkah kepadamu berita (tentang) hari pembalasan?) dalam dua shalat ied. \""},"1239":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجَ عُمَرُ يَوْمَ عِيدٍ فَأَرْسَلَ إِلَى أَبِي وَاقِدٍ اللَّيْثِيِّ بِأَيِّ شَيْءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي مِثْلِ هَذَا الْيَوْمِ قَالَ بِقَافْ وَاقْتَرَبَتْ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] dari [Dlamrah bin Sa'id] dari [Ubaidullah bin Abdullah] berkata, \"Pada hari ied Umar keluar, lalu ia mengutus utusan kepada Abu Waqid untuk menanyakan surat apa yang dibaca Nabi shallallahu 'alaihi wasallam di hari ied. [Abu Waqid berkata], \"Beliau membaca QAAF dan WAQTARABAT. \""},"1240":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ كَانَ يَقْرَأُ فِي الْعِيدَيْنِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Waki' bin Al Jarrah] berkata, telah menceritakan kepada kami [Musa bin 'Ubaidah] dari [Muhammad bin Amru bin 'Atho`] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam membaca SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) dan HAL ATAAKA HADIITSUL GHAASYIYAH (Sudah datangkah kepadamu berita (tentang) hari pembalasan?) dalam dua shalat ied. \""},"1241":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ قَالَ رَأَيْتُ أَبَا كَاهِلٍ وَكَانَتْ لَهُ صُحْبَةٌ فَحَدَّثَنِي أَخِي عَنْهُ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى نَاقَةٍ وَحَبَشِيٌّ آخِذٌ بِخِطَامِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] berkata; Aku melihat Abu Kahil -ia pernah bersahabat dengan Rasulullah-, [saudaraku] pernah menceritakan hadits kepadaku dari [Abu Kahil], ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam berkhutbah di atas unta, sementara seorang Habsyi memegang tali kekangnya. \""},"1242":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ عَائِذٍ هُوَ أَبُو كَاهِلٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى نَاقَةٍ حَسْنَاءَ وَحَبَشِيٌّ آخِذٌ بِخِطَامِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin 'A`idz] -yakni Abu Kahil- ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam berkhutbah di atas unta yang bagus, sementara seorang Habsyi memegang tali kekangnya. \""},"1243":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سَلَمَةَ بْنِ نُبَيْطٍ عَنْ أَبِيهِأَنَّهُ حَجَّ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى بَعِيرِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [Salamah bin Nubaith] dari [Bapaknya] Bahwasanya ia pernah melaksanakan haji, ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam berkhutbah di atas untanya. \""},"1244":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ الْمُؤَذِّنِ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ بَيْنَ أَضْعَافِ الْخُطْبَةِ يُكْثِرُ التَّكْبِيرَ فِي خُطْبَةِ الْعِيدَيْنِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin 'Ammar bin Sa'a] -mu`adzin Rasulullah shallallahu 'alaihi wasallam- berkata, telah menceritakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam bertakbir di tengah-tengah khutbah, beliau memperbanyak takbir pada khutbah dua hari raya. \" "},"1245":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ أَخْبَرَنِي أَبُو سَعِيدٍ الْخُدْرِيُّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ يَوْمَ الْعِيدِ فَيُصَلِّي بِالنَّاسِ رَكْعَتَيْنِ ثُمَّ يُسَلِّمُ فَيَقِفُ عَلَى رِجْلَيْهِ فَيَسْتَقْبِلُ النَّاسَ وَهُمْ جُلُوسٌ فَيَقُولُ تَصَدَّقُوا تَصَدَّقُوا فَأَكْثَرُ مَنْ يَتَصَدَّقُ النِّسَاءُ بِالْقُرْطِ وَالْخَاتَمِ وَالشَّيْءِ فَإِنْ كَانَتْ حَاجَةٌ يُرِيدُ أَنْ يَبْعَثَ بَعْثًا يَذْكُرُهُ لَهُمْ وَإِلَّا انْصَرَفَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepada kami [Dawud bin Qais] dari ['Iyadh bin Abdullah] berkata, telah mengabarkan kepadaku [Abu Sa'id Al Khudri] ia berkata, \"Pada hari ied Rasulullah shallallahu 'alaihi wasallam keluar dan shalat dua raka'at bersama manusia kemudian salam. Setelah itu beliau berdiri di atas kedua kakinya, beliau menghadap ke arah manusia yang sedang duduk seraya bersabda: \"Bersedekahlah kalian, bersedekahlah kalian, bersedekahlah kalian, \" maka yang paling banyak bersedekah adalah kaum wanita, dengan anting, cincin dan sesuatu. \" Jika ada suatu keperluan untuk mengirim pasukan, beliau menyebutkannya kepada mereka, dan jika tidak maka beliau langsung pergi berlalu. \" "},"1246":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو بَحْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ الْخَوْلَانِيُّ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فِطْرٍ أَوْ أَضْحَى فَخَطَبَ قَائِمًا ثُمَّ قَعَدَ قَعْدَةً ثُمَّ قَامَ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Bahr] berkata, telah menceritakan kepada kami [Isma'il bin Muslim Al Khaulani] berkata, telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar pada hari raya iedul fitri atau Adlha, beliau lalu berkhutbah dengan berdiri, kemudian duduk sejenak, kemudian bangun. \" "},"1247":{"ar":"حَدَّثَنَا هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ وَعَمْرُو بْنُ رَافِعٍ الْبَجَلِيُّ قَالَا حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَحَضَرْتُ الْعِيدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِنَا الْعِيدَ ثُمَّ قَالَ قَدْ قَضَيْنَا الصَّلَاةَ فَمَنْ أَحَبَّ أَنْ يَجْلِسَ لِلْخُطْبَةِ فَلْيَجْلِسْ وَمَنْ أَحَبَّ أَنْ يَذْهَبَ فَلْيَذْهَبْ","id":"Telah menceritakan kepada kami [Hadiyyah bin Abdul Wahhab] dan [Amru bin Rafi' Al Bajali] keduanya berkata; telah menceritakan kepada kami [Al Fadll bin Musa] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari ['Atho`] dari [Abdullah bin As Sa`ib] ia berkata, \"Aku pernah menghadiri shalat ied bersama Rasulullah shallallahu 'alaihi wasallam, beliau shalat 'ied bersama kami kemudian bersabda: \"Kita telah selesai melaksanakan shalat, maka barangsiapa ingin duduk mendengar khutbah hendaklah ia duduk, dan barangsiapa ingin pergi hendaklah ia pergi. \" "},"1248":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَدِيُّ بْنُ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَصَلَّى بِهِمْ الْعِيدَ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam berangkat dan melaksanakan shalat ied bersama para sahabat, namun beliau tidak mengerjakan shalat (sunnah) sebelum dan sesudahnya. \""},"1249":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الطَّائِفِيُّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا فِي عِيدٍ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Abdullah bin 'Abdurrahman Ath Tha`ifi] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] berkata, \"Di hari ied Nabi shallallahu 'alaihi wasallam tidak shalat baik sebelum maupun sesudahnya. \""},"1250":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا الْهَيْثَمُ بْنُ جَمِيلٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو الرَّقِّيِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّي قَبْلَ الْعِيدِ شَيْئًا فَإِذَا رَجَعَ إِلَى مَنْزِلِهِ صَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Al Haitsam bin Jamil] dari [Ubaidullah bin Amru Ar Raqi] berkata, telah menceritakan kepada kami [Abdullah bin Muhammad bin Aqil] dari ['Atho` bin Yasar] dari [Abu Sa'id Al Khudri] berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak melaksanakan shalat apapun sebelum shalat ied, dan jika telah sampai di rumahnya beliau shalat dua raka'at. \""},"1251":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْرُجُ إِلَى الْعِيدِ مَاشِيًا وَيَرْجِعُ مَاشِيًا","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin 'Ammar bin Sa'd] berkata, telah menceritakan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] berkata, \"Nabi shallallahu 'alaihi wasallam berangkat menuju shalat ied dengan berjalan, demikian juga ketika kembali. \""},"1252":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ الْعُمَرِيُّ عَنْ أَبِيهِ وَعُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ إِلَى الْعِيدِ مَاشِيًا وَيَرْجِعُ مَاشِيًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami ['Abdurrahman bin Abdullah Al Umari] dari [Bapaknya] dan [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berangkat menuju shalat ied dengan berjalan, demikian juga ketika kembali. \" "},"1253":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَإِنَّ مِنْ السُّنَّةِ أَنْ يُمْشَى إِلَى الْعِيدِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata, \"Termasuk dari sunnah adalah berjalan kaki menuju shalat ied. \""},"1254":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْخَطَّابِ حَدَّثَنَا مِنْدَلٌ عَنْ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِي الْعِيدَ مَاشِيًا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Al Khaththab] berkata, telah menceritakan kepada kami [Mindal] dari [Muhammad bin Ubaidullah bin Abu Rafi'] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi shalat ied dengan berjalan kaki. \""},"1255":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ أَخْبَرَنِي أَبِي عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ إِلَى الْعِيدَيْنِ سَلَكَ عَلَى دَارِ سَعِيدِ بْنِ أَبِي الْعَاصِ ثُمَّ عَلَى أَصْحَابِ الْفَسَاطِيطِ ثُمَّ انْصَرَفَ فِي الطَّرِيقِ الْأُخْرَى طَرِيقِ بَنِي زُرَيْقٍ ثُمَّ يَخْرُجُ عَلَى دَارِ عَمَّارِ بْنِ يَاسِرٍ وَدَارِ أَبِي هُرَيْرَةَ إِلَى الْبَلَاطِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Sa'd bin Ammar bin Sa'd] berkata, telah mengabarkan kepadaku [Bapakku] dari [Bapaknya] dari [Kakeknya] berkata, \"Jika Nabi shallallahu 'alaihi wasallam berangkat menuju shalat iedul fitri dan iedul adlha, beliau melintasi depan rumah Sa'id bin Abu Al 'Ash, kemudian melintasi para penghuni tenda, kemudian pergi ke jalan yang lain, yaitu jalan bani Zuraiq dan keluar melalui rumah Ammar bin Yasir, rumah Abu Hurairah hingga ke Al Balath (nama tempat). \" "},"1256":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو قُتَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يَخْرُجُ إِلَى الْعِيدِ فِي طَرِيقٍ وَيَرْجِعُ فِي أُخْرَى وَيَزْعُمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Qutaibah] berkata, telah menceritakan kepada kami [Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwasanya ia berangkat menuju 'ied melalui satu jalan, dan kembali dengan jalan lain. Dan ia meyakini bahwa Rasulullah shallallahu 'alaihi wasallam melakukan itu. \""},"1257":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْخَطَّابِ حَدَّثَنَا مِنْدَلٌ عَنْ مُحَمَّدِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْتِي الْعِيدَ مَاشِيًا وَيَرْجِعُ فِي غَيْرِ الطَّرِيقِ الَّذِي ابْتَدَأَ فِيهِ","id":"Telah menceritakan kepada kami [Ahmad Ibnul Azhar] berkata, telah menceritakan kepada kami [Abdul Aziz Ibnul Khaththab] berkata, telah menceritakan kepada kami [Mindal] dari [Muhammad bin Ubaidullah bin Abu Rafi'] dari [bapaknya] dari [Kakeknya] berkata, \"Nabi shallallahu 'alaihi wasallam berangkat shalat ied dengan berjalan kaki, dan beliau kembali pulang dengan menggunakan jalur lain. \""},"1258":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ الزُّرَقِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ إِلَى الْعِيدِ رَجَعَ فِي غَيْرِ الطَّرِيقِ الَّذِي أَخَذَ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] berkata, telah menceritakan kepada kami [Abu Tumailah] dari [Fulaih bin Sulaim] dari [Sa'id bin Al Harits Az Zuraqi] dari [Abu Hurairah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam keluar menuju shalat ied, maka beliau kembali pulang dengan jalur lain. \""},"1259":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا شَرِيكٌ عَنْ مُغِيرَةَ عَنْ عَامِرٍ قَالَشَهِدَ عِيَاضٌ الْأَشْعَرِيُّ عِيدًا بِالْأَنْبَارِ فَقَالَ مَا لِي لَا أَرَاكُمْ تُقَلِّسُونَ كَمَا كَانَ يُقَلَّسُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Syarik] dari [Mughirah] dari [Amir] ia berkata, \" ['Iyadl Al Asy'ari] menghadiri shalat ied di Al Ambar, ia lalu berkata, \"Kenapa aku tidak melihat kalian memukul rebana, sebagaimana pernah dilakukan pula di sisi Rasulullah shallallahu 'alaihi wasallam?\" "},"1260":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَامِرٍ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَمَا كَانَ شَيْءٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا وَقَدْ رَأَيْتُهُ إِلَّا شَيْءٌ وَاحِدٌ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَلَّسُ لَهُ يَوْمَ الْفِطْرِقَالَ أَبُو الْحَسَنِ بْنُ سَلَمَةَ الْقَطَّانُ حَدَّثَنَا ابْنُ دِيزِيلَ حَدَّثَنَا آدَمُ حَدَّثَنَا شَيْبَانُ عَنْ جَابِرٍ عَنْ عَامِرٍ ح وَحَدَّثَنَا إِسْرَائِيلُ عَنْ جَابِرٍ ح وَحَدَّثَنَا إِبْرَاهِيمُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَامِرٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abu Nu'aim] dari [Isra'il] dari [Abu Ishaq] dari [Amir] dari [Qais bin Sa'd] ia berkata; Segala sesuatu yang terjadi di masa Rasulullah shallallahu 'alaihi wasallam aku telah menyaksikannya, kecuali satu hal. Yakni, pada hari iedul fitri Rasulullah shallallahu 'alaihi wasallam di sambut dengan rebana. \" Abul Hasan bin Salamah Al Qaththan berkata; telah menceritakan kepada kami Ibnu Dizil, berkata; telah menceritakan kepada kami Adam, berkata; telah menceritakan kepada kami Syaiban, berkata; Jabir dari Amir. (dalam jalur lain disebutkan) Telah menceritakan kepada kami Isra'il dari Jabir. (dalam jalur lain disebutkan) Telah menceritakan kepada kami Ibrahim bin Nashr, berkata; telah menceritakan kepada kami Abu Nu'aim, berkata; telah menceritakan kepada kami Syarik, dari Ishaq, dari Amir sebagaimana dalam hadits. \""},"1261":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَا حَدَّثَنَا الْأَوْزَاعِيُّ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْدُو إِلَى الْمُصَلَّى فِي يَوْمِ الْعِيدِ وَالْعَنَزَةُ تُحْمَلُ بَيْنَ يَدَيْهِ فَإِذَا بَلَغَ الْمُصَلَّى نُصِبَتْ بَيْنَ يَدَيْهِ فَيُصَلِّي إِلَيْهَا وَذَلِكَ أَنَّ الْمُصَلَّى كَانَ فَضَاءً لَيْسَ فِيهِ شَيْءٌ يُسْتَتَرُ بِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Isa bin Yunus]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] keduanya berkata; telah menceritakan kepada kami [Al Auza'i] berkata, telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] berkata, \"Di pagi menjelang siang Rasulullah shallallahu 'alaihi wasallam berangkat melaksanakan shalat ied, sementara beliau membawa tombak kecil. Ketika sampai di tempat lapang, tombak kecil itu ditancapkan di hadapannya kemudian beliau shalat menghadapnya. Hal itu karena tanah lapang adalah tempat yang terbuka dan tidak ada sesuatu yang menutupinya. \""},"1262":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى يَوْمَ عِيدٍ أَوْ غَيْرَهُ نُصِبَتْ الْحَرْبَةُ بَيْنَ يَدَيْهِ فَيُصَلِّي إِلَيْهَا وَالنَّاسُ مِنْ خَلْفِهِقَالَ نَافِعٌ فَمِنْ ثَمَّ اتَّخَذَهَا الْأُمَرَاءُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Ubaidulah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam shalat di hari ied atau selainnya, beliau menancapkan tombak kecil di depannya, lalu beliau shalat menghadapnya sementara orang-orang di belakangnya. \" Nafi' berkata, \"Hal itu juga dilakukan oleh para umara (pemimpin-pemimpin). \" "},"1263":{"ar":"حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْعِيدَ بِالْمُصَلَّى مُسْتَتِرًا بِحَرْبَةٍ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat 'ied di tanah lapang dengan menjadikan tombak sebagai satirnya. \" "},"1264":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُخْرِجَهُنَّ فِي يَوْمِ الْفِطْرِ وَالنَّحْرِ قَالَ قَالَتْ أُمُّ عَطِيَّةَ فَقُلْنَا أَرَأَيْتَ إِحْدَاهُنَّ لَا يَكُونُ لَهَا جِلْبَابٌ قَالَ فَلْتُلْبِسْهَا أُخْتُهَا مِنْ جِلْبَابِهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Hassan] dari [Hafshah binti Sirin] dari [Ummu Athiah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar kami mengeluarkan mereka di hari raya iedul fitri dan iedul adlha. \" Ia berkata, \"Ummu Athiah berkata, \"kami bertanya, \"Bagaimana pendapat tuan jika salah seorang dari kami tidak mempunyai jilbab?\" beliau menjawab: \"Hendaklah saudara wanitanya memakaikan dari jilbab miliknya. \""},"1265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْرِجُوا الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ لِيَشْهَدْنَ الْعِيدَ وَدَعْوَةَ الْمُسْلِمِينَ وَلْيَجْتَنِبَنَّ الْحُيَّضُ مُصَلَّى النَّاسِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Sufyan] dari [Ayyub] dari [Ibnu Sirin] dari [Ummu Athiah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keluarkanlah para wanita-wanita belia (gadis) dan wanita berhijab untuk menghadiri shalat ied dan do`a kaum muslimin. Dan jauhkanlah wanita haid dari tempat shalat. \""},"1266":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ حَدَّثَنَا حَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُخْرِجُ بَنَاتِهِ وَنِسَاءَهُ فِي الْعِيدَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] berkata, telah menceritakan kepada kami [Hajjaj bin Arthah] dari ['Abdurrahman bin Abis] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam mengajak anak-anak wanita dan isteri-isterinya di dua hari ied. \""},"1267":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ إِيَاسِ بْنِ أَبِي رَمْلَةَ الشَّامِيِّ قَالَسَمِعْتُ رَجُلًا سَأَلَ زَيْدَ بْنَ أَرْقَمَ هَلْ شَهِدْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِيدَيْنِ فِي يَوْمٍ قَالَ نَعَمْ قَالَ فَكَيْفَ كَانَ يَصْنَعُ قَالَ صَلَّى الْعِيدَ ثُمَّ رَخَّصَ فِي الْجُمُعَةِ ثُمَّ قَالَ مَنْ شَاءَ أَنْ يُصَلِّيَ فَلْيُصَلِّ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Isra'il] dari [Utsman Ibnul Mughirah] dari [Iyas bin Abu Armalah Asy Syami] berkata; Aku mendengar seorang laki-laki bertanya kepada [Zaid bin Arqam], \"Apakah kamu bersama Rasulullah shallallahu 'alaihi wasallam pernah menyaksikan dua hari raya dalam satu hari?\" ia menjawab, \"Ya, \" laki-laki itu berkata, \"Lalu apa yang dilakukan oleh Rasulullah?\" ia menjawab, \"Beliau melaksanakan shalat ied dan memberikan keringanan untuk melaksanakan shalat jum'at, setelah itu beliau mengatakan: \"Barangsiapa ingin melaksanakan shalat (jum'at), silahkan mengerjakannya.\""},"1268":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي مُغِيرَةُ الضَّبِّيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي صَالِحٍ عَنْ ابْنِ عَبَّاسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ اجْتَمَعَ عِيدَانِ فِي يَوْمِكُمْ هَذَا فَمَنْ شَاءَ أَجْزَأَهُ مِنْ الْجُمُعَةِ وَإِنَّا مُجَمِّعُونَ إِنْ شَاءَ اللَّهُحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي مُغِيرَةُ الضَّبِّيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Mughirah Adl Dlabbi] dari [Abdul Aziz bin Rafi'] dari [Abu Shalih] dari [Ibnu Abbas] dari Rasulullah shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Pada hari kalian ini telah terkumpul dua hari raya, barangsiapa berkehendak, ia tidak perlu lagi shalat jum'at, namun kami akan melaksanakannya, jika Allah menghendaki. \" Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Abdu Rabbih] berkata, telah menceritakan kepada kami [Baqiyyah] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Mughirah Adl Dlabbi] dari [Abdul Aziz bin Rufai'] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1269":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا مِنْدَلُ بْنُ عَلِيٍّ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَاجْتَمَعَ عِيدَانِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ ثُمَّ قَالَ مَنْ شَاءَ أَنْ يَأْتِيَ الْجُمُعَةَ فَلْيَأْتِهَا وَمَنْ شَاءَ أَنْ يَتَخَلَّفَ فَلْيَتَخَلَّفْ","id":"Telah menceritakan kepada kami [Jubarah bin Al Mughallis] berkata, telah menceritakan kepada kami [Mindal bin Ali] dari [Abdul Aziz bin Umar] dari [Nafi'] dari [Ibnu Umar] dia berkata, \"Dua hari raya terkumpul menjadi satu pada masa Rasulullah shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam kemudian shalat bersama orang-orang, lalu bersabda: \"Barangsiapa ingin mendatangi jum'at hendaklah ia mendatanginya, dan barangsiapa ingin meninggalkannya hendaklah ia tinggalkan. \" "},"1270":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عِيسَى بْنُ عَبْدِ الْأَعْلَى بْنِ أَبِي فَرْوَةَ قَالَ سَمِعْتُ أَبَا يَحْيَى عُبَيْدَ اللَّهِ التَّيْمِيَّ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَأَصَابَ النَّاسَ مَطَرٌ فِي يَوْمِ عِيدٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِهِمْ فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Isa bin Abdul A'la bin Abu Farwah] ia berkata; Aku mendengar [Abu Yahya Ubaidullah At Taimi] menceritakan hadits dari [Abu Hurairah] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam orang-orang diguyur hujan di hari raya, maka beliau pun shalat bersama mereka di masjid. \" "},"1271":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنَا نَائِلُ بْنُ نَجِيحٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ زِيَادٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُلْبَسَ السِّلَاحُ فِي بِلَادِ الْإِسْلَامِ فِي الْعِيدَيْنِ إِلَّا أَنْ يَكُونُوا بِحَضْرَةِ الْعَدُوِّ","id":"Telah menceritakan kepada kami [Abdul Quddus bin Muhammad] berkata, telah menceritakan kepada kami [Na`il bin Najih] berkata, telah menceritakan kepada kami [Isma'il bin Ziyad] dari [Ibnu Juraij] dari ['Atho`] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam melarang menenteng senjata di negeri-negeri Islam pada dua hari raya, kecuali mereka berhadapan dengan musuh. \""},"1272":{"ar":"حَدَّثَنَا جُبَارَةُ بْنُ الْمُغَلِّسِ حَدَّثَنَا حَجَّاجُ بْنُ تَمِيمٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ يَوْمَ الْفِطْرِ وَيَوْمَ الْأَضْحَى","id":"Telah menceritakan kepada kami [Jubarah Al Mughallis] berkata, telah menceritakan kepada kami [Hajjaj bin Tamim] dari [Maimun bin Mihran] dari [Ibnu Abbas] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mandi pada hari raya iedul Fitri dan iedul Adlha. \""},"1273":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا يُوسُفُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُقْبَةَ بْنِ الْفَاكِهِ بْنِ سَعْدٍ عَنْ جَدِّهِ الْفَاكِهِ بْنِ سَعْدٍ وَكَانَتْ لَهُ صُحْبَةٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ يَوْمَ الْفِطْرِ وَيَوْمَ النَّحْرِ وَيَوْمَ عَرَفَةَوَكَانَ الْفَاكِهُ يَأْمُرُ أَهْلَهُ بِالْغُسْلِ فِي هَذِهِ الْأَيَّامِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Yusuf bin Khalid] berkata, telah menceritakan kepada kami [Abu Ja'far Al Khathmi] dari ['Abdurrahman bin Uqbah Ibnul Fakih bin Sa'd] dari kakeknya [Al Fakih bin Sa'd] -ia seorang sahabat Nabi- berkata, \"Rasulullah shallallahu 'alaihi wasallam selalu mandi di hari iedul fitri, iedul adlha dan hari Arafah, \" dan Al Fakih sendiri selalu memerintahkan keluarganya untuk mandi pada hari-hari itu. \""},"1274":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ الضَّحَّاكِ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو عَنْ يَزِيدَ بْنِ خُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍأَنَّهُ خَرَجَ مَعَ النَّاسِ يَوْمَ فِطْرٍ أَوْ أَضْحَى فَأَنْكَرَ إِبْطَاءَ الْإِمَامِ وَقَالَ إِنْ كُنَّا لَقَدْ فَرَغْنَا سَاعَتَنَا هَذِهِ وَذَلِكَ حِينَ التَّسْبِيحِ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Adl Dlahhak] berkata, telah menceritakan kepada kami [Isma'il bin 'Ayyasy] berkata, telah menceritakan kepada kami [Shafwan bin Amru] dari [Yazid bin Khumair] dari [Abdullah bin Busr] Bahwasanya ia (Abdullah) bersama orang-orang berangkat pada hari raya iedul Fitri, atau iedul Adlha, ia mencela keterlambatan imam seraya mengatakan, \"Seharusnya kita telah selesai pada saat ini, dan itu tatkala tasbih. \""},"1275":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ مَثْنَى مَثْنَى","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] dari [Anas bin Sirin] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat malam dua raka'at-dua raka'at. \""},"1276":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua raka'at-dua raka'at. \""},"1277":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ وَعَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ و عَنْ ابْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ و عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ يُصَلِّي مَثْنَى مَثْنَى فَإِذَا خَافَ الصُّبْحَ أَوْتَرَ بِوَاحِدَةٍ","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya] dan dari [Abdullah bin Dinar] dari [Ibnu Umar]. (dalam jalur lain disebutkan) dari [Ibnu Abu Labid] dari [Abu Salamah] dari [Ibnu Umar]. (dalam jalur lain disebutkan pula) dari [Amru bin Dinar] dari [Thawus] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam ditanya tentang shalat malam, maka beliau pun menjawab: \"Hendaklah shalat dua raka'at-dua raka'at, jika khawatir datang subuh hendaklah witir satu raka'at. \""},"1278":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا عَثَّامُ بْنُ عَلِيٍّ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِاللَّيْلِ رَكْعَتَيْنِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Atstsam bin Ali] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat malam dua raka'at-dua raka'at. \""},"1279":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ أَنَّهُ سَمِعَ عَلِيًّا الْأَزْدِيَّ يُحَدِّثُ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ صَلَاةُ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَى","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Abu Bakr bin Khallad] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atho`] Bahwasanya ia mendengar [Ali Al Azdi] menceritakan, bahwasanya ia mendengar [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat di waktu malam dan siang hari dua raka'at-dua raka'at. \""},"1280":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ رُمْحٍ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ صَلَّى سُبْحَةَ الضُّحَى ثَمَانِيَ رَكَعَاتٍ ثُمَّ سَلَّمَ مِنْ كُلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Ibnu Wahb] dari [Iyadl bin Abdullah] dari [Makhramah bin Sulaiman] dari [Kuraib] mantan pelayan Ibnu Abbas, dari [Ummu Hani` binti Abu Thalib] berkata, \"Pada pembukaan kota Makkah Rasulullah shallallahu 'alaihi wasallam shalat sunnah Dluha delapan raka'at, kemudian beliau salam pada setiap dua raka'at. \""},"1281":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِي سُفْيَانَ السَّعْدِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي كُلِّ رَكْعَتَيْنِ تَسْلِيمَةٌ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Abu Sufyan As Sa'di] dari [Abu Nadlrah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada setiap dua raka'at ada salam. \""},"1282":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَبْدُ رَبِّهِ بْنُ سَعِيدٍ عَنْ أَنَسِ بْنِ أَبِي أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ نَافِعِ ابْنِ الْعَمْيَاءِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ الْمُطَّلِبِ يَعْنِي ابْنَ أَبِي وَدَاعَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى وَتَشَهَّدُ فِي كُلِّ رَكْعَتَيْنِ وَتَبَاءَسُ وَتَمَسْكَنُ وَتُقْنِعُ وَتَقُولُ اللَّهُمَّ اغْفِرْ لِي فَمَنْ لَمْ يَفْعَلْ ذَلِكَ فَهِيَ خِدَاجٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah bin Sawwar] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Abdu Rabbih bin Sa'id] dari [Anas bin Abu Anas] dari [Abdullah bin Nafi' bin Al 'Amya] dari [Abdullah bin Al Harits] dari [Al Muthallib] -yaitu Ibnu Abu Wada'ah- ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua raka'at-dua raka'at, dan bertasyahud pada setiap dua raka'at. Hendaklah berlaku tunduk, butuh dan berqana'ah. Dan hendaklah engkau ucapkan, \"Ya Allah, ampunilah aku, \" barangsiapa tidak melakukannya, maka tidak sempurna. \" "},"1283":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَامَ رَمَضَانَ وَقَامَهُ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berpuasa dan shalat (malam) di bulan ramadlan karena iman dan mengharap pahala, maka dosanya yang lalu akan diampuni. \""},"1284":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا مَسْلَمَةُ بْنُ عَلْقَمَةَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ عَنْ أَبِي ذَرٍّ قَالَصُمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَضَانَ فَلَمْ يَقُمْ بِنَا شَيْئًا مِنْهُ حَتَّى بَقِيَ سَبْعُ لَيَالٍ فَقَامَ بِنَا لَيْلَةَ السَّابِعَةِ حَتَّى مَضَى نَحْوٌ مِنْ ثُلُثِ اللَّيْلِ ثُمَّ كَانَتْ اللَّيْلَةُ السَّادِسَةُ الَّتِي تَلِيهَا فَلَمْ يَقُمْهَا حَتَّى كَانَتْ الْخَامِسَةُ الَّتِي تَلِيهَا ثُمَّ قَامَ بِنَا حَتَّى مَضَى نَحْوٌ مِنْ شَطْرِ اللَّيْلِ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ نَفَّلْتَنَا بَقِيَّةَ لَيْلَتِنَا هَذِهِ فَقَالَ إِنَّهُ مَنْ قَامَ مَعَ الْإِمَامِ حَتَّى يَنْصَرِفَ فَإِنَّهُ يَعْدِلُ قِيَامَ لَيْلَةٍ ثُمَّ كَانَتْ الرَّابِعَةُ الَّتِي تَلِيهَا فَلَمْ يَقُمْهَا حَتَّى كَانَتْ الثَّالِثَةُ الَّتِي تَلِيهَا قَالَ فَجَمَعَ نِسَاءَهُ وَأَهْلَهُ وَاجْتَمَعَ النَّاسُ قَالَ فَقَامَ بِنَا حَتَّى خَشِينَا أَنْ يَفُوتَنَا الْفَلَاحُ قِيلَ وَمَا الْفَلَاحُ قَالَ السُّحُورُ قَالَ ثُمَّ لَمْ يَقُمْ بِنَا شَيْئًا مِنْ بَقِيَّةِ الشَّهْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Maslamah bin Alqamah] dari [Dawud bin Abu Hind] dari [Al Walid bin 'Abdurrahman Al Jurasyi] dari [Jubair bin Nufair Al Hadlrami] dari [Abu Dzar] ia berkata, \"Kami puasa ramadlan bersama Rasulullah shallallahu 'alaihi wasallam, namun beliau tidak shalat malam sekalipun, hingga tersisa tujuh hari dari bulan tersebut. Beliau shalat malam bersama kami pada malam ke tujuh hingga lewat dari seperti malam. Pada malam ke enam beliau tidak shalat hingga masuk malam ke lima di hari berikutnya. Beliau lalu shalat malam bersama kami hingga lewat pertengahan malam. Aku berkata, \"Wahai Rasulullah, bagaimana jika sisa malam ini kita manfaatkan untuk shalat nafilah?\" beliau bersabda: \"Barangsiapa shalat bersama imam hingga selesai, sesungguhnya hal itu telah menyamai shalat satu malam penuh. \" Kemudian pada malam ke empat hari berikutnya beliau tidak shalat hingga masuk malam ke tiga di hari berikutnya. \" Abu Dzar berkata, \"Beliau mengumpulkan semua isteri dan keluarganya, dan orang-orang pun ikut berkumpul. \" Abu Dzar berkata, \"Beliau shalat bersama kami hingga kami khawatir kehilangan Al Falah, \" dikatakan kepadanya, \"Al Falah itu apa?\" ia menjawab, \"Sahur. \" Abu Dzar berkata, \"Setelah itu beliau tidak lagi shalat bersama kami hingga akhir bulan. \""},"1285":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ وَعُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ نَصْرِ بْنِ عَلِيٍّ الْجَهْضَمِيِّ عَنْ النَّضْرِ بْنِ شَيْبَانَ ح و حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَالْقَاسِمُ بْنُ الْفَضْلِ الْحُدَّانِيُّ كِلَاهُمَا عَنْ النَّضْرِ بْنِ شَيْبَانَ قَالَ لَقِيتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ فَقُلْتُ حَدِّثْنِي بِحَدِيثٍ سَمِعْتَهُ مِنْ أَبِيكَ يَذْكُرُهُ فِي شَهْرِ رَمَضَانَ قَالَ نَعَمْ حَدَّثَنِي أَبِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ شَهْرَ رَمَضَانَ فَقَالَ شَهْرٌ كَتَبَ اللَّهُ عَلَيْكُمْ صِيَامَهُ وَسَنَنْتُ لَكُمْ قِيَامَهُ فَمَنْ صَامَهُ وَقَامَهُ إِيمَانًا وَاحْتِسَابًا خَرَجَ مِنْ ذُنُوبِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dan ['Ubaidullah bin Musa] berkata, telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dari [Nadlr bin Syaiban]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Qasim bin Fadhl Al Huddani] keduanya dari [Nadlr bin Syaiban] ia berkata, \"Aku menemui [Abu Salamah bin 'Abdurrahman], aku lalu berkata, \"Riwayatkanlah satu hadits yang engkau dengar dari ayahmu berkenaan dengan bulan Ramadlan, \" ia berkata, \"Ya, [bapakku] telah menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam menyebut-nyebut bulan ramadlan, beliau bersabda: \" (Ramadlan) adalah bulan yang Allah mewajibkan kalian berpuasa, dan aku sunnahkan shalat di malam harinya. Barangsiapa berpuasa di siangnya dan bangun di malamnya karena iman dan mengharap pahala, maka dosa-dosanya akan keluar seperti pada hari dilahirkan oleh ibunya. \""},"1286":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْقِدُ الشَّيْطَانُ عَلَى قَافِيَةِ رَأْسِ أَحَدِكُمْ بِاللَّيْلِ بِحَبْلٍ فِيهِ ثَلَاثُ عُقَدٍ فَإِنْ اسْتَيْقَظَ فَذَكَرَ اللَّهَ انْحَلَّتْ عُقْدَةٌ فَإِذَا قَامَ فَتَوَضَّأَ انْحَلَّتْ عُقْدَةٌ فَإِذَا قَامَ إِلَى الصَّلَاةِ انْحَلَّتْ عُقَدُهُ كُلُّهَا فَيُصْبِحُ نَشِيطًا طَيِّبَ النَّفْسِ قَدْ أَصَابَ خَيْرًا وَإِنْ لَمْ يَفْعَلْ أَصْبَحَ كَسِلًا خَبِيثَ النَّفْسِ لَمْ يُصِبْ خَيْرًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada malam hari setan mengikat kepala salah seorang dari kalian dengan tiga ikatan, jika ia bangun dan berdzikir kepada Allah akan terlepas satu ikatan. Jika ia bangun dan berwudlu maka akan terlepas satu ikatan lagi. Jika ia berdiri shalat maka akan terbuka semua ikatannya. Dan pada pagi harinya ia akan menjadi bersemangat, berfikir positif dan telah mendapatkan kebaikan. Namun jika tidak, pada pagi harinya ia akan menjadi tidak bersemangat, berfikir negative dan tidak mendapatkan kebaikan. \""},"1287":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ نَامَ لَيْلَةً حَتَّى أَصْبَحَ قَالَ ذَلِكَ الشَّيْطَانُ بَالَ فِي أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] ia berkata, \"Disebutkan di sisi Rasulullah shallallahu 'alaihi wasallam seorang laki-laki yang tidur hingga datang waktu subuh, maka beliau pun bersabda: \"Setan telah mengencingi telinganya. \""},"1288":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكُنْ مِثْلَ فُلَانٍ كَانَ يَقُومُ اللَّيْلَ فَتَرَكَ قِيَامَ اللَّيْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abdullah bin Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu seperti si fulan, ia bangun malam tetapi tidak mengerjakan shalat malam. \" "},"1289":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ وَالْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ وَالْعَبَّاسُ بْنُ جَعْفَرٍ وَمُحَمَّدُ بْنُ عَمْرٍو الْحَدَثَانِيُّ قَالُوا حَدَّثَنَا سُنَيْدُ بْنُ دَاوُدَ حَدَّثَنَا يُوسُفُ بْنُ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أُمُّ سُلَيْمَانَ بْنِ دَاوُدَ لِسُلَيْمَانَ يَا بُنَيَّ لَا تُكْثِرْ النَّوْمَ بِاللَّيْلِ فَإِنَّ كَثْرَةَ النَّوْمِ بِاللَّيْلِ تَتْرُكُ الرَّجُلَ فَقِيرًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Zuhair bin Muhammad] [Al Hasan bin Muhammad bin Ash Shabbah] dan [Al Abbas bin Ja'far] dan [Muhammad bin Amru Al Hadatsani] mereka berkata; telah menceritakan kepada kami [Sunaid bin Dawud] berkata, telah menceritakan kepada kami [Yusuf bin Muhammad bin Al Munkadir] dari [Bapaknya] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ibunya Sulaiman bin Daud berkata kepada Sulaiman, \"Wahai anakku, janganlah memperbanyak tidur di malam hari, sesungguhnya banyak tidur di malam hari akan menjadikan seorang laki-laki fakir pada hari kiamat. \""},"1290":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُحَمَّدٍ الطَّلْحِيُّ حَدَّثَنَا ثَابِتُ بْنُ مُوسَى أَبُو يَزِيدَ عَنْ شَرِيكٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَثُرَتْ صَلَاتُهُ بِاللَّيْلِ حَسُنَ وَجْهُهُ بِالنَّهَارِ","id":"Telah menceritakan kepada kami [Isma'il bin Muhammad Ath Thalhi] berkata, telah menceritakan kepada kami [Tsabit bin Musa Abu Yazid] dari [Syarik] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memperbanyak shalat di malam hari, maka wajahnya akan berseri-seri di siang hari. \""},"1291":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَابْنُ أَبِي عَدِيٍّ وَعَبْدُ الْوَهَّابِ وَمُحَمَّدُ بْنُ جَعْفَرٍ عَنْ عَوْفِ بْنِ أَبِي جَمِيلَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ انْجَفَلَ النَّاسُ إِلَيْهِ وَقِيلَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتُ فِي النَّاسِ لِأَنْظُرَ إِلَيْهِ فَلَمَّا اسْتَبَنْتُ وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَفْتُ أَنَّ وَجْهَهُ لَيْسَ بِوَجْهِ كَذَّابٍ فَكَانَ أَوَّلَ شَيْءٍ تَكَلَّمَ بِهِ أَنْ قَالَ يَا أَيُّهَا النَّاسُ أَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَصَلُّوا بِاللَّيْلِ وَالنَّاسُ نِيَامٌ تَدْخُلُوا الْجَنَّةَ بِسَلَامٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Ibnu Abu 'Adi] dan [Abdul Wahhab] dan [Muhammad Ja'far] dari ['Auf bin Abu Jamilah] dari [Zurarah bin Aufa] dari [Abdullah bin Salam] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, orang-orang berlari menuju ke arahnya. Ketika diumumkan \"Rasulullah shallallahu 'alaihi wasallam telah tiba, \" maka aku pun mendatangi kerumunan orang-orang itu untuk melihat beliau. Ketika aku dapat melihat dengan jelas wajah Rasulullah shallallahu 'alaihi wasallam, aku dapat mengetahui bahwa wajah beliau bukanlah wajah seorang pendusta, dan pertama kali yang beliau ucapkan adalah: \"Wahai manusia, sebarkanlah salam, berilah makanan, dan shalatlah di malam hari ketika orang-orang tidur, maka kalian akan masuk surga dengan selamat. \""},"1292":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا شَيْبَانُ أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ الْأَغَرِّ عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَيْقَظَ الرَّجُلُ مِنْ اللَّيْلِ وَأَيْقَظَ امْرَأَتَهُ فَصَلَّيَا رَكْعَتَيْنِ كُتِبَا مِنْ الذَّاكِرِينَ اللَّهَ كَثِيرًا وَالذَّاكِرَاتِ","id":"Telah menceritakan kepada kami [Al 'Abbas bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Syaiban Abu Mu'awiyah] dari [Al 'Amasy] dari [Ali bin Al Aqmar] dari [Al Aghar] dari [Abu Sa'id] dan [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang laki-laki bangun di malam hari kemudian membangunkan isterinya hingga keduanya shalat dua raka'at, maka akan ditulis sebagai orang yang selalu banyak mengingat Allah. \""},"1293":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ رَجُلًا قَامَ مِنْ اللَّيْلِ فَصَلَّى وَأَيْقَظَ امْرَأَتَهُ فَصَلَّتْ فَإِنْ أَبَتْ رَشَّ فِي وَجْهِهَا الْمَاءَ رَحِمَ اللَّهُ امْرَأَةً قَامَتْ مِنْ اللَّيْلِ فَصَلَّتْ وَأَيْقَظَتْ زَوْجَهَا فَصَلَّى فَإِنْ أَبَى رَشَّتْ فِي وَجْهِهِ الْمَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memberi rahmat seorang laki-laki yang bangun malam kemudian shalat, lalu membangunkan isterinya kemudian shalat. Jika isterinya enggan ia memercikkan air di wajahnya. Dan semoga Allah memberi rahmat seorang wanita yang bangun malam kemudian shalat, lalu membangunkan suaminya kemudian shalat. Jika suaminya enggan ia memercikkan air di wajahnya. \""},"1294":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَحْمَدَ بْنِ بَشِيرِ بْنِ ذَكْوَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو رَافِعٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ السَّائِبِ قَالَقَدِمَ عَلَيْنَا سَعْدُ بْنُ أَبِي وَقَّاصٍ وَقَدْ كُفَّ بَصَرُهُ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَنْ أَنْتَ فَأَخْبَرْتُهُ فَقَالَ مَرْحَبًا بِابْنِ أَخِي بَلَغَنِي أَنَّكَ حَسَنُ الصَّوْتِ بِالْقُرْآنِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذَا الْقُرْآنَ نَزَلَ بِحُزْنٍ فَإِذَا قَرَأْتُمُوهُ فَابْكُوا فَإِنْ لَمْ تَبْكُوا فَتَبَاكَوْا وَتَغَنَّوْا بِهِ فَمَنْ لَمْ يَتَغَنَّ بِهِ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Abdullah bin Ahmad bin Basyir bin Dzakwan Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Abu Rafi'] dari [Ibnu Abu Mulaikah] dari ['Abdurrahman bin As Sa`ib] ia berkata, \" [Sa'd bin Abu Waqash] datang menemui kami sementara matanya telah buta, maka aku pun mengucapkan salam kepadanya, ia berkata, \"Siapa kamu?\" maka aku pun kabarkan kepadanya (siapa kami). Ia pun berkata, \"Selamat datang wahai anak saudaraku, telah sampai kepadaku bahwa suaramu bagus ketika membaca Al Qur`an. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Al Qur`an turun dengan kesedihan, jika kalian membacanya maka bacalah dengan menangis, jika kalian tidak bisa menangis maka berpura-puralah untuk menangis. Dan lagukanlah dalam membaca, barangsiapa tidak melagukannya maka ia bukan dari golongan kami. \""},"1295":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا حَنْظَلَةُ بْنُ أَبِي سُفْيَانَ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ سَابِطٍ الْجُمَحِيَّ يُحَدِّثُ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْأَبْطَأْتُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً بَعْدَ الْعِشَاءِ ثُمَّ جِئْتُ فَقَالَ أَيْنَ كُنْتِ قُلْتُ كُنْتُ أَسْتَمِعُ قِرَاءَةَ رَجُلٍ مِنْ أَصْحَابِكَ لَمْ أَسْمَعْ مِثْلَ قِرَاءَتِهِ وَصَوْتِهِ مِنْ أَحَدٍ قَالَتْ فَقَامَ وَقُمْتُ مَعَهُ حَتَّى اسْتَمَعَ لَهُ ثُمَّ الْتَفَتَ إِلَيَّ فَقَالَ هَذَا سَالِمٌ مَوْلَى أَبِي حُذَيْفَةَ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي أُمَّتِي مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Hanzhalah bin Abu Sufyan] Bahwasanya ia mendengar ['Abdurrahman bin Sabith Al Jumahi] menceritakan dari ['Aisyah] -isteri Nabi shallallahu 'alaihi wasallam- ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam aku datang terlambat pada malam hari setelah isya, setelah aku datang, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dari mana kamu?\" aku menjawab, \"Aku mendengar suara bacaan Al Qur`an seorang laki-laki dari sahabatmu, dan aku belum pernah mendengar suara sebagus itu. \" 'Aisyah berkata, \"Beliau lalu bangun dan aku pun ikut bangun bersamanya, beliau mendengar suaranya lalu menoleh ke arahku, beliau bersabda: \"Ini adalah Salim, mantan budak Abu Hudzaifah. Segala puji bagi Allah yang telah menjadikan dalam umatku orang seperti ini. \""},"1296":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الضَّرِيرُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْمَدَنِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْمَعِيلَ بْنِ مُجَمِّعٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَحْسَنِ النَّاسِ صَوْتًا بِالْقُرْآنِ الَّذِي إِذَا سَمِعْتُمُوهُ يَقْرَأُ حَسِبْتُمُوهُ يَخْشَى اللَّهَ","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Adl Dlarir] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far Al Madani] berkata, telah menceritakan kepada kami [Ibrahim bin Isma'il bin Mujammi'] dari [Abu Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang paling baik suaranya dalam membaca Al Qur`an adalah orang yang apabila kalian mendengarnya sedang membaca (Al Qur`an), kalian mengiranya ia takut kepada Allah. \""},"1297":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدِ بْنِ رَاشِدٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ عُبَيْدِ اللَّهِ عَنْ مَيْسَرَةَ مَوْلَى فَضَالَةَ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَلَّهُ أَشَدُّ أَذَنًا إِلَى الرَّجُلِ الْحَسَنِ الصَّوْتِ بِالْقُرْآنِ يَجْهَرُ بِهِ مِنْ صَاحِبِ الْقَيْنَةِ إِلَى قَيْنَتِهِ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id bin Rasyid Ar Ramli] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'i] berkata, telah menceritakan kepada kami [Isma'il bin Ubaidullah] dari [Maisarah] -mantan pelayan Fadlalah bin Ubaid- dari [Fadlalah bin Ubaid] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah lebih mudah dalam memberi izin bagi orang yang bacaan Al Qur`annya bagus untuk mengeraskan suaranya dari seorang pemilik budak kepada budaknya (untuk melagu). \""},"1298":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ فَسَمِعَ قِرَاءَةَ رَجُلٍ فَقَالَ مَنْ هَذَا فَقِيلَ عَبْدُ اللَّهِ بْنُ قَيْسٍ فَقَالَ لَقَدْ أُوتِيَ هَذَا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid, beliau mendengar bacaan Al Qur`an seorang laki-laki. Beliau bertanya: \"Siapa ini?\" dikatakan, \"Dia adalah Abdullah bin Qais. \" Beliau bersabda: \"Orang ini telah diberi seruling dari seruling keluarga Dawud. \""},"1299":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ طَلْحَةَ الْيَامِيَّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَوْسَجَةَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يُحَدِّثُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيِّنُوا الْقُرْآنَ بِأَصْوَاتِكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dan [Muhammad bin Ja'far] keduanya berkata; telah menceritakan kepada kami [Syu'bah] berkata; Aku mendengar [Thalhah Al Yami] berkata; Aku mendengar ['Abdurrahman bin 'Aujasah] berkata; Aku mendengar [Al Barra bin 'Azib] menceritakan, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hiasilah Al Qur`an dengan suara kalian. \""},"1300":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ وَعُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ أَخْبَرَاهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ حِزْبِهِ أَوْ عَنْ شَيْءٍ مِنْهُ فَقَرَأَهُ فِيمَا بَيْنَ صَلَاةِ الْفَجْرِ وَصَلَاةِ الظُّهْرِ كُتِبَ لَهُ كَأَنَّمَا قَرَأَهُ مِنْ اللَّيْلِ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah memberitakan kepada kami [Yunus bin Yazid] dari [Ibnu Syihab] bahwa [As Sa`ib bin Yazid] dan [Ubaidullah bin Abdullah] keduanya mengabarkan kepadanya dari ['Abdurrahman bin Abdul Qari] ia berkata; Aku mendengar [Umar Ibnul Khaththab] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tertidur hingga tidak membaca wirit atau sesuatu darinya, kemudian ia baca antara shalat subuh dan shalat zhuhur, maka akan dituliskan baginya seakan-akan ia melakukannya di waktu malam. \""},"1301":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ عَنْ أَبِي الدَّرْدَاءِيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى فِرَاشَهُ وَهُوَ يَنْوِي أَنْ يَقُومَ فَيُصَلِّيَ مِنْ اللَّيْلِ فَغَلَبَتْهُ عَيْنُهُ حَتَّى يُصْبِحَ كُتِبَ لَهُ مَا نَوَى وَكَانَ نَوْمُهُ صَدَقَةً عَلَيْهِ مِنْ رَبِّهِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah Al Hammal] berkata, telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] dari [Za`idah] dari [Sulaiman Al A'masy] dari [Habib bin Abu Tsabit] dari [Abdah bin Abu Lubabah] dari [Suwaid bin Ghaflah] dari [Abu Darda] dan sanadnya sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa beranjak tidur dengan niat untuk bangun dan shalat malam, namun kantuk mengalahkannya hingga tiba pagi, maka akan ditulis baginya apa yang dia niatkan, dan tidurnya dihitung sebagai sedekah dari Rabbnya. \""},"1302":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى الطَّائِفِيِّ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ عَنْ جَدِّهِ أَوْسِ بْنِ حُذَيْفَةَ قَالَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ ثَقِيفٍ فَنَزَّلُوا الْأَحْلَافَ عَلَى الْمُغِيرَةِ بْنِ شُعْبَةَ وَأَنْزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي مَالِكٍ فِي قُبَّةٍ لَهُ فَكَانَ يَأْتِينَا كُلَّ لَيْلَةٍ بَعْدَ الْعِشَاءِ فَيُحَدِّثُنَا قَائِمًا عَلَى رِجْلَيْهِ حَتَّى يُرَاوِحَ بَيْنَ رِجْلَيْهِ وَأَكْثَرُ مَا يُحَدِّثُنَا مَا لَقِيَ مِنْ قَوْمِهِ مِنْ قُرَيْشٍ وَيَقُولُ وَلَا سَوَاءَ كُنَّا مُسْتَضْعَفِينَ مُسْتَذَلِّينَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ بَيْنَنَا وَبَيْنَهُمْ نُدَالُ عَلَيْهِمْ وَيُدَالُونَ عَلَيْنَا فَلَمَّا كَانَ ذَاتَ لَيْلَةٍ أَبْطَأَ عَنْ الْوَقْتِ الَّذِي كَانَ يَأْتِينَا فِيهِ فَقُلْتُ يَا رَسُولَ اللَّهِ لَقَدْ أَبْطَأْتَ عَلَيْنَا اللَّيْلَةَ قَالَ إِنَّهُ طَرَأَ عَلَيَّ حِزْبِي مِنْ الْقُرْآنِ فَكَرِهْتُ أَنْ أَخْرُجَ حَتَّى أُتِمَّهُقَالَ أَوْسٌ فَسَأَلْتُ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ تُحَزِّبُونَ الْقُرْآنَ قَالُوا ثَلَاثٌ وَخَمْسٌ وَسَبْعٌ وَتِسْعٌ وَإِحْدَى عَشْرَةَ وَثَلَاثَ عَشْرَةَ وَحِزْبُ الْمُفَصَّلِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Abdullah bin 'Abdurrahman bin Ya'la Ath Tha`ifi] dari [Utsman bin Abdullah bin Aus] dari kakeknya [Aus bin Khudzaifah] ia berkata, \"Kami mendatangi Rasulullah shallallahu 'alaihi wasallam dalam rombongan utusan Bani Tsaqif, kemudian rombongan kabilah itu singgah menemui Al Mughirah bin Syu'bah, sementara Rasulullah shallallahu 'alaihi wasallam menempatkan Bani Malik di kubah miliknya. Beliau mendatangi kami setiap malam setelah isya, kemudian menceritakan hadits sambil berdiri di atas kedua kakinya sehingga berganti-gantian di antara kedua kakinya. Paling banyak yang beliau ceritakan adalah apa yang ia alami dari kaumnya, Quraisy. Beliau bersabda: \"Tidaklah sama, kami orang-orang yang lemah dan terhina, tatkala keluar ke Madinah peperangan silih berganti di antara kami dan mereka, kami mengalahkan mereka dan mereka mengalahkan kami. \" Tatkala suatu malam beliau terlambat dari waktu kedatangannya kepada kami, aku pun bertanya, \"Wahai Rasulullah, pada malam ini engkau terlambat datang kepada kami. \" Beliau bersabda: \"Sungguh, telah datang padaku bagianku dari Al Qur'an, maka aku tidak ingin keluar hingga menyempurnakannya. \" Aus berkata, \"Aku bertanya kepada para sahabat Rasulullah shallallahu 'alaihi wasallam; bagaimanakah kalian menggolong-golongkan Al Qur'an? Mereka menjawab: \"Tiga, lima, tujuh, sembilan, sebelas, tiga belas dan hizbul mufashshal. \""},"1303":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ يَحْيَى بْنِ حَكِيمِ بْنِ صَفْوَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَجَمَعْتُ الْقُرْآنَ فَقَرَأْتُهُ كُلَّهُ فِي لَيْلَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَخْشَى أَنْ يَطُولَ عَلَيْكَ الزَّمَانُ وَأَنْ تَمَلَّ فَاقْرَأْهُ فِي شَهْرٍ فَقُلْتُ دَعْنِي أَسْتَمْتِعْ مِنْ قُوَّتِي وَشَبَابِي قَالَ فَاقْرَأْهُ فِي عَشْرَةٍ قُلْتُ دَعْنِي أَسْتَمْتِعْ مِنْ قُوَّتِي وَشَبَابِي قَالَ فَاقْرَأْهُ فِي سَبْعٍ قُلْتُ دَعْنِي أَسْتَمْتِعْ مِنْ قُوَّتِي وَشَبَابِي فَأَبَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] dari [Yahya bin Hakim bin Shafwan] dari [Abdullah bin Amru] berkata; Aku mengumpulkan Al Qur`an dan membaca semuanya dalam semalam, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Aku khawatir terlalu lama hingga engkau menjadi bosan, bacalah dalam satu bulan. \" Aku menjawab, \"Biarkanlah aku enjoi dengan kemampuan dan masa mudaku. \" Beliau bersabda: \"Bacalah dalam sepuluh hari, \" aku menjawab, \"Biarkanlah aku enjoi dengan kemampuan dan masa mudaku. \" Beliau bersabda: \"Bacalah dalam tujuh hari, \" aku menjawab, \"Biarkanlah aku enjoi dengan kemampuan dan masa mudaku, \" namun beliau tidak setuju. \""},"1304":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمْ يَفْقَهْ مَنْ قَرَأَ الْقُرْآنَ فِي أَقَلَّ مِنْ ثَلَاثٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bakr bin Khallad] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Yazid bin Abdullah bin Asy Syikhkhir] dari [Abdullah bin Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan dapat memahami orang yang membaca Al Qur`an kurang dari tiga hari. \""},"1305":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ حَدَّثَنَا قَتَادَةُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْلَا أَعْلَمُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْقُرْآنَ كُلَّهُ حَتَّى الصَّبَاحِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] berkata, telah menceritakan kepada kami [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] ia berkata, \"Aku tidak pernah melihat Nabi Allah shallallahu 'alaihi wasallam membaca Al Qur`an hingga datang waktu subuh. \""},"1306":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ عَنْ أَبِي الْعَلَاءِ عَنْ يَحْيَى بْنِ جَعْدَةَ عَنْ أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ قَالَتْكُنْتُ أَسْمَعُ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ وَأَنَا عَلَى عَرِيشِي","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Mis'ar] dari [Abu Al 'Ala] dari [Yahya bin Ja'dah] dari [Ummu Hani` binti Abu Thalib] ia berkata, \"Aku mendengar bacaan Al Qur`an Nabi shallallahu 'alaihi wasallam di malam hari, sementara aku berada di atas bangsalku. \" "},"1307":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ قُدَامَةَ بْنِ عَبْدِ اللَّهِ عَنْ جَسْرَةَ بِنْتِ دَجَاجَةَ قَالَتْ سَمِعْتُ أَبَا ذَرٍّ يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِآيَةٍ حَتَّى أَصْبَحَ يُرَدِّدُهَا وَالْآيَةُ{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Qudamah bin Abdullah] dari [Jasrah binti Dajajah] ia berkata; Aku mendengar [Abu Dzar] berkata, \"Nabi shallallahu 'alaihi wasallam berdiri membaca ayat dan diulang-ulang, yakni ayat; \" (Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah Yang Maha Perkasa lagi Maha Bijaksana). \""},"1308":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فَكَانَ إِذَا مَرَّ بِآيَةِ رَحْمَةٍ سَأَلَ وَإِذَا مَرَّ بِآيَةِ عَذَابٍ اسْتَجَارَ وَإِذَا مَرَّ بِآيَةٍ فِيهَا تَنْزِيهٌ لِلَّهِ سَبَّحَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Sa'd bin Ubaidah] dari [Al Mustaurid Ibnul Ahnaf] dari [Shillah bin Zufar] dari [Hudzaifah] berkata, \"Jika Nabi shallallahu 'alaihi wasallam, kemudian membaca ayat yang berkenaan dengan rahmat beliau meminta, jika membaca ayat yang berkenaan dengan siksa beliau minta perlindungan, dan jika membaca ayat yang mensucikan Allah beliau bertasbih. \""},"1309":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي لَيْلَى قَالَصَلَّيْتُ إِلَى جَنْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي مِنْ اللَّيْلِ تَطَوُّعًا فَمَرَّ بِآيَةِ عَذَابٍ فَقَالَ أَعُوذُ بِاللَّهِ مِنْ النَّارِ وَوَيْلٌ لِأَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Hasyim] dari [Ibnu Abu Laila] dari [Tsabit] dari ['Abdurrahman bin Abu Laila] dari [Abu Laila] ia berkata, \"Aku shalat di samping Rasulullah shallallahu 'alaihi wasallam yang sedang shalat malam untuk thathawu', ketika beliau membaca satu ayat yang berkenaan dengan siksa beliau bersabda: \"Aku berlindung kepada Allah dari neraka dan dari Wail yang diperuntukkan bagi penghuni neraka. \""},"1310":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ قَالَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ قِرَاءَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ يَمُدُّ صَوْتَهُ مَدًّا","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Jarir bin Hazim] dari [Qatadah] ia berkata, \"Aku bertanya kepada [Anas bin Malik] tentang bacaan Nabi shallallahu 'alaihi wasallam, ia menjawab, \"Beliau memanjangkan suaranya. \""},"1311":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ بُرْدِ بْنِ سِنَانٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ غُضَيْفِ بْنِ الْحَارِثِ قَالَأَتَيْتُ عَائِشَةَ فَقُلْتُ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْهَرُ بِالْقُرْآنِ أَوْ يُخَافِتُ بِهِ قَالَتْ رُبَّمَا جَهَرَ وَرُبَّمَا خَافَتَ قُلْتُ اللَّهُ أَكْبَرُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي هَذَا الْأَمْرِ سَعَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Burd bin Sinan] dari [Ubadah bin Nusay] dari [Ghudlaif bin Al Harits] ia berkata, \"Aku mendatangi ['Aisyah] dan bertanya; apakah Rasulullah shallallahu 'alaihi wasallam mengeraskan bacaan Al Qur'annya, atau membacanya dengan pelan? Ia menjawab: \"Kadang dengan keras dan kadang dengan pelan. \" Aku berkata, \"Maha Besar Allah, segala puji bagi Allah, yang telah menjadikan urusan ini luas. \" "},"1312":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَهَجَّدَ مِنْ اللَّيْلِ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ قَيَّامُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ مَالِكُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ الْحَقُّ وَوَعْدُكَ حَقٌّ وَقَوْلُكَ حَقٌّ وَلِقَاؤُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ وَالنَّبِيُّونَ حَقٌّ وَمُحَمَّدٌ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَ وَلَا إِلَهَ غَيْرُكَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِكَحَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا سُلَيْمَانُ بْنُ أَبِي مُسْلِمٍ الْأَحْوَلُ خَالُ ابْنِ أَبِي نَجِيحٍ سَمِعَ طَاوُسًا عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ لِلتَّهَجُّدِ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Sulaiman Al Ahwal] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Jika shalat malam Rasulullah shallallahu 'alaihi wasallam membaca: \"ALLAHUMMA LAKAL HAMDU ANTA NUURUS SAMAWAATI WAL ARDLI WA MAN FIHINNA WA LAKAL HAMDU ANTA QAYYAAMUS SAMAWAATI WAL ARDLI WA MAN FIHINNA WA LAKAL HAMDU ANTA MAALIKUS SAMAWAATI WAL ARDLI WA MAN FIHINNA WA LAKAL HAMDU ANTAL HAQQU WA WA'DUKA HAQQUN WA QAULUKA HAQQUN WA LIQAA`UKA HAQQUN WA JANNATU HAQQUN WANNARU HAQQUN WAS SAA'ATU HAQQUN WANNABIYYUUNA HAQQUN WA MUHAMMADUN HAQQUN ALLAHUMMA LAKA ASLAMTU WA BIKA AAMANTU WA 'ALAIKA TAWAKKALTU WA ILAIKA ANABTU WA BIKA KHAASHAMTU WA ILAIKA HAAKAMTU FAGHFIRLI MAA QADDAMTU WA MAA ASRARTU WA MAA A'LANTU ANTAL MUQADDIM WA ANTAL MU`AKHKHIR LAA ILAAHA ILLA ANTA WA LAA HAULA WA LAA QUWWATA ILLA BIKA. \" Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] berkata, telah menceritakan kepada kami [Sulaiman bin Abu Muslim Al Ahwal] -paman Ibnu Abu Najih- mendengar [Thawus] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam jika bangun malam untuk tahajjud, lalu ia menyebutkan sebagaimana dalam hadits. \""},"1313":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ حَدَّثَنِي أَزْهَرُ بْنُ سَعِيدٍ عَنْ عَاصِمِ بْنِ حُمَيْدٍ قَالَسَأَلْتُ عَائِشَةَ مَاذَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ بِهِ قِيَامَ اللَّيْلِ قَالَتْ لَقَدْ سَأَلْتَنِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ قَبْلَكَ كَانَ يُكَبِّرُ عَشْرًا وَيَحْمَدُ عَشْرًا وَيُسَبِّحُ عَشْرًا وَيَسْتَغْفِرُ عَشْرًا وَيَقُولُ اللَّهُمَّ اغْفِرْ لِي وَاهْدِنِي وَارْزُقْنِي وَعَافِنِي وَيَتَعَوَّذُ مِنْ ضِيقِ الْمُقَامِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] dari [Mu'awiyah bin Shalih] berkata, telah menceritakan kepadaku [Azhar bin Sa'id] dari ['Ashim bin Humaid] ia berkata, \"Aku bertanya kepada ['Aisyah]; \"Dengan apakah Nabi shallallahu 'alaihi wasallam membuka shalat malamnya? ia menjawab: \"Kamu telah menanyakan kepadaku sesuatu yang tidak pernah ditanyakan oleh orang lain sebelumnya. Beliau bertakbir sepuluh kali, bertahmid sepuluh kali, bertasbih sepuluh kali, beristighfar sepuluh kali lalu berdo'a; \"Ya Allah, ampunilah aku, tunjukkanlah aku, limpahkanlah rizki kepadaku, berilah kesehatan pada diriku, \" dan beliau juga berlindung dari sempitnya tempat berdiri pada hari kiamat. \""},"1314":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَسَأَلْتُ عَائِشَةَ بِمَ كَانَ يَسْتَفْتِحُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ إِذَا قَامَ مِنْ اللَّيْلِ قَالَتْ كَانَ يَقُولُ اللَّهُمَّ رَبَّ جِبْرَئِيلَ وَمِيكَائِيلَ وَإِسْرَافِيلَ فَاطِرَ السَّمَوَاتِ وَالْأَرْضِ عَالِمَ الْغَيْبِ وَالشَّهَادَةِ أَنْتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِيمَا كَانُوا فِيهِ يَخْتَلِفُونَ اهْدِنِي لِمَا اخْتُلِفَ فِيهِ مِنْ الْحَقِّ بِإِذْنِكَ إِنَّكَ لَتَهْدِي إِلَى صِرَاطٍ مُسْتَقِيمٍقَالَ عَبْدُ الرَّحْمَنِ بْنُ عُمَرَ احْفَظُوهُ جِبْرَئِيلَ مَهْمُوزَةً فَإِنَّهُ كَذَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Umar] berkata, telah menceritakan kepada kami [Umar bin Yunus Al Yamami] berkata, telah menceritakan kepada kami [Ikrimah bin Ammar] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdurrahman] ia berkata, \"Aku tanyakan kepada ['Aisyah]; ketika shalat malam bagaimana Nabi shallallahu 'alaihi wasallam membuka shalatnya?\" ia berkata, \"Beliau membaca; ALLAHUMMA RABBA JIBRA`IIL WA MIKAA`IL WA ISRAAFIIL FAATHIRAS SAMAWAATI WAL ARDLI 'AALIMAL GHAIBI WASY SYAHADAHI ANTA TAHKUMU BAINA 'IBAADIKA FIIMAA KAANUU FIIHI YAKHTALIFUUN IHDINII LIMAKHTULIFA FIIHI MINAL HAQQI BI IDZNIKA INNAKA LATAHDI ILAA SHIRAATHIN MUSTAQIIMIN. \" 'Abdurrahman bin Umar berkata, \"Biarkanlah dengan lafazh JIBRA`IIL (dengan kata kerja mahmuz), sebab seperti itulah lafadz asli dari Nabi shallallahu 'alaihi wasallam. \""},"1315":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ ح و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ وَهَذَا حَدِيثُ أَبِي بَك��رٍ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مَا بَيْنَ أَنْ يَفْرُغَ مِنْ صَلَاةِ الْعِشَاءِ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ فِي كُلِّ اثْنَتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ وَيَسْجُدُ فِيهِنَّ سَجْدَةً بِقَدْرِ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُ فَإِذَا سَكَتَ الْمُؤَذِّنُ مِنْ الْأَذَانِ الْأَوَّلِ مِنْ صَلَاةِ الصُّبْحِ قَامَ فَرَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Urwah] dari ['Aisyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid] berkata, telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] -dan ini adalah hadits Abu Bakr- ia berkata, \"Selepas waktu isya hingga fajar Nabi shallallahu 'alaihi wasallam shalat sebanyak sebelas raka'at. Pada setiap dua raka'at beliau salam dan witir dengan satu raka'at, dan pada setiap raka'at tersebut beliau sujud sekadar salah seorang dari kalian membaca lima puluh ayat sebelum mengangkat kepalanya. Jika mu`adzin diam setelah mengumandangkan adzan pertama pada shalat subuh, beliau berdiri dan shalat dua raka'at ringan. \""},"1316":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam shalat malam sebanyak tiga belas raka'at. \""},"1317":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي مِنْ اللَّيْلِ تِسْعَ رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam shalat malam sebanyak sembilan raka'at. \""},"1318":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ أَبُو عُبَيْدٍ الْمَدِينِيُّ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَامِرٍ الشَّعْبِيِّ قَالَسَأَلْتُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَعَبْدَ اللَّهِ بْنَ عُمَرَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَقَالَا ثَلَاثَ عَشْرَةَ رَكْعَةً مِنْهَا ثَمَانٍ وَيُوتِرُ بِثَلَاثٍ وَرَكْعَتَيْنِ بَعْدَ الْفَجْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Maimun Abu Ubaid Al Madani] berkata, telah menceritakan kepada kami [Bapakku] dari [Muhammad bin Ja'far] dari [Musa bin Uqbah] dari [Abu Ishaq] dari [Amir bin Sya'bi] ia berkata, \"Aku bertanya kepada [Abdullah bin Abbas] dan [Abdullah bin Umar] tentang shalat Rasulullah shallallahu 'alaihi wasallam pada waktu malam. Maka keduanya menjawab, \"Tiga belas raka'at; delapan raka'at tahajjud dan tiga raka'at shalat witir, ditambah dua raka'at shalat setelah fajar. \""},"1319":{"ar":"حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ عَاصِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعِ بْنِ ثَابِتٍ الزُّبَيْرِيُّ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ أَنَّ عَبْدَ اللَّهِ بْنَ قَيْسِ بْنِ مَخْرَمَةَ أَخْبَرَهُ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقُلْتُ لَأَرْمُقَنَّ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّيْلَةَ قَالَ فَتَوَسَّدْتُ عَتَبَتَهُ أَوْ فُسْطَاطَهُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ رَكْعَتَيْنِ طَوِيلَتَيْنِ طَوِيلَتَيْنِ طَوِيلَتَيْنِ ثُمَّ رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ فَتِلْكَ ثَلَاثَ عَشْرَةَ رَكْعَةً","id":"Telah menceritakan kepada kami [Abdus Salam bin Ashim] berkata, telah menceritakan kepada kami [Abdullah bin Nafi' bin Tsabit Az Zubairi] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Abdullah bin Abu Bakr] dari [Bapaknya] bahwa [Abdullah bin Qais bin Makhramah] mengabarkan kepadanya dari [Zaid bin Khalid Al Juhani] ia berkata, \"Sungguh, aku akan mengamati bagaimana shalat Rasulullah shallallahu 'alaihi wasallam di malam hari. \" Ia berkata, \"Maka aku pun memanjat lotengnya, beliau bangun dan shalat dua raka'at ringan, kemudian dua raka'at panjang, kemudian panjang, kemudian panjang. Setelah itu beliau shalat dua raka'at namun tidak sebagaimana dua raka'at sebelumnya, kemudian shalat dua raka'at namun tidak sebagaimana dua raka'at sebelumnya, kemudian shalat dua raka'at namun tidak sebagaimana dua raka'at sebelumnya. Setelah itu shalat dua raka'at dan witir. Maka genaplah tiga belas raka'at. \""},"1320":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ أَخْبَرَهُأَنَّهُ نَامَ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ آيَاتٍ مِنْ آخِرِ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ أُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Ma'n bin Isa] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Makhramah bin Sulaiman] dari [Kuraib] -mantan budak Ibnu Abbas- dari [Ibnu Abbas] ia mengabarkan kepadanya, bahwa ia pernah tidur di rumah Maimunah, isteri Nabi shallallahu 'alaihi wasallam -Maimunah adalah bibinya- ia berkata, \"Aku berbaring di bantal bagian sisinya, sementara Nabi shallallahu 'alaihi wasallam dan isterinya di bagian tengahnya. Hingga pada pertengahan malam atau kurang sedikit, atau lewat tengah malam atau lebih sedikit, Nabi shallallahu 'alaihi wasallam bangun seraya mengusap mukanya dengan kedua tangan sambil membaca sepuluh ayat terakhir surat Ali Imran. Setelah itu beliau berdiri menuju girbah (bejana) kulit yang tergantung, beliau wudlu darinya dan membaguskan wudlunya kemudian melaksanakan shalat. \" Abdullah bin Abbas berkata, \"Kemudian aku bangun dan melakukan sebagaimana yang beliau lakukan, aku berjalan dan berdiri di sisinya. Rasulullah shallallahu 'alaihi wasallam kemudian meletakkan tangan kanannya di kepalaku meraih daun telinga, beliau menggeser posisiku. Setelah itu beliau shalat dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian witir. Lalu beliau berbaring hingga tukang adzannya mendatanginya, beliau lalu shalat dua raka'at ringan baru kemudian keluar untuk melaksanakan shalat (subuh). \""},"1321":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ يَزِيدَ بْنِ طَلْقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ أَسْلَمَ مَعَكَ قَالَ ح��رٌّ وَعَبْدٌ قُلْتُ هَلْ مِنْ سَاعَةٍ أَقْرَبُ إِلَى اللَّهِ مِنْ أُخْرَى قَالَ نَعَمْ جَوْفُ اللَّيْلِ الْأَوْسَطُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Basysyar] dan [Muhammad Ibnul Walid] mereka berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atho`] dari [Yazid bin Thalq] dari ['Abdurrahman bin Al Bailani] dari [Amru bin Abasah] ia berkata, \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan kukatakan kepadanya, \"Wahai Rasulullah, siapakah yang akan selamat bersamamu? ' beliau menjawab: \"Orang merdeka dan budak, \" aku bertanya lagi, \"Apakah ada satu waktu yang paling dekat kepada Allah dari waktu yang lainnya?\" beliau menjawab: \"Ya, pertengahan malam. \""},"1322":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنَامُ أَوَّلَ اللَّيْلِ وَيُحْيِي آخِرَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaidullah] dari [Isra'il] dari [Abu Ishaq] dari [Al Aswad] dari ['Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam tidur di awal waktu dan shalat di akhir malamnya. \""},"1323":{"ar":"حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ وَيَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَأَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا تَبَارَكَ وَتَعَالَى حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ كُلَّ لَيْلَةٍ فَيَقُولُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ حَتَّى يَطْلُعَ الْفَجْرُ فَلِذَلِكَ كَانُوا يَسْتَحِبُّونَ صَلَاةَ آخِرِ اللَّيْلِ عَلَى أَوَّلِهِ","id":"Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Ustsmani] dan [Ya'qub bin Humaid bin Kasib] keduanya berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Abu Salamah] dan [Abu Abdullah Al Aghar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada setiap malam Rabb kita Tabaaraka wa Ta'ala turun pada sepertiga malam akhir, lalu Ia berfirman: \"Siapa yang meminta kepada-Ku maka Aku akan memberinya, siapa yang berdo`a kepada-Ku maka Aku akan mengabulkannya, dan siapa yang meminta ampun kepada-Ku maka Aku akan mengampuninya, \" hal itu hingga terbit fajar. \" Maka mereka lebih suka shalat di akhir malam daripada di awal malam. \""},"1324":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُمْهِلُ حَتَّى إِذَا ذَهَبَ مِنْ اللَّيْلِ نِصْفُهُ أَوْ ثُلُثَاهُ قَالَ لَا يَسْأَلَنَّ عِبَادِي غَيْرِي مَنْ يَدْعُنِي أَسْتَجِبْ لَهُ مَنْ يَسْأَلْنِي أُعْطِهِ مَنْ يَسْتَغْفِرْنِي أَغْفِرْ لَهُ حَتَّى يَطْلُعَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Mush'ab] dari [Al Auza'i] dari [Yahya bin Abu katsir] dari [Hilal bin Abu Maimunah] dari ['Atho` bin Yasar] dari [Rifa'ah Al Juhani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah memperlambat hingga berlalu setengah atau dua pertiga malam, Allah berfirman: \"Jangan sekali-kali para hamba-Ku meminta kepada selain Aku! Barangsiapa berdo`a kepada-Ku maka akan Aku kabulkan, barangsiapa meminta kepada-Ku maka akan Aku beri dan barangsiapa meminta ampun kepada-Ku maka akan Aku ampuni hingga terbit fajar. \""},"1325":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ وَأَسْبَاطُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَلْقَمَةَ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَتَانِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ مَنْ قَرَأَهُمَا فِي لَيْلَةٍ كَفَتَاهُقَالَ حَفْصٌ فِي حَدِيثِهِ قَالَ عَبْدُ الرَّحْمَنِ فَلَقِيتُ أَبَا مَسْعُودٍ وَهُوَ يَطُوفُ فَحَدَّثَنِي بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dan [Asbath bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari [Alqamah] dari [Abu Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah pada suatu malam, maka itu telah mencukupi. \" Hafsh menyebutkan dalam haditsnya, \"'Abdurrahman berkata, \"Aku bertemu Abu Mas'ud ketika thawaf, lalu ia menceritakan hadits itu kepadaku. \""},"1326":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari [Abu Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah dalam satu malam, maka itu telah cukup. \""},"1327":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا أَبُو مَرْوَانَ مُحَمَّدُ بْنُ عُثْمَانَ الْعُثْمَانِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَعَسَ أَحَدُكُمْ فَلْيَرْقُدْ حَتَّى يَذْهَبَ عَنْهُ النَّوْمُ فَإِنَّهُ لَا يَدْرِي إِذَا صَلَّى وَهُوَ نَاعِسٌ لَعَلَّهُ يَذْهَبُ فَيَسْتَغْفِرُ فَيَسُبُّ نَفْسَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdullah bin Numair]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Marwan Muhammad bin Utsman Al Utsmani] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] semuanya dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengantuk hendaklah tidur hingga rasa kantuknya hilang, sebab jika shalat dalam kondisi mengantuk ia tidak tahu, ia meminta ampun tetapi justru menghina dirinya. \""},"1328":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مُوسَى اللَّيْثِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَرَأَى حَبْلًا مَمْدُودًا بَيْنَ سَارِيَتَيْنِ فَقَالَ مَا هَذَا الْحَبْلُ قَالُوا لِزَيْنَبَ تُصَلِّي فِيهِ فَإِذَا فَتَرَتْ تَعَلَّقَتْ بِهِ فَقَالَ حُلُّوهُ حُلُّوهُ لِيُصَلِّ أَحَدُكُمْ نَشَاطَهُ فَإِذَا فَتَرَ فَلْيَقْعُدْ","id":"Telah menceritakan kepada kami [Imran bin Musa Al Laits] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk ke dalam masjid dan melihat seutas tali yang terbentang antara dua tiang, beliau bersabda: \"Ini tali apa?\" para sahabat, \"Ini tali milik Zainab yang ia gunakan untuk shalat, jika lelah ia mengikatkan talinya pada tiang tersebut. \" Maka beliau pun bersabda: \"Lepaskanlah, lepaskanlah, hendaklah kalian shalat ketika dalam kondisi kuat, jika lelah hendaklah duduk. \""},"1329":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ أَبِي بَكْرِ بْنِ يَحْيَى بْنِ النَّضْرِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَامَ أَحَدُكُمْ مِنْ اللَّيْلِ فَاسْتَعْجَمَ الْقُرْآنُ عَلَى لِسَانِهِ فَلَمْ يَدْرِ مَا يَقُولُ اضْطَجَعَ","id":"Telah menceritakan kepada kami [Ya`qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Abu Bakr bin Yahya bin An Nadlr] dari [Bapaknya] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian shalat malam dan terasa berat lisannya dalam melantunkan ayat Al Qur`an hingga tidak tahu apa yang ia ucapkan, hendaklah ia tidur. \""},"1330":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَعْقُوبُ بْنُ الْوَلِيدِ الْمَدَنِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ عِشْرِينَ رَكْعَةً بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Ya'qub bin Al Walid Al Madani] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat antara maghrib dan isya sebanyak dua puluh raka'at, maka Allah akan membangunkan baginya rumah di surga. \""},"1331":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَأَبُو عُمَرَ حَفْصُ بْنُ عُمَرَ قَالَا حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي عُمَرُ بْنُ أَبِي خَثْعَمٍ الْيَمَامِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى سِتَّ رَكَعَاتٍ بَعْدَ الْمَغْرِبِ لَمْ يَتَكَلَّمْ بَيْنَهُنَّ بِسُوءٍ عُدِلَتْ لَهُ عِبَادَةَ اثْنَتَيْ عَشْرَةَ سَنَةً","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Abu Umar Hafsh bin Umar] keduanya berkata; telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah menceritakan kepadaku [Umar bin Abu Khats'am Al Yamami] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat enam raka'at setelah maghrib, tidak mengucapkan ucapan-ucapan buruk antara raka'at tersebut, maka akan dituliskan baginya pahala shalat dua belas raka'at. \""},"1332":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ طَارِقٍ عَنْ عَاصِمِ بْنِ عَمْرٍو قَالَخَرَجَ نَفَرٌ مِنْ أَهْلِ الْعِرَاقِ إِلَى عُمَرَ فَلَمَّا قَدِمُوا عَلَيْهِ قَالَ لَهُمْ مِمَّنْ أَنْتُمْ قَالُوا مِنْ أَهْلِ الْعِرَاقِ قَالَ فَبِإِذْنٍ جِئْتُمْ قَالُوا نَعَمْ قَالَ فَسَأَلُوهُ عَنْ صَلَاةِ الرَّجُلِ فِي بَيْتِهِ فَقَالَ عُمَرُ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَّا صَلَاةُ الرَّجُلِ فِي بَيْتِهِ فَنُورٌ فَنَوِّرُوا بُيُوتَكُمْحَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْحُسَيْنِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ عَمْرٍو عَنْ عُمَيْرٍ مَوْلَى عُمَرَ بْنِ الْخَطَّابِ عَنْ عُمَرَ بْنِ الْخَطَّابِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Al Ahwash] dari [Thariq] dari [Ashim bin Amru] berkata, \"Sekelompok orang dari Irak mendatangi Umar, ketika mereka telah sampai di hadapannya, Umar berkata, \"Dari mana kamu?\" mereka menjawab, \"Dari penduduk Irak. \" Umar bertanya, \"Apakah kalian datang dengan izin?\" mereka menjawab, \"Ya. \" Ashim berkata, \"Lalu mereka bertanya kepada Umar tentang shalatnya seorang laki-laki yang dilakukan di dalam rumah, [Umar] pun menjawab, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Adapun shalatnya seorang laki-laki di dalam rumah adalah cahaya, maka terangilah rumah kalian dengan cahaya. \" Telah menceritakan kepada kami [Muhammad bin Abu Al Husain] berkata, telah menceritakan kepada kami [Abdullah bin Ja'far] berkata; telah menceritakan kepada kami [Abdullah bin Amru] dari [Zaid bin Abu Unaisah] dari [Abu Ishaq] dari [Ashim bin Amru] dari [Umair] -mantan budak Umar Ibnul Khaththab- dari [Umar Ibnul Khaththab] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1333":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَضَى أَحَدُكُمْ صَلَاتَهُ فَلْيَجْعَلْ لِبَيْتِهِ مِنْهَا نَصِيبًا فَإِنَّ اللَّهَ جَاعِلٌ فِي بَيْتِهِ مِنْ صَلَاتِهِ خَيْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami ['Abdurrahman bin mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian selesai dari shalatnya, hendaklah memberikan bagian dari shalatnya bagi rumahnya, sebab Allah menjadikan kebaikan bagi rumahnya dengan shalatnya tersebut. \""},"1334":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ وَعَبْدُ الرَّحْمَنِ بْنُ عُمَرَ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتَّخِذُوا بُيُوتَكُمْ قُبُورًا","id":"Telah menceritakan kepada kami [Zaid bin Akhzam] dan ['Abdurrahman bin Umar] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jadikan rumah kalian sebagai kuburan. \""},"1335":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ حَرَامِ بْنِ مُعَاوِيَةَ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ سَعْدٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا أَفْضَلُ الصَّلَاةُ فِي بَيْتِي أَوْ الصَّلَاةُ فِي الْمَسْجِدِ قَالَ أَلَا تَرَى إِلَى بَيْتِي مَا أَقْرَبَهُ مِنْ الْمَسْجِدِ فَلَأَنْ أُصَلِّيَ فِي بَيْتِي أَحَبُّ إِلَيَّ مِنْ أَنْ أُصَلِّيَ فِي الْمَسْجِدِ إِلَّا أَنْ تَكُونَ صَلَاةً مَكْتُوبَةً","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Al 'Ala Ibnul Harits] dari [Haram bin Mu'awiyah] dari pamannya [Abdullah bin Sa'd] ia berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam; lebih utama mana shalat di rumahku atau shalat di masjid?\" beliau bersabda: \"Tidakkah engkau lihat betapa dekatnya rumahku dengan masjid? Sungguh, sekiranya aku shalat di rumahku, maka itu lebih aku sukai daripada shalat di masjid, kecuali shalat wajib. \""},"1336":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَسَأَلْتُ فِي زَمَنِ عُثْمَانَ بْنِ عَفَّانَ وَالنَّاسُ مُتَوَافِرُونَ أَوْ مُتَوَافُونَ عَنْ صَلَاةِ الضُّحَى فَلَمْ أَجِدْ أَحَدًا يُخْبِرُنِي أَنَّهُ صَلَّاهَا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ أُمِّ هَانِئٍ فَأَخْبَرَتْنِي أَنَّهُ صَلَّاهَا ثَمَانَ رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Yazid bin Abu Ziyad] dari [Abdullah Ibnul Harits] ia berkata, \"Pada masa pemerintahan Utsman bin Affan aku bertanya, banyak orang-orang yang meninggalkan shalat dluha hingga aku tidak mendapatkan seseorang yang memberitahuku bahwasanya ia -yakni Nabi shallallahu 'alaihi wasallam- melaksanakannya (shalat dluha) selain [Ummu Hani`]. Ia mengabarkan kepadaku bahwa Nabi shallallahu 'alaihi wasallam melaksanakannya dengan mengerjakan delapan raka'at. \""},"1337":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ ثُمَامَةَ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى الضُّحَى ثِنْتَيْ عَشْرَةَ رَكْعَةً بَنَى اللَّهُ لَهُ قَصْرًا مِنْ ذَهَبٍ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Yunus bin Bukair] berkata, telah menceritakan kepada kami [Muhamad bin Ishaq] dari [Musa bin Anas] dari [Tsumamah bin Anas] dari [Anas bin Malik] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat dluha dua belas raka'at, maka Allah akan membangunkan baginya sebuah istana dari emas. \" "},"1338":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُعَاذَةَ الْعَدَوِيَّةِ قَالَتْ سَأَلْتُ عَائِشَةَأَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى قَالَتْ نَعَمْ أَرْبَعًا وَيَزِيدُ مَا شَاءَ اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Syababah] berkata, telah menceritakan kepada kami [Syu'bah] dari [Yazid Ar Risk] dari [Mu'adzah Al 'Adawiyah] ia berkata, \"Aku bertanya kepada ['Aisyah]; \"Apakah Nabi shallallahu 'alaihi wasallam melaksanakan shalat dluha? ia menjawab: \"Ya, empat raka'at. Beliau menambahnya atas sekehendak Allah. \""},"1339":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ النَّهَّاسِ بْنِ قَهْمٍ عَنْ شَدَّادٍ أَبِي عَمَّارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَافَظَ عَلَى شُفْعَةِ الضُّحَى غُفِرَتْ لَهُ ذُنُوبُهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki'] dari [An Nuhas bin Qahm] dari [Syaddad bin Abu Ammar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjaga dua raka'at dluha maka dosa-dosa yang telah lalu akan diampuni meskipun sebanyak buih di laut. \""},"1340":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ الْمُنْكَدِرِ يُحَدِّثُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا الِاسْتِخَارَةَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ إِذَا هَمَّ أَحَدُكُمْ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ مِنْ غَيْرِ الْفَرِيضَةِ ثُمَّ لِيَقُلْ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُك�� بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ هَذَا الْأَمْرَ فَيُسَمِّيهِ مَا كَانَ مِنْ شَيْءٍ خَيْرًا لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ خَيْرًا لِي فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاقْدُرْهُ لِي وَيَسِّرْهُ لِي وَبَارِكْ لِي فِيهِ وَإِنْ كُنْتَ تَعْلَمُ يَقُولُ مِثْلَ مَا قَالَ فِي الْمَرَّةِ الْأُولَى وَإِنْ كَانَ شَرًّا لِي فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدُرْ لِي الْخَيْرَ حَيْثُمَا كَانَ ثُمَّ رَضِّنِي بِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Khalid bin Makhlad] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Al Mawali] berkata; aku mendengar [Muhammad Ibnul Munkadir] menceritakan dari [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengajari kami do`a istikharah sebagaimana beliau mengajari kami surat Al Qur`an. Beliau bersabda: \"Jika salah seorang dari kalian menginginkan sesuatu hendaklah shalat sunnah dua raka'at, setelah itu ucapkanlah; \"ALLAHUMMA INNI ASTAKHIIRUKA BI 'ILMIKA WA ASTAQDIRUKA BI QURATIKA WA AS`ALUKA MIN FADLIKAL 'AZHIIM FA INNAKA TAQDIRU WA LAA AQDIRU WA TA'LAMU WA LAA A'LAMU WA ANTA ALLAAMUL GHUYUUB ALLAHUMMA IN KUNTA TA'LAMU HADZAL AMRA KHAIRAN LI FII DIINI WA MA'AASYII WA 'AAQIBATI AMRII AU KHAIRAN LII FII 'AAJILI AMRII WA AAJILIHI FAQDURHULII WA YASSIRHULII WA BAARIKLII FIIHI WA IN KUNTA TA'LAMU SYARRAN LII FASHRIFHU 'ANNII WASHRIFNII 'ANHU WAQDURHULIL KHAIRA HAISTUMAA KAANA TSUMMA RADLDLINII BIHI (Ya Allah, sesungguhnya aku meminta pilihan yang tepat kepada-Mu dengan ilmu pengetahuan-Mu dan aku memohon kekuasaan-Mu (untuk mengatasi persoalanku) dengan kemahakuasaan-Mu. Aku mohon kepada-Mu sesuatu dari anugerah-Mu Yang Maha Agung, sesungguhnya Engkau Maha Agung, sesungguhnya Engkau Maha kuasa, sedang aku tidak kuasa, Engkau mengetahui sedang aku tidak mengetahui, dan Engkau adalah Maha Mengetahui hal yang ghaib. Ya Allah, apabila Engkau mengetahui bahwa urusan ini -menyebutkan apa yang menjadi persoalannya- lebih baik dalam agama dan kehidupanku, dan akibat terhadap diriku, atau beliau mengatakan: \"baik bagiku di dunia dan di akhirat, maka takdirkanlah untukku, mudahkan, dan berkahilah. Akan tetapi jika Engkau tahu bahwa perkara ini -ia menyebutkan kembali persoalan yang ia sebutkan di muka- berakibat buruk bagiku, maka singkirkanlah persoalan tersebut dan jauhkan aku darinya. Takdirkanlah untukku di mana pun kebaikan itu berada, kemudian ridlailah aku dengannya. \""},"1341":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَاصِمٍ الْعَبَّادَانِيُّ عَنْ فَائِدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى الْأَسْلَمِيِّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ كَانَتْ لَهُ حَاجَةٌ إِلَى اللَّهِ أَوْ إِلَى أَحَدٍ مِنْ خَلْقِهِ فَلْيَتَوَضَّأْ وَلْيُصَلِّ رَكْعَتَيْنِ ثُمَّ لِيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ الْحَلِيمُ الْكَرِيمُ سُبْحَانَ اللَّهِ رَبِّ الْعَرْشِ الْعَظِيمِ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ اللَّهُمَّ إِنِّي أَسْأَلُكَ مُوجِبَاتِ رَحْمَتِكَ وَعَزَائِمَ مَغْفِرَتِكَ وَالْغَنِيمَةَ مِنْ كُلِّ بِرٍّ وَالسَّلَامَةَ مِنْ كُلِّ إِثْمٍ أَسْأَلُكَ أَلَّا تَدَعَ لِي ذَنْبًا إِلَّا غَفَرْتَهُ وَلَا هَمًّا إِلَّا فَرَّجْتَهُ وَلَا حَاجَةً هِيَ لَكَ رِضًا إِلَّا قَضَيْتَهَا لِي ثُمَّ يَسْأَلُ اللَّهَ مِنْ أَمْرِ الدُّنْيَا وَالْآخِرَةِ مَا شَاءَ فَإِنَّهُ يُقَدَّرُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Abu 'Ashim Al 'Abbadani] dari [Fa`id bin 'Abdurrahman] dari [Abdullah bin Abu Aufa Al Aslami] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar mengunjungi kami seraya bersabda: \"Barangsiapa memiliki hajat kepada Allah, atau kepada salah seorang dari makhluk-Nya, maka hendaklah ia berwudlu dan shalat dua raka'at, kemudian berdo'a \"LAA ILAAHA ILLA ALLAHU AL HALIIMUL KARIIMU SUBHAANAALLAHU RABBAL 'ARSYIL AZHIIMI AL HAMDULILLAHI RABBIL 'AALAMIIN ALLAHUMMA INNI AS`ALUKA MUUJIBAATI RAHMATIKA WA 'AZAA`IMI MAGHFIRATIKA WA GHANIIMATI MIN KULLI BIRRIN WAS SALAAMATA MIN KULLI ITSMIN AS`ALUKA ALLA TADA'A LII ILLA GHAFARTA WA LAA HAMMAN ILLA FARRAJTA WA LAA HAAJATAN HIYA LAKA RIDLAN ILLA QADLAITA LII (Tidak ada Tuhan yang berhak diibadahi kecuali Allah Yang Maha Lembut dan Maha Pemberi. Maha Suci Allah, pemilik 'Arsy yang agung, segala puji bagi Allah Rabb semesta alam. Ya Allah, sesungguhnya aku memohon kepada-Mu sesuatu yang mewajibkan datangnya rahmat-Mu dan hal-hal yang menguatkan datangnya ampunan-Mu, mendapatkan semua kebaikan, bersih dari segala dosa. Aku memohon kepada-Mu agar tidak meninggalkan dosa bagiku kecuali Engkau ampuni, dan kesedihan kecuali Engkau hapuskan, dan hajat yang Engkau ridlai kecuali engkau penuhi). \" Kemudian ia memohon kepada Allah dari urusan dunia dan akhirat apa yang dia inginkan. Sesungguhnya setiap orang telah ditentukan. \""},"1342":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنْصُورِ بْنِ سَيَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَعْفَرٍ الْمَدَنِيِّ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ عُثْمَانَ بْنِ حُنَيْفٍأَنَّ رَجُلًا ضَرِيرَ الْبَصَرِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْعُ اللَّهَ لِي أَنْ يُعَافِيَنِي فَقَالَ إِنْ شِئْتَ أَخَّرْتُ لَكَ وَهُوَ خَيْرٌ وَإِنْ شِئْتَ دَعَوْتُ فَقَالَ ادْعُهْ فَأَمَرَهُ أَنْ يَتَوَضَّأَ فَيُحْسِنَ وُضُوءَهُ وَيُصَلِّيَ رَكْعَتَيْنِ وَيَدْعُوَ بِهَذَا الدُّعَاءِ اللَّهُمَّ إِنِّي أَسْأَلُكَ وَأَتَوَجَّهُ إِلَيْكَ بِمُحَمَّدٍ نَبِيِّ الرَّحْمَةِ يَا مُحَمَّدُ إِنِّي قَدْ تَوَجَّهْتُ بِكَ إِلَى رَبِّي فِي حَاجَتِي هَذِهِ لِتُقْضَى اللَّهُمَّ شَفِّعْهُ فِيَّقَالَ أَبُو إِسْحَقَ هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Manshur bin Sayyar] berkata, telah menceritakan kepada kami [Utsman bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ja'far Al Madani] dari ['Umarah bin Khuzaimah bin Tsabit] dari [Utsman bin Hunaif] berkata, \"Seorang lelaki buta datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Do'akanlah aku agar Allah menyembuhkanku. \" Beliau bersabda: \"Jika kamu mau maka aku tangguhkan bagimu dan itu lebih baik, dan jika kamu mau maka aku akan do'akan kamu, \" ia berkata, \"Do'akanlah. \" Maka beliau menyuruhnya agar berwudlu dan membaguskan wudlunya, kemudian shalat dua raka'at dan berdo'a, \"Ya Allah, sesungguhnya aku meminta dan menghadap kepada-Mu dengan perantaraan Muhammad, Nabi pembawa rahmat. Ya Muhammad, aku telah menghadap dengan perantaraanmu kepada Rabbku di dalam hajatku ini agar terpenuhi. Ya Allah, berilah syafa'at kepadanya bagi diriku. \" Abu Ishaq berkata, \"Ini hadits shahih. \""},"1343":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ أَبُو عِيسَى الْمَسْرُوقِيُّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُوسَى بْنُ عُبَيْدَةَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ مَوْلَى أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِي رَافِعٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ يَا عَمِّ أَلَا أَحْبُوكَ أَلَا أَنْفَعُكَ أَلَا أَصِلُكَ قَالَ بَلَى يَا رَسُولَ اللَّهِ قَالَ فَصَلِّ أَرْبَعَ رَكَعَاتٍ تَقْرَأُ فِي كُلِّ رَكْعَةٍ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ فَإِذَا انْقَضَتْ الْقِرَاءَةُ فَقُلْ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ خَمْسَ عَشْرَةَ مَرَّةً قَبْلَ أَنْ تَرْكَعَ ثُمَّ ارْكَعْ فَقُلْهَا عَشْرًا ثُمَّ ارْفَعْ رَأْسَكَ فَقُلْهَا عَشْرًا ثُمَّ اسْجُدْ فَقُلْهَا عَشْرًا ثُمَّ ارْفَعْ رَأْسَك فَقُلْهَا عَشْرًا ثُمَّ اسْجُدْ فَقُلْهَا عَشْرًا ثُمَّ ارْفَعْ رَأْسَكَ فَقُلْهَا عَشْرًا قَبْلَ أَنْ تَقُومَ فَتِلْكَ خَمْسٌ وَسَبْعُونَ فِي كُلِّ رَكْعَةٍ وَهِيَ ثَلَاثُ مِائَةٍ فِي أَرْبَعِ رَكَعَاتٍ فَلَوْ كَانَتْ ذُنُوبُكَ مِثْلَ رَمْلِ عَالِجٍ غَفَرَهَا اللَّهُ لَكَ قَالَ يَا رَسُولَ اللَّهِ وَمَنْ لَمْ يَسْتَطِعْ يَقُولُهَا فِي يَوْمٍ قَالَ قُلْهَا فِي جُمُعَةٍ فَإِنْ لَمْ تَسْتَطِعْ فَقُلْهَا فِي شَهْرٍ حَتَّى قَالَ فَقُلْهَا فِي سَنَةٍ","id":"Telah menceritakan kepada kami [Musa bin 'Abdurrahman Abu Isa Al Masruqi] berkata, telah menceritakan kepada kami [Zaid Al Hubab] berkata, telah menceritakan kepada kami [Musa bin Ubaidah] berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id] -mantan budak Abu Bakr bin Amru bin Hazm- dari [Abu Rafi'] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abbas: \"Wahai paman, maukah jika aku memberimu hadiah, maukah jika aku memberikan manfaat kepadamu, maukah jika aku menyambung silaturahmi kepadamu?\" ia menjawab, \"Tentu, ya Rasulullah. \" Beliau bersabda: \"Shalatlah empat raka'at, di setiap raka'at engkau membaca Fatihatul kitab (surat Al Fatihah) dan satu surat. Apabila selesai membaca, maka ucapkanlah; \"SUBHAANALLAHU WAL HAMDULILLAH WA LAA ILAAHA ILLA ALLAHU WALLAHU AKBAR (Maha Suci Allah dan Segala Puji bagi Allah, tidak ada Tuhan Yang berhak disembah kecuali Allah, Allah Maha Besar) sebanyak lima belas kali sebelum rukuk. Kemudian rukuk dan ucapkanlah bacaan itu lagi sepuluh kali. Kemudian angkatlah kepalamu dan ucapkanlah lagi sepuluh kali, kemudian sujud dan ucapkanlah lagi sepuluh kali, kemudian angkatlah kepalamu dan ucapkanlah lagi sepuluh kali, kemudian sujud dan ucapkanlah lagi sepuluh kali, kemudian angkatlah kepalamu dan ucapkanlah lagi sepuluh kali sebelum engkau bangun. Semua itu genap berjumlah tujuh puluh lima dalam setiap raka'at, dan berjumlah tiga ratus dalam empat raka'at. Sekiranya dosa-dosamu seperti pasir yang menggunung, Allah akan mengampuninya. \" Abbas berkata, \"Wahai Rasulullah, bagaimana dengan orang yang tidak mampu mengucapkan itu dalam sehari?\" Beliau bersabda: \"Lakukanlah sekali dalam seminggu, jika tidak mampu maka lakukanlah sekali dalam sebulan, \" hingga beliau bersabda: \"Maka Lakukanlah sekali dalam setahun. \" "},"1344":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرِ بْنِ الْحَكَمِ النَّيْسَابُورِيُّ حَدَّثَنَا مُوسَى بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا الْحَكَمُ بْنُ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ يَا عَبَّاسُ يَا عَمَّاهُ أَلَا أُعْطِيكَ أَلَا أَمْنَحُكَ أَلَا أَحْبُوكَ أَلَا أَفْعَلُ لَكَ عَشْرَ خِصَالٍ إِذَا أَنْتَ فَعَلْتَ ذَلِكَ غَفَرَ اللَّهُ لَكَ ذَنْبَكَ أَوَّلَهُ وَآخِرَهُ وَقَدِيمَهُ وَحَدِيثَهُ وَخَطَأَهُ وَعَمْدَهُ وَصَغِيرَهُ وَكَبِيرَهُ وَسِرَّهُ وَعَلَانِيَتَهُ عَشْرُ خِصَالٍ أَنْ تُصَلِّيَ أَرْبَعَ رَكَعَاتٍ تَقْرَأُ فِي كُلِّ رَكْعَةٍ بِفَاتِحَةِ الْكِتَابِ وَسُورَةٍ فَإِذَا فَرَغْتَ مِنْ الْقِرَاءَةِ فِي أَوَّلِ رَكْعَةٍ قُلْتَ وَأَنْتَ قَائِمٌ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ خَمْسَ عَشْرَةَ مَرَّةً ثُمَّ تَرْكَعُ فَتَقُولُ وَأَنْتَ رَاكِعٌ عَشْرًا ثُمَّ تَرْفَعُ رَأْسَكَ مِنْ الرُّكُوعِ فَتَقُولُهَا عَشْرًا ثُمَّ تَهْوِي سَاجِدًا فَتَقُولُهَا وَأَنْتَ سَاجِدٌ عَشْرًا ثُمَّ تَرْفَعُ رَأْسَكَ مِنْ السُّجُودِ فَتَقُولُهَا عَشْرًا ثُمَّ تَسْجُدُ فَتَقُولُهَا عَشْرًا ثُمَّ تَرْفَعُ رَأْسَكَ مِنْ السُّجُودِ فَتَقُولُهَا عَشْرًا فَذَلِكَ خَمْسَةٌ وَسَبْعُونَ فِي كُلِّ رَكْعَةٍ تَفْعَلُ فِي أَرْبَعِ رَكَعَاتٍ إِنْ اسْتَطَعْتَ أَنْ تُصَلِّيَهَا فِي كُلِّ يَوْمٍ مَرَّةً فَافْعَلْ فَإِنْ لَمْ تَسْتَطِعْ فَفِي كُلِّ جُمُعَةٍ مَرَّةً فَإِنْ لَمْ تَفْعَلْ فَفِي كُلِّ شَهْرٍ مَرَّةً فَإِنْ لَمْ تَفْعَلْ فَفِي عُمُرِكَ مَرَّةً","id":"Telah menceritakan kepada kami ['Abdurrahman bin Bisyr bin Al Hakam] berkata, telah menceritakan kepada kami [Musa bin Abdul Aziz] berkata, telah menceritakan kepada kami [Al Hakam bin Aban] berkata, telah menceritakan kepada kami [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abbas bin Abdul Muththalib: \"Wahai Abbas, wahai paman, maukah jika aku menganugerahimu, maukah jika aku memberimu hadiah dan maukah jika aku berbuat untukmu sepuluh perbuatan terpuji? Jika kamu melakukannya, Allah akan mengampuni dosa-dosamu baik yang pertama atau yang terakhir, yang telah lalu atau yang baru, yang salah atau yang sengaja, yang kecil atau yang besar, yang tersembunyi atau yang nampak. Sepuluh hal itu adalah; engkau laksanakan shalat empat raka'at, pada setiap raka'atnya engkau baca Fatihatul kitab (surat al Fatihah) dan satu surat. Jika engkau selesai dari membaca di raka'at pertama, maka ucapkan dalam keadaan berdiri; \"SUBHAANALLAHU WAL HAMDULILLAH WA LAA ILAAHA ILLA ALLAHU WALLAHU AKBAR (Maha Suci Allah dan Segala Puji bagi Allah, tidak ada Tuhan Yang berhak disembah kecuali Allah, Allah Maha Besar) sebanyak lima belas kali. Kemudian engkau rukuk dan engkau baca sepuluh kali dalam kondisi seperti itu, lalu angkat kepalamu dari rukuk dan engkau ucapkan sebanyak sepuluh kali, kemudian engkau sujud dan engkau ucapkan sebanyak sepuluh kali ketika sujud. Kemudian engkau angkat kepalamu dari sujud dan engkau ucapkan sebanyak sepuluh kali. Kemudian engkau sujud dan engkau ucapkan sepuluh kali. Kemudian engkau angkat kepalamu dari sujud dan engkau ucapkan sepuluh kali. Maka semua itu berjumlah tujuh puluh lima dalam satu raka'at, dan lakukanlah hal itu di empat raka'at, jika engkau mampu melakukan shalat seperti itu sekali dalam setiap harinya maka lakukanlah. Jika tidak mampu maka lakukanlah sekali dalam tiap jum'atnya. Jika tidak mampu melakukannya maka lakukanlah sebulan sekali, jika tidak mampu melakukannya maka lakukanlah sekali seumur hidup. \""},"1345":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا ابْنُ أَبِي سَبْرَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ عَنْ مُعَاوِيَةَ بْنِ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَتْ لَيْلَةُ النِّصْفِ مِنْ شَعْبَانَ فَقُومُوا لَيْلَهَا وَصُومُوا نَهَارَهَا فَإِنَّ اللَّهَ يَنْزِلُ فِيهَا لِغُرُوبِ الشَّمْسِ إِلَى سَمَاءِ الدُّنْيَا فَيَقُولُ أَلَا مِنْ مُسْتَغْفِرٍ لِي فَأَغْفِرَ لَهُ أَلَا مُسْتَرْزِقٌ فَأَرْزُقَهُ أَلَا مُبْتَلًى فَأُعَافِيَهُ أَلَا كَذَا أَلَا كَذَا حَتَّى يَطْلُعَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah memberitakan kepada kami [Ibnu Abu Sabrah] dari [Ibrahim bin Muhammad] dari [Mu'awiyah bin Abdullah bin Ja'far] dari [Bapaknya] dari [Ali bin Abu Thalib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila malam nisfu Sya'ban (pertengahan bulan Sya'ban), maka shalatlah di malam harinya dan berpuasalah di siang harinya. Sesungguhnya Allah turun ke langit bumi pada saat itu ketika matahari terbenam, kemudian Dia berfirman: \"Adakah orang yang meminta ampun kepada-Ku, maka Aku akan mengampuninya? Adakah orang yang meminta rizki maka Aku akan memberinya rizki? Adakah orang yang mendapat cobaan maka Aku akan menyembuhkannya? Adakah yang begini, dan adakah yang begini…hingga terbit fajar. \""},"1346":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ أَبُو بَكْرٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا حَجَّاجٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْفَقَدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَخَرَجْتُ أَطْلُبُهُ فَإِذَا هُوَ بِالْبَقِيعِ رَافِعٌ رَأْسَهُ إِلَى السَّمَاءِ فَقَالَ يَا عَائِشَةُ أَكُنْتِ تَخَافِينَ أَنْ يَحِيفَ اللَّهُ عَلَيْكِ وَرَسُولُهُ قَالَتْ قَدْ قُلْتُ وَمَا بِي ذَلِكَ وَلَكِنِّي ظَنَنْتُ أَنَّكَ أَتَيْتَ بَعْضَ نِسَائِكَ فَقَالَ إِنَّ اللَّهَ تَعَالَى يَنْزِلُ لَيْلَةَ النِّصْفِ مِنْ شَعْبَانَ إِلَى السَّمَاءِ الدُّنْيَا فَيَغْفِرُ لِأَكْثَرَ مِنْ عَدَدِ شَعَرِ غَنَمِ كَلْبٍ","id":"Telah menceritakan kepada kami [Abdah bin Abdullah Al Khuza'i] dan [Muhammad bin Abdul Malik Abu Bakr] keduanya berkata; telah menceritakan kepada kami [Yazin bin Harun] berkata, telah memberitakan kepada kami [Hajjaj] dari [Yahya bin Abu Katsir] dari [Urwah] dari ['Aisyah] ia berkata, \"Suatu malam aku kehilangan Nabi shallallahu 'alaihi wasallam, aku pun mencarinya, dan ternyata beliau berada di Baqi' menengadahkan kepalanya ke langit, beliau lalu bersabda: \"Wahai 'Aisyah, apakah engkau takut Allah dan Rasul-Nya akan mengurangi (haknya) atasmu?\" ia menjawab, \"Aku telah mengatakan tidak, hanya saja aku khawatir engkau mendatangi salah seorang dari isterimu. \" Maka beliau pun bersabda: \"Sesungguhnya pada pertengahan malam Sya'ban Allah turun ke langit dunia lalu mengampuni orang-orang yang jumlahnya lebih banyak dari jumlah bulu kambing. \""},"1347":{"ar":"حَدَّثَنَا رَاشِدُ بْنُ سَعِيدِ بْنِ رَاشِدٍ الرَّمْلِيُّ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ لَهِيعَةَ عَنْ الضَّحَّاكِ بْنِ أَيْمَنَ عَنْ الضَّحَّاكِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَرْزَبٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَطَّلِعُ فِي لَيْلَةِ النِّصْفِ مِنْ شَعْبَانَ فَيَغْفِرُ لِجَمِيعِ خَلْقِهِ إِلَّا لِمُشْرِكٍ أَوْ مُشَاحِنٍحَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنَا أَبُو الْأَسْوَدِ النَّضْرُ بْنُ عَبْدِ الْجَبَّارِ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ الزُّبَيْرِ بْنِ سُلَيْمٍ عَنْ الضَّحَّاكِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبَا مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Rasyid bin Sa'id bin Rasyid Ar Ramli] berkata, telah menceritakan [Al Walid] dari [Ibnu Lahi'ah] dari [Adl Dlahhak bin Aiman] dari [Adl Dlahhak bin 'Abdurrahman bin 'Arzab] dari [Abu Musa Al Asy'ari] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah akan muncul di malam nishfu Sya'ban kemudian mengampuni semua makhluk-Nya kecuali orang musyrik atau orang yang meninggalkan jama'ah (murtad). \" Telah menceritakan kepada kami [Muhammad bin Ishaq] berkata, telah menceritakan kepada kami [Abul Aswad An Nadlr bin Abdul Jabbar] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Az Zubair bin Sualim] dari [Adl Dlahhak bin 'Abdurrahman] dari [Bapaknya] ia berkata; aku mendengar [Abu Musa] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1348":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا سَلَمَةُ بْنُ رَجَاءٍ حَدَّثَتْنِي شَعْثَاءُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ بُشِّرَ بِرَأْسِ أَبِي جَهْلٍ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Bisyr Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Salamah bin Raja`] berkata, telah menceritakan kepadaku [Sya'tsa`] dari [Abdullah bin Abu Aufa] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat dua raka'at ketika mendapat kabar gembira terpenggalnya kepala Abu Jahal. \" "},"1349":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ صَالِحٍ الْمِصْرِيُّ أَنْبَأَنَا أَبِي أَنْبَأَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَمْرِو بْنِ الْوَلِيدِ بْنِ عَبْدَةَ السَّهْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُشِّرَ بِحَاجَةٍ فَخَرَّ سَاجِدًا","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Shalih Al Mishri] berkata, telah memberitakan kepada kami [Bapakku] berkata, telah memberitakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Amru bin Al Walid bin 'Abdah As Sahmi] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam diberi kabar gembira dengan satu perkara, beliau pun sujud. \" "},"1350":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَلَمَّا تَابَ اللَّهُ عَلَيْهِ خَرَّ سَاجِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] dari ['Abdurrahman bin Ka'b bin Malik] dari [Bapaknya] ia berkata, \"Ketika Allah menerima taubatnya beliau sujud tersungkur. \""},"1351":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ وَأَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ قَالَا حَدَّثَنَا أَبُو عَاصِمٍ عَنْ بَكَّارِ بْنِ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَتَاهُ أَمْرٌ يَسُرُّهُ أَوْ بُشِّرَ بِهِ خَرَّ سَاجِدًا شُكْرًا لِلَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah Al Khuza'i] dan [Ahmad bin Yusuf As Sulami] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Bakkar bin Abdul Aziz bin Abdullah bin Abu Bakrah] dari [Bapaknya] dari [Abu Bakrah] berkata, \"Nabi shallallahu 'alaihi wasallam apabila didatangi oleh urusan yang menyenangkan atau diberi kabar gembira, beliau tersungkur sujud sebagai tanda syukur kepada Allah Tabaraka wa Ta'ala. \""},"1352":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَنَصْرُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ وَسُفْيَانُ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ الثَّقَفِيِّ عَنْ عَلِيِّ بْنِ رَبِيعَةَ الْوَالِبِيِّ عَنْ أَسْمَاءَ بْنِ الْحَكَمِ الْفَزَارِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَكُنْتُ إِذَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا يَنْفَعُنِي اللَّهُ بِمَا شَاءَ مِنْهُ وَإِذَا حَدَّثَنِي عَنْهُ غَيْرُهُ اسْتَحْلَفْتُهُ فَإِذَا حَلَفَ صَدَّقْتُهُ وَإِنَّ أَبَا بَكْرٍ حَدَّثَنِي وَصَدَقَ أَبُو بَكْرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ رَجُلٍ يُذْنِبُ ذَنْبًا فَيَتَوَضَّأُ فَيُحْسِنُ الْوُضُوءَ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَقَالَ مِسْعَرٌ ثُمَّ يُصَلِّي وَيَسْتَغْفِرُ اللَّهَ إِلَّا غَفَرَ اللَّهُ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Nashr bin Ali] keduanya berkata; telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Mis'ar] dan [Sufyan] dari [Utsman Ibnul Mughirah Ats Tsaqafi] dari [Ali bin Rabi'ah Al Walibi] dari [Asma Ibnul Hakam Al Fazari] dari [Ali bin Abu Thalib] ia berkata, \"Jika aku mendengar sebuah hadits dari Rasulullah shallallahu 'alaihi wasallam, Allah selalu memberiku manfaat darinya sesuai dengan kehendak-Nya, jika aku mendengar hadits beliau dari orang lain, maka aku memintanya bersumpah, jika ia telah bersumpah maka aku akan membenarkannya. [Abu Bakar] telah menceritakan kepadaku, dan benarlah Abu Bakar, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki melakukan sebuah dosa lalu berwudlu dan membaguskan wudlunya, kemudian shalat dua raka'at, Mis'ar menyebutkan, \"Kemudian shalat dan meminta ampun kepada Allah, kecuali pasti Allah akan mengampuninya. \""},"1353":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ أَظُنُّهُ عَنْ عَاصِمِ بْنِ سُفْيَانَ الثَّقَفِيِّأَنَّهُمْ غَزَوْا غَزْوَةَ السُّلَاسِلِ فَفَاتَهُمْ الْغَزْوُ فَرَابَطُوا ثُمَّ رَجَعُوا إِلَى مُعَاوِيَةَ وَعِنْدَهُ أَبُو أَيُّوبَ وَعُقْبَةُ بْنُ عَامِرٍ فَقَالَ عَاصِمٌ يَا أَبَا أَيُّوبَ فَاتَنَا الْغَزْوُ الْعَامَ وَقَدْ أُخْبِرْنَا أَنَّهُ مَنْ صَلَّى فِي الْمَسَاجِدِ الْأَرْبَعَةِ غُفِرَ لَهُ ذَنْبُهُ فَقَالَ يَا ابْنَ أَخِي أَدُلُّكَ عَلَى أَيْسَرَ مِنْ ذَلِكَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَوَضَّأَ كَمَا أُمِرَ وَصَلَّى كَمَا أُمِرَ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ عَمَلٍأَكَذَلِكَ يَا عُقْبَةُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitahukan kepada kami [Al Laits bin Sa'ad] dari [Abu Zubair] dari [Sufyan bin Abdullah] aku mengira dari ['Ashim bin Sufyan Ats Tsaqafi] bahwasanya mereka pergi dalam peperangan As-Sulasil, hanya saja mereka ketinggalan (tidak ikut perang). Maka mereka pun ribath (berjaga-jaga di perbatasan), kemudian mereka menemui Mu'awiyah sementara di sampingnya ada Abu Ayyub dan 'Uqbah bin Amir. 'Ashim bertanya, \"Wahai Abu Ayyub, tahun ini kami ketinggalan perang, dan telah sampai berita kepada kami bahwasanya barangsiapa shalat di empat masjid maka dosanya akan diampuni! \" [Abu Ayyub] berkata, \"Wahai anak saudaraku, aku akan tunjukkan kepadamu sesuatu yang lebih mudah dari itu, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu dan shalat sebagaimana diperintahkan maka dosanya yang telah lalu akan diampuni, \" bukankah seperti itu wahai 'Uqbah? [Uqbah] menjawab, \"Benar. \""},"1354":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنِي ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ حَدَّثَنِي صَالِحُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي فَرْوَةَ أَنَّ عَامِرَ بْنَ سَعْدٍ أَخْبَرَهُ قَالَ سَمِعْتُ أَبَانَ بْنَ عُثْمَانَ يَقُولَ قَالَ عُثْمَانُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَرَأَيْتَ لَوْ كَانَ بِفِنَاءِ أَحَدِكُمْ نَهْرٌ يَجْرِي يَغْتَسِلُ فِيهِ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍ مَا كَانَ يَبْقَى مِنْ دَرَنِهِ قَالَ لَا شَيْءَ قَالَ فَإِنَّ الصَّلَاةَ تُذْهِبُ الذُّنُوبَ كَمَا يُذْهِبُ الْمَاءُ الدَّرَنَ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Ziyad] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] berkata, telah menceritakan kepadaku [Ibnu Akhi Ibnu Syihab] dari [Pamannya] berkata, telah menceritakan kepadaku [Shalih bin Abdullah bin Abu Farwah] bahwa [Amir bin Sa'd] mengabarkan kepadanya, ia berkata, \"Aku mendengar [Aban bin Utsman] berkata, \" [Utsman] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana pendapatmu jika di depan rumah salah seorang dari kalian terdapat sungai yang mengalir hingga ia bisa mandi lima kali dalam sehari, apakah masih ada kotoran daki pada tubuhnya?\" ia menjawab, \"Tidak, \" beliau bersabda: \"Sesungguhnya shalat dapat membersihkan dosa sebagaimana air dapat membersihkan kotoran daki. \""},"1355":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَجُلًا أَصَابَ مِنْ امْرَأَةٍ يَعْنِي مَا دُونَ الْفَاحِشَةِ فَلَا أَدْرِي مَا بَلَغَ غَيْرَ أَنَّهُ دُونَ الزِّنَا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ أَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }فَقَالَ يَا رَسُولَ اللَّهِ أَلِي هَذِهِ قَالَ لِمَنْ أَخَذَ بِهَا","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Sualiman At Taimi] dari [Abu Utsman An Nahdi] dari [Abdullah bin Mas'ud] berkata, \"Seorang laki-laki terkena fitnah wanita, aku tidak tahu apa yang telah ia lakukan, hanya saja ia memang belum sampai zina. Lalu ia mendatangi Nabi shallallahu 'alaihi wasallam dan menyebutkan semua yang telah ia lakukan, maka Allah menurunkan ayat: \" (Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat). \""},"1356":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى الْمِصْرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ اللَّهُ عَلَى أُمَّتِي خَمْسِينَ صَلَاةً فَرَجَعْتُ بِذَلِكَ حَتَّى آتِيَ عَلَى مُوسَى فَقَالَ مُوسَى مَاذَا افْتَرَضَ رَبُّكَ عَلَى أُمَّتِكَ قُلْتُ فَرَضَ عَلَيَّ خَمْسِينَ صَلَاةً قَالَ فَارْجِعْ إِلَى رَبِّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ فَرَاجَعْتُ رَبِّي فَوَضَعَ عَنِّي شَطْرَهَا فَرَجَعْتُ إِلَى مُوسَى فَأَخْبَرْتُهُ فَقَالَ ارْجِعْ إِلَى رَبِّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ فَرَاجَعْتُ رَبِّي فَقَالَ هِيَ خَمْسٌ وَهِيَ خَمْسُونَ لَا يُبَدَّلُ الْقَوْلُ لَدَيَّ فَرَجَعْتُ إِلَى مُوسَى فَقَالَ ارْجِعْ إِلَى رَبِّكَ فَقُلْتُ قَدْ اسْتَحْيَيْتُ مِنْ رَبِّي","id":"Telah menceritakan kepada kami [Harmalah bin Yahya Al Mishri] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah mewajibkan umatku shalat sebanyak lima puluh kali, maka aku meminta keringan dari hal itu hingga aku mendatangi Musa, ia berkata kepadaku, \"Apa yang telah diwajibkan oleh Rabbmu kepada umatmu?\" aku menjawab, \"Ia telah mewajibkan kepadaku shalat sebanyak lima puluh kali. \" Musa berkata, \"Kembalilah menemui Rabbmu, karena umatmu tidak akan mampu mengerjakan kewajiban itu, \" aku pun kembali menemui Rabbku hingga Ia memberikan keringanan hingga setengahnya. Aku kembali menemui Musa dan aku kabarkan hal itu padanya, ia berkata, \"Kembalilah menemui Rabbmu, karena umatmu tidak akan mampu melakukan kewajiban itu, \" aku pun kembali menemui Rabbku, Ia berfirman: \" (Shalat) Lima kali itu akan menyamai (shalat) lima puluh kali, dan tidak ada lagi perubahan di sisi-Ku. \" Maka aku kembali menemui Musa, lalu aku katakan kepadanya: \"Aku sudah malu kepada Rabbku. \""},"1357":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ عُصْمٍ أَبِي عُلْوَانَ عَنْ ابْنِ عَبَّاسٍ قَالَأُمِرَ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَمْسِينَ صَلَاةً فَنَازَلَ رَبَّكُمْ أَنْ يَجْعَلَهَا خَمْسَ صَلَوَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Abu Al Walid] berkata, telah menceritakan kepada kami [Syarik] dari [Abdullah bin Ushm Abu Ulwan] dari [Ibnu Abbas] ia berkata, \"Nabi kalian shallallahu 'alaihi wasallam diperintahkan shalat sebanyak lima puluh kali, lalu ia meminta kepada Rabbnya agar menjadikan lima kali. \""},"1358":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ الْمُخْدِجِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَمْسُ صَلَوَاتٍ افْتَرَضَهُنَّ اللَّهُ عَلَى عِبَادِهِ فَمَنْ جَاءَ بِهِنَّ لَمْ يَنْتَقِصْ مِنْهُنَّ شَيْئًا اسْتِخْفَافًا بِحَقِّهِنَّ فَإِنَّ اللَّهَ جَاعِلٌ لَهُ يَوْمَ الْقِيَامَةِ عَهْدًا أَنْ يُدْخِلَهُ الْجَنَّةَ وَمَنْ جَاءَ بِهِنَّ قَدْ انْتَقَصَ مِنْهُنَّ شَيْئًا اسْتِخْفَافًا بِحَقِّهِنَّ لَمْ يَكُنْ لَهُ عِنْدَ اللَّهِ عَهْدٌ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdu Rabbih bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] dari [Al Mukhdiji] dari [Ubadah bin Ash Shamit] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima waktu shalat telah Allah wajibkan atas hamba-hamba-Nya, barangsiapa melaksanakannya dengan tidak mengurangi sesuatu darinya sedikitpun karena meremehkan hak-haknya, maka Allah akan membuat satu janji bahwa Ia akan memasukkannya ke dalam surga pada hari kiamat. Dan barangsiapa mengurangi sesuatu darinya karena meremehkan hak-haknya, maka Allah tidak mempunyai janji dengannya, jika mau Allah akan menyiksanya dan jika mau akan mengampuninya. \""},"1359":{"ar":"حَدَّثَنَا عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُبَيْنَمَا نَحْنُ جُلُوسٌ فِي الْمَسْجِدِ دَخَلَ رَجُلٌ عَلَى جَمَلٍ فَأَنَاخَهُ فِي الْمَسْجِدِ ثُمَّ عَقَلَهُ ثُمَّ قَالَ لَهُمْ أَيُّكُمْ مُحَمَّدٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ بَيْنَ ظَهْرَانَيْهِمْ قَالَ فَقَالُوا هَذَا الرَّجُلُ الْأَبْيَضُ الْمُتَّكِئُ فَقَالَ لَهُ الرَّجُلُ يَا ابْنَ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَبْتُكَ فَقَالَ لَهُ الرَّجُلُ يَا مُحَمَّدُ إِنِّي سَائِلُكَ وَمُشَدِّدٌ عَلَيْكَ فِي الْمَسْأَلَةِ فَلَا تَجِدَنَّ عَلَيَّ فِي نَفْسِكَ فَقَالَ سَلْ مَا بَدَا لَكَ قَالَ لَهُ الرَّجُلُ نَشَدْتُكَ بِرَبِّكَ وَرَبِّ مَنْ قَبْلَكَ آللَّهُ أَرْسَلَكَ إِلَى النَّاسِ كُلِّهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ آللَّهُ أَمَرَكَ أَنْ تُصَلِّيَ الصَّلَوَاتِ الْخَمْسَ فِي الْيَوْمِ وَاللَّيْلَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ آللَّهُ أَمَرَكَ أَنْ تَصُومَ هَذَا الشَّهْرَ مِنْ السَّنَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ آللَّهُ أَمَرَكَ أَنْ تَأْخُذَ هَذِهِ الصَّدَقَةَ مِنْ أَغْنِيَائِنَا فَتَقْسِمَهَا عَلَى فُقَرَائِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ نَعَمْ فَقَالَ الرَّجُلُ آمَنْتُ بِمَا جِئْتَ بِهِ وَأَنَا رَسُولُ مَنْ وَرَائِي مِنْ قَوْمِي وَأَنَا ضِمَامُ بْنُ ثَعْلَبَةَ أَخُو بَنِي سَعْدِ بْنِ بَكْرٍ","id":"Telah menceritakan kepada kami [Isa bin Hammad Al Mishri] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Sa'id Al Maqburi] dari [Syarik bin Abdullah bin Abu Namir] bahwa ia mendengar [Anas bin Malik] ia berkata, \"Ketika kami sedang duduk-duduk di masjid seorang laki-laki masuk ke dalam masjid dengan mengendarai unta, lalu ia derumkan untanya dan ia ikat dalam masjid. Setelah itu ia berkata kepada orang-orang, \"Manakah dari kalian yang bernama Muhammad! \" padahal Rasulullah shallallahu 'alaihi wasallam sedang duduk bersandar di antara mereka. \" Anas berkata, \"Para sahabat pun menjawab, \"Laki-laki berkulit putih yang duduk bersandar inilah orangnya, \" laki-laki itu lalu berkata kepada beliau, \"Wahai anak Abdul Muthallib! \" Nabi shallallahu 'alaihi wasallam menjawab, \"Aku telah memenuhi panggilanmu, \" laki-laki itu berkata lagi, \"Wahai Muhammad, aku ingin bertanya kepadamu dan keras dalam bertanya kepadamu, maka janganlah engkau marah kepadaku, \" beliau bersabda: \"Tanyakanlah apa yang engkau inginkan?\" laki-laki itu berkata, \"Aku bersumpah atas Tuhanmu dan Tuhan orang-orang sebelummu, apakah Allah mengutusmu untuk seluruh manusia?\" beliau menjawab: \"Ya Allah, itu benar, \" laki-laki itu berkata, \"Aku persaksikan dirimu atas Allah, apakah Allah yang memerintahkan kepadamu kewajiban shalat lima waktu dalam sehari semalam?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya Allah, itu benar, \" laki-laki itu berkata, \"Aku persaksikan dirimu atas Allah, apakah Allah yang memerintahkan kamu puasa di bulan ini dalam setahunnya?\" beliau menjawab: \"Ya Allah, itu benar, \" laki-laki itu berkata, \"Aku persaksikan dirimu atas Allah, apakah Allah yang memerintahkan kamu mengambil sedekah ini dari orang-orang kaya kami lalu membagikannya kepada orang-orang miskin kami?\" beliau menjawab, \"Ya Allah, itu benar, \" lalu laki-laki itu berkata, \"Aku beriman dengan apa yang engkau bawa, aku adalah utusan dari kaumku, aku Dlimam bin Tsa'labah, saudara bani Sa'd bin Bakr. \""},"1360":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنَا ضُبَارَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي السُّلَيْكِ أَخْبَرَنِي دُوَيْدُ بْنُ نَافِعٍ عَنْ الزُّهْرِيِّ قَالَ قَالَ سَعِيدُ بْنُ الْمُسَيَّبِ إِنَّ أَبَا قَتَادَةَ بْنَ رِبْعِيٍّ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ افْتَرَضْتُ عَلَى أُمَّتِكَ خَمْسَ صَلَوَاتٍ وَعَهِدْتُ عِنْدِي عَهْدًا أَنَّهُ مَنْ حَافَظَ عَلَيْهِنَّ لِوَقْتِهِنَّ أَدْخَلْتُهُ الْجَنَّةَ وَمَنْ لَمْ يُحَافِظْ عَلَيْهِنَّ فَلَا عَهْدَ لَهُ عِنْدِي","id":"Telah menceritakan kepada kami [Yahya bin Utsman bin Sa'id bin Katsir bin Dinar Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah bin Al Walid] [Dlubarah bin Abdullah bin Abu Salik] berkata, telah mengabarkan kepadaku [Duwaid bin Nafi'] dari [Az Zuhri] berkata; [Sa'id bin Musayyab] berkata; [Abu Qatadah bin Rib'i] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza Wa Jalla berfirman: \"Aku telah mewajibkan umatmu shalat lima waktu, dan Aku telah menetapkan sebuah perjanjian di sisi-Ku, bahwa barangsiapa menjaganya sesuai waktunya Aku akan memasukkannya ke dalam surga. Dan barangsiapa tidak menjaganya, maka tidak ada perjanjian di sisi-Ku. \""},"1361":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدَنِيُّ أَحْمَدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ رَبَاحٍ وَعُبَيْدِ اللَّهِ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي مَسْجِدِي هَذَا أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا الْمَسْجِدَ الْحَرَامَحَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Mush'ab Al Madani Ahmad bin Abu Katsir bin Abu Bakr] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Zaid bin Rabah] dan [Ubaidullah bin Abu Abdullah] dari [Abu Abdullah Al Aghar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat di masjidku ini lebih utama seribu kali dari shalat di tempat lain kecuali masjidil haram. \" Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1362":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي مَسْجِدِي هَذَا أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ مِنْ الْمَسَاجِدِ إِلَّا الْمَسْجِدَ الْحَرَامَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah menceritakan kepada kami [Abdullah bin Numair] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat di masjidku ini lebih utama seribu kali dari shalat di masjid selainnya kecuali masjidil haram. \""},"1363":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَسَدٍ حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ أَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي مَسْجِدِي أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا الْمَسْجِدَ الْحَرَامَ وَصَلَاةٌ فِي الْمَسْجِدِ الْحَرَامِ أَفْضَلُ مِنْ مِائَةِ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ","id":"Telah menceritakan kepada kami [Isma'il bin Asad] berkata, telah menceritakan kepada kami [Zakaria bin Adi] berkata, telah memberitakan kepada kami [Ubaidullah bin Amru] dari [Abdul Karim] dari ['Atho`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat di masjidku lebih utama seribu kali dari shalat di masjid selainnya, kecuali masjidil haram. Dan shalat di masjidil haram lebih utama seratus ribu kali dari shalat di tempat selainnya. \""},"1364":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ عَنْ زِيَادِ بْنِ أَبِي سَوْدَةَ عَنْ أَخِيهِ عُثْمَانَ بْنِ أَبِي سَوْدَةَ عَنْ مَيْمُونَةَ مَوْلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَفْتِنَا فِي بَيْتِ الْمَقْدِسِ قَالَ أَرْضُ الْمَحْشَرِ وَالْمَنْشَرِ ائْتُوهُ فَصَلُّوا فِيهِ فَإِنَّ صَلَاةً فِيهِ كَأَلْفِ صَلَاةٍ فِي غَيْرِهِ قُلْتُ أَرَأَيْتَ إِنْ لَمْ أَسْتَطِعْ أَنْ أَتَحَمَّلَ إِلَيْهِ قَالَ فَتُهْدِي لَهُ زَيْتًا يُسْرَجُ فِيهِ فَمَنْ فَعَلَ ذَلِكَ فَهُوَ كَمَنْ أَتَاهُ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah Ar Raqqi] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] dari [Ziyad bin Abu Saudah] dari saudaranya [Utsman bin Abu Saudah] dari [Maimunah] mantan budak Nabi shallallahu 'alaihi wasallam, ia berkata, \"Wahai Rasulullah, berilah kami fatwa berkenaan dengan Baitul Maqdis, \" beliau bersabda: \"Ia adalah bumi Al Muntasyar dan Al Muntasyar (tempat dikumpulkannya manusia pada hari kiamat), datangi dan shalatlah kalian di sana, sebab shalat di dalamnya seperti shalat seribu kali di tempat lainnya. \" Aku bertanya, \"Bagaimana pendapat tuan jika saya tidak bisa ke sana?\" beliau menjawab: \"Memberi minyak yang dengannya lampu bisa dinyalakan di dalamnya, barangsiapa melakukan itu, maka ia seperti telah mendatanginya. \""},"1365":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْجَهْمِ الْأَنْمَاطِيُّ حَدَّثَنَا أَيُّوبُ بْنُ سُوَيْدٍ عَنْ أَبِي زُرْعَةَ السَّيْبَانِيِّ يَحْيَى بْنِ أَبِي عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الدَّيْلَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا فَرَغَ سُلَيْمَانُ بْنُ دَاوُدَ مِنْ بِنَاءِ بَيْتِ الْمَقْدِسِ سَأَلَ اللَّهَ ثَلَاثًا حُكْمًا يُصَادِفُ حُكْمَهُ وَمُلْكًا لَا يَنْبَغِي لَأَحَدٍ مِنْ بَعْدِهِ وَأَلَّا يَأْتِيَ هَذَا الْمَسْجِدَ أَحَدٌ لَا يُرِيدُ إِلَّا الصَّلَاةَ فِيهِ إِلَّا خَرَجَ مِنْ ذُنُوبِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا اثْنَتَانِ فَقَدْ أُعْطِيَهُمَا وَأَرْجُو أَنْ يَكُونَ قَدْ أُعْطِيَ الثَّالِثَةَ","id":"Telah menceritakan kepada kami [Ubaidullah Ibnul Jahm Al Anmathi] berkata, telah menceritakan kepada kami [Ayyub bin Suwaid] dari [Abu Zur'ah As Saibani Yahya bin Abu Amru] berkata, telah menceritakan kepada kami [Abdullah bin Ad Daili] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ketika Sulaiman bin Dawud selesai membangun Baitul Maqdis ia meminta Allah tiga hal; hukum yang sesuai dengan hukum-Nya, kerajaan yang tidak dimiliki oleh orang-orang setelahnya, dan tidak ada seorang pun yang mendatangi masjid ini kecuali untuk shalat, melainkan akan keluar semua dosanya sebagaimana bayi yang dilahirkan ibunya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Dua perkara pertama telah dikabulkan, dan aku berharap yang ketiga juga telah diberikan. \""},"1366":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِي هَذَا وَالْمَسْجِدِ الْأَقْصَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh bersusah payah melakukan perjalanan kecuali pada masjid; masjidil haram, masjidku ini dan masjidil aqsha. \""},"1367":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي مَرْيَمَ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ إِلَى الْمَسْجِدِ الْحَرَامِ وَإِلَى الْمَسْجِدِ الْأَقْصَى وَإِلَى مَسْجِدِي هَذَا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Muhammad bin Syu'aib] berkata, telah menceritakan kepada kami [Yazid bin Abu Maryam] dari [Qaza'ah] dari [Abu Sa'id] dan [Abdullah bin Amr bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh bersusah payah melakukan perjalanan kecuali pada masjid; masjidil haram, masjidil aqsha dan masjidku ini. \""},"1368":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنَا أَبُو الْأَبْرَدِ مَوْلَى بَنِي خَطْمَةَ أَنَّهُ سَمِعَ أُسَيْدَ بْنَ ظُهَيْرٍ الْأَنْصَارِيَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ صَلَاةٌ فِي مَسْجِدِ قُبَاءَ كَعُمْرَةٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] berkata, telah menceritakan kepada kami [Abul Abrad] mantan budak bani Khathmah, ia mendengar [Usaid bin Zhuhair Al Anshari] -ia termasuk sahabat Nabi shallallahu 'alaihi wasallam- ia menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat di masjid Quba seperti melakukan Umrah. \""},"1369":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ وَعِيسَى بْنُ يُونُسَ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْكَرْمَانِيُّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلِ بْنِ حُنَيْفٍ يَقُولَ قَالَ سَهْلُ بْنُ حُنَيْفٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَطَهَّرَ فِي بَيْتِهِ ثُمَّ أَتَى مَسْجِدَ قُبَاءَ فَصَلَّى فِيهِ صَلَاةً كَانَ لَهُ كَأَجْرِ عُمْرَةٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dan [Isa bin Yunus] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Sulaiman Al Karmani] berkata; aku mendengar [Abu Umamah bin Sahl bin Hunaif] berkata; [Sahl bin Hunaif] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersuci di rumahnya kemudian mendatangi masjid Quba dan shalat di dalamnya, maka ia akan mendapatkan pahala umrah. \""},"1370":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا أَبُو الْخَطَّابِ الدِّمَشْقِيُّ حَدَّثَنَا رُزَيْقٌ أَبُو عَبْدِ اللَّهِ الْأَلْهَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي بَيْتِهِ بِصَلَاةٍ وَصَلَاتُهُ فِي مَسْجِدِ الْقَبَائِلِ بِخَمْسٍ وَعِشْرِينَ صَلَاةً وَصَلَاتُهُ فِي الْمَسْجِدِ الَّذِي يُجَمَّعُ فِيهِ بِخَمْسِ مِائَةِ صَلَاةٍ وَصَلَاتُهُ فِي الْمَسْجِدِ الْأَقْصَى بِخَمْسِينَ أَلْفِ صَلَاةٍ وَصَلَاتُهُ فِي مَسْجِدِي بِخَمْسِينَ أَلْفِ صَلَاةٍ وَصَلَاةٌ فِي الْمَسْجِدِ الْحَرَامِ بِمِائَةِ أَلْفِ صَلَاةٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Abu Khaththab Ad Dimasyqi] berkata, telah menceritakan kepada kami [Ruzaiq Abu Abdullah Al Alhani] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seorang laki-laki di rumahnya sebanding dengan satu shalat, shalatnya di masjid kabilahnya sebanding dengan dua puluh lima shalat, shalatnya di masjid jami' sebanding dengan seratus shalat, shalatnya di masjid Al Aqsha sebanding dengan seribu shalat, shalatnya di masjidku sebanding dengan lima puluh ribu shalat, dan shalat di Masjidil Haram sebanding dengan seratus ribu shalat. \""},"1371":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى جِذْعٍ إِذْ كَانَ الْمَسْجِدُ عَرِيشًا وَكَانَ يَخْطُبُ إِلَى ذَلِكَ الْجِذْعِ فَقَالَ رَجُلٌ مِنْ أَصْحَابِهِ هَلْ لَكَ أَنْ نَجْعَلَ لَكَ شَيْئًا تَقُومُ عَلَيْهِ يَوْمَ الْجُمُعَةِ حَتَّى يَرَاكَ النَّاسُ وَتُسْمِعَهُمْ خُطْبَتَكَ قَالَ نَعَمْ فَصَنَعَ لَهُ ثَلَاثَ دَرَجَاتٍ فَهِيَ الَّتِي أَعْلَى الْمِنْبَرِ فَلَمّ��ا وُضِعَ الْمِنْبَرُ وَضَعُوهُ فِي مَوْضِعِهِ الَّذِي هُوَ فِيهِ فَلَمَّا أَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقُومَ إِلَى الْمِنْبَرِ مَرَّ إِلَى الْجِذْعِ الَّذِي كَانَ يَخْطُبُ إِلَيْهِ فَلَمَّا جَاوَزَ الْجِذْعَ خَارَ حَتَّى تَصَدَّعَ وَانْشَقَّ فَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا سَمِعَ صَوْتَ الْجِذْعِ فَمَسَحَهُ بِيَدِهِ حَتَّى سَكَنَ ثُمَّ رَجَعَ إِلَى الْمِنْبَرِ فَكَانَ إِذَا صَلَّى صَلَّى إِلَيْهِفَلَمَّا هُدِمَ الْمَسْجِدُ وَغُيِّرَ أَخَذَ ذَلِكَ الْجِذْعَ أُبَيُّ بْنُ كَعْبٍ وَكَانَ عِنْدَهُ فِي بَيْتِهِ حَتَّى بَلِيَ فَأَكَلَتْهُ الْأَرَضَةُ وَعَادَ رُفَاتًا","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah Ar Raqqi] berkata, telah menceritakan kepada kami [Ubaidullah bin Amru Ar Raqqi] dari [Abdullah bin Muhammad bin Aqil] dari [Ath Thufail bin Abu Ubai bin Ka'b] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat menghadap ke arah sebatang kayu kurma, sebab masjid pada masa itu tidak mempunyai dinding, dan beliau juga berkhutbah di atas kayu tersebut. Seorang laki-laki dari sahabatnya berkata, \"Bagaimana jika kami buatkan sesuatu (mimbar) yang dapat engkau gunakan berdiri di hari jum'at, hingga orang-orang dapat melihatmu dan mendengar khutbahmu?\" beliau menjawab: \"Ya, \" maka sahabat itu membuatkan Rasulullah mimbar yang mempunyai tiga undakan, ketika para sahabat meletakkan mimbar tersebut pada tempat yang biasa beliau gunakan khutbah, dan Rasulullah shallallahu 'alaihi wasallam ingin berdiri di atasnya, beliau melintasi batang kayu yang biasa beliau gunakan untuk berkhutbah. Ketika melintas, batang kayu tersebut mengeluarkan suara dan terbelah. Rasulullah shallallahu 'alaihi wasallam pun turun, ketika beliau mendengar suara kayu itu beliau mengusapnya dengan tangan hingga ia menjadi tenang, setelah itu beliau kembali lagi ke atas mimbar. Jika shalat beliau selalu menghadap ke arah batang kayu tersebut, maka ketika masjid dirombak dan di ubah, Ubai bin Ka'b mengambil batang kayu tersebut. Batang kayu tersebut tetap di rumahnya hingga lapuk dan di makan rayap dan menjadi remukan-remukan kecil. \""},"1372":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ ابْنِ عَبَّاسٍ وَعَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ إِلَى جِذْعٍ فَلَمَّا اتَّخَذَ الْمِنْبَرَ ذَهَبَ إِلَى الْمِنْبَرِ فَحَنَّ الْجِذْعُ فَأَتَاهُ فَاحْتَضَنَهُ فَسَكَنَ فَقَالَ لَوْ لَمْ أَحْتَضِنْهُ لَحَنَّ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Bahz bin Asad] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Ammar bin Abu Ammar] dari [Ibnu Abbas] dan dari [Tsabit] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam berkhutbah di atas batang kayu kurma, ketika mimbar telah dibuat beliau pindah ke mimbar hingga batang kayu tersebut bersuara. Maka beliau pun mendatangi dan mendekapnya hingga ia menjadi tenang. Beliau lalu bersabda: \"Sekiranya tidak aku peluk (menenangkan), sungguh ia akan bersuara hingga hari kiamat. \""},"1373":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ ثَابِتٍ الْجَحْدَرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي حَازِمٍ قَالَاخْتَلَفَ النَّاسُ فِي مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَيِّ شَيْءٍ هُوَ فَأَتَوْا سَهْلَ بْنَ سَعْدٍ فَسَأَلُوهُ فَقَالَ مَا بَقِيَ أَحَدٌ مِنْ النَّاسِ أَعْلَمُ بِهِ مِنِّي هُوَ مِنْ أَثْلِ الغَابَةِ عَمِلَهُ فُلَانٌ مَوْلَى فُلَانَةَ نَجَّارٌ فَجَاءَ بِهِ فَقَامَ عَلَيْهِ حِينَمَا وُضِعَ فَاسْتَقْبَلَ وَقَامَ النَّاسُ خَلْفَهُ فَقَرَأَ ثُمَّ رَكَعَ ثُمَّ رَفَعَ رَأْسَهُ فَرَجَعَ الْقَهْقَرَى حَتَّى سَجَدَ بِالْأَرْضِ ثُمَّ عَادَ إِلَى الْمِنْبَرِ فَقَرَأَ ثُمَّ رَكَعَ فَقَامَ ثُمَّ رَجَعَ الْقَهْقَرَى حَتَّى سَجَدَ بِالْأَرْضِ","id":"Telah menceritakan kepada kami [Ahmad bin Tsabit Al Jahdari] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Hazim] berkata, \"Orang-orang saling berselisih mengenai mimbar Rasulullah shallallahu 'alaihi wasallam, yakni dibuat dari apa mimbar tersebut. Mereka kemudian mendatangi Sahl bin Sa'd dan menanyakan hal itu kepadanya. [Sahl bin Sa'd] lalu berkata, \"Tidak seorang (sahabat) pun yang tersisa, yang lebih tahu tentang mimbar itu selain aku, mimbar itu dibuat dari kayu hutan, ia dibuat oleh Fulan mantan budak Fulanah. Tukang kayu itu membawakan mimbar tersebut, ketika diletakkan beliau berdiri di atasnya dan menghadap ke arah kiblat, dan orang-orang berdiri di belakangnya. Beliau membaca surat lalu rukuk, kemudian mengangkat kepalanya seraya mundur ke belakang hingga beliau dapat sujud. Setelah itu beliau kembali lagi ke atas mimbar dan membaca surat, kemudian rukuk dan berdiri, kemudian mundur ke belakang lagi hingga beliau dapat sujud. \""},"1374":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ إِلَى أَصْلِ شَجَرَةٍ أَوْ قَالَ إِلَى جِذْعٍ ثُمَّ اتَّخَذَ مِنْبَرًا قَالَ فَحَنَّ الْجِذْعُ قَالَ جَابِرٌ حَتَّى سَمِعَهُ أَهْلُ الْمَسْجِدِ حَتَّى أَتَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَهُ فَسَكَنَفَقَالَ بَعْضُهُمْ لَوْ لَمْ يَأْتِهِ لَحَنَّ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abu Bisyr bin Khalaf] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sulaiman At Taimi] dari [Abu Nadlrah] dari [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri di atas batang pohon, atau ia mengatakan, \"di atas batang kurma hingga kayu itu dijadikan sebagai mimbar. \" Abu Nadlrah berkata, \"Batang kurma itu bersuara. \" Jabir berkata, \"Orang-orang yang di masjid sampai mendengar suaranya, hingga Rasulullah shallallahu 'alaihi wasallam datang dan mengusapnya, batang kayu itu pun diam. Sebagian sahabat berkata, \"Sekiranya beliau tidak mengusapnya, maka ia akan bersuara hingga hari kiamat. \""},"1375":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ وَسُوَيْدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَصَلَّيْتُ ذَاتَ لَيْلَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَزَلْ قَائِمًا حَتَّى هَمَمْتُ بِأَمْرِ سَوْءٍ قُلْتُ وَمَا ذَاكَ الْأَمْرُ قَالَ هَمَمْتُ أَنْ أَجْلِسَ وَأَتْرُكَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] dan [Suwaid bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] berkata, \"Pada suatu malam aku shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau masih saja berdiri hingga muncul pikiran jelek dalam diriku. \" Aku bertanya, \"Perkara apa itu?\" Abdullah menjawab, \"Aku ingin duduk, namun tidak aku teruskan. \""},"1376":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ سَمِعَ الْمُغِيرَةَ يَقُولُقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَوَرَّمَتْ قَدَمَاهُ فَقِيلَ يَا رَسُولَ اللَّهِ قَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ziyad bin Ilaqah] ia mendengar [Al Mughirah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri (shalat) hingga bengkak kedua kakinya, dikatakan kepada beliau, \"Wahai Rasulullah, dosamu telah diampuni baik yang lalu atau yang akan datang! \" beliau menjawab: \"Tidak bolehkah aku menjadi hamba yang bersyukur. \""},"1377":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي حَتَّى تَوَرَّمَتْ قَدَمَاهُ فَقِيلَ لَهُ إِنَّ اللَّهَ قَدْ غَفَرَ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'I Muhammad bin Yazid] berkata, telah menceritakan kepada kami [Yahya bin Yaman] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam selalu melaksanakan shalat (tahajjud) sehingga kedua kakinya bengkak. Dikatakan kepadanya, \"Sesungguhnya Allah telah mengampuni dosamu baik yang lalu maupun yang akan datang! \" Beliau bersabda: \"Tidak bolehkah aku menjadi hamba yang senantiasa bersyukur?\""},"1378":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقُنُوتِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Bisyr] berkata, telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam ditanya; shalat yang bagaimana yang paling utama?\" beliau menjawab: \"Yang panjang berdirinya. \""},"1379":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيَّانِ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ عَنْ أَبِيهِ عَنْ مَكْحُولٍ عَنْ كَثِيرِ بْنِ مُرَّةَ أَنَّ أَبَا فَاطِمَةَ حَدَّثَهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ أَسْتَقِيمُ عَلَيْهِ وَأَعْمَلُهُ قَالَ عَلَيْكَ بِالسُّجُودِ فَإِنَّكَ لَا تَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَكَ اللَّهُ بِهَا دَرَجَةً وَحَطَّ بِهَا عَنْكَ خَطِيئَةً","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan ['Abdurrahman bin Ibrahim Ad Dimasyqiyani] keduanya berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami ['Abdurrahman bin Tsabit bin Tsauban] dari [Bapaknya] dari [Makhul] dari [Katsir min Murrah] bahwa [Abu Fathimah] menceritakan kepadanya, ia berkata, \"Aku berkata, \"Wahai Rasulullah, kabarkanlah kepadaku suatu amalan yang aku bisa istiqamah dan mampu melaksanakannya, \" beliau bersabda: \"Sujudlah kepada Allah, sebab tidaklah engkau sujud kepada-Nya sekali saja, kecuali dengannya Allah akan mengangkat satu derajat dan menghapus satu kesalahan darimu. \""},"1380":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو أَبُو عَمْرٍو الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ هِشَامٍ الْمُعَيْطِيُّ حَدَّثَهُ مَعْدَانُ بْنُ أَبِي طَلْحَةَ الْيَعْمُرِيُّ قَالَلَقِيتُ ثَوْبَانَ فَقُلْتُ لَهُ حَدِّثْنِي حَدِيثًا عَسَى اللَّهُ أَنْ يَنْفَعَنِي بِهِ قَالَ فَسَكَتَ ثُمَّ عُدْتُ فَقُلْتُ مِثْلَهَا فَسَكَتَ ثَلَاثَ مَرَّاتٍ فَقَالَ لِي عَلَيْكَ بِالسُّجُودِ لِلَّهِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةًقَالَ مَعْدَانُ ثُمَّ لَقِيتُ أَبَا الدَّرْدَاءِ فَسَأَلْتُهُ فَقَالَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami ['Abdurrahman bin Amru Abu Al Auza'i] berkata; telah menceritakan kepadaku [Al Walid bin Hisyam Al Mu'aithi] berkata, telah menceritakan kepadanya [Ma'dan bin Abu Thalhah Al Ya'muri] berkata, \"Aku pernah bertemu [Tsauban], lalu aku katakan kepadanya, \"Bacakanlah satu hadits kepadaku, mudah-mudahan dengan hadits tersebut Allah memberiku manfaat. \" Ma'dan berkata, \"Tsauban diam, lalu aku ulangi lagi dan kukatakan seperti itu. Namun ia tetap diam, aku ulangi lagi hingga tiga kali. Setelah itu ia berkata kepadaku, \"Sujudlah engkau kepada Allah, sungguh aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba sujud kepada Allah kecuali dengannya Allah akan menaikkan satu derajat dan menghapus darinya satu kesalahan. \" Ma'dan berkata, \"Setelah itu aku bertemu [Abu Darda] dan aku tanyakan kepadanya, dan ia pun menjawab memberi jawaban seperti itu. \""},"1381":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ خَالِدِ بْنِ يَزِيدَ الْمُرِّيِّ عَنْ يُونُسَ بْنِ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ الصُّنَابِحِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا كَتَبَ اللَّهُ لَهُ بِهَا حَسَنَةً وَمَحَا عَنْهُ بِهَا سَيِّئَةً وَرَفَعَ لَهُ بِهَا دَرَجَةً فَاسْتَكْثِرُوا مِنْ السُّجُودِ","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman Ad-Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Khalid bin Yazid Al Murri] dari [Yunus bin Maisarah bin Jals] dari [As Shunabi] dari [Ubadah bin Shamit] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba melakukan sujud sekali kepada Allah, kecuali Allah akan menuliskan baginya satu kebaikan, menghapus satu keburukan, dan mengangkatnya satu derajat. Oleh sebab itu perbanyaklah melakukan sujud. \""},"1382":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ حَكِيمٍ الضَّبِّيِّ قَالَقَالَ لِي أَبُو هُرَيْرَةَ إِذَا أَتَيْتَ أَهْلَ مِصْرِكَ فَأَخْبِرْهُمْ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ مَا يُحَاسَبُ بِهِ الْعَبْدُ الْمُسْلِمُ يَوْمَ الْقِيَامَةِ الصَّلَاةُ الْمَكْتُوبَةُ فَإِنْ أَتَمَّهَا وَإِلَّا قِيلَ انْظُرُوا هَلْ لَهُ مِنْ تَطَوُّعٍ فَإِنْ كَانَ لَهُ تَطَوُّعٌ أُكْمِلَتْ الْفَرِيضَةُ مِنْ تَطَوُّعِهِ ثُمَّ يُفْعَلُ بِسَائِرِ الْأَعْمَالِ الْمَفْرُوضَةِ مِثْلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Sufyan bin Husain] dari [Ali bin Zaid] dari [Anas bin Hakim Adl Dlabbi] berkata; [Abu Hurairah] berkata kepadaku, \"Jika engkau datang kepada warga kampungmu maka kabarkanlah kepada mereka bahwa aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pertama kali yang akan dihitung atas seorang muslim pada hari kiamat adalah shalat wajibnya, jika ia menyempurnakannya (akan diterima), jika tidak menyempurnakannya maka akan dikatakan, \"Lihatlah, apakah ia mempunyai ibadah thathawu'? jika ia mempunyai ibadah thathawu' maka sempurnakanlah ibadah wajib dengan ibadah tathawu'nya, \" kemudian semua amalan wajib akan dilakukan seperti itu. \""},"1383":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ تَمِيمٍ الدَّارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ الصَّبَّاحِ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَنْبَأَنَا حُمَيْدٌ عَنْ الْحَسَنِ عَنْ رَجُلٍ عَنْ أَبِي هُرَيْرَةَ وَدَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ تَمِيمٍ الدَّارِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ يَوْمَ الْقِيَامَةِ صَلَاتُهُ فَإِنْ أَكْمَلَهَا كُتِبَتْ لَهُ نَافِلَةً فَإِنْ لَمْ يَكُنْ أَكْمَلَهَا قَالَ اللَّهُ سُبْحَانَهُ لِمَلَائِكَتِهِ انْظُرُوا هَلْ تَجِدُونَ لِعَبْدِي مِنْ تَطَوُّعٍ فَأَكْمِلُوا بِهَا مَا ضَيَّعَ مِنْ فَرِيضَتِهِ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Ad Darimi] berkata, telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Dawud bin Abu Hind] dari [Zurarah bin Aufa] dari [Tamim Ad Dari] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Affan] berkata, telah memberitakan kepada kami [Humaid] dari [Al Hasan] dari [seorang laki-laki] dari [Abu Hurairah] dan [Dawud bin Abu Hind] dari [Zurarah bin Aufa] dari [Tamim Ad Dari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pertama yang akan dihisab atas seorang hamba pada hari kiamat adalah shalatnya, jika ia menyempurnakannya maka akan ditulis baginya pahala nafilah. Jika tidak menyempurnakannya, Allah Subhaanahu kepada malaikat-Nya, \"Lihatlah, apakah kalian mendapati ia mempunyai ibadah thathawu'? dengannya sempurnakanlah ibadah wajibnya yang kurang, \" kemudian semua amalan akan diperlakukan seperti itu. \""},"1384":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ لَيْثٍ عَنْ حَجَّاجِ بْنِ عُبَيْدٍ عَنْ إِبْرَاهِيمَ بْنِ إِسْمَعِيلَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيَعْجِزُ أَحَدُكُمْ إِذَا صَلَّى أَنْ يَتَقَدَّمَ أَوْ يَتَأَخَّرَ أَوْ عَنْ يَمِينِهِ أَوْ عَنْ شِمَالِهِ يَعْنِي السُّبْحَةَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Laits] dari [Hajjaj bin Ubaid] dari [Ibrahim bin Isma'il] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak mampukah salah seorang dari kalian jika shalat untuk maju ke depan, atau ke belakang, atau ke kanan, atau ke kiri. Yakni dalam shalat sunnah. \""},"1385":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عُثْمَانَ بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُصَلِّي الْإِمَامُ فِي مُقَامِهِ الَّذِي صَلَّى فِيهِ الْمَكْتُوبَةَ حَتَّى يَتَنَحَّى عَنْهُحَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ أَبِي عَبْدِ الرَّحْمَنِ التَّمِيمِيِّ عَنْ عُثْمَانَ بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ الْمُغِيرَةِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Utsman bin 'Atho`] dari [Bapaknya] dari [Mughirah bin Syu'bah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang imam shalat (sunnah) di tempat yang telah ia gunakan untuk shalat wajib, hingga ia bergeser dari tempatnya tersebut. \" Telah menceritakan kepada kami [Katsir bin Ubaid Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Abu 'Abdurrahman At Tamimi] dari [Utsman bin 'Atho`] dari [Bapaknya] dari [Al Mughirah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits. \""},"1386":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ أَبِيهِ عَنْ تَمِيمِ بْنِ مَحْمُودٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَلَاثٍ عَنْ نَقْرَةِ الْغُرَابِ وَعَنْ فِرْشَةِ السَّبُعِ وَأَنْ يُوطِنَ الرَّجُلُ الْمَكَانَ الَّذِي يُصَلِّي فِيهِ كَمَا يُوطِنُ الْبَعِيرُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abu Bisyir Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Bapaknya] dari [Tamim bin Mahmud] dari ['Abdurrahman bin Syibl] berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari tiga hal; mematuk sebagaimana seperti burung gagak, membentangkan tangan seperti binatang buas dan seorang laki-laki shalat di tempat yang telah ia gunakan shalat, sebagaimana unta (yang menempati tempatnya kembali). \" "},"1387":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِأَنَّهُ كَانَ يَأْتِي إِلَى سُبْحَةِ الضُّحَى فَيَعْمِدُ إِلَى الْأُسْطُوَانَةِ دُونَ الْمُصْحَفِ فَيُصَلِّ قَرِيبًا مِنْهَا فَأَقُولُ لَهُ أَلَا تُصَلِّي هَا هُنَا وَأُشِيرُ إِلَى بَعْضِ نَوَاحِي الْمَسْجِدِ فَيَقُولُ إِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَرَّى هَذَا الْمُقَامَ","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Al Mughirah bin 'Abdurrahman Al Makhzumi] dari [Yazid bin Abu Ubaid] dari [Salamah Ibnul Akwa'] bahwa ia pernah shalat sunnah dluha. Ia menuju tiang, tidak ke mushhaf Utsmani, lalu ia shalat di dekatnya. Aku tanyakan kepadanya, \"Kenapa kamu tidak shalat di sini? Lalu aku menunjuk pada salah satu sujud masjid. Ia menjawab, \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam menghindari tempat ini. \""},"1388":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ مُحَمَّدِ بْنِ عَبَّادٍ عَنْ عَبْدِ اللَّهِ بْنِ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْفَتْحِ فَجَعَلَ نَعْلَيْهِ عَنْ يَسَارِهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] dari [Muhammad bin 'Abbad] dari [Abdullah bin Sufyan] dari [Abdullah bin As Sa`ib] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam shalat di hari penaklukan kota Makkah, beliau meletakkan kedua sandalnya di samping kirinya. \""},"1389":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ بْنِ حَبِيبٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْزِمْ نَعْلَيْكَ قَدَمَيْكَ فَإِنْ خَلَعْتَهُمَا فَاجْعَلْهُمَا بَيْنَ رِجْلَيْكَ وَلَا تَجْعَلْهُمَا عَنْ يَمِينِكَ وَلَا عَنْ يَمِينِ صَاحِبِكَ وَلَا وَرَاءَكَ فَتُؤْذِيَ مَنْ خَلْفَكَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim bin Habib] dan [Muhammad bin Isma'il] keduanya berkata; telah menceritakan kepada kami ['Abdurrahman Al Muharibi] dari [Abdullah bin Sa'id bin Abu Sa'id] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetaplah engkau pakai kedua sandalmu, Jika kamu lepas maka letakkanlah di antara kedua kakimu dan jangan kamu letakkan di sebelah kananmu, atau di sebelah kanan temanmu, atau di belakangmu, karena akan mengganggu orang yang ada di belakangmu. \" "},"1390":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسْلِمِ عَلَى الْمُسْلِمِ سِتَّةٌ بِالْمَعْرُوفِ يُسَلِّمُ عَلَيْهِ إِذَا لَقِيَهُ وَيُجِيبُهُ إِذَا دَعَاهُ وَيُشَمِّتُهُ إِذَا عَطَسَ وَيَعُودُهُ إِذَا مَرِضَ وَيَتْبَعُ جِنَازَتَهُ إِذَا مَاتَ وَيُحِبُّ لَهُ مَا يُحِبُّ لِنَفْسِهِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Al Harits] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara muslim dengan muslim yang lain ada enam kewajiban untuk berbuat baik; memberi salam jika bertemu, memenuhi undangannya jika diundang, menjawabnya jika bersin, menjenguknya jika sakit, mengantar jenazahnya jika meninggal dan menyukainya sebagaimana ia menyukai dirinya. \""},"1391":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ أَبِيهِ عَنْ حَكِيمِ بْنِ أَفْلَحَ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْمُسْلِمِ عَلَى الْمُسْلِمِ أَرْبَعُ خِلَالٍ يُشَمِّتُهُ إِذَا عَطَسَ وَيُجِيبُهُ إِذَا دَعَاهُ وَيَشْهَدُهُ إِذَا مَاتَ وَيَعُودُهُ إِذَا مَرِضَ","id":"Telah menceritakan kepada kami [Abu Bisyr bin Khalaf] dan [Muhammad bin Basysyar] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Bapaknya] dari [Hakim bin Aflah] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Antara muslim satu dengan muslim lainnya ada empat kewajiban; menjawabnya jika bersin, memenuhi undangannya jika mengundang, berta'ziyah jika meninggal dan menjenguknya jika sakit. \""},"1392":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ حَقِّ الْمُسْلِمِ عَلَى الْمُسْلِمِ رَدُّ التَّحِيَّةِ وَإِجَابَةُ الدَّعْوَةِ وَشُهُودُ الْجِنَازَةِ وَعِيَادَةُ الْمَرِيضِ وَتَشْمِيتُ الْعَاطِسِ إِذَا حَمِدَ اللَّهَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima hak seorang muslim atas muslim lainnya; menjawab salam, memenuhi undangan, mengiringi jenazah, menjenguk di kala sakit, dan menjawab bersin jika ia bertahmid (mengucapkan Al Hamdulillah). \""},"1393":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الصَّنْعَانِيُّ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ الْمُنْكَدِرِ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاشِيًا وَأَبُو بَكْرٍ وَأَنَا فِي بَنِي سَلَمَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Ash Shan'ani] berkata, telah menceritakan kepada kami [Sufyan] berkata; Aku mendengar [Muhammad bin Al Munkadir] berkata; aku mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam menjengukku dengan berjalan kaki, sementara aku dan Abu Bakar berada di bani Salamah. \""},"1394":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا مَسْلَمَةُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَعُودُ مَرِيضًا إِلَّا بَعْدَ ثَلَاثٍ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Maslamah bin Ali] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam tidak menjenguk orang sakit kecuali setelah tiga hari. \""},"1395":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ السَّكُونِيُّ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلْتُمْ عَلَى الْمَرِيضِ فَنَفِّسُوا لَهُ فِي الْأَجَلِ فَإِنَّ ذَلِكَ لَا يَرُدُّ شَيْئًا وَهُوَ يَطِيبُ بِنَفْسِ الْمَرِيضِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Uqbah bin Khalid As Sakuni] dari [Musa bin Muhammad bin Ibrahim At Taimi] dari [Bapaknya] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian menjenguk orang sakit maka berilah ia semangat dalam menghadapi ajal, meskipun itu tidak dapat menolak sesuatu tetapi akan membuat jiwa yang sakit menjadi baik. \""},"1396":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا صَفْوَانُ بْنُ هُبَيْرَةَ حَدَّثَنَا أَبُو مَكِينٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَادَ رَجُلًا فَقَالَ مَا تَشْتَهِي قَالَ أَشْتَهِي خُبْزَ بُرٍّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ عِنْدَهُ خُبْزُ بُرٍّ فَلْيَبْعَثْ إِلَى أَخِيهِ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَهَى مَرِيضُ أَحَدِكُمْ شَيْئًا فَلْيُطْعِمْهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Shafwan bin Hubair] berkata, telah menceritakan kepada kami [Abu Makin] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam seorang yang sakit, beliau lalu bertanya: \"Apa yang kamu inginkan?\" ia menjawab, \"Aku ingin roti gandum. \" Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempunyai roti gandum hendaklah mengirimkannya pada saudaranya. \" Kemudian beliau bersabda lagi: \"Apabila di antara kalian ada yang sakit dan menginginkan sesuatu, maka berikanlah. \""},"1397":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبُو يَحْيَى الْحِمَّانِيُّ عَنْ الْأَعْمَشِ عَنْ يَزِيدَ الرَّقَاشِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَرِيضٍ يَعُودُهُ فَقَالَ أَتَشْتَهِي شَيْئًا أَتَشْتَهِي كَعْكًا قَالَ نَعَمْ فَطَلَبُوا لَهُ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'] berkata, telah menceritakan kepada kami [Abu Yahya Al Himmani] dari [Al A'masy] dari [Yazid Ar Raqqasyi] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam menjenguk orang sakit, lalu beliau bertanya: \"Apakah kamu menginginkan sesuatu? Apakah kamu ingin roti?\" ia menjawab, \"Ya, \" lalu para sahabat pun mencarikan roti untuknya. \" "},"1398":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنِي كَثِيرُ بْنُ هِشَامٍ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلْتَ عَلَى مَرِيضٍ فَمُرْهُ أَنْ يَدْعُوَ لَكَ فَإِنَّ دُعَاءَهُ كَدُعَاءِ الْمَلَائِكَةِ","id":"Telah menceritakan kepada kami [Ja'far bin Musafir] berkata, telah menceritakan kepadaku [Katsir bin Hisyam] berkata, telah menceritakan kepada kami [Ja'far bin Burqan] dari [Maimun bin Mihran] dari [Umar bin Khaththab] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Jika kamu mengunjungi orang sakit maka mintalah agar ia mendo'akanmu. Sebab do`anya seperti do`a para malaikat. \""},"1399":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَتَى أَخَاهُ الْمُسْلِمَ عَائِدًا مَشَى فِي خَرَافَةِ الْجَنَّةِ حَتَّى يَجْلِسَ فَإِذَا جَلَسَ غَمَرَتْهُ الرَّحْمَةُ فَإِنْ كَانَ غُدْوَةً صَلَّى عَلَيْهِ سَبْعُونَ أَلْفَ مَلَكٍ حَتَّى يُمْسِيَ وَإِنْ كَانَ مَسَاءً صَلَّى عَلَيْهِ سَبْعُونَ أَلْفَ مَلَكٍ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Al Hakam] dari ['Abdurrahman bin Abu Laila] dari [Ali] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengunjungi saudaranya sesama muslim maka seakan ia berjalan di bawah pepohonan surga hingga ia duduk, jika telah duduk maka rahmat akan melingkupinya. Jika mengunjunginya di waktu pagi, maka tujuh puluh ribu malaikat akan bershalawat kepadanya hingga sore hari, dan jika ia mengunjunginya di waktu sore, maka tujuh puluh ribu malaikat akan bershalawat kepadanya hingga pagi hari. \""},"1400":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ حَدَّثَنَا أَبُو سِنَانٍ الْقَسْمَلِيُّ عَنْ عُثْمَانَ بْنِ أَبِي سَوْدَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَادَ مَرِيضًا نَادَى مُنَادٍ مِنْ السَّمَاءِ طِبْتَ وَطَابَ مَمْشَاكَ وَتَبَوَّأْتَ مِنْ الْجَنَّةِ مَنْزِلًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yusuf bin Ya'qub] berkata, telah menceritakan kepada kami [Abu Sinan Al Qasmali] dari [Utsman bin Abu Saudah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjenguk orang sakit, maka akan ada penyeru dari langit yang menyeru, \"Kamu telah baik, baik pula perjalananmu, dan kamu akan menempati tempat tinggal di surga. \""},"1401":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Talqinlah orang yang akan meninggal di antara kamu dengan LAA ILAAHA ILLA ALLAH. \""},"1402":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sulaiman bin Bilal] dari [Umarah bin Ghaziah] dari [Yahya bin Umarah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Talqinlah orang yang akan meninggal di antara kamu dengan LAA ILAAHA ILLA ALLAH. \""},"1403":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا كَثِيرُ بْنُ زَيْدٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ لَا إِلَهَ إِلَّا اللَّهُ الْحَلِيمُ الْكَرِيمُ سُبْحَانَ اللَّهِ رَبِّ الْعَرْشِ الْعَظِيمِ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ لِلْأَحْيَاءِ قَالَ أَجْوَدُ وَأَجْوَدُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Amir] berkata, telah menceritakan kepada kami [Katsir bin Yazid] dari [Ishaq bin Abdullah bin Ja'far] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lakukanlah talqin kepada orang-orang yang akan meninggal di antara kalian dengan; LAA ILAAHA ILLA ALLAH AL HALIIMU AL KARIIMU SUBHAANA ALLAH RABBUl 'ARSYIl 'AZHIIM AL HAMDULILLAAHI RABBIL 'AALAMIIN (Tidak ada Tuhan yang berhak disembah kecuali Allah yang Maha Lembut lagi Maha Pemurah. Maha Suci Allah Rabb 'Arsy yang agung. Segala puji bagi Allah Rabb sekalian alam). \" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana jika untuk orang-orang yang masih hidup?\" beliau menjawab: \"Itu akan lebih baik. \" "},"1404":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرْتُمْ الْمَرِيضَ أَوْ الْمَيِّتَ فَقُولُوا خَيْرًا فَإِنَّ الْمَلَائِكَةَ يُؤَمِّنُونَ عَلَى مَا تَقُولُونَ فَلَمَّا مَاتَ أَبُو سَلَمَةَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سَلَمَةَ قَدْ مَاتَ قَالَ قُولِي اللَّهُمَّ اغْفِرْ لِي وَلَهُ وَأَعْقِبْنِي مِنْهُ عُقْبًى حَسَنَةًقَالَتْ فَفَعَلْتُ فَأَعْقَبَنِي اللَّهُ مَنْ هُوَ خَيْرٌ مِنْهُ مُحَمَّدٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian menghadiri orang sakit atau orang meninggal maka ucapkanlah yang baik-baik, sebab para malaikat mengamini atas apa yang kalian ucapkan. \" Ketika Abu Salamah meninggal aku mendatangi Nabi shallallahu 'alaihi wasallam, aku berkata, \"Wahai Rasulullah, Abu Salamah telah meninggal! \" beliau bersabda: \"Berdo`alah; Ya Allah, ampunilah aku dan dia, dan berilah pengganti untukku yang lebih baik darinya. \" Ummu Salamah berkata, \"Lalu aku melakukannya, dan ternyata Allah memberi ganti yang lebih baik darinya, Muhammad Rasulullah shallallahu 'alaihi wasallam. \""},"1405":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْ��ُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ عَنْ ابْنِ الْمُبَارَكِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ وَلَيْسَ بِالنَّهْدِيِّ عَنْ أَبِيهِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوهَا عِنْدَ مَوْتَاكُمْ يَعْنِي يس","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali Ibnul Hasan bin Syaqiq] dari [Ibnul Mubarak] dari [Sulaiman At Taimi] dari [Abu Utsman] -bukan An Nahdi- dari [Bapaknya] dari [Ma'qil bin Yasar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacakanlah ia untuk orang-orang akan meninggal dari kalian, yakni YASIIN. \""},"1406":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا الْمُحَارِبِيُّ جَمِيعًا عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الْحَارِثِ بْنِ فُضَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ كَعْبًا الْوَفَاةُ أَتَتْهُ أُمُّ بِشْرٍ بِنْتُ الْبَرَاءِ بْنِ مَعْرُورٍ فَقَالَتْ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنْ لَقِيتَ فُلَانًا فَاقْرَأْ عَلَيْهِ مِنِّي السَّلَامَ قَالَ غَفَرَ اللَّهُ لَكِ يَا أُمَّ بِشْرٍ نَحْنُ أَشْغَلُ مِنْ ذَلِكَ قَالَتْ يَا أَبَا عَبْدِ الرَّحْمَنِ أَمَا سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَرْوَاحَ الْمُؤْمِنِينَ فِي طَيْرٍ خُضْرٍ تَعْلُقُ بِشَجَرِ الْجَنَّةِ قَالَ بَلَى قَالَتْ فَهُوَ ذَاكَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Yazid bin Harun]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepada kami [Al Muharibi] semuanya dari [Muhammad bin Ishaq] dari [Al Harits bin Fudlail] dari [Az Zuhri] dari ['Abdurrahman bin Ka'b bin Malik] dari [Bapaknya] berkata, \"Ketika ajal akan menjemput Ka'b, Ummu Bisyr binti Al Bara bin Ma'ruf datang kepadanya dan berkata, \"Wahai Abu 'Abdurrahman, jika engkau bertemu dengan si fulan, maka sampaikanlah salam dariku, \" Ka'b berkata, \"Semoga Allah mengampunimu wahai Ummu Bisyr, kami lebih sibuk dari hal itu. \" Ummu Bisyr berkata, \"Wahai Abu 'Abdurrahman, tidakkah engkau dengar sabda Rasulullah shallallahu 'alaihi wasallam: \"Sesungguhnya arwah kaum mukminin berada bersama burung-burung hijau yang bergelantungan di pepohonan surga, \" Ka'b menjawab, \"Benar, \" Ummu Bisyr berkata, \" Itulah (yang aku maksud). \""},"1407":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْأَزْهَرِ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يُوسُفُ بْنُ الْمَاجِشُونِ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ قَالَدَخَلْتُ عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِ وَهُوَ يَمُوتُ فَقُلْتُ اقْرَأْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّلَامَ","id":"Telah menceritakan kepada kami [Ahmad Ibnul Azhar] berkata, telah menceritakan kepada kami [Muhammad bin Isa] berkata, telah menceritakan kepada kami [Yusuf Ibnul Majisyun] berkata, telah menceritakan kepada kami [Muhammad Ibnul Munkadir] ia berkata, \"Aku menemui Jabir bin Abdullah ketika ia telah wafat, aku berkata, \"Sampaikan salam kepada Rasulullah shallallahu 'alaihi wasallam. \""},"1408":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَطَاءٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا حَمِيمٌ لَهَا يَخْنُقُهُ الْمَوْتُ فَلَمَّا رَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بِهَا قَالَ لَهَا لَا تَبْتَئِسِي عَلَى حَمِيمِكِ فَإِنَّ ذَلِكَ مِنْ حَسَنَاتِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Al Auza'I] dari ['Atho`] dari ['Aisyah] Bahwasanya Rasulullah shallallahu 'alaihi wasallam menjenguknya, sementara di sampingnya ada saudara iparnya yang sedang meregang nyawa. Ketika Nabi shallallahu 'alaihi wasallam melihat apa yang terjadi dengannya 'Aisyah, beliau bersabda kepadanya: \"Janganlah bersedih hati atas saudara iparmu, karena itu bagian dari amal baiknya. \" "},"1409":{"ar":"حَدَّثَنَا بَكْرُ بْنُ خَلَفٍ أَبُو بِشْرٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ الْمُثَنَّى بْنِ سَعِيدٍ عَنْ قَتَادَةَ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ يَمُوتُ بِعَرَقِ الْجَبِينِ","id":"Telah menceritakan kepada kami [Bakr bin Khalaf Abu Biysr] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Al Mutsanna bin Sa'id] dari [Qatadah] dari [Ibnu Buraidah] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Orang mukmin jika meninggal dahinya berkeringat. \" "},"1410":{"ar":"حَدَّثَنَا رَوْحُ بْنُ الْفَرَجِ حَدَّثَنَا نَصْرُ بْنُ حَمَّادٍ حَدَّثَنَا مُوسَى بْنُ كَرْدَمٍ عَنْ مُحَمَّدِ بْنِ قَيْسٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَتَى تَنْقَطِعُ مَعْرِفَةُ الْعَبْدِ مِنْ النَّاسِ قَالَ إِذَا عَايَنَ","id":"Telah menceritakan kepada kami [Rauh bin Al Faraj] berkata, telah menceritakan kepada kami [Nashr bin Hammad] berkata, telah menceritakan kepada kami [Musa bin Kardam] dari [Muhammad bin Qais] dari [Abu Burdah] dari [Abu Musa] dia berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Kapan terputusnya pengetahuan seorang hamba dari manusia?\" beliau menjawab: \"Jika ia melihat dengan matanya (melihat malaikat saat sekarat). \" "},"1411":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ أَسَدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ عَنْ أُمِّ سَلَمَةَ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَبِي سَلَمَةَ وَقَدْ شَقَّ بَصَرُهُ فَأَغْمَضَهُ ثُمَّ قَالَ إِنَّ الرُّوحَ إِذَا قُبِضَ تَبِعَهُ الْبَصَرُ","id":"Telah menceritakan kepada kami [Isma'il bin Asad] berkata, telah menceritakan kepada kami [Mu'awiyah bin Amru] berkata, telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Qabishah bin Dzu'aib] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui Abu Salamah, sementara matanya membuka. Maka beliau pun menutupnya dan bersabda: \"Jika ruh diambil maka akan diikuti oleh mata. \""},"1412":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ تَوْبَةَ حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا قَزَعَةُ بْنُ سُوَيْدٍ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرْتُمْ مَوْتَاكُمْ فَأَغْمِضُوا الْبَصَرَ فَإِنَّ الْبَصَرَ يَتْبَعُ الرُّوحَ وَقُولُوا خَيْرًا فَإِنَّ الْمَلَائِكَةَ تُؤَمِّنُ عَلَى مَا قَالَ أَهْلُ الْبَيْتِ","id":"Telah menceritakan kepada kami [Abu Dawud bin Taubah] berkata, telah menceritakan kepada kami [Ashim bin Ali] berkata, telah menceritakan kepada kami [Qaza'ah bin Suwaid] dari [Humaid Al A'raj] dari [Az Zuhri] dari [Mahmud bin Labid] dari [Syaddad bin Aus] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian menghadiri orang-orang yang telah meninggal dari kalian maka rapatkanlah mata mereka, sebab mata mengikuti perginya ruh. Dan ucapkanlah hal-hal baik, sebab para malaikat mengamini apa yang dikatakan oleh ahli bait. \""},"1413":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْقَبَّلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُثْمَانَ بْنَ مَظْعُونٍ وَهُوَ مَيِّتٌ فَكَأَنِّي أَنْظُرُ إِلَى دُمُوعِهِ تَسِيلُ عَلَى خَدَّيْهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ashim bin Ubaidullah] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mencium Utsman bin Mazh'un, padahal ia telah menjadi mayat. Seakan-akan aku melihat air mata beliau mengalir pada kedua pipinya. \""},"1414":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ وَالْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ وَعَائِشَةَأَنَّ أَبَا بَكْرٍ قَبَّلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مَيِّتٌ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] dan [Al Abbas bin Abdul Azhim] dan [Sahl bin Abu Sahl] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dari [Musa bin Abu 'Aisyah] dari [Ubaidullah] dari [Ibnu Abbas] dan ['Aisyah] berkata, \"Abu Bakar mencium Nabi shallallahu 'alaihi wasallam sementara beliau sudah menjadi mayat. \""},"1415":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نُغَسِّلُ ابْنَتَهُ أُمَّ كُلْثُومٍ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حَقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ أَيُّوبَ حَدَّثَتْنِي حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ بِمِثْلِ حَدِيثِ مُحَمَّدٍ وَكَانَ فِي حَدِيثِ حَفْصَةَ اغْسِلْنَهَا وِتْرًا وَكَانَ فِيهِ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا وَكَانَ فِيهِ ابْدَءُوا بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا وَكَانَ فِيهِ أَنَّ أُمَّ عَطِيَّةَ قَالَتْ وَمَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Ayyub] dari [Muhammad bin Sirin] dari [Ummu Athiah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami ketika kami sedang memandikan putrinya, Ummu Kultsum. Beliau bersabda: \"Mandikanlah ia tiga kali, atau lima kali, atau lebih dari itu. Jika kalian memandikannya dengan air bidara maka bilaslah di akhir kalinya dengan air kapur barus, atau sesuatu darinya, dan jika kalian telah selesai kabarilah aku. \" Ketika selesai kami memberitahu Rasulullah, beliau lalu memberikan haqwah (kain sejenis semacam sarung) miliknya dan bersabda: \"Pakaikan itu padanya. \" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Ayyub] berkata, telah menceritakan kepadaku [Hafshah] dari [Ummu Athiah] sebagaimana hadits Muhammad. Dalam hadits Hafshah disebutkan, \"mandikanlah ia dengan bilangan ganjil, \" dalam hadits itu disebutkan, \"Mandikanlah ia tiga kali atau lima kali, \" juga dengan lafadz, \"mulailah dari sebelah kanan dan tempat-tempat wudlu. \" Dalam hadits itu juga disebutkan bahwa Ummu Athiah berkata, \"dan kami menyisir rambutnya dalam tiga ekor kuda. \""},"1416":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبْرِزْ فَخِذَكَ وَلَا تَنْظُرْ إِلَى فَخِذِ حَيٍّ وَلَا مَيِّتٍ","id":"Telah menceritakan kepada kami [Bisyr bin Adam] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] dari [Ibnu Juraij] dari [Habib bin Abu Tsabit] dari [Ashim bin Dlamrah] dari [Ali] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Jangan engkau perlihatkan pahamu, dan janganlah engkau lihat paha orang yang masih hidup atau yang telah meninggal. \""},"1417":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ مُبَشِّرِ بْنِ عُبَيْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُغَسِّلْ مَوْتَاكُمْ الْمَأْمُونُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Mubasysyir bin Ubaid] dari [Zaid bin Aslam] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang memandikan mayat hendaknya orang-orang yang dapat dipercaya. \""},"1418":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ حَدَّثَنَا عَبَّادُ بْنُ كَثِيرٍ عَنْ عَمْرِو بْنِ خَالِدٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ غَسَّلَ مَيِّتًا وَكَفَّنَهُ وَحَنَّطَهُ وَحَمَلَهُ وَصَلَّى عَلَيْهِ وَلَمْ يُفْشِ عَلَيْهِ مَا رَأَى خَرَجَ مِنْ خَطِيئَتِهِ مِثْلَ يَوْمِ وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami ['Abdurrahman Al Muharibi] berkata, telah menceritakan kepada kami ['Abbad bin Katsir] dari [Amru bin Khalid] dari [Habib bin Abu Tsabit] dari ['Ashim bin Dlamrah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memandikan mayit, mengafani, memberinya minyak, memanggul dan menshalatkannya, dan ia tidak menyebarkan apa yang dilihatnya, maka semua dosanya akan keluar sebagaimana hari ia dilahirkan oleh ibunya. \" "},"1419":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ غَسَّلَ مَيِّتًا فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib] berkata, telah menceritakan kepada kami [Abdul Aziz Ibnul Mukhtar] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memandikan mayat hendaklah ia mandi. \""},"1420":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ الذَّهَبِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَوْ كُنْتُ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا غَسَّلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ نِسَائِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ahmad bin Khalid Adz Dzahabi] berkata, telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yahya bin 'Abbad bin Abdullah bin Zubair] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Jika aku berhadapan dengan urusanku maka aku tidak akan berpaling. Dan tidak akan ada yang memandikan Nabi shallallahu 'alaihi wasallam selain dari isteri-isterinya. \""},"1421":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَعْقُوبَ بْنِ عُتْبَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَائِشَةَ قَالَتْرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْبَقِيعِ فَوَجَدَنِي وَأَنَا أَجِدُ صُدَاعًا فِي رَأْسِي وَأَنَا أَقُولُ وَا رَأْسَاهُ فَقَالَ بَلْ أَنَا يَا عَائِشَةُ وَا رَأْسَاهُ ثُمَّ قَالَ مَا ضَرَّكِ لَوْ مِتِّ قَبْلِي فَقُمْتُ عَلَيْكِ فَغَسَّلْتُكِ وَكَفَّنْتُكِ وَصَلَّيْتُ عَلَيْكِ وَدَفَنْتُكِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Ya'qub bin Utbah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam kembali dari Baqi' dan mendapatiku sakit kepala, aku bergumam, \"Duh.. kepalaku! \" Beliau pun bersabda: \"Wahai 'Aisyah, aku juga merasakannya. \" kemudian beliau bersabda: \"Tidak ada bahaya sekiranya kamu meninggal sebelumku, aku akan mengurusimu, memandikan, mengafani, menshalatkan dan menguburkanmu. \""},"1422":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ الْأَزْهَرِ الْوَاسِطِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا أَبُو بُرْدَةَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَلَمَّا أَخَذُوا فِي غُسْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَادَاهُمْ مُنَادٍ مِنْ الدَّاخِلِ لَا تَنْزِعُوا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Al Azhar Al Wasithi] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Abu Burdah] dari [Alqamah bin Martsad] dari [Ibnu Buraidah] dari [Bapaknya] ia berkata, \"Ketika mereka akan memandikan Nabi shallallahu 'alaihi wasallam, tiba-tiba dari dalam ada seseorang yang berseru: \"Jangan kalian lepas gamis Rasulullah shallallahu 'alaihi wasallam. \" "},"1423":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خِذَامٍ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَلَمَّا غَسَّلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ يَلْتَمِسُ مِنْهُ مَا يَلْتَمِسُ مِنْ الْمَيِّتِ فَلَمْ يَجِدْهُ فَقَالَ بِأَبِي الطَّيِّبُ طِبْتَ حَيًّا وَطِبْتَ مَيِّتًا","id":"Telah menceritakan kepada kami [Yahya bin Khidzam] berkata, telah menceritakan kepada kami [Shafwan bin Isa] berkata, telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Ali bin Abu Thalib] ia berkata, \"Ketika Ali memandikan Nabi shallallahu 'alaihi wasallam, ia mencari sesuatu yang biasa di cari pada mayit yang lain (kotoran), tetapi ia tidak mendapatinya. Ia lantas berkata, \"Demi ayahku, engkau baik dalam di masa hidup dan matimu. \" "},"1424":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ يَعْقُوبَ حَدَّثَنَا الْحُسَيْنُ بْنُ زَيْدِ بْنِ عَلِيِّ بْنِ الْحُسَيْنِ بْنِ عَلِيٍّ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنَا مُتُّ فَاغْسِلُونِي بِسَبْعِ قِرَبٍ مِنْ بِئْرِي بِئْرِ غَرْسٍ","id":"Telah menceritakan kepada kami ['Abbad bin Ya'qub] berkata, telah menceritakan kepada kami [Al Husain bin Zaid bin Ali bin Al Husain bin Ali] dari [Isma'il bin Abdullah bin Ja'far] dari [Bapaknya] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika aku meninggal, maka mandikanlah aku dengan tujuh geriba dari air sumurku, sumur Ghars. \""},"1425":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ يَمَانِيَةٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ فَقِيلَ لِعَائِشَةَ إِنَّهُمْ كَانُوا يَزْعُمُونَ أَنَّهُ قَدْ كَانَ كُفِّنَ فِي حِبَرَةٍ فَقَالَتْ عَائِشَةُ قَدْ جَاءُوا بِبُرْدِ حِبَرَةٍ فَلَمْ يُكَفِّنُوهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] berkata, \"Nabi shallallahu 'alaihi wasallam dikafani dengan tiga lapis kain putih dari Yaman, tanpa gamis dan imamah (semacam surban yang dililitkan pada kepala). \" Dikatakan kepada 'Aisyah, \"Mereka mengklaim bahwa beliau dikafani dengan kain hibrah (kain yang direnda dengan benang sutera)! \" 'Aisyah berkata, \"Mereka memang datang dengan membawa selendang hibrah, namun mereka tidak mengafani dengannya. \""},"1426":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ الْعَسْقَلَانِيُّ حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ قَالَ هَذَا مَا سَمِعْتُ مِنْ أَبِي مُعَيْدٍ حَفْصِ بْنِ غَيْلَانَ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثِ رِيَاطٍ بِيضٍ سُحُولِيَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Khalaf Al 'Asqalani] berkata, telah menceritakan kepada kami [Amru bin Abu Salamah] ia berkata; inilah yang aku dengar dari [Abu Mu'aid Hafsh bin Ghailan] dari [Sulaiman bin Musa] dari [Nafi'] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam dikafani dengan tiga lapis kain putih yang ditenun dari kapas. \" "},"1427":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَكُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابٍ قَمِيصُهُ الَّذِي قُبِضَ فِيهِ وَحُلَّةٌ نَجْرَانِيَّةٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Yazid bin Abu Ziyad] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam dikafani dengan tiga lapis kain, kain yang beliau kenakan ketika meninggal dan kain dari Najran. \""},"1428":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ الْمَكِّيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ ثِيَابِكُمْ الْبَيَاضُ فَكَفِّنُوا فِيهَا مَوْتَاكُمْ وَالْبَسُوهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Abdullah bin Raja` Al Makki] dari [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pakaian kalian adalah putih, kafanilah mayat kalian dengan warna itu, dan kenakanlah. \" "},"1429":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ وَهْبٍ أَنْبَأَنَا هِشَامُ بْنُ سَعْدٍ عَنْ حَاتِمِ بْنِ أَبِي نَصْرٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ أَبِيهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الْكَفَنِ الْحُلَّةُ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah memberitakan kepada kami [Hisyam bin Sa'd] dari [Hatim bin Abu Nashr] dari [Ubadah bin Nusai] dari [Bapaknya] dari [Ubadah bin Ash Shamit] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sebaik-baik kafan adalah pakaian. \""},"1430":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَلِيَ أَحَدُكُمْ أَخَاهُ فَلْيُحْسِنْ كَفَنَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Umar bin Yunus] berkata, telah menceritakan kepada kami [Ikrimah bin Ammar] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Abu Qatadah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian dipercaya mengurusi kafan saudaranya, maka hendaklah ia perbagus. \" "},"1431":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْحَسَنِ حَدَّثَنَا أَبُو شَيْبَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا قُبِضَ إِبْرَاهِيمُ ابْنُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُدْرِجُوهُ فِي أَكْفَانِهِ حَتَّى أَنْظُرَ إِلَيْهِ فَأَتَاهُ فَانْكَبَّ عَلَيْهِ وَبَكَى","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il bin Samurah] berkata, telah menceritakan kepada kami [Muhammad bin Al Hasan] berkata, telah menceritakan kepada kami [Abu Syaibah] dari [Anas bin Malik] ia berkata, \"Ketika Ibrahim putra Nabi shallallahu 'alaihi wasallam wafat, beliau bersabda kepada para sahabatnya: \"Jangan kalian bungkus dengan kafan hingga aku melihatnya. \" Kemudian beliau mendatanginya dan memeluk sambil menangis. \""},"1432":{"ar":"حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَبِيبِ بْنِ سُلَيْمٍ عَنْ بِلَالِ بْنِ يَحْيَى قَالَكَانَ حُذَيْفَةُ إِذَا مَاتَ لَهُ الْمَيِّتُ قَالَ لَا تُؤْذِنُوا بِهِ أَحَدًا إِنِّي أَخَافُ أَنْ يَكُونَ نَعْيًا إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأُذُنَيَّ هَاتَيْنِ يَنْهَى عَنْ النَّعْيِ","id":"Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] dari [Habib bin Sulaim] dari [Bilal bin Yahya] berkata, [Hudzifah] berkata, \"Jika ada yang meninggal dunia jangan kalian sebarkan kepada seorang pun, aku khawatir itu akan menjadi ni'ayah (ratapan). Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda dengan kedua telingaku ini bahwa beliau melarang ni'ayah. \""},"1433":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهِشَامُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْرِعُوا بِالْجِنَازَةِ فَإِنْ تَكُنْ صَالِحَةً فَخَيْرٌ تُقَدِّمُونَهَا إِلَيْهِ وَإِنْ تَكُنْ غَيْرَ ذَلِكَ فَشَرٌّ تَضَعُونَهُ عَنْ رِقَابِكُمْ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hisyam bin Ammar] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersegeralah dalam membawa jenazah, jika ia orang shalih maka engkau telah menyegerakan suatu kebaikan. Jika ia bukan orang shalih, maka kalian telah meletakkan keburukan dari pundak kalian. \""},"1434":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مَنْصُورٍ عَنْ عُبَيْدِ بْنِ نِسْطَاسٍ عَنْ أَبِي عُبَيْدَةَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍمَنْ اتَّبَعَ جِنَازَةً فَلْيَحْمِلْ بِجَوَانِبِ السَّرِيرِ كُلِّهَا فَإِنَّهُ مِنْ السُّنَّةِ ثُمَّ إِنْ شَاءَ فَلْيَتَطَوَّعْ وَإِنْ شَاءَ فَلْيَدَعْ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Manshur] dari [Ubaid bin Nisthas] dari [Abu Ubaidah] ia berkata; [Abdullah bin Mas'ud] berkata, \"Barangsiapa mengiring jenazah hendaklah ia panggul pada setiap sisinya karena hal itu termasuk sunnah, Barangsiapa mau memanggulnya hendaklah ia lakukan, dan jika tidak ia boleh meninggalkannya. \" "},"1435":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ عَقِيلٍ حَدَّثَنَا بِشْرُ بْنُ ثَابِتٍ حَدَّثَنَا شُعْبَةُ عَنْ لَيْثٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ رَأَى جِنَازَةً يُسْرِعُونَ بِهَا قَالَ لِتَكُنْ عَلَيْكُمْ السَّكِينَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid bin Aqil] berkata, telah menceritakan kepada kami [Bisyr bin Tsabit] berkata, telah menceritakan kepada kami [Syu'bah] dari [Laits] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau melihat orang-orang membawa jenazah dengan tergesa-gesa, maka beliau bersabda: \"Hendaklah kalian tenang dalam membawa. \" "},"1436":{"ar":"حَدَّثَنَا كَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ أَبِي بَكْرِ بْنِ أَبِي مَرْيَمَ عَنْ رَاشِدِ بْنِ سَعْدٍ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسًا رُكْبَانًا عَلَى دَوَابِّهِمْ فِي جِنَازَةٍ فَقَالَ أَلَا تَسْتَحْيُونَ أَنَّ مَلَائِكَةَ اللَّهِ يَمْشُونَ عَلَى أَقْدَامِهِمْ وَأَنْتُمْ رُكْبَانٌ","id":"Telah menceritakan kepada kami [Katsir bin Ubaid Al Himshi], telah menceritakan kepada kami [Baqiyah bin Al Walid] dari [Abu Bakr bin Abu Maryam] dari [Rasyid bin Sa'd] dari [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melihat orang-orang mengendarai kendaraan ketika mengantar jenazah, maka beliau bersabda: \"Apakah kalian tidak malu, Malaikat Allah berjalan dengan kaki sementara kalian berkendaraan. \""},"1437":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدِ اللَّهِ بْنِ جُبَيْرِ بْنِ حَيَّةَ حَدَّثَنِي زِيَادُ بْنُ جُبَيْرِ بْنِ حَيَّةَ سَمِعَ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرَّاكِبُ خَلْفَ الْجِنَازَةِ وَالْمَاشِي مِنْهَا حَيْثُ شَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Sa'id bin Ubaidullah bin Jubair bin Hayyah] berkata, telah menceritakan kepada kami [Ziyad bin Jubair bin Hayyah] bahwa ia mendengar [Al Mughirah bin Syu'bah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah yang berkendaraan di belakang jenazah, adapun yang berjalan kaki bisa sekehendaknya. \""},"1438":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ وَهِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ يَمْشُونَ أَمَامَ الْجِنَازَةِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar berjalan di depan jenazah. \""},"1439":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ وَهَارُونُ بْنُ عَبْدِ اللَّهِ الْحَمَّالُ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ الْأَيْلِيُّ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ يَمْشُونَ أَمَامَ الْجِنَازَةِ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] dan [Harun bin Abdullah Al Hammal] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Bakr Al Bursani] berkata, telah memberitakan kepada kami [Yunus bin Yazid Al Aili] dari [Az-Zuhri] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman selalu berjalan di depan jenazah. \""},"1440":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ التَّيْمِيِّ عَنْ أَبِي مَاجِدَةَ الْحَنَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجِنَازَةُ مَتْبُوعَةٌ وَلَيْسَتْ بِتَابِعَةٍ لَيْسَ مِنْهَا مَنْ تَقَدَّمَهَا","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] berkata, telah memberitakan kepada kami [Abdul Wahid bin Ziyad] dari [Yahya bin Abdullah At Taimi] dari [Abu Majidah Al Hanafi] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam: \"Jenazah itu diikuti dan tidak mengikuti. Maka tidak boleh ada yang mendahuluinya. \""},"1441":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَخْبَرَنِي عَمْرُو بْنُ النُّعْمَانِ حَدَّثَنَا عَلِيُّ بْنُ الْحَزَوَّرِ عَنْ نُفَيْعٍ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ وَأَبِي بَرْزَةَ قَالَاخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جِنَازَةٍ فَرَأَى قَوْمًا قَدْ طَرَحُوا أَرْدِيَتَهُمْ يَمْشُونَ فِي قُمُصٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبِفِعْلِ الْجَاهِلِيَّةِ تَأْخُذُونَ أَوْ بِصُنْعِ الْجَاهِلِيَّةِ تَشَبَّهُونَ لَقَدْ هَمَمْتُ أَنْ أَدْعُوَ عَلَيْكُمْ دَعْوَةً تَرْجِعُونَ فِي غَيْرِ صُوَرِكُمْ قَالَ فَأَخَذُوا أَرْدِيَتَهُمْ وَلَمْ يَعُودُوا لِذَلِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Amru bin An Nu'man] berkata, telah menceritakan kepada kami [Ali bin Al Hazawwar] dari [Nufai'] dari [Imran bin Hushain] dan [Abu Barzah] keduanya berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam mengantar jenazah. Lalu Beliau melihat sekelompok orang yang melepaskan mantel-mantel mereka dan berjalan dengan gamis, beliau bersabda: \"Apakah tingkah laku jahiliyyah yang kalian praktikkan atau kalian meniru perbuatan jahiliyah? Sungguh, aku berkeinginan sekali mendo'akan kalian (laknat) hingga kalian kembali bukan dengan wajah-wajah kalian. \" Imran berkata, \"Kemudian mereka mengambil kembali mantel-mantel mereka dan tidak mengulanginya lagi. \""},"1442":{"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي سَعِيدُ بْنُ عَبْدِ اللَّهِ الْجُهَنِيُّ أَنَّ مُحَمَّدَ بْنَ عُمَرَ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ جَدِّهِ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُؤَخِّرُوا الْجِنَازَةَ إِذَا حَضَرَتْ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] berkata, telah menceritakan kepada kami [Abdullah bin Wahb] berkata, telah mengabarkan kepadaku [Sa'id bin Abdullah Al Juhani] bahwa [Muhammad bin Umar bin Ali bin Abu Thalib] menceritakan kepadanya dari [Bapaknya] dari kakeknya [Ali bin Abu Thalib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian akhirkan jenazah jika telah tiba. \""},"1443":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ أَنْبَأَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ قَرَأْتُ عَلَى الْفُضَيْلِ بْنِ مَيْسَرَةَ عَنْ أَبِي حَرِيزٍ أَنَّ أَبَا بُرْدَةَ حَدَّثَهُ قَالَأَوْصَى أَبُو مُوسَى الْأَشْعَرِيُّ حِينَ حَضَرَهُ الْمَوْتُ فَقَالَ لَا تُتْبِعُونِي بِمِجْمَرٍ قَالُوا لَهُ أَوَ سَمِعْتَ فِيهِ شَيْئًا قَالَ نَعَمْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] berkata, telah memberitakan kepada kami [Mu'tamar bin Sulaiman] ia berkata; aku telah membacakan di hadapan [Al Fudlail bin Maisarah] dari [Abu Hariz] bahwa [Abu Burdah] menceritakan kepadanya, ia berkata; \"Menjelang kematiannya [Abu Musa Al Asy'ari] berwasiat, \"Janganlah kalian mengiringi aku dengan dupa api. \" Orang-orang bertanya: \"Apakah engkau mendengar sesuatu (hadits) tentang itu?\" ia menjawab, \"Ya, dari Rasulullah shallallahu 'alaihi wasallam. \" "},"1444":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ أَنْبَأَنَا شَيْبَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَيْهِ مِائَةٌ مِنْ الْمُسْلِمِينَ غُفِرَ لَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ubaidullah] berkata, telah memberitakan kepada kami [Syaiban] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa seratus orang kaum muslimin menshalatkan jenazahnya, maka ia akan diampuni. \""},"1445":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا بَكْرُ بْنُ سُلَيْمٍ حَدَّثَنِي حُمَيْدُ بْنُ زِيَادٍ الْخَرَّاطُ حَدَّثَنَا شَرِيكٌ عَنْ كُرَيْبٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَهَلَكَ ابْنٌ لِعَبْدِ اللَّهِ بْنِ عَبَّاسٍ فَقَالَ لِي يَا كُرَيْبُ قُمْ فَانْظُرْ هَلْ اجْتَمَعَ لِابْنِي أَحَدٌ فَقُلْتُ نَعَمْ فَقَالَ وَيْحَكَ كَمْ تَرَاهُمْ أَرْبَعِينَ قُلْتُ لَا بَلْ هُمْ أَكْثَرُ قَالَ فَاخْرُجُوا بِابْنِي فَأَشْهَدُ لَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ أَرْبَعِينَ مِنْ مُؤْمِنٍ يَشْفَعُونَ لِمُؤْمِنٍ إِلَّا شَفَّعَهُمْ اللَّهُ","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Bakr bin Muslim] berkata, telah menceritakan kepadaku [Humaid bin Ziyad Al Kharrath] berkata, telah menceritakan kepada kami [Syarik] dari [Kuraib] mantan budak Abdullah bin Abbas, ia berkata, \"Anak Abdullah bin Abbas meninggal, lalu ia ([Abdullah bin Abbas]) berkata kepadaku, \"Wahai Kuraib, berdiri dan lihatlah, apakah sudah ada yang berkumpul untuk (menshalati) anakku meskipun hanya seorang?\" aku menjawab, \"Ya, \" ia berkata, \"Celaka kamu, berapa orang yang kami lihat, empat puluh orang?\" aku menjawab, \"Tidak, bahkan jumlah mereka lebih banyak. \" Ia berkata, \"kalau begitu keluarlah dengan (jenazah) anakku, aku bersaksi bahwa aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah empat puluh orang mukmin memintakan syafa'at untuk seorang mukmin, kecuali Allah akan memberi syafa'at kepada mereka. \""},"1446":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ مَالِكِ بْنِ هُبَيْرَةَ الشَّامِيِّ وَكَانَتْ لَهُ صُحْبَةٌ قَالَكَانَ إِذَا أُتِيَ بِجِنَازَةٍ فَتَقَالَّ مَنْ تَبِعَهَا جَزَّأَهُمْ ثَلَاثَةَ صُفُوفٍ ثُمَّ صَلَّى عَلَيْهَا وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا صَفَّ صُفُوفٌ ثَلَاثَةٌ مِنْ الْمُسْلِمِينَ عَلَى مَيِّتٍ إِلَّا أَوْجَبَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Numair] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Martsad bin Abdullah Al Yazani] dari [Malik bin Hubairah Asy Syami] -ia adalah seorang sahabat- berkata, \"Jika Malik bin Hubairah didatangkan jenazah kepadanya dan hanya sedikit orang yang akan menshalatkannya, maka ia membagi shaf menjadi tiga baris kemudian shalat. Setelah itu ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Tidaklah tiga shaf kaum muslimin berjajar menshalati jenazah, kecuali telah wajib (pengampunan Allah atas mayit). \""},"1447":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجِنَازَةٍ فَأُثْنِيَ عَلَيْهَا خَيْرًا فَقَالَ وَجَبَتْ ثُمَّ مُرَّ عَلَيْهِ بِجِنَازَةٍ فَأُثْنِيَ عَلَيْهَا شَرًّا فَقَالَ وَجَبَتْ فَقِيلَ يَا رَسُولَ اللَّهِ قُلْتَ لِهَذِهِ وَجَبَتْ وَلِهَذِهِ وَجَبَتْ فَقَالَ شَهَادَةُ الْقَوْمِ وَالْمُؤْمِنُونَ شُهُودُ اللَّهِ فِي الْأَرْضِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas bin Malik] berkata; Ada satu jenazah yang melintas di hadapan Nabi shallallahu 'alaihi wasallam, lalu jenazah itu dipuji dengan suatu kebaikan, maka beliau pun bersabda: \"Telah wajib (baginya surga). \" Setelah itu ada lagi jenazah lain yang lewat di hadapannya, lalu jenazah tersebut dipuji dengan suatu keburukan, maka beliau pun bersabda: \"Telah wajib (baginya neraka). \" lalu ditanyakan kepada beliau, \"Wahai Rasulullah, engkau katakan untuk jenazah ini, \"Telah wajib, \" dan untuk jenazah ini, \"Telah wajib! \" beliau menjawab: \"Persaksian orang-orang dan kaum muslimin adalah persaksian Allah di muka bumi. \""},"1448":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجِنَازَةٍ فَأُثْنِيَ عَلَيْهَا خَيْرًا فِي مَنَاقِبِ الْخَيْرِ فَقَالَ وَجَبَتْ ثُمَّ مَرُّوا عَلَيْهِ بِأُخْرَى فَأُثْنِيَ عَلَيْهَا شَرًّا فِي مَنَاقِبِ الشَّرِّ فَقَالَ وَجَبَتْ إِنَّكُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Ali bin Mushir] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Ada satu jenazah lewat di hadapan Nabi shallallahu 'alaihi wasallam, lalu jenazah tersebut dipuji dengan suatu kebaikan, maka beliau pun bersabda: \"Telah wajib (baginya surga). \" Setelah itu ada lagi jenazah lain yang lewat di hadapannya, lalu jenazah tersebut dipuji dengan suatu keburukan, maka beliau pun bersabda: \"Telah wajib (baginya neraka). Sesungguhnya kalian adalah para saksi Allah di muka bumi. \""},"1449":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ الْحُسَيْنُ بْنُ ذَكْوَانَ أَخْبَرَنِي عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ الْأَسْلَمِيِّ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ الْفَزَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى امْرَأَةٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ وَسَطَهَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah mengabarkan kepadaku [Al Husain bin Dzakwan] dari [Abdullah bin Buraidah Al Aslami] dari [Samurah bin Jundub Al Fazari] berkata, \"Rasulullah shallallahu 'alaihi wasallam menshalati seorang wanita yang meninggal di saat nifas, lalu beliau berdiri di tengah-tengahnya. \""},"1450":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هَمَّامٍ عَنْ أَبِي غَالِبٍ قَالَرَأَيْتُ أَنَسَ بْنَ مَالِكٍ صَلَّى عَلَى جِنَازَةِ رَجُلٍ فَقَامَ حِيَالَ رَأْسِهِ فَجِيءَ بِجِنَازَةٍ أُخْرَى بِامْرَأَةٍ فَقَالُوا يَا أَبَا حَمْزَةَ صَلِّ عَلَيْهَا فَقَامَ حِيَالَ وَسَطِ السَّرِيرِ فَقَالَ الْعَلَاءُ بْنُ زِيَادٍ يَا أَبَا حَمْزَةَ هَكَذَا رَأَيْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ مِنْ الْجِنَازَةِ مُقَامَكَ مِنْ الرَّجُلِ وَقَامَ مِنْ الْمَرْأَةِ مُقَامَكَ مِنْ الْمَرْأَةِ قَالَ نَعَمْ فَأَقْبَلَ عَلَيْنَا فَقَالَ احْفَظُوا","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] berkata, telah menceritakan kepada kami [Sa'id bin Amir] dari [Hammam] dari [Abu Ghalib] ia berkata, \"Aku pernah melihat [Anas bin Malik] menshalati jenazah laki-laki. Lalu berdiri di sisi kepalanya. Kemudian di datangkan jenazah perempuan, orang-orang berkata, \"Wahai Abu Hamzah, shalatlah untuknya. \" Lalu ia berdiri di bagian tengah keranda. \" Al 'Ala bin Ziyad berkata, \"Wahai Abu Hamzah, seperti posisimu inikah engkau melihat Rasulullah shallallahu 'alaihi wasallam menshalati jenazah laki-laki dan jenazah perempuan?\" ia menjawab, \"Benar. \" Kemudian ia menghadap ke arah kami seraya berkata, \"Jagalah. \""},"1451":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُثْمَانَ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ عَلَى الْجِنَازَةِ بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Zaid bin Al Hubab] berkata, telah menceritakan kepada kami [Ibrahim bin Utsman] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam dalam shalat jenazah membaca Al Fatihah. \""},"1452":{"ar":"حَدَّثَنَا عَمْرُو بْنُ أَبِي عَاصِمٍ النَّبِيلُ وَإِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ قَالَا حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ جَعْفَرٍ الْعَبْدِيُّ حَدَّثَنِي شَهْرُ بْنُ حَوْشَبٍ حَدَّثَتْنِي أُمُّ شَرِيكٍ الْأَنْصَارِيَّةُ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَقْرَأَ عَلَى الْجِنَازَةِ بِفَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Amru bin Abu 'Ashim An Nabil] dan [Ibrahim bin Al Mustamir] keduanya berkata; telah menceritakan kepada kami [Abu 'Ashim] berkata, telah menceritakan kepada kami [Hammad bin Ja'far Al 'Abdi] berkata, telah menceritakan kepadaku [Syahr bin Hausyab] berkata, telah menceritakan kepadaku [Ummu Syarik Al Anshariah] ia berkata, \"Ketika shalat jenazah Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk membaca surat Al Fatihah. \" "},"1453":{"ar":"حَدَّثَنَا أَبُو عُبَيْدٍ مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ الْمَدِينِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا صَلَّيْتُمْ عَلَى الْمَيِّتِ فَأَخْلِصُوا لَهُ الدُّعَاءَ","id":"Telah menceritakan kepada kami [Abu Ubaid Muhammad bin Ubaid bin Maimun Al Madini] berkata, telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian menshalati mayit, maka ikhlaskanlah ketika berdo'a untuknya. \" "},"1454":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى عَلَى جِنَازَةٍ يَقُولُ اللَّهُمَّ اغْفِرْ لِحَيِّنَا وَمَيِّتِنَا وَشَاهِدِنَا وَغَائِبِنَا وَصَغِيرِنَا وَكَبِيرِنَا وَذَكَرِنَا وَأُنْثَانَا اللَّهُمَّ مَنْ أَحْيَيْتَهُ مِنَّا فَأَحْيِهِ عَلَى الْإِسْلَامِ وَمَنْ تَوَفَّيْتَهُ مِنَّا فَتَوَفَّهُ عَلَى الْإِيمَانِ اللَّهُمَّ لَا تَحْرِمْنَا أَجْرَهُ وَلَا تُضِلَّنَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] berkata, telah menceritakan kepada kami [Ali bin Mushar] dari [Muhammad bin Ishaq] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam jika melakukan shalat jenazah selalu membaca berdo'a: \"ALLAHUMMAGHFIR LIHAYYINAA, WA MAYYITINAA, WA SYAAHIDINAA, WA GHAA`IBINAA, WA SHAGHIIRINAA, WA KABIIRINAA, WA DZAKARINAA, WA UNTSAANAA, ALLAHUMMA MAN AHYAITAHU MINNAA FA AHYIHI 'ALAL ISLAAM, WA MAN TAWAFFAITAHU MINNAA FA TAWAFFAHU 'ALAL IIMAAN, ALLAHUMMA LAA TAHRIMNA AJRAHU, WA LAA TUDLILLANAA BA'DAHU (Ya Allah, ampunilah kami yang masih hidup, yang telah meninggal dari kami, yang masih ada, yang telah tiada, anak kecil kami, orang tua kami, lelaki kami, perempuan kami. Ya Allah, siapa saja yang Engkau hidupkan dari kami, maka hidupkanlah di atas Islam, dan siapa saja yang Engkau wafatkan dari kami, maka wafatkanlah di atas iman. Ya Allah, janganlah Engkau haramkan bagi kami pahalanya, dan janganlah Engkau sesatkan kami sepeninggalnya. \""},"1455":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا مَرْوَانُ بْنُ جَنَاحٍ حَدَّثَنِي يُونُسُ بْنُ مَيْسَرَةَ بْنِ حَلْبَسٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ مِنْ الْمُسْلِمِينَ فَأَسْمَعُهُ يَقُولُ اللَّهُمَّ إِنَّ فُلَانَ بْنَ فُلَانٍ فِي ذِمَّتِكَ وَحَبْلِ جِوَارِكَ فَقِهِ مِنْ فِتْنَةِ الْقَبْرِ وَعَذَابِ النَّارِ وَأَنْتَ أَهْلُ الْوَفَاءِ وَالْحَقِّ فَاغْفِرْ لَهُ وَارْحَمْهُ إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim Ad Dimasqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Marwan bin Janah] berkata, telah menceritakan kepadaku [Yunus bin Maisarah bin Halbas] dari [Watsilah Ibnul Asqa'] berkata; Rasulullah shallallahu 'alaihi wasallam menshalati seorang laki-laki dari kaum muslimin, lalu aku mendengar beliau mengatakan: \"ALLAHUMMA INNA FULAN BIN FULAN FII DZIMMATIKA WA HABLI JIWAARIKA FAQIHI MIN FITNATIL QABRI WA 'ADZAABIN NAAR WA ANTA AHLUL WAFA` WAL HAQ FAGHFIRLAHU WARHAMHU INNAKA ANTAL GHAFUURUR RAHIIM (Ya Allah, sesungguhnya fulan bin fulan berada dalam jaminan dan perjanjian-Mu, maka jagalah ia dari fitnah kubur dan siksa neraka. Engkau Maha menepati janji dan Maha benar, ampuni dan sayangilah ia. Sesungguhnya Engkau Maha Pengampun lagi Maha Penyayang). \""},"1456":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا فَرَجُ بْنُ الْفَضَالَةِ حَدَّثَنِي عِصْمَةُ بْنُ رَاشِدٍ عَنْ حَبِيبِ بْنِ عُبَيْدٍ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى رَجُلٍ مِنْ الْأَنْصَارِ فَسَمِعْتُهُ يَقُولُ اللَّهُمَّ صَلِّ عَلَيْهِ وَاغْفِرْ لَهُ وَارْحَمْهُ وَعَافِهِ وَاعْفُ عَنْهُ وَاغْسِلْهُ بِمَاءٍ وَثَلْجٍ وَبَرَدٍ وَنَقِّهِ مِنْ الذُّنُوبِ وَالْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ وَأَبْدِلْهُ بِدَارِهِ دَارًا خَيْرًا مِنْ دَارِهِ وَأَهْلًا خَيْرًا مِنْ أَهْلِهِ وَقِهِ فِتْنَةَ الْقَبْرِ وَعَذَابَ النَّارِقَالَ عَوْفٌ فَلَقَدْ رَأَيْتُنِي فِي مُقَامِي ذَلِكَ أَتَمَنَّى أَنْ أَكُونَ مَكَانَ الرَّجُلِ","id":"Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] berkata, telah menceritakan kepada kami [Faraj Ibnul Fadlalah] berkata, telah menceritakan kepadaku [Ishmah bin Rasyid] dari [Habib bin Ubaid] dari [Auf bin Malik] ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menshalati seorang laki-laki Anshar, lalu aku mendengar beliau mengucapkan: \"ALLAHUMMA SHALLI 'ALAIHI WAGHFIRLAHU WARHAMHU WA 'AAFIHI WA'FU 'ANHU WAGHSILHU BI MA`IN WA TSALJIN WA BARADIN WA NAQQIHI MINADZ DZUNUUBI WAL KHATHAAYA KAMAA YUNAQQTS TSAUBUL ABYADLU MINAD DANAS WA ABDILHU BI DAARIHI WA AHLAN KHAIRAN MIN AHLIHI WAQIHI FITNATAL QABRI WA 'ADZAABAN NAAR (Ya Allah, bershalawatlah untuknya, ampuni dan rahmatilah dia, selamatkan dan maafkan kesalahannya. Mandikan dia dengan air dan es, bersihkanlah dia dari dosa dan kesalahan sebagaimana baju putih dibersihkan dari noda. Gantilah rumahnya dengan rumah yang lebih baik, dan keluarganya dengan keluarga yang lebih baik. Jagalah dia dari fitnah kubur dan siksa neraka. \" Auf berkata, \"Aku melihat posisiku hingga aku berharap sekiranya laki-laki itu adalah aku. \""},"1457":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ حَجَّاجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَمَا أَبَاحَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَبُو بَكْرٍ وَلَا عُمَرُ فِي شَيْءٍ مَا أَبَاحُوا فِي الصَّلَاةِ عَلَى الْمَيِّتِ يَعْنِي لَمْ يُوَقِّتْ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hajjaj] dari [Abu Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar tidak pernah memperbolehkan kami dalam suatu perkara sebagaimana pembolehannya dalam shalat jenazah. Maksudnya adalah tidak membatasi waktunya (boleh kapan saja). \" "},"1458":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا خَالِدُ بْنُ الْإِيَاسِ عَنْ إِسْمَعِيلَ بْنِ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَكَمِ بْنِ الْحَارِثِ عَنْ عُثْمَانَ بْنِ عَفَّانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى عُثْمَانَ بْنِ مَظْعُونٍ وَكَبَّرَ عَلَيْهِ أَرْبَعًا","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Al Mughirah bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Khalid bin Ilyas] dari [Isma'il bin Amru bin Sa'id bin Al 'Ash] dari [Utsman bin Abdullah bin Al Hakim bin Harits] dari [Utsman bin Affan] berkata, \"Nabi shallallahu 'alaihi wasallam menshalatkan Utsman bin Mazh'un dan beliau takbir sebanyak empat kali. \""},"1459":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ حَدَّثَنَا الْهَجَرِيُّ قَالَصَلَّيْتُ مَعَ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى الْأَسْلَمِيِّ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جِنَازَةِ ابْنَةٍ لَهُ فَكَبَّرَ عَلَيْهَا أَرْبَعًا فَمَكَثَ بَعْدَ الرَّابِعَةِ شَيْئًا قَالَ فَسَمِعْتُ الْقَوْمَ يُسَبِّحُونَ بِهِ مِنْ نَوَاحِي الصُّفُوفِ فَسَلَّمَ ثُمَّ قَالَ أَكُنْتُمْ تَرَوْنَ أَنِّي مُكَبِّرٌ خَمْسًا قَالُوا تَخَوَّفْنَا ذَلِكَ قَالَ لَمْ أَكُنْ لِأَفْعَلَ وَلَكِنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُكَبِّرُ أَرْبَعًا ثُمَّ يَمْكُثُ سَاعَةً فَيَقُولُ مَا شَاءَ اللَّهُ أَنْ يَقُولَ ثُمَّ يُسَلِّمُ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami ['Abdurrahman Al Muharibi] berkata, telah menceritakan kepada kami [Al Hajari] berkata; Aku bersama [Abdullah bin Abu Aufa Al Aslami] - seorang sahabat Rasulullah shallallahu 'alaihi wasallam- menshalati jenazah anak wanitanya. Ia bertakbir sebanyak empat kali kemudian diam sejenak. \" Al Hajari berkata, \"Aku lalu mendengar orang-orang mengucapkan tasbih (mengingatkan imam) dari sudut-sudut shaf, maka Abdullah bin Abu Aufa Al Aslami salam setelah itu berkata, \"Apakah kalian mengira aku akan takbir yang kelima! \" mereka berkata, \"Itulah yang kami khawatirkan. \" Ia berkata, \"Aku tidak akan melakukannya, Rasulullah shallallahu 'alaihi wasallam hanya bertakbir empat kali, lalu diam sesaat. Setelah itu beliau mengatakan atas kehendak Allah apa yang ia katakan, kemudian salam. \""},"1460":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ وَمُحَمَّدُ بْنُ الصَّبَّاحِ وَأَبُو بَكْرِ بْنُ خَلَّادٍ قَالُوا حَدَّثَنَا يَحْيَى بْنُ الْيَمَانِ عَنْ الْمِنْهَالِ بْنِ خَلِيفَةَ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'I] dan [Muhammad bin Ash Shabbah] dan [Abu Bakr bin Khallad] mereka berkata; telah menceritakan kepada kami [Yahya bin Al Yaman] dari [Al Minhal bin Khalifah] dari [Hajjaj] dari ['Atho`] dari [Ibnu Abbas] berkata, \"Nabi shallallahu 'alaihi wasallam bertakbir sebanyak empat kali. \""},"1461":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا يَحْيَى بْنُ حَكِيمٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ وَأَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَكَانَ زَيْدُ بْنُ أَرْقَمَ يُكَبِّرُ عَلَى جَنَائِزِنَا أَرْبَعًا وَأَنَّهُ كَبَّرَ عَلَى جِنَازَةٍ خَمْسًا فَسَأَلْتُهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Yahya bin Hakim] berkata, telah menceritakan kepada kami [Ibnu Abu 'Adiy] dan [Abu Dawud] dari [Amru bin Murrah] dari ['Abdurrahman bin Abu Laila] ia berkata, \"Ketika menshalati jenazah [Zaid bin Arqam] takbir sebanyak empat kali, dan suatu ketika ia pernah menshalati jenazah lalu bertakbir lima kali, maka aku pun menanyakan hal itu kepadanya, ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam pernah melakukan itu (takbir lima kali). \" "},"1462":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَلِيٍّ الرَّافِعِيُّ عَنْ كَثِيرِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ خَمْسًا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir Al Hizami] berkata, telah menceritakan kepada kami [Ibrahim bin Ali Ar Rafi'I] dari [Katsir bin Abdullah] dari [Bapaknya] dari [Kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bertakbir sebanyak lima kali. \""},"1463":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدِ اللَّهِ بْنِ جُبَيْرِ بْنِ حَيَّةَ حَدَّثَنِي عَمِّي زِيَادُ بْنُ جُبَيْرٍ حَدَّثَنِي أَبِي جُبَيْرُ بْنُ حَيَّةَ أَنَّهُ سَمِعَ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الطِّفْلُ يُصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata; telah menceritakan kepada kami [Sa'id bin Ubaidullah bin Jubair bin Hayyah] berkata, telah menceritakan kepadaku pamanku [Ziyad bin Jubair] berkata, telah menceritakan kepadaku bapakku [Jubair bin Hayyah] bahwa ia pernah mendengar [Al Mughirah bin Syu'bah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak kecil itu dishalatkan. \" "},"1464":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَهَلَّ الصَّبِيُّ صُلِّيَ عَلَيْهِ وَوُرِثَ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Rabi' bin Badr] berkata, telah menceritakan kepada kami [Abu Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika bayi telah menangis, maka ia telah berhak untuk dishalatkan dan diwarisi. \" "},"1465":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا الْبَخْتَرِيُّ بْنُ عُبَيْدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا عَلَى أَطْفَالِكُمْ فَإِنَّهُمْ مِنْ أَفْرَاطِكُمْ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Al Bakhtari bin 'Ubaid] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Shalatlah untuk anak-anak kalian, karena mereka telah mendahului kalian. \" "},"1466":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ قَالَقُلْتُ لِعَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَأَيْتَ إِبْرَاهِيمَ ابْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَاتَ وَهُوَ صَغِيرٌ وَلَوْ قُضِيَ أَنْ يَكُونَ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيٌّ لَعَاشَ ابْنُهُ وَلَكِنْ لَا نَبِيَّ بَعْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] berkata, telah menceritakan kepada kami [Isma'il bin Abu Khalid] ia berkata; Aku bertanya kepada [Abdullah bin Abu Aufa], \"Apa yang anda ketahui tentang Ibrahim putra Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab: \"Dia meninggal ketika masih kecil. Sekiranya ada Nabi setelah Nabi shallallahu 'alaihi wasallam niscaya puteranya (Ibrahim) akan hidup, tetapi tidak ada Nabi setelahnya. \""},"1467":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنَا دَاوُدُ بْنُ شَبِيبٍ الْبَاهِلِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُثْمَانَ حَدَّثَنَا الْحَكَمُ بْنُ عُتَيْبَةَ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا مَاتَ إِبْرَاهِيمُ ابْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ لَهُ مُرْضِعًا فِي الْجَنَّةِ وَلَوْ عَاشَ لَكَانَ صِدِّيقًا نَبِيًّا وَلَوْ عَاشَ لَعَتَقَتْ أَخْوَالُهُ الْقِبْطُ وَمَا اسْتُرِقَّ قِبْطِيٌّ","id":"Telah menceritakan kepada kami [Abdul Qudus bin Muhammad] berkata, telah menceritakan kepada kami [Dawud bin Syabib Al Bahili] berkata, telah menceritakan kepada kami [Ibrahim bin Utsman] berkata, telah menceritakan kepada kami [Al Hakam bin Utaibah] dari [Miqsam] dari [Ibnu Abbas] ia berkata, \"Tatkala Ibrahim putra Rasulullah shallallahu 'alaihi wasallam meninggal, Rasulullah shallallahu 'alaihi wasallam menshalatkannya, beliau berkata: \"Sesungguhnya dia memiliki orang yang menyusuinya di surga. Kalau saja ia hidup, niscaya akan menjadi seorang yang jujur dan seorang nabi. Kalau saja ia hidup niscaya paman-pamannya dari kalangan Qibti akan merdeka, tetapi Qibti bukanlah seorang budak. \""},"1468":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هِشَامُ بْنُ أَبِي الْوَلِيدِ عَنْ أُمِّهِ عَنْ فَاطِمَةَ بِنْتِ الْحُسَيْنِ عَنْ أَبِيهَا الْحُسَيْنِ بْنِ عَلِيٍّ قَالَلَمَّا تُوُفِّيَ الْقَاسِمُ ابْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ خَدِيجَةُ يَا رَسُولَ اللَّهِ دَرَّتْ لُبَيْنَةُ الْقَاسِمِ فَلَوْ كَانَ اللَّهُ أَبْقَاهُ حَتَّى يَسْتَكْمِلَ رِضَاعَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ إِتْمَامَ رَضَاعِهِ فِي الْجَنَّةِ قَالَتْ لَوْ أَعْلَمُ ذَلِكَ يَا رَسُولَ اللَّهِ لَهَوَّنَ عَلَيَّ أَمْرَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتِ دَعَوْتُ اللَّهَ تَعَالَى فَأَسْمَعَكِ صَوْتَهُ قَالَتْ يَا رَسُولَ اللَّهِ بَلْ أُصَدِّقُ اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Imran] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Hisyam bin Abul Walid] dari [Ibunya] dari [Fatimah binti Al Husain] dari bapaknya [Al Husain bin Ali] ia berkata, \"Tatkala Al Qasim putra Rasulullah shallallahu 'alaihi wasallam wafat, Khadijah berkata, \"Wahai Rasulullah, air susu Al Qasim melimpah, sekiranya saja Allah memberinya kehidupan hingga tuntas penyusuannya. \" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Sungguh penyusuannya akan disempurnakan di surga. \" Khadijah berkata, \"Wahai Rasulullah, sekiranya aku mengetahui hal itu, pasti urusannya akan menjadi ringan bagiku. \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu mau, aku akan berdo'a kepada Allah Ta'ala agar memperdengarkan suaranya kepadamu. \" Khadijah menjawab, \"Ya Rasulullah, aku percaya Allah dan Rasul-Nya shallallahu 'alaihi wasallam. \" "},"1469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُتِيَ بِهِمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَجَعَلَ يُصَلِّي عَلَى عَشَرَةٍ عَشَرَةٍ وَحَمْزَةُ هُوَ كَمَا هُوَ يُرْفَعُونَ وَهُوَ كَمَا هُوَ مَوْضُوعٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Abu Bakr bin 'Ayyas] dari [Yazid bin Abu Ziyad] dari [Miqsam] dari [Ibnu Abbas] ia berkata, \"Pada perang Uhud, mereka (para sahabat yang mati syahid) dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau menshalatkan mereka sepuluh orang-sepuluh orang, jenazah-jenazah itu diangkat silih berganti, sementara Hamzah masih dalam posisi semula (hingga ia dishalati berulang-ulang). \""},"1470":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الرَّجُلَيْنِ وَالثَّلَاثَةِ مِنْ قَتْلَى أُحُدٍ فِي ثَوْبٍ وَاحِدٍ ثُمَّ يَقُولُ أَيُّهُمْ أَكْثَرُ أَخْذًا لِلْقُرْآنِ فَإِذَا أُشِيرَ لَهُ إِلَى أَحَدِهِمْ قَدَّمَهُ فِي اللَّحْدِ وَقَالَ أَنَا شَهِيدٌ عَلَى هَؤُلَاءِ وَأَمَرَ بِدَفْنِهِمْ فِي دِمَائِهِمْ وَلَمْ يُصَلِّ عَلَيْهِمْ وَلَمْ يُغَسَّلُوا","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Ibnu Syihab] dari ['Abdurrahman bin Ka'b bin Malik] dari [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam menggabungkan dua hingga tiga laki-laki yang syahid dalam perang Uhud dalam satu kain kafan. Kemudian beliau bersabda: \"Siapakah di antara mereka yang lebih banyak hafalan Al Qur`annya?\" ketika beliau diberi isyarat pada salah satu dari mereka, beliau pun mendahulukannya ketika memasukkan ke dalam lahad. Beliau bersabda: \"Aku bersaksi atas mereka semua. \" Lalu beliau memerintahkan agar mereka dikubur dalam keadaan masih berlumuran darah, tidak dishalatkan dan tidak dimandikan. \""},"1471":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلَى أُحُدٍ أَنْ يُنْزَعَ عَنْهُمْ الْحَدِيدُ وَالْجُلُودُ وَأَنْ يُدْفَنُوا فِي ثِيَابِهِمْ بِدِمَائِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, telah menceritakan kepada kami [Ali bin Ashim] dari ['Atho` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar orang-orang yang terbunuh di peperangan Uhud agar dilepaskan dari senjata dan baju perang mereka. Setelah itu dikuburkan dengan baju dan darah mereka. \""},"1472":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ سَمِعَ نُبَيْحًا الْعَنْزِيَّ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلَى أُحُدٍ أَنْ يُرَدُّوا إِلَى مَصَارِعِهِمْ وَكَانُوا نُقِلُوا إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Hisyam bin Ammar] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Al Aswad bin Qais] ia mendengar [Nubaih Al 'Anzi] berkata, \"Aku mendengar [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan agar orang-orang yang terbunuh dalam perang Uhud dikembalikan ke tempat mereka terbunuh, maka mereka dipindahkan ke Madinah. \""},"1473":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ صَالِحٍ مَوْلَى التَّوْأَمَةِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَى جِنَازَةٍ فِي الْمَسْجِدِ فَلَيْسَ لَهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Shalih] mantan pelayan At Tau`amah, dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menshalati jenazah dalam masjid, maka ia tidak mendapat pahala (sempurna). \""},"1474":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ صَالِحِ بْنِ عَجْلَانَ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْوَاللَّهِ مَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سُهَيْلِ ابْنِ بَيْضَاءَ إِلَّا فِي الْمَسْجِدِقَالَ ابْن مَاجَةَ حَدِيثُ عَائِشَةَ أَقْوَى","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Yunus bin Muhammad] berkata, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Shalih bin 'Ajlan] dari [Abbad bin Abdullah bin Az Zubair] dari ['Aisyah] ia berkata, \"Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak menshalati Suhail bin Baidla` kecuali di dalam masjid. \" Ibnu Majah berkata, \"Hadits 'Aisyah ini lebih kuat. \""},"1475":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ جَمِيعًا عَنْ مُوسَى بْنِ عَلِيِّ بْنِ رَبَاحٍ قَالَ سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ نَقْبِرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً وَحِينَ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَمِيلَ الشَّمْسُ وَحِينَ تَضَيَّفُ لِلْغُرُوبِ حَتَّى تَغْرُبَ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] semuanya dari [Musa bin Rabah] berkata; aku mendengar [Bapakku] berkata; aku mendengar [Uqbah bin Amir Al Juhani] berkata, \"Ada tiga waktu Rasulullah shallallahu 'alaihi wasallam melarang kami untuk menegakkan shalat atau menguburkan orang-orang yang telah meninggal dari kami; ketika matahari terbit dengan jelas, ketika tengah hari hingga matahari condong dan ketika menjelang maghrib hingga matahari terbenam. \""},"1476":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ أَنْبَأَنَا يَحْيَى بْنُ الْيَمَانِ عَنْ مِنْهَالِ بْنِ خَلِيفَةَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْخَلَ رَجُلًا قَبْرَهُ لَيْلًا وَأَسْرَجَ فِي قَبْرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah memberitakan kepada kami [Yahya bin Al Yaman] dari [Minhal bin Khalifah] dari ['Atho`] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah menguburkan seseorang pada malam hari, dan memberikan penerangan di kuburnya. \""},"1477":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبْدِ اللَّهِ الْأَوْدِيُّ حَدَّثَنَا وَكِيعٌ عَنْ إِبْرَاهِيمَ بْنِ يَزِيدَ الْمَكِّيِّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْفِنُوا مَوْتَاكُمْ بِاللَّيْلِ إِلَّا أَنْ تُضْطَرُّوا","id":"Telah menceritakan kepada kami [Amru bin Abdullah Al Audi] berkata, telah menceritakan kepada kami [Waki'] dari [Ibrahim bin Yazid Al Makki] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menguburkan orang-orang yang telah meninggal dari kalian pada malam hari, kecuali terpaksa. \""},"1478":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ ابْنِ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلُّوا عَلَى مَوْتَاكُمْ بِاللَّيْلِ وَالنَّهَارِ","id":"Telah menceritakan kepada kami [Al Abbas bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Ibnu Lahi'ah] dari [Abu Zubair] dari [Jabir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Shalatkanlah orang-orang yang telah meninggal dari kalian baik di siang hari maupun malam hari. \""},"1479":{"ar":"حَدَّثَنَا أَبُو بِشْرٍ بَكْرُ بْنُ خَلَفٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آذِنُونِي بِهِ فَلَمَّا أَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ عَلَيْهِ قَالَ لَهُ عُمَرُ بْنُ الْخَطَّابِ مَا ذَاكَ لَكَ فَصَلَّى عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا بَيْنَ خِيَرَتَيْنِ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ }فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","id":"Telah menceritakan kepada kami [Abu Bisyir Bakr bin Khalaf] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Ketika Abdullah bin Ubai mati, anaknya datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, berikanlah gamismu kepadaku hingga aku bisa gunakan untuk mengkafaninya, \" Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Beritahukanlah aku (jika ia sudah siap). \" Maka ketika Nabi shallallahu 'alaihi wasallam ingin menshalatinya, Umar Ibnul Khtahthab berkata kepada beliau, \"Apa yang engkau lakukan?\" Nabi shallallahu 'alaihi wasallam kemudian menshalatinya, setelah itu bersabda: \"Aku antara dua pilihan; (Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). Maka Allah Azza Wa Jalla menurunkan: (Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya). \""},"1480":{"ar":"حَدَّثَنَا عَمَّارُ بْنُ خَالِدٍ الْوَاسِطِيُّ وَسَهْلُ بْنُ أَبِي سَهْلٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ جَابِرٍ قَالَمَاتَ رَأْسُ الْمُنَافِقِينَ بِالْمَدِينَةِ وَأَوْصَى أَنْ يُصَلِّيَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْ يُكَفِّنَهُ فِي قَمِيصِهِ فَصَلَّى عَلَيْهِ وَكَفَّنَهُ فِي قَمِيصِهِ وَقَامَ عَلَى قَبْرِهِ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","id":"Telah menceritakan kepada kami [Ammar bin khalid Al Wasithi] dan [Sahl bin Abu Sahl] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Mujalid] dari [Amir] dari [Jabir] ia berkata, \"Salah seorang pemimpin kaum munafik Madinah mati. Dan ia berwasiat agar Nabi shallallahu 'alaihi wasallam menshalatkan dan mengkafaninya dengan gamisnya. Maka beliau menshalatkan dan mengkafaninya dengan gamisnya, serta berdiri di atas kuburannya. Hingga Allah menurunkan ayat; (Dan janganlah kamu menshalati salah seorang dari mereka yang mati selamanya, dan jangan berdiri di atas kuburnya). \""},"1481":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُوسُفَ السُّلَمِيُّ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْحَارِثُ بْنُ نَبْهَانَ حَدَّثَنَا عُتْبَةُ بْنُ يَقْظَانَ عَنْ أَبِي سَعِيدٍ عَنْ مَكْحُولٍ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلُّوا عَلَى كُلِّ مَيِّتٍ وَجَاهِدُوا مَعَ كُلِّ أَمِيرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yusuf As Sulami] berkata, telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Al Harits bin Nabhan] berkata, telah menceritakan kepada kami [Utbah bin Yaqzhan] dari [Abu Sa'id] dari [Makhul] dari [Watsilah bin Al Asqa'] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatkanlah setiap mayit dan berjihadlah bersama setiap pemimpin. \""},"1482":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ زُرَارَةَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُرِحَ فَآذَتْهُ الْجِرَاحَةُ فَدَبَّ إِلَى مَشَاقِصَ فَذَبَحَ بِهَا نَفْسَهُ فَلَمْ يُصَلِّ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَكَانَ ذَلِكَ مِنْهُ أَدَبًا","id":"Telah menceritakan kepada kami [Abdullah bin Amir bin Zurarah] berkata, telah menceritakan kepada kami [Syarik bin Abdullah] dari [Simak bin Harb] dari [Jabir bin Samurah] berkata, \"Seorang laki-laki dari sahabat Nabi shallallahu 'alaihi wasallam terluka hingga membuatnya tersiksa kesakitan, ia lalu merayap menuju sebilah pedang dan bunuh diri dengan pedang tersebut, hingga Nabi shallallahu 'alaihi wasallam tidak mau menshalatinya. Jabir bin Abdullah berkata, \"Itu adalah bentuk pelajaran dari beliau. \""},"1483":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ أَنْبَأَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ امْرَأَةً سَوْدَاءَ كَانَتْ تَقُمُّ الْمَسْجِدَ فَفَقَدَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عَنْهَا بَعْدَ أَيَّامٍ فَقِيلَ لَهُ إِنَّهَا مَاتَتْ قَالَ فَهَلَّا آذَنْتُمُونِي فَأَتَى قَبْرَهَا فَصَلَّى عَلَيْهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdah] berkata, telah memberitakan kepada kami [Hammad bin Zaid] berkata, telah menceritakan kepada kami [Tsabit] dari [Abu Rafi'] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam merasa kehilangan seorang wanita berkulit hitam yang biasa merawat (kebersihan) masjid, kemudian beliau mencari tahu tentang wanita tersebut setelah beberapa hari. Lalu dikatakan kepada beliau, \"Wanita itu telah meninggal, \" beliau bersabda: \"Kenapa kalian tidak memberitahukan kepadaku! \" beliau pun mendatangi kuburannya dan menshalatinya. \""},"1484":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَنَا خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ عَنْ يَزِيدَ بْنِ ثَابِتٍ وَكَانَ أَكْبَرَ مِنْ زَيْدٍ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا وَرَدَ الْبَقِيعَ فَإِذَا هُوَ بِقَبْرٍ جَدِيدٍ فَسَأَلَ عَنْهُ قَالُوا فُلَانَةُ قَالَ فَعَرَفَهَا وَقَالَ أَلَا آذَنْتُمُونِي بِهَا قَالُوا كُنْتَ قَائِلًا صَائِمًا فَكَرِهْنَا أَنْ نُؤْذِيَكَ قَالَ فَلَا تَفْعَلُوا لَا أَعْرِفَنَّ مَا مَاتَ مِنْكُمْ مَيِّتٌ مَا كُنْتُ بَيْنَ أَظْهُرِكُمْ إِلَّا آذَنْتُمُونِي بِهِ فَإِنَّ صَلَاتِي عَلَيْهِ لَهُ رَحْمَةٌ ثُمَّ أَتَى الْقَبْرَ فَصَفَفْنَا خَلْفَهُ فَكَبَّرَ عَلَيْهِ أَرْبَعًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Husyaim] berkata, telah menceritakan kepada kami [Utsman bin Hakim] berkata, telah menceritakan kepada kami [Kharijah bin Zaid bin Tsabit] dari [Yazid bin Tsabit] -dan ia lebih tua dari pada Zaid-. Yazid berkata, \"Kami keluar bersama Nabi shallallahu 'alaihi wasallam, ketika melewati Baqi' ada sebuah kuburan yang masih baru, beliau pun menanyakan perihal kuburan tersebut. Para sahabat pun menjawab, \"Ini adalah kuburan si fulanah (kuburan seorang wanita). \" Yazid berkata, \"Ternyata beliau mengenalnya, beliau lalu bersabda: \"Kenapa kalian tidak memberitahukannya kepadaku! \" Mereka menjawab: \"Tadi engkau sedang tidur siang dan berpuasa, maka kami tidak ingin mengganggu anda. \" Beliau menjawab: \"Selayaknya kalian tidak melakukan hal itu. Sungguh aku tidak mengetahui sama sekali. Tidaklah salah seorang dari kalian yang mati kemudian aku berada di tengah kalian melainkan kalian harus mengabariku. Karena sesungguhnya shalatku merupakan rahmat baginya. \" Kemudian Beliau pergi ke kubur sementara kami membuat shaf di belakangnya, dan beliau melakukan takbir sebanyak empat kali. \""},"1485":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ حُمَيْدِ بْنِ كَاسِبٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ مُحَمَّدِ بْنِ زَيْدِ بْنِ الْمُهَاجِرِ بْنِ قُنْفُذٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِأَنَّ امْرَأَةً سَوْدَاءَ مَاتَتْ وَلَمْ يُؤْذَنْ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْبِرَ بِذَلِكَ فَقَالَ هَلَّا آذَنْتُمُونِي بِهَا ثُمَّ قَالَ لِأَصْحَابِهِ صُفُّوا عَلَيْهَا فَصَلَّى عَلَيْهَا","id":"Telah menceritakan kepada kami [Ya'qub bin Humaid bin Kasib] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Muhammad bin Zaid bin Al Muhajir bin Qunfudz] dari [Abdullah bin Amir bin Rabi'ah] dari [Bapaknya] berkata, \"Seorang wanita berkulit hitam meninggal dunia, sementara Nabi shallallahu 'alaihi wasallam tidak diberi tahu. Setelah itu beliau diberi tahu, beliau bersabda: \"Kenapa kalian tidak memberitahukannya kepadaku?\" Beliau bersabda lagi kepada para sahabatnya: \"Berbarislah. \" Kemudian beliau menshalatkannya. \" "},"1486":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ أَبِي إِسْحَقَ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَمَاتَ رَجُلٌ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَدَفَنُوهُ بِاللَّيْلِ فَلَمَّا أَصْبَحَ أَعْلَمُوهُ فَقَالَ مَا مَنَعَكُمْ أَنْ تُعْلِمُونِي قَالُوا كَانَ اللَّيْلُ وَكَانَتْ الظُّلْمَةُ فَكَرِهْنَا أَنْ نَشُقَّ عَلَيْكَ فَأَتَى قَبْرَهُ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Ali bin Muhammad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Abu Ishaq Asy Syaibani] dari [Asy Sya'bi] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki meninggal dunia, dan beliau biasa menjenguknya. Para sahabat kemudian menguburkannya di waktu malam hari, ketika pagi hari mereka baru memberitahukan kepada beliau. Beliau lalu bersabda: \"Apa yang menghalangi kalian untuk memberitahukannya kepadaku?\" mereka menjawab, \"Kami menguburkannya di malam hari, dan waktu itu sangat gelap, maka kami tidak ingin menyusahkanmu. \" Beliau lalu mendatangi kuburnya dan shalat di atasnya. \""},"1487":{"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى قَبْرٍ بَعْدَ مَا قُبِرَ","id":"Telah menceritakan kepada kami [Al Abbas bin Abdul Azhim Al 'Anbari] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Habib bin Asy Syahid] dari [Tsabit] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam shalat di atas kuburan setelah (mayat) dikuburkan. \""},"1488":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا مِهْرَانُ بْنُ أَبِي عُمَرَ عَنْ أَبِي سِنَانٍ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى مَيِّتٍ بَعْدَ مَا دُفِنَ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] berkata, telah menceritakan kepada kami [Mihran bin Abu Umar] dari [Abu Sinan] dari [Alqamah bin Martsad] dari [Ibnu Buraidah] dari [Bapaknya] berkata, \"Nabi shallallahu 'alaihi wasallam menshalati mayat setelah dikuburkan. \""},"1489":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا سَعِيدُ بْنُ شُرَحْبِيلَ عَنْ ابْنِ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ الْمُغِيرَةِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ قَالَكَانَتْ سَوْدَاءُ تَقُمُّ الْمَسْجِدَ فَتُوُفِّيَتْ لَيْلًا فَلَمَّا أَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُخْبِرَ بِمَوْتِهَا فَقَالَ أَلَا آذَنْتُمُونِي بِهَا فَخَرَجَ بِأَصْحَابِهِ فَوَقَفَ عَلَى قَبْرِهَا فَكَبَّرَ عَلَيْهَا وَالنَّاسُ خَلْفَهُ وَدَعَا لَهَا ثُمَّ انْصَرَفَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Sa'id bin Syurahbil] dari [Ibnu Lahi'ah] dari [Ubaidullah bin Al Mughirah] dari [Abul Haitsam] dari [Abu Sa'id] ia berkata, \"Dulu ada seorang wanita hitam yang sering menyapu masjid, pada suatu malam dia meninggal dunia. Di pagi hari, Rasulullah shallallahu 'alaihi wasallam diberi kabar perihal kematiannya, maka beliau bersabda: \"Kenapa kalian tidak memberitahukannya kepadaku?\" Beliau dan para sahabat kemudian keluar dan berdiri di atas kuburnya. Beliau melakukan takbir (shalat) untuknya sementara para sahabat berada di belakangnya. Beliau mendo`akannya kemudian pergi. \" "},"1490":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ النَّجَاشِيَّ قَدْ مَاتَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ إِلَى الْبَقِيعِ فَصَفَّنَا خَلْفَهُ وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Raja Najasyi telah meninggal. \" Kemudian Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya keluar menuju Baqi', kami membuat shaf di belakangnya sementara Rasulullah shallallahu 'alaihi wasallam maju ke depan dan bertakbir empat kali. \""},"1491":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ وَمُحَمَّدُ بْنُ زِيَادٍ قَالَا حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ ح و حَدَّثَنَا عَمْرُو بْنُ رَافِعٍ حَدَّثَنَا هُشَيْمٌ جَمِيعًا عَنْ يُونُسَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَخَاكُمْ النَّجَاشِيَّ قَدْ مَاتَ فَصَلُّوا عَلَيْهِ قَالَ فَقَامَ فَصَلَّيْنَا خَلْفَهُ وَإِنِّي لَفِي الصَّفِّ الثَّانِي فَصَلَّى عَلَيْهِ صَفَّيْنِ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] dan [Muhammad bin Ziyad] keduanya berkata; telah menceritakan kepada kami [Bisyr Ibnul Mufadldlal]. (dalamjalur lain disebutkan) Telah menceritakan kepada kami [Amru bin Rafi'] berkata, telah menceritakan kepada kami [Husyaim] semuanya dari [Yunus] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran Ibnul Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Raja Najasyi, saudara kalian telah meninggal dunia. Shalatlah kalian untuknya. \" Imran Ibnul Hushain berkata, \"Beliau lalu berdiri dan kami shalat di belakangnya. Aku ada di barisan kedua, dan ada dua barisan yang menshalatinya. \""},"1492":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ حُمْرَانَ بْنِ أَعْيَنَ عَنْ أَبِي الطُّفَيْلِ عَنْ مُجَمِّعِ بْنِ جَارِيَةَ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَخَاكُمْ النَّجَاشِيَّ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ فَصَفَّنَا خَلْفَهُ صَفَّيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Mu'awiyah bin Hisyam] berkata, telah menceritakan kepada kami [Sufyan] dari [Humran bin A'yan] dari [Abu Thufail] dari [Mujammi' bin Jariyah Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saudara kalian Najasyi telah meninggal, maka berdiri dan shalatilah ia. \" Lalu kami membuat dua shaf di belakang beliau. \" "},"1493":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ الْمُثَنَّى بْنِ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ بْنِ أَسِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ بِهِمْ فَقَالَ صَلُّوا عَلَى أَخٍ لَكُمْ مَاتَ بِغَيْرِ أَرْضِكُمْ قَالُوا مَنْ هُوَ قَالَ النَّجَاشِيُّ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Al Mutsanna bin Sa'id] dari [Qatadah] dari [Abu Ath Thufail] dari [Hidzaifah bin Asid] berkata, \"Nabi shallallahu 'alaihi wasallam keluar bersama para sahabatnya, beliau lalu bersabda: \"Shalatlah untuk saudara kalian yang meninggal di tempat lain, \" para sahabat bertanya, \"Siapa itu?\" beliau bersabda: \"Najasyi. \""},"1494":{"ar":"حَدَّثَنَا سَهْلُ بْنُ أَبِي سَهْلٍ حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ أَبُو السَّكَنِ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى النَّجَاشِيِّ فَكَبَّرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Sahl bin Abu Sahl] berkata, telah menceritakan kepada kami [Makki bin Ibrahim Abu Sakan] dari [Malik] dari [Nafi'] dari [Ibnu Umar] berkata, \"Nabi shallallahu 'alaihi wasallam menshalatkan Najasyi, lalu beliau bertakbir sebanyak empat takbir. \""},"1495":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَى جِنَازَةٍ فَلَهُ قِيرَاطٌ وَمَنْ انْتَظَرَ حَتَّى يُفْرَغَ مِنْهَا فَلَهُ قِيرَاطَانِ قَالُوا وَمَا الْقِيرَاطَانِ قَالَ مِثْلُ الْجَبَلَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menshalati jenazah maka ia akan mendapatkan pahala satu qirath, dan barangsiapa menunggunya hingga dikuburkan maka ia akan mendapatkan pahala dua qirath. \" Para sahabat bertanya, \"Dua qirath itu berapa?\" beliau menjawab: \"Seperti dua gunung besar. \""},"1496":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ حَدَّثَنِي سَالِمُ بْنُ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ ثَوْبَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَى جِنَازَةٍ فَلَهُ قِيرَاطٌ وَمَنْ شَهِدَ دَفْنَهَا فَلَهُ قِيرَاطَانِ قَالَ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقِيرَاطِ فَقَالَ مِثْلُ أُحُدٍ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Khalid Ibnul Harits] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] berkata, telah menceritakan kepadaku [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menshalati jenazah maka ia mendapatkan pahala satu qirath, dan barangsiapa menyaksikan hingga dikuburkan maka ia mendapatkan pahala dua qirath. \" Ma'dan berkata, \"Nabi shallallahu 'alaihi wasallam lalu ditanya tentang ukuran qirath, beliau menjawab: \"Seperti gunung Uhud. \""},"1497":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْمُحَارِبِيُّ عَنْ حَجَّاجِ بْنِ أَرْطَاةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَى جِنَازَةٍ فَلَهُ قِيرَاطٌ وَمَنْ شَهِدَهَا حَتَّى تُدْفَنَ فَلَهُ قِيرَاطَانِ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ الْقِيرَاطُ أَعْظَمُ مِنْ أُحُدٍ هَذَا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] berkata, telah menceritakan kepada kami ['Abdurrahman Al Muharibi] dari [Hajjaj bin Arthah] dari [Adi bin Tsabit] dari [Zir bin Hubasiy] dari [Ubai bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menshalati jenazah maka baginya pahala satu qirath, dan barangsiapa menyaksikannya hingga dikuburkan maka baginya pahala dua qirath. Dan demi Dzat yang jiwa Muhammad ada dalam genggaman-Nya, satu qirath adalah lebih besar dari gunung Uhud ini. \""},"1498":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عَامِرِ بْنِ رَبِيعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ عَامِرِ بْنِ رَبِيعَةَ سَمِعَهُ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الْجِنَازَةَ فَقُومُوا لَهَا حَتَّى تُخَلِّفَكُمْ أَوْ تُوضَعَ","id":"Telah menceritakan kepada kami [Muhammad bin Rumh] berkata, telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Nafi'] dari [Ibnu Umar] dari [Amir bin Rabi'ah] dari Nabi shallallahu 'alaihi wasallam. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hisyam bin Ammar] berkata, telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya] dari [Amir bin Rabi'ah] bahwa ia mendengarnya menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kalian melihat jenazah maka berdirilah hingga ia melewati kalian, atau hingga ia diletakkan. \""},"1499":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجِنَازَةٍ فَقَامَ وَقَالَ قُومُوا فَإِنَّ لِلْمَوْتِ فَزَعًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hannad bin As Sarri] keduanya berkata; telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Satu jenazah lewat di hadapan Nabi shallallahu 'alaihi wasallam, maka beliau pun berdiri dan bersabda: \"Bangunlah, sebab pada kematian ada ketakutan. \""},"1500":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ مَسْعُودِ بْنِ الْحَكَمِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجِنَازَةٍ فَقُمْنَا حَتَّى جَلَسَ فَجَلَسْنَا","id":"Telah menceritakan kepada kami [Ali bin Muhammad] dan [Waki'] dari [Syu'bah] dari [Muhammad Ibnul Munkadir] dari [Mas'ud Ibnul Hakam] dari [Ali bin Abu Thalib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri ketika ada jenazah, maka kami pun ikut berdiri. Ketika beliau duduk maka kami ikut duduk. \""}};
